def _simulation_overlay_visible() -> bool:
    return bool(getattr(simulation_runtime_state, "simulation_overlay_visible", True))


def _sync_simulation_overlay_artist_visibility() -> bool:
    visible = _simulation_overlay_visible()
    artist = globals().get("image_display")
    set_visible = getattr(artist, "set_visible", None)
    if callable(set_visible):
        try:
            set_visible(bool(visible))
        except Exception:
            pass
    return bool(visible)


def toggle_simulation_overlay_visibility() -> bool:
    """Toggle display of the simulation raster overlay without changing fit inputs."""

    simulation_runtime_state.simulation_overlay_visible = not _simulation_overlay_visible()
    visible = _sync_simulation_overlay_artist_visibility()
    try:
        progress_label.config(text=f"Simulation overlay {'shown' if visible else 'hidden'}.")
    except Exception:
        pass
    try:
        _request_main_canvas_redraw(force_matplotlib=False)
    except Exception:
        pass
    return bool(visible)


def _background_visibility_source_for_view(
    active_view_mode: str,
) -> tuple[object | None, object | None]:
    if active_view_mode not in {"caked", "q_space"}:
        return _current_background_display_for_mode(), None

    source_attr = (
        "last_caked_background_image_unscaled"
        if active_view_mode == "caked"
        else "last_q_space_background_image_unscaled"
    )
    raw_source = getattr(simulation_runtime_state, source_attr, None)
    if raw_source is None:
        return None, None

    scale = _get_scale_factor_value(default=1.0)
    source = np.asarray(raw_source, dtype=float) * scale
    source_signature = _analysis_display_raster_source_signature(
        view_mode=active_view_mode,
        role="background",
        scale=scale,
        display_source=source,
        raw_source=raw_source,
    )
    return source, source_signature


def _refresh_background_visibility_display() -> bool:
    """Refresh the current background artist visibility without scheduling updates."""

    visible = bool(getattr(background_runtime_state, "visible", True))
    active_view_mode = str(_resolved_primary_analysis_display_mode())
    source = None
    source_signature = None
    if visible:
        source, source_signature = _background_visibility_source_for_view(active_view_mode)
        visible = source is not None
    artist = globals().get("background_display")
    if visible:
        _store_primary_raster_source(artist, source, source_signature=source_signature)
        try:
            origin, extent = _primary_raster_geometry_for_view(active_view_mode)
            _store_primary_raster_geometry(artist, origin=origin, extent=extent)
            _apply_projected_primary_raster_to_artist(artist)
        except Exception:
            pass
        try:
            _apply_intensity_display_range(
                artist,
                source,
                display_controls_view_state.background_min_var.get(),
                display_controls_view_state.background_max_var.get(),
            )
        except Exception:
            pass
    set_visible = getattr(artist, "set_visible", None)
    if callable(set_visible):
        try:
            set_visible(bool(visible))
        except Exception:
            pass
    request_redraw = globals().get("_request_main_canvas_redraw")
    if callable(request_redraw):
        try:
            request_redraw(force_matplotlib=False)
        except Exception:
            pass
    return bool(visible)


