class _StartupInputSelectionCancelled(RuntimeError):
    """Signal that the user cancelled a required startup file picker."""


def _startup_path_value(key: str) -> object | None:
    if key in app_state.file_paths:
        return app_state.file_paths[key]
    try:
        return get_path(key)
    except KeyError:
        return None


def _startup_file_list(value: object) -> list[str]:
    raw_values = value if isinstance(value, Sequence) and not isinstance(value, str) else [value]
    return [
        str(Path(str(raw_path).strip()).expanduser())
        for raw_path in raw_values
        if raw_path is not None and str(raw_path).strip()
    ]


def _required_startup_file(key: str) -> str:
    value = _startup_path_value(key)
    candidate = Path(str(value)).expanduser() if value is not None else None
    if candidate is None or not candidate.is_file():
        raise FileNotFoundError(f"No valid file selected for {key}.")
    return str(candidate)


def _ensure_startup_inputs_selected() -> None:
    """Prompt for required experiment files that are absent from local config."""

    background_paths = _startup_file_list(background_runtime_state.osc_files)
    if not background_paths or any(not Path(path).is_file() for path in background_paths):
        selected = filedialog.askopenfilenames(
            parent=root,
            title="Select Background OSC Files",
            initialdir=str(get_dir("file_dialog_dir")),
            filetypes=[("OSC files", "*.osc *.OSC"), ("All files", "*.*")],
        )
        background_paths = _startup_file_list(selected)
        if not background_paths:
            raise _StartupInputSelectionCancelled(
                "Startup cancelled: no background OSC files were selected."
            )
        missing = [path for path in background_paths if not Path(path).is_file()]
        if missing:
            raise FileNotFoundError(f"Background file not found: {missing[0]}")
        background_runtime_state.osc_files = background_paths
        app_state.file_paths["simulation_background_osc_files"] = list(background_paths)

    required_files = (
        (
            "geometry_poni",
            "Select Detector Geometry PONI File",
            [("PONI files", "*.poni *.PONI"), ("All files", "*.*")],
        ),
        (
            "cif_file",
            "Select Primary CIF File",
            [("CIF files", "*.cif *.CIF"), ("All files", "*.*")],
        ),
    )
    for key, title, filetypes in required_files:
        value = _startup_path_value(key)
        candidate = Path(str(value)).expanduser() if value is not None else None
        if candidate is not None and candidate.is_file():
            continue
        selected = filedialog.askopenfilename(
            parent=root,
            title=title,
            initialdir=str(get_dir("file_dialog_dir")),
            filetypes=filetypes,
        )
        if not selected:
            raise _StartupInputSelectionCancelled(f"Startup cancelled: no {key} file was selected.")
        candidate = Path(str(selected)).expanduser()
        if not candidate.is_file():
            raise FileNotFoundError(f"Selected file not found: {candidate}")
        app_state.file_paths[key] = str(candidate)


