def _runtime_report_callback_exception(exc_type, exc_value, exc_tb):
    """Surface Tk callback failures to the console and user."""

    try:
        traceback.print_exception(exc_type, exc_value, exc_tb)
    except Exception:
        pass
    try:
        messagebox.showerror(
            "SLATE-rMC Error",
            f"An unexpected GUI callback error occurred:\n{exc_value}",
        )
    except Exception:
        pass


