def _resolve_primary_extent(raw_extent: object, fallback: Sequence[float]) -> list[float]:
    if isinstance(raw_extent, Sequence) and len(raw_extent) >= 4:
        try:
            extent = [float(raw_extent[index]) for index in range(4)]
        except Exception:
            pass
        else:
            if (
                all(math.isfinite(value) for value in extent)
                and abs(extent[1] - extent[0]) > 1.0e-12
                and abs(extent[3] - extent[2]) > 1.0e-12
            ):
                return extent
    return list(fallback)


def _primary_raster_geometry_for_view(view_mode: str) -> tuple[str, list[float]]:
    normalized_mode = str(view_mode or "").strip().lower()
    if normalized_mode == "q_space":
        return "lower", _resolve_primary_extent(
            getattr(simulation_runtime_state, "last_q_space_extent", None),
            (0.0, 1.0, -1.0, 1.0),
        )
    if normalized_mode == "caked":
        return "lower", _resolve_primary_extent(
            getattr(simulation_runtime_state, "last_caked_extent", None),
            (0.0, 90.0, -180.0, 180.0),
        )
    return "upper", [0.0, float(image_size), float(image_size), 0.0]


def _sync_primary_raster_geometry(
    *,
    show_caked_image: bool | None = None,
    view_mode: str | None = None,
) -> None:
    normalized_mode = str(view_mode or "").strip().lower()
    if normalized_mode not in {"detector", "caked", "q_space"}:
        normalized_mode = "caked" if bool(show_caked_image) else "detector"
    origin, extent = _primary_raster_geometry_for_view(normalized_mode)
    for artist in (image_display, background_display, integration_region_overlay):
        if artist is None:
            continue
        controls_ready = bool(globals().get("_RUNTIME_CONTROLS_INITIALIZED", False))
        store_geometry = globals().get("_store_primary_raster_geometry") if controls_ready else None
        apply_projection = (
            globals().get("_apply_projected_primary_raster_to_artist") if controls_ready else None
        )
        if callable(store_geometry):
            store_geometry(artist, origin=origin, extent=extent)
        if callable(apply_projection):
            apply_projection(artist)
            continue
        artist.origin = origin
        setter = getattr(artist, "set_extent", None)
        if callable(setter):
            setter(list(extent))


def _initialize_runtime_plot_block_02() -> None:
    _sync_primary_raster_geometry(show_caked_image=False)


