def _undo_last_geometry_manual_placement() -> None:
    """Restore the most recent manual-placement state."""

    if not geometry_manual_state.undo_stack:
        progress_label_geometry.config(text="No manual placement changes are available to undo.")
        return

    gui_controllers.restore_last_manual_geometry_undo_state(geometry_manual_state)
    _sync_geometry_fit_background_selection_after_manual_pair_update(None, None)
    _clear_geometry_fit_dataset_cache()
    _clear_geometry_manual_preview_artists(redraw=False)
    _render_current_geometry_manual_pairs(update_status=True)
    _update_geometry_manual_pick_button_label()
    _refresh_background_status()
    progress_label_geometry.config(text="Undid the last manual placement change.")


def _refine_geometry_manual_pair_entry_from_cache(
    entry: dict[str, object] | None,
    *,
    source_entry: dict[str, object] | None = None,
    reuse_only: bool = False,
    invalidate_pick_cache: bool = True,
) -> dict[str, object] | None:
    """Refine one saved manual-pair simulation point from the cached caked peak map."""

    if not isinstance(entry, dict):
        return None

    updated_entry = dict(entry)
    try:
        caked_sim_image = np.asarray(
            simulation_runtime_state.last_caked_image_unscaled,
            dtype=float,
        )
        radial_axis = np.asarray(
            simulation_runtime_state.last_caked_radial_values,
            dtype=float,
        )
        azimuth_axis = np.asarray(
            simulation_runtime_state.last_caked_azimuth_values,
            dtype=float,
        )
    except Exception:
        return updated_entry

    if (
        caked_sim_image.ndim != 2
        or caked_sim_image.size == 0
        or radial_axis.size <= 0
        or azimuth_axis.size <= 0
    ):
        return updated_entry

    stored_sim_image = getattr(simulation_runtime_state, "stored_sim_image", None)
    if stored_sim_image is not None:
        native_image_shape = tuple(int(v) for v in np.asarray(stored_sim_image).shape[:2])
    else:
        native_image_shape = (int(image_size), int(image_size))

    placement_refine_cache: dict[str, object] = {}
    resolved_source_entry = dict(source_entry) if source_entry is not None else None
    has_source_entry = resolved_source_entry is not None
    if has_source_entry:
        try:
            sim_match_cfg = dict(_current_geometry_manual_match_config())
        except Exception:
            sim_match_cfg = {}
    else:
        try:
            placement_refine_cache = _get_geometry_manual_pick_cache(
                param_set=dict(_current_geometry_fit_params()),
                prefer_cache=True,
                reuse_only=bool(reuse_only),
                background_image=_current_geometry_manual_pick_background_image(),
            )
            sim_match_cfg = dict(placement_refine_cache.get("match_config", {}))
        except Exception:
            placement_refine_cache = {}
            sim_match_cfg = {}
    try:
        resolved_sim_match_cfg, sim_background_context = _auto_match_background_context(
            caked_sim_image,
            sim_match_cfg,
        )
    except Exception:
        resolved_sim_match_cfg = dict(sim_match_cfg)
        sim_background_context = None
    sim_refine_cache = {
        "match_config": dict(resolved_sim_match_cfg),
        "background_context": sim_background_context,
    }

    if not has_source_entry:
        simulated_lookup = dict(placement_refine_cache.get("simulated_lookup", {}))
        resolved_source_entry = gui_manual_geometry.geometry_manual_lookup_source_entry(
            simulated_lookup,
            updated_entry,
            normalize_hkl_key=_normalize_hkl_key,
        )
    if resolved_source_entry is None:
        return updated_entry
    try:
        seed_tth = float(
            resolved_source_entry.get(
                "caked_x",
                resolved_source_entry.get("two_theta_deg", np.nan),
            )
        )
        seed_phi = float(
            resolved_source_entry.get(
                "caked_y",
                resolved_source_entry.get("phi_deg", np.nan),
            )
        )
    except Exception:
        seed_tth = float("nan")
        seed_phi = float("nan")
    if not (np.isfinite(seed_tth) and np.isfinite(seed_phi)):
        try:
            seed_tth = float(
                updated_entry.get(
                    "refined_sim_caked_x",
                    updated_entry.get("caked_x", updated_entry.get("raw_caked_x", np.nan)),
                )
            )
            seed_phi = float(
                updated_entry.get(
                    "refined_sim_caked_y",
                    updated_entry.get("caked_y", updated_entry.get("raw_caked_y", np.nan)),
                )
            )
        except Exception:
            seed_tth = float("nan")
            seed_phi = float("nan")
    if not (np.isfinite(seed_tth) and np.isfinite(seed_phi)):
        return updated_entry

    refined_tth, refined_phi = gui_manual_geometry.geometry_manual_refine_preview_point(
        source_entry=resolved_source_entry,
        raw_col=float(seed_tth),
        raw_row=float(seed_phi),
        display_background=caked_sim_image,
        cache_data=sim_refine_cache,
        use_caked_space=True,
        radial_axis=radial_axis,
        azimuth_axis=azimuth_axis,
        match_simulated_peaks_to_peak_context=match_simulated_peaks_to_peak_context,
        caked_axis_to_image_index_fn=gui_manual_geometry.caked_axis_to_image_index,
        caked_image_index_to_axis_fn=gui_manual_geometry.caked_image_index_to_axis,
        refine_caked_peak_center_fn=_refine_caked_peak_center,
    )
    if not (np.isfinite(refined_tth) and np.isfinite(refined_phi)):
        return updated_entry

    updated_entry["refined_sim_caked_x"] = float(refined_tth)
    updated_entry["refined_sim_caked_y"] = float(refined_phi)

    try:
        refined_background_display = _caked_angles_to_background_display_coords(
            float(refined_tth),
            float(refined_phi),
        )
    except Exception:
        refined_background_display = None
    try:
        native_point = (
            _background_display_to_native_detector_coords(
                float(refined_background_display[0]),
                float(refined_background_display[1]),
            )
            if (
                isinstance(refined_background_display, tuple)
                and len(refined_background_display) >= 2
                and refined_background_display[0] is not None
                and refined_background_display[1] is not None
                and np.isfinite(float(refined_background_display[0]))
                and np.isfinite(float(refined_background_display[1]))
            )
            else None
        )
    except Exception:
        native_point = None
    if (
        isinstance(native_point, tuple)
        and len(native_point) >= 2
        and np.isfinite(float(native_point[0]))
        and np.isfinite(float(native_point[1]))
    ):
        updated_entry["refined_sim_native_x"] = float(native_point[0])
        updated_entry["refined_sim_native_y"] = float(native_point[1])
        refined_display = _geometry_manual_detector_display_from_native(
            float(native_point[0]),
            float(native_point[1]),
            native_image_shape,
        )
        if (
            isinstance(refined_display, tuple)
            and len(refined_display) >= 2
            and np.isfinite(float(refined_display[0]))
            and np.isfinite(float(refined_display[1]))
        ):
            updated_entry["refined_sim_x"] = float(refined_display[0])
            updated_entry["refined_sim_y"] = float(refined_display[1])

    if bool(invalidate_pick_cache):
        geometry_runtime_state.manual_pick_cache_signature = None
        geometry_runtime_state.manual_pick_cache_data = {}
    return updated_entry


def _refine_geometry_manual_auto_seed_candidate(
    candidate: dict[str, object] | None,
    *,
    use_caked_space: bool,
    auto_refine_search_radius_px: object | None = None,
    **_kwargs,
) -> dict[str, object] | None:
    """Refine the simulated candidate before using it as an automatic pick seed."""

    if not isinstance(candidate, dict):
        return None
    search_radius = _geometry_manual_auto_refine_search_radius_px(auto_refine_search_radius_px)
    try:
        refined_candidate = gui_manual_geometry.geometry_manual_refine_qr_sim_peak_for_view(
            candidate,
            view_mode="caked" if bool(use_caked_space) else "detector",
            detector_simulation_image=simulation_runtime_state.unscaled_image,
            detector_display_to_native_coords=_background_display_to_native_detector_coords,
            native_detector_coords_to_caked_display_coords=(
                _native_detector_coords_to_caked_display_coords
            ),
            search_radius_px=max(1, int(round(float(search_radius)))),
        )
    except Exception:
        refined_candidate = None
    if isinstance(refined_candidate, Mapping):
        return dict(refined_candidate)
    return dict(candidate)


def _toggle_geometry_background_qr_set_pick_mode() -> None:
    """Arm one-click placement for a background-only Qr reference point."""

    background_index = int(background_runtime_state.current_background_index)
    current_session = geometry_manual_state.pick_session
    if bool(
        getattr(geometry_runtime_state, "manual_pick_armed", False)
    ) and gui_manual_geometry.geometry_manual_pick_session_is_background_qr_reference(
        current_session
    ):
        _set_geometry_manual_pick_mode(False, message="Background Qr reference picking disabled.")
        return

    display_background = _current_geometry_manual_pick_background_image()
    if display_background is None:
        progress_label_geometry.config(
            text="Load a background image before placing a background Qr reference."
        )
        return

    if gui_manual_geometry.geometry_manual_pick_session_active(
        current_session,
        current_background_index=background_index,
    ):
        _set_geometry_manual_pick_mode(False, message="Manual Qr/Qz placement canceled.")

    base_entries = [dict(entry) for entry in _geometry_manual_pairs_for_index(background_index)]
    session = gui_manual_geometry.start_geometry_manual_background_qr_reference_session(
        current_background_index=background_index,
        base_entries=base_entries,
    )
    _set_geometry_manual_pick_session(session)
    _set_geometry_manual_pick_mode(
        True,
        message=(
            "Background Qr reference picking armed. Click the background peak; "
            "local peak fitting will snap to the top and save its 2theta/phi label."
        ),
    )
    _render_current_geometry_manual_pairs(update_status=False)
    _update_geometry_manual_pick_button_label()


def _add_all_current_geometry_q_group_peaks() -> None:
    """Auto-place all enabled Qr/Qz set peaks for the current background."""

    background_index = int(background_runtime_state.current_background_index)
    display_background = _current_geometry_manual_pick_background_image()
    auto_search_radius = _geometry_manual_auto_refine_search_radius_px()
    if gui_manual_geometry.geometry_manual_pick_session_active(
        geometry_manual_state.pick_session,
        current_background_index=background_index,
    ):
        progress_label_geometry.config(
            text="Finish the active Qr/Qz placement before auto-adding Qr set peaks."
        )
        return

    try:
        listed_entries = [
            dict(entry)
            for entry in (_listed_geometry_q_group_entries() or ())
            if isinstance(entry, Mapping)
        ]
    except Exception:
        listed_entries = []
    selected_entries = None
    if listed_entries:
        selected_entries = gui_controllers.filter_enabled_q_group_rows(
            listed_entries,
            geometry_q_group_state,
        )
        if not selected_entries:
            progress_label_geometry.config(
                text="No enabled Qr/Qz groups are selected for automatic placement."
            )
            return

    def _get_auto_place_cache(**kwargs: object) -> dict[str, object]:
        cache_data = _get_geometry_manual_pick_cache(
            param_set=dict(_current_geometry_fit_params()),
            prefer_cache=True,
            **kwargs,
        )
        adjusted_cache = gui_manual_geometry.geometry_manual_cache_with_auto_refine_search_radius(
            cache_data,
            search_radius_px=auto_search_radius,
        )
        background_for_context = kwargs.get("background_image", display_background)
        match_cfg = (
            dict(adjusted_cache.get("match_config", {}))
            if isinstance(adjusted_cache.get("match_config"), Mapping)
            else {}
        )
        if background_for_context is not None and match_cfg:
            try:
                resolved_cfg, background_context = _auto_match_background_context(
                    background_for_context,
                    match_cfg,
                )
            except Exception:
                resolved_cfg = dict(match_cfg)
                background_context = adjusted_cache.get("background_context")
            adjusted_cache["match_config"] = dict(resolved_cfg)
            adjusted_cache["background_context"] = background_context
        return adjusted_cache

    result = gui_manual_geometry.geometry_manual_auto_add_q_group_peaks(
        current_background_index=background_index,
        display_background=display_background,
        get_cache_data=_get_auto_place_cache,
        pairs_for_index=_geometry_manual_pairs_for_index,
        set_pairs_for_index_fn=_set_geometry_manual_pairs_for_index,
        set_pick_session_fn=_set_geometry_manual_pick_session,
        clear_preview_artists_fn=_clear_geometry_manual_preview_artists,
        restore_view_fn=_restore_geometry_manual_pick_view,
        render_current_pairs_fn=_render_current_geometry_manual_pairs,
        update_button_label_fn=_update_geometry_manual_pick_button_label,
        refine_preview_point=_geometry_manual_refine_preview_point,
        selected_q_group_entries=selected_entries,
        format_q_group_line=_format_geometry_q_group_line,
        set_status_text=lambda text: progress_label_geometry.config(text=text),
        push_undo_state_fn=_push_geometry_manual_undo_state,
        use_caked_space=_geometry_manual_pick_uses_caked_space(),
        caked_angles_to_background_display_coords=_caked_angles_to_background_display_coords,
        background_display_to_native_detector_coords=(
            _background_display_to_native_detector_coords
        ),
        native_detector_coords_to_caked_display_coords=(
            _native_detector_coords_to_caked_display_coords
        ),
        radial_axis=np.asarray(simulation_runtime_state.last_caked_radial_values, dtype=float),
        azimuth_axis=np.asarray(simulation_runtime_state.last_caked_azimuth_values, dtype=float),
        caked_axis_to_image_index_fn=gui_manual_geometry.caked_axis_to_image_index,
        caked_image_index_to_axis_fn=gui_manual_geometry.caked_image_index_to_axis,
        position_error_px=gui_manual_geometry.geometry_manual_position_error_px,
        position_sigma_px=(
            lambda value, *, floor_px=None: gui_manual_geometry.geometry_manual_position_sigma_px(
                value,
                floor_px=float(
                    GEOMETRY_MANUAL_POSITION_SIGMA_FLOOR_PX if floor_px is None else floor_px
                ),
            )
        ),
        refine_saved_pair_entry_fn=(
            lambda entry, candidate=None: _refine_geometry_manual_pair_entry_from_cache(
                entry,
                source_entry=candidate,
            )
        ),
        refine_sim_candidate_fn=_refine_geometry_manual_auto_seed_candidate,
        auto_refine_search_radius_px=auto_search_radius,
        profile_cache=simulation_runtime_state.profile_cache,
    )
    if int(result.get("placed_count", 0) or 0) > 0:
        _clear_geometry_fit_dataset_cache()
        _refresh_background_status()


def _remove_current_geometry_q_group_peaks() -> None:
    """Remove saved manual placements for the enabled Qr/Qz set rows."""

    background_index = int(background_runtime_state.current_background_index)
    if gui_manual_geometry.geometry_manual_pick_session_active(
        geometry_manual_state.pick_session,
        current_background_index=background_index,
    ):
        progress_label_geometry.config(
            text="Finish the active Qr/Qz placement before removing Qr set peaks."
        )
        return

    try:
        listed_entries = [
            dict(entry)
            for entry in (_listed_geometry_q_group_entries() or ())
            if isinstance(entry, Mapping)
        ]
    except Exception:
        listed_entries = []
    if not listed_entries:
        progress_label_geometry.config(
            text="No listed Qr/Qz groups are available to remove. Update or select Qr sets first."
        )
        return
    selected_entries = gui_controllers.filter_enabled_q_group_rows(
        listed_entries,
        geometry_q_group_state,
    )
    if not selected_entries:
        progress_label_geometry.config(text="No enabled Qr/Qz groups are selected for removal.")
        return

    current_entries = [dict(entry) for entry in _geometry_manual_pairs_for_index(background_index)]
    if not current_entries:
        progress_label_geometry.config(
            text="No saved Qr/Qz placements exist for the current background image."
        )
        return

    kept_entries, removed_count, removed_keys = (
        gui_manual_geometry.geometry_manual_remove_q_group_peak_entries(
            current_entries,
            selected_q_group_entries=selected_entries,
        )
    )
    if removed_count <= 0:
        progress_label_geometry.config(
            text="No saved placements matched the enabled Qr/Qz groups for this background."
        )
        return

    _push_geometry_manual_undo_state()
    _set_geometry_manual_pairs_for_index(background_index, kept_entries)
    _set_geometry_manual_pick_session({})
    _clear_geometry_fit_dataset_cache()
    _clear_geometry_manual_preview_artists(redraw=False)
    _render_current_geometry_manual_pairs(update_status=False)
    _update_geometry_manual_pick_button_label()
    _refresh_background_status()
    progress_label_geometry.config(
        text=(
            f"Removed {removed_count} manual Qr/Qz peak placements across "
            f"{len(removed_keys)} enabled groups on background {background_index + 1}."
        )
    )


def _copy_geometry_fit_state_value(value):
    """Deep-copy simple geometry-fit GUI state."""

    return gui_geometry_fit.copy_geometry_fit_state_value(value)


def _geometry_fit_last_overlay_state() -> dict[str, object] | None:
    """Return the remembered geometry-fit overlay state."""

    history_state = globals().get("geometry_fit_history_state")
    if history_state is None:
        return None
    return getattr(history_state, "last_overlay_state", None)


def _set_geometry_fit_dataset_cache(
    payload: dict[str, object] | None,
) -> dict[str, object] | None:
    """Replace the cached successful geometry-fit dataset bundle."""

    if not payload:
        gui_controllers.clear_geometry_fit_dataset_cache(geometry_fit_dataset_cache_state)
        return None
    return gui_controllers.replace_geometry_fit_dataset_cache(
        geometry_fit_dataset_cache_state,
        payload,
        copy_state_value=_copy_geometry_fit_state_value,
    )


def _clear_geometry_fit_dataset_cache() -> None:
    """Discard the cached successful geometry-fit dataset bundle."""

    gui_controllers.clear_geometry_fit_dataset_cache(geometry_fit_dataset_cache_state)


def _set_geometry_fit_last_overlay_state(
    overlay_state: dict[str, object] | None,
) -> dict[str, object] | None:
    """Replace the remembered geometry-fit overlay state."""

    history_state = globals().get("geometry_fit_history_state")
    if history_state is None:
        return None
    return gui_controllers.replace_geometry_fit_last_overlay_state(
        history_state,
        overlay_state,
        copy_state_value=_copy_geometry_fit_state_value,
    )




def _current_geometry_fit_ui_params() -> dict[str, object]:
    """Capture the current geometry-fit UI parameter values."""

    return _geometry_fit_runtime_values().current_ui_params()


def _clear_geometry_fit_undo_stack() -> None:
    """Discard the geometry-fit undo/redo history."""

    gui_controllers.clear_geometry_fit_history(geometry_fit_history_state)
    _clear_geometry_fit_dataset_cache()
    _clear_geometry_fit_pending_review()
    _update_geometry_fit_undo_button_state()


GEOMETRY_FIT_REVIEW_PRIOR_IMAGE = "prior"
GEOMETRY_FIT_REVIEW_NEW_IMAGE = "new"


def _geometry_fit_review_image_snapshot(
    image: object,
    *,
    extent: object | None = None,
    origin: str = "upper",
    source_signature: object | None = None,
    view_mode: str | None = None,
) -> dict[str, object] | None:
    """Return a copied display-image snapshot suitable for pending fit review."""

    try:
        array = np.asarray(image)
    except Exception:
        return None
    if array.ndim < 2 or array.size <= 0:
        return None

    normalized_extent: tuple[float, float, float, float] | None = None
    if isinstance(extent, (list, tuple)) and len(extent) == 4:
        try:
            candidate = tuple(float(value) for value in extent)
        except Exception:
            candidate = None
        if (
            isinstance(candidate, tuple)
            and len(candidate) == 4
            and all(np.isfinite(value) for value in candidate)
        ):
            normalized_extent = candidate

    return {
        "image": array.copy(),
        "extent": normalized_extent,
        "origin": str(origin or "upper"),
        "source_signature": source_signature,
        "view_mode": str(view_mode or _current_primary_figure_mode()),
    }


def _geometry_fit_review_current_display_snapshot() -> dict[str, object] | None:
    """Capture the current primary image artist source for later comparison."""

    artist = globals().get("image_display")
    source, extent, origin, source_signature = _primary_raster_source_payload(artist)
    if source is None:
        source = globals().get("global_image_buffer")
    return _geometry_fit_review_image_snapshot(
        source,
        extent=extent,
        origin=origin,
        source_signature=source_signature,
        view_mode=_current_primary_figure_mode(),
    )


def _geometry_fit_pending_review() -> dict[str, object] | None:
    review = geometry_runtime_state.geometry_fit_pending_review
    return review if isinstance(review, dict) else None


def _geometry_fit_review_snapshot(
    review: Mapping[str, object] | None,
    image_key: str,
) -> Mapping[str, object] | None:
    if not isinstance(review, Mapping):
        return None
    normalized_key = str(image_key)
    if normalized_key not in {GEOMETRY_FIT_REVIEW_PRIOR_IMAGE, GEOMETRY_FIT_REVIEW_NEW_IMAGE}:
        return None
    snapshot = review.get(normalized_key)
    return snapshot if isinstance(snapshot, Mapping) else None


def _geometry_fit_review_can_compare(review: Mapping[str, object] | None = None) -> bool:
    current_review = _geometry_fit_pending_review() if review is None else review
    return bool(
        _geometry_fit_review_snapshot(current_review, GEOMETRY_FIT_REVIEW_PRIOR_IMAGE) is not None
        and _geometry_fit_review_snapshot(current_review, GEOMETRY_FIT_REVIEW_NEW_IMAGE) is not None
    )


def _set_geometry_fit_review_progress_text(text: str) -> None:
    try:
        progress_label_geometry.config(text=str(text))
    except Exception:
        pass


def _clear_geometry_fit_pending_review(*, update_controls: bool = True) -> None:
    geometry_runtime_state.geometry_fit_pending_review = None
    if update_controls:
        _update_geometry_fit_review_button_state()
        _set_geometry_fit_button_running(False)


def _update_geometry_fit_review_button_state() -> None:
    review = _geometry_fit_pending_review()
    can_compare = _geometry_fit_review_can_compare(review)
    try:
        gui_views.set_geometry_fit_review_button_state(
            geometry_tool_actions_view_state,
            can_compare=can_compare,
            active_view=(
                str(review.get("active"))
                if isinstance(review, Mapping) and review.get("active") is not None
                else None
            ),
        )
    except Exception:
        pass


def _geometry_fit_review_pending_active() -> bool:
    return _geometry_fit_pending_review() is not None


def _begin_geometry_fit_pending_review() -> None:
    prior_snapshot = _geometry_fit_review_current_display_snapshot()
    if prior_snapshot is None:
        _clear_geometry_fit_pending_review()
        return
    geometry_runtime_state.geometry_fit_pending_review = {
        GEOMETRY_FIT_REVIEW_PRIOR_IMAGE: prior_snapshot,
        GEOMETRY_FIT_REVIEW_NEW_IMAGE: None,
        "active": GEOMETRY_FIT_REVIEW_PRIOR_IMAGE,
        "status": "running",
        "action_result": None,
    }
    _update_geometry_fit_review_button_state()
    _set_geometry_fit_button_running(True)


def _geometry_fit_action_result_accepted(action_result: object) -> bool:
    execution_result = getattr(action_result, "execution_result", None)
    apply_result = getattr(execution_result, "apply_result", None)
    return bool(getattr(apply_result, "accepted", False))


def _prepare_geometry_fit_pending_review_after_action(action_result: object | None) -> None:
    review = _geometry_fit_pending_review()
    if review is None:
        return
    if not _geometry_fit_action_result_accepted(action_result):
        _clear_geometry_fit_pending_review()
        return
    review["status"] = "awaiting_new_image"
    review["action_result"] = action_result
    _update_geometry_fit_review_button_state()
    _set_geometry_fit_button_running(True)


def _geometry_fit_apply_review_snapshot(
    snapshot: Mapping[str, object],
    *,
    image_key: str,
) -> bool:
    image = snapshot.get("image")
    try:
        image_array = np.asarray(image)
    except Exception:
        return False
    if image_array.ndim < 2 or image_array.size <= 0:
        return False

    artist = globals().get("image_display")
    if artist is None:
        return False
    _store_primary_raster_source(
        artist,
        image_array,
        source_signature=("geometry_fit_review", str(image_key), id(image_array)),
    )
    extent = snapshot.get("extent")
    if isinstance(extent, (list, tuple)) and len(extent) == 4:
        _store_primary_raster_geometry(
            artist,
            origin=str(snapshot.get("origin", "upper") or "upper"),
            extent=extent,
        )
    _apply_projected_primary_raster_to_artist(artist)
    try:
        colorbar_main.update_normal(artist)
    except Exception:
        pass
    _request_main_canvas_redraw(force_matplotlib=False)
    return True


def _geometry_fit_review_show_cached_image(image_key: str) -> bool:
    review = _geometry_fit_pending_review()
    normalized_key = str(image_key)
    snapshot = _geometry_fit_review_snapshot(review, normalized_key)
    if snapshot is None:
        return False
    if not _geometry_fit_apply_review_snapshot(snapshot, image_key=normalized_key):
        return False
    review["active"] = normalized_key
    _update_geometry_fit_review_button_state()
    return True


def _show_geometry_fit_review_prior_image() -> bool:
    return _geometry_fit_review_show_cached_image(GEOMETRY_FIT_REVIEW_PRIOR_IMAGE)


def _show_geometry_fit_review_new_image() -> bool:
    return _geometry_fit_review_show_cached_image(GEOMETRY_FIT_REVIEW_NEW_IMAGE)


def _capture_geometry_fit_review_new_image_after_update() -> None:
    review = _geometry_fit_pending_review()
    if not isinstance(review, dict):
        return
    if str(review.get("status", "")) != "awaiting_new_image":
        return
    if isinstance(review.get(GEOMETRY_FIT_REVIEW_NEW_IMAGE), Mapping):
        return
    new_snapshot = _geometry_fit_review_current_display_snapshot()
    if new_snapshot is None:
        return
    review[GEOMETRY_FIT_REVIEW_NEW_IMAGE] = new_snapshot
    review["active"] = GEOMETRY_FIT_REVIEW_NEW_IMAGE
    review["status"] = "pending_decision"
    _update_geometry_fit_review_button_state()
    _set_geometry_fit_review_progress_text(
        "Geometry fit ready for review: compare Prior/New, then Keep Fit or Revert Fit."
    )


def _accept_pending_geometry_fit_review() -> bool:
    review = _geometry_fit_pending_review()
    if review is None or not _geometry_fit_review_can_compare(review):
        return False
    _geometry_fit_review_show_cached_image(GEOMETRY_FIT_REVIEW_NEW_IMAGE)
    _clear_geometry_fit_pending_review()
    _set_geometry_fit_review_progress_text("Geometry fit kept.")
    return True


def _reject_pending_geometry_fit_review() -> bool:
    review = _geometry_fit_pending_review()
    if review is None or not _geometry_fit_review_can_compare(review):
        return False
    _geometry_fit_review_show_cached_image(GEOMETRY_FIT_REVIEW_PRIOR_IMAGE)
    restored = bool(_undo_last_geometry_fit())
    _clear_geometry_fit_pending_review()
    _set_geometry_fit_review_progress_text(
        (
            "Geometry fit reverted; restored previous geometry."
            if restored
            else "Geometry fit reverted; previous geometry restore was unavailable."
        )
    )
    return bool(restored)


