def _current_geometry_fit_caked_roi_selection(
    *,
    force_enabled: bool = False,
) -> Mapping[str, object] | None:
    """Return the current selected-branch detector ROI for geometry-fit preview/use."""

    background_index = int(background_runtime_state.current_background_index)
    required_pairs = [
        dict(entry)
        for entry in (_geometry_manual_pairs_for_index(int(background_index)) or ())
        if isinstance(entry, Mapping)
    ]
    if not required_pairs:
        return None

    native_background = _get_current_background_native()
    if native_background is None:
        return None
    native_shape = tuple(int(v) for v in np.asarray(native_background).shape[:2])
    if len(native_shape) < 2 or native_shape[0] <= 0 or native_shape[1] <= 0:
        return None

    source_rows = [
        dict(entry)
        for entry in (_build_live_preview_simulated_peaks_from_cache() or ())
        if isinstance(entry, Mapping)
    ]
    if not source_rows:
        return None

    selection = gui_geometry_fit.build_geometry_fit_caked_roi_selection(
        source_rows,
        required_pairs=required_pairs,
        image_shape=native_shape,
        fit_config=fit_config,
        enabled_override=(True if force_enabled else _current_geometry_fit_caked_roi_enabled()),
        fit_space_to_detector_point=_geometry_fit_caked_roi_fit_space_to_detector_point(
            detector_shape=native_shape,
            radial_axis=simulation_runtime_state.last_caked_radial_values,
            azimuth_axis=simulation_runtime_state.last_caked_azimuth_values,
            ai=simulation_runtime_state.ai_cache.get("ai"),
            transform_bundle=_current_live_caked_transform_bundle(),
        ),
    )
    return selection if isinstance(selection, Mapping) else None


def _rotate_native_detector_pixels_for_display(
    rows: np.ndarray,
    cols: np.ndarray,
    *,
    native_shape: tuple[int, int],
    k: int,
) -> tuple[np.ndarray, np.ndarray, tuple[int, int]]:
    """Rotate native detector pixel indices into display-space indices."""

    disp_rows = np.asarray(rows, dtype=np.int64).reshape(-1)
    disp_cols = np.asarray(cols, dtype=np.int64).reshape(-1)
    height = int(native_shape[0])
    width = int(native_shape[1])
    for _ in range(int(k) % 4):
        disp_rows, disp_cols, height, width = (
            (int(width) - 1) - disp_cols,
            disp_rows,
            int(width),
            int(height),
        )
    return disp_rows, disp_cols, (int(height), int(width))


def _mask_detector_display_image(
    image: np.ndarray | None,
    *,
    selection: Mapping[str, object] | None,
    native_shape: tuple[int, int],
) -> np.ndarray | None:
    """Mask one detector-space display image down to the selected branch ROI."""

    if image is None or not isinstance(selection, Mapping):
        return image
    if not bool(selection.get("valid", False)):
        return image
    try:
        rows = np.asarray(selection.get("rows"), dtype=np.int64).reshape(-1)
        cols = np.asarray(selection.get("cols"), dtype=np.int64).reshape(-1)
    except Exception:
        return image
    if rows.size <= 0 or cols.size != rows.size:
        return image

    display_image = np.asarray(image)
    if display_image.ndim != 2 or display_image.size <= 0:
        return image

    disp_rows, disp_cols, display_shape = _rotate_native_detector_pixels_for_display(
        rows,
        cols,
        native_shape=native_shape,
        k=DISPLAY_ROTATE_K,
    )
    if tuple(int(v) for v in display_image.shape[:2]) != tuple(display_shape):
        return image

    valid = (
        (disp_rows >= 0)
        & (disp_rows < int(display_shape[0]))
        & (disp_cols >= 0)
        & (disp_cols < int(display_shape[1]))
    )
    if not np.any(valid):
        return image

    masked = np.zeros_like(display_image)
    masked[disp_rows[valid], disp_cols[valid]] = display_image[disp_rows[valid], disp_cols[valid]]
    return masked


def _current_geometry_fit_preview_integrator() -> ExactCakeIntegrator | None:
    """Build the live integrator used to project detector ROI pixels into caked space."""

    try:
        return _build_analysis_integrator(
            {
                "center": np.asarray(
                    [float(center_x_var.get()), float(center_y_var.get())],
                    dtype=np.float64,
                ),
                "distance_m": float(corto_detector_var.get()),
                "pixel_size_m": float(pixel_size_m),
            }
        )
    except Exception:
        return None


def _nearest_sorted_axis_indices(
    axis_values: Sequence[float] | None,
    sample_values: np.ndarray,
) -> np.ndarray | None:
    """Return nearest-bin indices on one sorted axis for many sample values."""

    try:
        axis = np.asarray(axis_values, dtype=float).reshape(-1)
        samples = np.asarray(sample_values, dtype=float).reshape(-1)
    except Exception:
        return None
    if axis.size <= 0 or samples.size <= 0:
        return None
    if axis.size == 1:
        return np.zeros(samples.shape, dtype=np.int64)

    insertion = np.searchsorted(axis, samples, side="left")
    insertion = np.clip(insertion, 1, axis.size - 1)
    left = axis[insertion - 1]
    right = axis[insertion]
    choose_left = np.abs(samples - left) <= np.abs(right - samples)
    return np.where(choose_left, insertion - 1, insertion).astype(np.int64, copy=False)


def _geometry_fit_detector_shape_2d(
    detector_shape: Sequence[object] | None,
) -> tuple[int, int] | None:
    try:
        normalized_shape = tuple(int(v) for v in (detector_shape or ())[:2])
    except Exception:
        return None
    if len(normalized_shape) < 2 or int(normalized_shape[0]) <= 0 or int(normalized_shape[1]) <= 0:
        return None
    return int(normalized_shape[0]), int(normalized_shape[1])


def _normalize_geometry_fit_caked_view_payload(
    payload: Mapping[str, object] | None,
    *,
    detector_shape: Sequence[object] | None = None,
    ai: ExactCakeIntegrator | None = None,
) -> dict[str, object] | None:
    return gui_geometry_fit.normalize_geometry_fit_caked_view_payload(
        payload,
        detector_shape=detector_shape,
        ai=ai,
    )


def _geometry_fit_caked_roi_preview_mask(
    *,
    selection: Mapping[str, object] | None,
    native_shape: tuple[int, int],
    radial_axis: Sequence[float] | None,
    azimuth_axis: Sequence[float] | None,
) -> np.ndarray | None:
    """Return a caked-bin mask corresponding to the current detector ROI preview."""

    if not isinstance(selection, Mapping) or not bool(selection.get("valid", False)):
        return None
    try:
        normalized_shape = tuple(int(v) for v in tuple(native_shape)[:2])
        rows = np.asarray(selection.get("rows"), dtype=np.int64).reshape(-1)
        cols = np.asarray(selection.get("cols"), dtype=np.int64).reshape(-1)
        radial = np.asarray(radial_axis, dtype=float).reshape(-1)
        azimuth = np.asarray(azimuth_axis, dtype=float).reshape(-1)
    except Exception:
        return None
    if (
        len(normalized_shape) < 2
        or normalized_shape[0] <= 0
        or normalized_shape[1] <= 0
        or rows.size <= 0
        or cols.size != rows.size
    ):
        return None
    if radial.size <= 0 or azimuth.size <= 0:
        return None

    valid = (
        (rows >= 0)
        & (rows < int(normalized_shape[0]))
        & (cols >= 0)
        & (cols < int(normalized_shape[1]))
    )
    if not np.any(valid):
        return None

    live_bundle = _current_live_caked_transform_bundle()
    caked_view_payload = _normalize_geometry_fit_caked_view_payload(
        {
            "detector_shape": normalized_shape,
            "radial_axis": radial,
            "azimuth_axis": azimuth,
            "transform_bundle": live_bundle,
        },
        detector_shape=normalized_shape,
        ai=None,
    )
    if not isinstance(
        caked_view_payload.get("transform_bundle")
        if isinstance(caked_view_payload, Mapping)
        else None,
        CakeTransformBundle,
    ):
        caked_view_payload = _normalize_geometry_fit_caked_view_payload(
            {
                "detector_shape": normalized_shape,
                "radial_axis": radial,
                "azimuth_axis": azimuth,
                "transform_bundle": live_bundle,
            },
            detector_shape=normalized_shape,
            ai=_current_geometry_fit_preview_integrator(),
        )
    bundle = (
        caked_view_payload.get("transform_bundle")
        if isinstance(caked_view_payload, Mapping)
        else None
    )
    if not isinstance(bundle, CakeTransformBundle):
        return None

    mask = np.zeros((int(azimuth.size), int(radial.size)), dtype=bool)
    for row_idx, col_idx in zip(rows[valid], cols[valid]):
        two_theta_value, phi_value = detector_pixel_to_caked_bin(
            bundle,
            float(col_idx),
            float(row_idx),
        )
        if two_theta_value is None or phi_value is None:
            continue
        radial_idx = _nearest_sorted_axis_indices(radial, [two_theta_value])
        azimuth_idx = _nearest_sorted_axis_indices(azimuth, [phi_value])
        if radial_idx is None or azimuth_idx is None:
            continue
        mask[azimuth_idx, radial_idx] = True
    if not np.any(mask):
        return None
    return mask


def _mask_caked_display_image(
    image: np.ndarray | None,
    *,
    caked_mask: np.ndarray | None,
) -> np.ndarray | None:
    """Mask one caked image down to the previewed branch ROI."""

    if image is None or caked_mask is None:
        return image
    caked_image = np.asarray(image)
    if caked_image.ndim != 2 or tuple(caked_image.shape) != tuple(caked_mask.shape):
        return image
    masked = np.zeros_like(caked_image)
    masked[caked_mask] = caked_image[caked_mask]
    return masked


def _geometry_fit_caked_roi_preview_display_sources(
    *,
    show_caked_image: bool,
    simulation_image: np.ndarray | None,
    background_image: np.ndarray | None,
) -> tuple[np.ndarray | None, np.ndarray | None]:
    """Resolve the primary/secondary rasters used while ROI preview is enabled."""

    preview_sim_image, preview_background_image = _geometry_fit_caked_roi_preview_images(
        show_caked_image=bool(show_caked_image),
        simulation_image=simulation_image,
        background_image=background_image,
    )
    primary_source = (
        preview_sim_image if isinstance(preview_sim_image, np.ndarray) else simulation_image
    )
    secondary_source = (
        preview_background_image
        if isinstance(preview_background_image, np.ndarray)
        else background_image
    )
    if _current_geometry_fit_caked_roi_preview_enabled() and isinstance(
        preview_background_image, np.ndarray
    ):
        return np.asarray(preview_background_image), None
    return primary_source, secondary_source


def _hide_geometry_fit_caked_roi_preview_aux_artists() -> None:
    """Hide non-raster artists so ROI preview shows only the selected regions."""

    _clear_all_geometry_overlay_artists(redraw=False)
    try:
        gui_qr_cylinder_overlay.clear_runtime_qr_cylinder_overlay_artists(
            qr_cylinder_overlay_runtime_bindings_factory(),
            redraw=False,
        )
    except Exception:
        pass
    gui_controllers.clear_geometry_preview_skip_once(geometry_preview_state)
    for artist_name in ("center_marker", "selected_peak_marker", "integration_region_overlay"):
        artist = globals().get(artist_name)
        setter = getattr(artist, "set_visible", None)
        if callable(setter):
            try:
                setter(False)
            except Exception:
                continue


def _geometry_fit_caked_roi_preview_images(
    *,
    show_caked_image: bool,
    simulation_image: np.ndarray | None,
    background_image: np.ndarray | None,
) -> tuple[np.ndarray | None, np.ndarray | None]:
    """Return detector/caked display images masked to the selected branch ROI."""

    if not _current_geometry_fit_caked_roi_preview_enabled():
        return simulation_image, background_image

    selection = _current_geometry_fit_caked_roi_selection(force_enabled=True)
    if not isinstance(selection, Mapping) or not bool(selection.get("valid", False)):
        return simulation_image, background_image

    native_background = _get_current_background_native()
    if native_background is None:
        return simulation_image, background_image
    native_shape = tuple(int(v) for v in np.asarray(native_background).shape[:2])
    if len(native_shape) < 2 or native_shape[0] <= 0 or native_shape[1] <= 0:
        return simulation_image, background_image

    if not show_caked_image:
        return (
            _mask_detector_display_image(
                simulation_image,
                selection=selection,
                native_shape=native_shape,
            ),
            _mask_detector_display_image(
                background_image,
                selection=selection,
                native_shape=native_shape,
            ),
        )

    caked_mask = _geometry_fit_caked_roi_preview_mask(
        selection=selection,
        native_shape=native_shape,
        radial_axis=simulation_runtime_state.last_caked_radial_values,
        azimuth_axis=simulation_runtime_state.last_caked_azimuth_values,
    )
    if caked_mask is None:
        return simulation_image, background_image
    return (
        _mask_caked_display_image(simulation_image, caked_mask=caked_mask),
        _mask_caked_display_image(background_image, caked_mask=caked_mask),
    )


def _native_detector_coords_to_live_caked_coords(
    col: float,
    row: float,
) -> tuple[float, float] | None:
    """Map simulation-native detector pixels into the live caked axes.

    The caked simulation image is generated by feeding the unrotated simulation
    raster directly to the active cake transform. Qr/Qz seed points derived from
    simulation hit tables are in that same simulation-native pixel frame, so they
    must not pass through the background display/bundle frame adapter.
    """

    try:
        col_val = float(col)
        row_val = float(row)
    except Exception:
        return None
    if not (np.isfinite(col_val) and np.isfinite(row_val)):
        return None
    try:
        two_theta_value, phi_value = detector_pixel_to_caked_bin(
            _current_live_caked_transform_bundle(),
            col_val,
            row_val,
        )
    except Exception:
        return None
    if two_theta_value is None or phi_value is None:
        return None
    try:
        two_theta_float = float(two_theta_value)
        phi_float = float(phi_value)
    except Exception:
        return None
    if not (np.isfinite(two_theta_float) and np.isfinite(phi_float)):
        return None
    return two_theta_float, phi_float


def _current_qr_cylinder_caked_projection_context() -> Mapping[str, object] | None:
    try:
        radial_axis = np.asarray(
            simulation_runtime_state.last_caked_radial_values,
            dtype=np.float64,
        ).reshape(-1)
        azimuth_axis = np.asarray(
            simulation_runtime_state.last_caked_azimuth_values,
            dtype=np.float64,
        ).reshape(-1)
    except Exception:
        return None
    if radial_axis.size <= 0 or azimuth_axis.size <= 0:
        return None

    transform_bundle = _current_live_caked_transform_bundle()
    detector_shape = (
        transform_bundle.detector_shape
        if isinstance(transform_bundle, CakeTransformBundle)
        else None
    )
    if detector_shape is None:
        detector_shape = simulation_runtime_state.ai_cache.get("detector_shape")
    if detector_shape is None:
        detector_image = simulation_runtime_state.unscaled_image
        if detector_image is not None:
            detector_shape = np.asarray(detector_image).shape[:2]
    if detector_shape is None:
        native_background = _get_current_background_native()
        if native_background is not None:
            detector_shape = np.asarray(native_background).shape[:2]
    if detector_shape is None:
        return None

    return _normalize_geometry_fit_caked_view_payload(
        {
            "background": np.zeros((azimuth_axis.size, radial_axis.size), dtype=np.float64),
            "detector_shape": detector_shape,
            "radial_axis": radial_axis,
            "azimuth_axis": azimuth_axis,
            "raw_azimuth_axis": (
                np.asarray(transform_bundle.raw_azimuth_deg, dtype=np.float64)
                if isinstance(transform_bundle, CakeTransformBundle)
                else None
            ),
            "transform_bundle": transform_bundle,
        },
        detector_shape=detector_shape,
        ai=simulation_runtime_state.ai_cache.get("ai"),
    )


def _geometry_fit_targeted_projection_analysis_bins(
    analysis_preview_bins: Sequence[object] | None = None,
) -> tuple[int | None, int | None]:
    preview_bins = analysis_preview_bins
    if not (isinstance(preview_bins, (tuple, list)) and len(preview_bins) >= 2):
        preview_bins = getattr(simulation_runtime_state, "analysis_preview_bins", None)
    try:
        npt_rad = (
            int(max(1, preview_bins[0]))
            if isinstance(preview_bins, (tuple, list)) and len(preview_bins) >= 2
            else None
        )
    except Exception:
        npt_rad = None
    try:
        npt_azim = (
            int(max(1, preview_bins[1]))
            if isinstance(preview_bins, (tuple, list)) and len(preview_bins) >= 2
            else None
        )
    except Exception:
        npt_azim = None
    return npt_rad, npt_azim


def _geometry_fit_resolve_targeted_caked_projection_payload(
    background_index: int,
    *,
    caked_payload: Mapping[str, object] | None = None,
    detector_shape: Sequence[object] | None = None,
    ai: ExactCakeIntegrator | None = None,
    analysis_preview_bins: Sequence[object] | None = None,
    allow_generated_payload: bool = False,
) -> dict[str, object] | None:
    background_idx = int(background_index)
    resolved_payload = caked_payload
    if not isinstance(resolved_payload, Mapping):
        resolved_payload = _geometry_fit_caked_view_for_index(background_idx)

    ai_value = ai
    if ai_value is None:
        ai_cache = getattr(simulation_runtime_state, "ai_cache", None)
        ai_value = ai_cache.get("ai") if isinstance(ai_cache, Mapping) else None

    normalized_shape = _geometry_fit_detector_shape_2d(detector_shape)
    if normalized_shape is None and isinstance(resolved_payload, Mapping):
        normalized_shape = _geometry_fit_detector_shape_2d(resolved_payload.get("detector_shape"))
    if normalized_shape is None:
        try:
            if int(background_idx) == int(background_runtime_state.current_background_index):
                native_background = _get_current_background_native()
            else:
                native_background, _display_background = _load_background_image_by_index(
                    int(background_idx)
                )
            normalized_shape = _geometry_fit_detector_shape_2d(
                np.asarray(native_background, dtype=np.float64).shape[:2]
            )
        except Exception:
            normalized_shape = None
    if (
        not isinstance(resolved_payload, Mapping)
        and bool(allow_generated_payload)
        and normalized_shape is not None
        and isinstance(ai_value, ExactCakeIntegrator)
    ):
        npt_rad, npt_azim = _geometry_fit_targeted_projection_analysis_bins(analysis_preview_bins)
        resolved_payload = _geometry_fit_worker_caked_projection_view(
            detector_shape=normalized_shape,
            ai=ai_value,
            npt_rad=npt_rad,
            npt_azim=npt_azim,
        )

    if not isinstance(resolved_payload, Mapping):
        return None
    normalized_payload = _normalize_geometry_fit_caked_view_payload(
        resolved_payload,
        detector_shape=normalized_shape,
        ai=ai_value,
    )
    if isinstance(normalized_payload, Mapping):
        return normalized_payload
    projection_payload = gui_geometry_fit.geometry_fit_caked_projection_payload(resolved_payload)
    if not isinstance(projection_payload, Mapping):
        return None
    return _normalize_geometry_fit_caked_view_payload(
        projection_payload,
        detector_shape=normalized_shape,
        ai=ai_value,
    )


def _geometry_fit_rows_for_background(
    background_index: int,
    raw_rows: Sequence[object] | None,
) -> list[dict[str, object]]:
    normalized_rows: list[dict[str, object]] = []
    for raw_entry in raw_rows or ():
        if not isinstance(raw_entry, Mapping):
            continue
        entry = dict(raw_entry)
        entry.setdefault("background_index", int(background_index))
        normalized_rows.append(entry)
    return normalized_rows


def _geometry_fit_group_rows_by_background(
    raw_rows: Sequence[object] | None,
    *,
    default_background_index: int,
    order_key: str | None = None,
) -> list[tuple[int, list[dict[str, object]]]]:
    grouped_rows: dict[int, list[dict[str, object]]] = {}
    ordered_backgrounds: list[int] = []
    for position, raw_entry in enumerate(raw_rows or ()):
        if not isinstance(raw_entry, Mapping):
            continue
        entry = dict(raw_entry)
        try:
            background_idx = int(entry.get("background_index"))
        except Exception:
            background_idx = int(default_background_index)
        entry.setdefault("background_index", int(background_idx))
        if order_key is not None:
            entry[order_key] = int(position)
        if int(background_idx) not in grouped_rows:
            ordered_backgrounds.append(int(background_idx))
            grouped_rows[int(background_idx)] = []
        grouped_rows[int(background_idx)].append(entry)
    return [
        (int(background_idx), list(grouped_rows.get(int(background_idx), ())))
        for background_idx in ordered_backgrounds
    ]


def _geometry_manual_project_peaks_for_background(
    background_index: int,
    raw_rows: Sequence[object] | None,
    *,
    mode_override: str | None = None,
    caked_payload: Mapping[str, object] | None = None,
    background_native: object = None,
    background_display: object = None,
    strict_caked_projection: bool = True,
) -> list[dict[str, object]]:
    normalized_rows = _geometry_fit_rows_for_background(background_index, raw_rows)
    if not normalized_rows:
        return []

    requested_mode_override = None if mode_override is None else str(mode_override).strip().lower()
    normalized_mode = (
        str(
            requested_mode_override
            if requested_mode_override is not None
            else _geometry_fit_targeted_projection_view_mode()
        )
        .strip()
        .lower()
    )
    if normalized_mode not in {"detector", "caked", "q_space"}:
        normalized_mode = "detector"
    explicit_detector_projection = requested_mode_override == "detector"

    try:
        current_background_index = int(background_runtime_state.current_background_index)
    except Exception:
        current_background_index = int(background_index)

    is_current_background = int(background_index) == int(current_background_index)

    if normalized_mode == "q_space":
        if not is_current_background or not callable(
            _project_geometry_manual_peaks_to_current_view
        ):
            return []
        try:
            return _geometry_fit_rows_for_background(
                background_index,
                _project_geometry_manual_peaks_to_current_view(normalized_rows),
            )
        except Exception:
            return []

    if (
        normalized_mode != "caked"
        and not explicit_detector_projection
        and is_current_background
        and callable(_project_geometry_manual_peaks_to_current_view)
    ):
        try:
            return _geometry_fit_rows_for_background(
                background_index,
                _project_geometry_manual_peaks_to_current_view(normalized_rows),
            )
        except Exception:
            if normalized_mode == "q_space":
                return []
            if normalized_mode == "caked":
                raise
            return normalized_rows

    native_background = background_native
    display_background = background_display
    if native_background is None or display_background is None:
        try:
            native_background, display_background = _load_background_image_by_index(
                int(background_index)
            )
        except Exception:
            native_background = background_native
            display_background = background_display
    try:
        detector_shape = tuple(
            int(v) for v in np.asarray(native_background, dtype=np.float64).shape[:2]
        )
    except Exception:
        detector_shape = None

    resolved_caked_payload = None
    if normalized_mode == "caked":
        resolved_caked_payload = _geometry_fit_resolve_targeted_caked_projection_payload(
            int(background_index),
            caked_payload=caked_payload,
            detector_shape=detector_shape,
            allow_generated_payload=True,
        )
        if not isinstance(resolved_caked_payload, Mapping):
            if not bool(strict_caked_projection):
                return []
            raise RuntimeError(
                f"exact caked projector unavailable for background {int(background_index) + 1}"
            )
        hydrated_caked_payload = gui_geometry_fit._geometry_fit_hydrate_exact_caked_payload(
            resolved_caked_payload,
            detector_shape=detector_shape,
            require_background=False,
        )
        if not isinstance(hydrated_caked_payload, Mapping) or not isinstance(
            hydrated_caked_payload.get("transform_bundle"),
            CakeTransformBundle,
        ):
            if not bool(strict_caked_projection):
                return []
            raise RuntimeError(
                f"exact caked projector unavailable for background {int(background_index) + 1}"
            )
        resolved_caked_payload = hydrated_caked_payload
        if is_current_background:
            _set_live_caked_transform_bundle(hydrated_caked_payload.get("transform_bundle"))
    def _background_native_detector_coords_to_bundle_detector_coords(
        col: float,
        row: float,
    ) -> tuple[float | None, float | None]:
        return _native_detector_coords_to_bundle_detector_coords(
            float(col),
            float(row),
            detector_shape,
        )

    projection_callbacks = gui_manual_geometry.make_runtime_geometry_manual_projection_callbacks(
        caked_view_enabled=lambda: bool(
            normalized_mode == "caked" and isinstance(resolved_caked_payload, Mapping)
        ),
        last_caked_background_image_unscaled=lambda: (
            resolved_caked_payload.get("background")
            if isinstance(resolved_caked_payload, Mapping)
            else None
        ),
        last_caked_radial_values=lambda: (
            resolved_caked_payload.get("radial_axis")
            if isinstance(resolved_caked_payload, Mapping)
            else None
        ),
        last_caked_azimuth_values=lambda: (
            resolved_caked_payload.get("azimuth_axis")
            if isinstance(resolved_caked_payload, Mapping)
            else None
        ),
        current_background_display=lambda: display_background,
        current_background_native=lambda: native_background,
        caked_transform_bundle=lambda: (
            resolved_caked_payload.get("transform_bundle")
            if isinstance(resolved_caked_payload, Mapping)
            else None
        ),
        rotate_point_for_display=gui_geometry_overlay.rotate_point_for_display,
        display_rotate_k=int(globals().get("DISPLAY_ROTATE_K", 0) or 0),
        current_background_index=lambda: int(background_index),
        caked_projection_payload=lambda: resolved_caked_payload,
        image_size=int(image_size),
        display_to_native_sim_coords=globals().get("_display_to_native_sim_coords"),
        native_sim_to_display_coords=globals().get("_native_sim_to_display_coords"),
        native_detector_coords_to_detector_display_coords=(
            _background_native_detector_coords_to_bundle_detector_coords
        ),
        backend_detector_coords_to_native_detector_coords=(
            globals().get("_backend_background_to_native_detector_coords")
            or (lambda col, row, *_args, **_kwargs: (float(col), float(row)))
        ),
        native_detector_coords_to_bundle_detector_coords=(
            _background_native_detector_coords_to_bundle_detector_coords
        ),
        bundle_detector_coords_to_background_display_coords=(
            lambda col, row: (float(col), float(row))
        ),
        filter_simulated_peaks=(lambda peaks, *_args, **_kwargs: (list(peaks or ()), [], 0)),
        collapse_simulated_peaks=(lambda peaks, *_args, **_kwargs: (list(peaks or ()), 0)),
        profile_cache=lambda: simulation_runtime_state.profile_cache,
    )
    try:
        return _geometry_fit_rows_for_background(
            background_index,
            projection_callbacks.project_peaks_to_current_view(normalized_rows),
        )
    except Exception:
        if normalized_mode == "q_space":
            return []
        if normalized_mode == "caked" and bool(strict_caked_projection):
            raise
        return normalized_rows


def _geometry_manual_project_peaks_by_row_background(
    raw_rows: Sequence[object] | None,
) -> list[dict[str, object]]:
    try:
        default_background_index = int(background_runtime_state.current_background_index)
    except Exception:
        default_background_index = 0
    order_key = "__ra_sim_projection_row_order__"
    grouped_rows = _geometry_fit_group_rows_by_background(
        raw_rows,
        default_background_index=default_background_index,
        order_key=order_key,
    )
    if not grouped_rows:
        return []
    normalized_mode = _geometry_fit_targeted_projection_view_mode()
    projected_rows: list[dict[str, object]] = []
    for background_idx, rows_for_background in grouped_rows:
        try:
            projected_rows.extend(
                dict(entry)
                for entry in (
                    _geometry_manual_project_peaks_for_background(
                        int(background_idx),
                        rows_for_background,
                        mode_override=normalized_mode,
                    )
                    or ()
                )
                if isinstance(entry, Mapping)
            )
        except Exception:
            if normalized_mode == "caked":
                raise
            continue
    sorted_rows = sorted(
        projected_rows,
        key=lambda entry: (
            int(entry.get(order_key))
            if isinstance(entry, Mapping) and entry.get(order_key) is not None
            else int(1e12)
        ),
    )
    cleaned_rows: list[dict[str, object]] = []
    for raw_entry in sorted_rows:
        if not isinstance(raw_entry, Mapping):
            continue
        entry = dict(raw_entry)
        entry.pop(order_key, None)
        cleaned_rows.append(entry)
    return cleaned_rows


def _analysis_selected_qr_rod_entries() -> list[dict[str, object]]:
    active_entries_factory = globals().get("active_qr_cylinder_overlay_entries_factory")
    if not callable(active_entries_factory):
        return []
    return [dict(entry) for entry in (active_entries_factory() or ()) if isinstance(entry, Mapping)]


def _selected_qr_rod_option_pairs(
    entries: Sequence[Mapping[str, object]] | None,
) -> list[tuple[str, str]]:
    option_pairs: list[tuple[str, str]] = []
    for entry in entries or ():
        encoded_key = gui_controllers.encode_bragg_qr_group_key(entry.get("key"))
        if not encoded_key:
            continue
        option_pairs.append(
            (
                encoded_key,
                gui_controllers.format_bragg_qr_entry_label(entry),
            )
        )
    return option_pairs


def _selected_qr_rod_entry_for_key(
    entries: Sequence[Mapping[str, object]] | None,
    encoded_key: object,
) -> dict[str, object] | None:
    normalized_key = gui_controllers.decode_bragg_qr_group_key(encoded_key)
    if normalized_key is None:
        return None
    for entry in entries or ():
        if not isinstance(entry, Mapping):
            continue
        entry_key = gui_controllers.decode_bragg_qr_group_key(
            gui_controllers.encode_bragg_qr_group_key(entry.get("key"))
        )
        if entry_key == normalized_key:
            return dict(entry)
    return None


def _current_selected_qr_rod_keys_from_roi(
    roi_values: Mapping[str, object] | None = None,
) -> list[str]:
    values = roi_values if isinstance(roi_values, Mapping) else _current_analysis_roi_values()
    raw_keys = values.get("selected_qr_rod_keys", [])
    if isinstance(raw_keys, (str, bytes)):
        selected_keys = [str(raw_keys)] if str(raw_keys) else []
    elif isinstance(raw_keys, Sequence):
        selected_keys = [str(key) for key in raw_keys if str(key)]
    else:
        selected_keys = []
    normalized: list[str] = []
    for key in selected_keys:
        if key and key not in normalized:
            normalized.append(key)
    return normalized


def _current_selected_qr_rod_entries(
    entries: Sequence[Mapping[str, object]] | None = None,
) -> list[dict[str, object]]:
    entries_list = [dict(entry) for entry in (entries or _analysis_selected_qr_rod_entries())]
    if not entries_list:
        return []
    roi_values = _current_analysis_roi_values()
    selected_entries: list[dict[str, object]] = []
    for selected_key in _current_selected_qr_rod_keys_from_roi(roi_values):
        entry = _selected_qr_rod_entry_for_key(entries_list, selected_key)
        if entry is not None:
            selected_entries.append(entry)
    if selected_entries:
        return selected_entries
    return [dict(entries_list[0])]


def _current_caked_qz_extent() -> tuple[float, float] | None:
    radial_axis = np.asarray(
        simulation_runtime_state.last_caked_radial_values,
        dtype=float,
    ).reshape(-1)
    azimuth_axis = np.asarray(
        simulation_runtime_state.last_caked_azimuth_values,
        dtype=float,
    ).reshape(-1)
    radial_axis = radial_axis[(radial_axis >= 0.0) & (radial_axis <= 90.0)]
    if radial_axis.size <= 0 or azimuth_axis.size <= 0:
        return None
    try:
        _qr_map, qz_map = gui_controllers.caked_axes_to_qr_qz_maps(
            radial_axis,
            azimuth_axis,
            wavelength_m=float(lambda_) * 1.0e-10,
        )
    except Exception:
        return None
    valid_qz = qz_map[np.isfinite(qz_map)]
    if valid_qz.size <= 0:
        return None
    return float(np.min(valid_qz)), float(np.max(valid_qz))


def _current_detector_shape() -> tuple[int, int] | None:
    detector_image = getattr(simulation_runtime_state, "unscaled_image", None)
    try:
        detector_array = np.asarray(detector_image, dtype=float)
    except Exception:
        return None
    if detector_array.ndim != 2:
        return None
    detector_shape = tuple(int(v) for v in detector_array.shape[:2])
    if detector_shape[0] <= 0 or detector_shape[1] <= 0:
        return None
    return detector_shape


def _current_detector_qz_extent() -> tuple[float, float] | None:
    detector_shape = _current_detector_shape()
    if detector_shape is None:
        return None
    config_factory = globals().get("qr_cylinder_overlay_render_config_factory")
    if not callable(config_factory):
        return None
    try:
        config = config_factory()
    except Exception:
        return None
    if not isinstance(config, gui_qr_cylinder_overlay.QrCylinderOverlayRenderConfig):
        return None
    q_maps = gui_qr_cylinder_overlay.detector_qr_qz_maps_for_projection(
        config=config,
        detector_shape=detector_shape,
    )
    if q_maps is None:
        return None
    _qr_map, qz_map, valid_q = q_maps
    qz_values = np.asarray(qz_map, dtype=float)
    valid = np.asarray(valid_q, dtype=bool)
    if qz_values.shape != detector_shape or valid.shape != detector_shape:
        return None
    finite = valid & np.isfinite(qz_values)
    if not np.any(finite):
        return None
    selected_qz = qz_values[finite]
    return float(np.min(selected_qz)), float(np.max(selected_qz))


def _qz_slider_bounds_from_extent(
    qz_extent: tuple[float, float] | None,
) -> tuple[float, float]:
    qz_lower = 0.0
    qz_upper = 5.0
    if qz_extent is not None:
        try:
            candidate_max = max(float(qz_extent[0]), float(qz_extent[1]))
        except Exception:
            candidate_max = qz_upper
        if np.isfinite(candidate_max) and candidate_max > qz_lower:
            qz_upper = float(candidate_max)
    return qz_lower, qz_upper


def _finite_selected_qr_rod_lattice_c(value: object) -> float | None:
    try:
        lattice_c = float(value)
    except Exception:
        return None
    if not np.isfinite(lattice_c) or lattice_c <= 0.0:
        return None
    return float(lattice_c)


def _current_selected_qr_rod_lattice_c() -> float | None:
    return _finite_selected_qr_rod_lattice_c(_get_var_value(globals().get("c_var"), None))


def _selected_qr_rod_qz_to_l_values(
    qz_values: object,
    lattice_c: object,
) -> np.ndarray | None:
    c_value = _finite_selected_qr_rod_lattice_c(lattice_c)
    if c_value is None:
        return None
    try:
        qz_array = np.asarray(qz_values, dtype=np.float64)
    except Exception:
        return None
    return qz_array * (c_value / (2.0 * np.pi))


def _selected_qr_rod_qz_display_scale_from_view_state(view_state: object | None = None) -> float:
    if view_state is None:
        view_state = globals().get("integration_range_controls_view_state")
    try:
        scale = float(getattr(view_state, "qz_display_scale_value", 1.0))
    except Exception:
        return 1.0
    if not np.isfinite(scale) or scale <= 0.0:
        return 1.0
    return float(scale)


def _selected_qr_rod_qz_to_display_value(
    qz_value: object,
    view_state: object | None = None,
) -> float:
    try:
        qz_float = float(qz_value)
    except Exception:
        qz_float = 0.0
    return qz_float * _selected_qr_rod_qz_display_scale_from_view_state(view_state)


def _selected_qr_rod_display_to_qz_value(
    display_value: object,
    view_state: object | None = None,
) -> float:
    try:
        display_float = float(display_value)
    except Exception:
        display_float = 0.0
    return display_float / _selected_qr_rod_qz_display_scale_from_view_state(view_state)


def _selected_qr_rod_geometry_summary_text() -> str:
    def _number(var_name: str) -> float:
        return float(_get_var_value(globals().get(var_name), np.nan))

    try:
        return (
            f"Fit geometry: theta {_number('theta_initial_var'):.2f} deg | "
            f"chi {_number('chi_var'):.2f} deg | "
            f"psi_z {_number('psi_z_var'):.2f} deg | "
            f"cor {_number('cor_angle_var'):.2f} deg | "
            f"gamma {_number('gamma_var'):.2f} deg | "
            f"Gamma {_number('Gamma_var'):.2f} deg | "
            f"dist {_number('corto_detector_var') * 1e3:.2f} mm | "
            f"center {_number('center_x_var'):.1f}/{_number('center_y_var'):.1f} px"
        )
    except Exception:
        return "Fit geometry unavailable."


def _sync_selected_qr_rod_geometry_summary_text() -> None:
    view_state = globals().get("integration_range_controls_view_state")
    summary_var = getattr(view_state, "selected_qr_geometry_summary_var", None)
    setter = getattr(summary_var, "set", None)
