def _hkl_pick_simulation_points_from_qr_picker_cache() -> dict[str, object]:
    """Return indexed Qr/manual simulation-point rows used by HKL picking."""

    cache_data = _get_geometry_manual_pick_cache(
        param_set=_current_geometry_fit_params(),
        prefer_cache=True,
    )
    if not isinstance(cache_data, dict):
        raise TypeError("manual-pick cache must be a mapping")

    grouped = cache_data.get("grouped_candidates")
    if any(
        bool(cache_data.get(key))
        for key in (
            "detector_picker_rows",
            "detector_picker_source_rows",
            "detector_picker_grouped_candidates",
        )
    ):
        detector_grouped = (
            gui_manual_geometry.geometry_manual_detector_picker_grouped_candidates_from_cache(
                cache_data,
                profile_cache=simulation_runtime_state.profile_cache,
            )
        )
        if detector_grouped:
            grouped = detector_grouped

    if not isinstance(grouped, dict):
        raise TypeError("manual-pick cache requires grouped_candidates")
    rows = [
        dict(entry)
        for entries in grouped.values()
        if isinstance(entries, (list, tuple))
        for entry in entries
        if isinstance(entry, dict)
    ]
    return gui_peak_selection.build_hkl_pick_simulation_point_payload(rows)


