QR_CYLINDER_DISPLAY_MODE_OFF = "Off"
QR_CYLINDER_DISPLAY_MODE_ADD = "Add to Image"
QR_CYLINDER_DISPLAY_MODE_REPLACE = "Replace Simulation"
QR_CYLINDER_DISPLAY_MODE_OPTIONS = (
    QR_CYLINDER_DISPLAY_MODE_OFF,
    QR_CYLINDER_DISPLAY_MODE_ADD,
    QR_CYLINDER_DISPLAY_MODE_REPLACE,
)


def _qr_cylinder_display_mode(default=QR_CYLINDER_DISPLAY_MODE_OFF) -> str:
    mode_var = getattr(
        geometry_overlay_actions_view_state,
        "qr_cylinder_display_mode_var",
        None,
    )
    if mode_var is None:
        return str(default)
    try:
        mode = str(mode_var.get()).strip()
    except Exception:
        return str(default)
    if mode in QR_CYLINDER_DISPLAY_MODE_OPTIONS:
        return mode
    return str(default)


def _qr_cylinder_replace_simulation_enabled() -> bool:
    return _qr_cylinder_display_mode() == QR_CYLINDER_DISPLAY_MODE_REPLACE


def _sync_qr_cylinder_overlay_visibility_var() -> None:
    overlay_var = getattr(
        geometry_overlay_actions_view_state,
        "show_qr_cylinder_overlay_var",
        None,
    )
    if overlay_var is None:
        return
    try:
        overlay_var.set(_qr_cylinder_display_mode() != QR_CYLINDER_DISPLAY_MODE_OFF)
    except Exception:
        pass


def _sync_selected_qr_rod_controls_state() -> None:
    range_view_state = globals().get("integration_range_controls_view_state")
    if range_view_state is None:
        return

    option_pairs = _selected_qr_rod_option_pairs(_analysis_selected_qr_rod_entries())
    gui_integration_range_drag._set_runtime_selected_qr_rod_options(
        range_view_state,
        option_pairs,
    )

    selected_qr_rod_view_active = _current_app_shell_view_mode() != "q_space"
    has_options = bool(option_pairs)
    toggle_widget = getattr(range_view_state, "integrate_selected_qr_rod_checkbutton", None)
    toggle_var = getattr(range_view_state, "integrate_selected_qr_rod_var", None)

    if selected_qr_rod_view_active and not has_options:
        setattr(range_view_state, "integrate_selected_qr_rod_value", False)
        gui_integration_range_drag._safe_var_set(toggle_var, False)

    selected_key = gui_integration_range_drag._get_runtime_string_value(
        range_view_state,
        "selected_qr_rod_key",
        "",
    )
    selected_keys = list(getattr(range_view_state, "selected_qr_rod_keys_value", []) or [])
    if not selected_keys and selected_key:
        selected_keys = [selected_key]
    option_keys = [encoded_key for encoded_key, _label in option_pairs]
    selected_keys = [key for key in option_keys if key in set(selected_keys)]
    if option_keys and not selected_keys:
        selected_keys = [option_keys[0]]
    if option_keys:
        gui_integration_range_drag._set_runtime_selected_qr_rod_keys(
            range_view_state,
            selected_keys,
        )
        selected_key = selected_keys[0] if selected_keys else ""
    elif not option_keys and selected_qr_rod_view_active:
        gui_integration_range_drag._set_runtime_selected_qr_rod_keys(
            range_view_state,
            [],
        )
        selected_key = ""

    display_label = (getattr(range_view_state, "selected_qr_rod_option_labels", {}) or {}).get(
        selected_key, ""
    )
    gui_integration_range_drag._safe_var_set(
        getattr(range_view_state, "selected_qr_rod_display_var", None),
        display_label,
    )

    current_view_mode = _current_app_shell_view_mode()
    qz_extent = (
        _current_caked_qz_extent()
        if current_view_mode == "caked"
        else (_current_detector_qz_extent() if current_view_mode == "detector" else None)
    )
    if qz_extent is not None:
        qz_lo, qz_hi = _qz_slider_bounds_from_extent(qz_extent)
        qz_display_lo = _selected_qr_rod_qz_to_display_value(qz_lo, range_view_state)
        qz_display_hi = _selected_qr_rod_qz_to_display_value(qz_hi, range_view_state)
        gui_integration_range_drag._set_runtime_slider_bounds(
            range_view_state,
            "qz_min",
            qz_display_lo,
            qz_display_hi,
        )
        gui_integration_range_drag._set_runtime_slider_bounds(
            range_view_state,
            "qz_max",
            qz_display_lo,
            qz_display_hi,
        )
        current_qz_min = _selected_qr_rod_display_to_qz_value(
            _read_analysis_value(
                getattr(range_view_state, "qz_min_var", None),
                getattr(range_view_state, "qz_min_value", qz_display_lo),
                float,
            ),
            range_view_state,
        )
        current_qz_max = _selected_qr_rod_display_to_qz_value(
            _read_analysis_value(
                getattr(range_view_state, "qz_max_var", None),
                getattr(range_view_state, "qz_max_value", qz_display_hi),
                float,
            ),
            range_view_state,
        )
        clamped_qz_min = min(max(float(current_qz_min), qz_lo), qz_hi)
        clamped_qz_max = min(max(float(current_qz_max), qz_lo), qz_hi)
        if clamped_qz_min > clamped_qz_max:
            clamped_qz_min, clamped_qz_max = qz_lo, qz_hi
        gui_integration_range_drag._set_runtime_range_value(
            range_view_state,
            "qz_min",
            _selected_qr_rod_qz_to_display_value(clamped_qz_min, range_view_state),
        )
        gui_integration_range_drag._set_runtime_range_value(
            range_view_state,
            "qz_max",
            _selected_qr_rod_qz_to_display_value(clamped_qz_max, range_view_state),
        )

    rod_mode_enabled = _read_analysis_value(
        toggle_var,
        bool(getattr(range_view_state, "integrate_selected_qr_rod_value", False)),
        bool,
    )

    rectangle_widgets = (
        getattr(range_view_state, "tth_min_slider", None),
        getattr(range_view_state, "tth_min_entry", None),
        getattr(range_view_state, "tth_max_slider", None),
        getattr(range_view_state, "tth_max_entry", None),
    )
    phi_widgets = (
        getattr(range_view_state, "phi_min_slider", None),
        getattr(range_view_state, "phi_min_entry", None),
        getattr(range_view_state, "phi_max_slider", None),
        getattr(range_view_state, "phi_max_entry", None),
    )
    rod_widgets = (
        getattr(range_view_state, "selected_qr_rod_listbox", None),
        getattr(range_view_state, "mirror_selected_qr_phi_checkbutton", None),
        getattr(range_view_state, "include_selected_qr_rod_shape_checkbutton", None),
        *((getattr(range_view_state, "rod_profile_intensity_mode_buttons", {}) or {}).values()),
        getattr(range_view_state, "qz_min_slider", None),
        getattr(range_view_state, "qz_min_entry", None),
        getattr(range_view_state, "qz_max_slider", None),
        getattr(range_view_state, "qz_max_entry", None),
        getattr(range_view_state, "delta_qr_slider", None),
        getattr(range_view_state, "delta_qr_entry", None),
    )

    if not selected_qr_rod_view_active:
        gui_integration_range_drag._set_widget_enabled(toggle_widget, False)
        for widget in rectangle_widgets:
            gui_integration_range_drag._set_widget_enabled(widget, True)
        for widget in phi_widgets:
            gui_integration_range_drag._set_widget_enabled(widget, True)
        for widget in rod_widgets:
            gui_integration_range_drag._set_widget_enabled(widget, False)
    else:
        gui_integration_range_drag._set_widget_enabled(toggle_widget, has_options)
        for widget in rectangle_widgets:
            gui_integration_range_drag._set_widget_enabled(widget, not rod_mode_enabled)
        for widget in phi_widgets:
            gui_integration_range_drag._set_widget_enabled(widget, True)
        for widget in rod_widgets:
            gui_integration_range_drag._set_widget_enabled(widget, has_options and rod_mode_enabled)

    gui_integration_range_drag._sync_runtime_range_text_vars(range_view_state)


def _geometry_overlays_enabled() -> bool:
    """Return whether geometry overlays should currently be visible."""

    overlay_var = geometry_overlay_actions_view_state.show_geometry_overlays_var
    if overlay_var is None:
        return True
    try:
        return bool(overlay_var.get())
    except Exception:
        return True


def _clear_all_geometry_overlay_artists(*, redraw: bool = True):
    """Clear fitted, live-preview, and manual-preview geometry overlays."""

    _clear_geometry_pick_artists(redraw=False)
    _clear_geometry_preview_artists(redraw=False)
    _clear_geometry_manual_preview_artists(redraw=False)
    if redraw:
        _request_overlay_canvas_redraw(force=True)


def _toggle_geometry_overlay_visibility() -> None:
    """Apply the persistent geometry-overlay visibility toggle."""

    if _geometry_overlays_enabled():
        _refresh_settled_overlays()
        status_text = "Geometry overlays shown."
    else:
        _clear_all_geometry_overlay_artists(redraw=True)
        gui_controllers.clear_geometry_preview_skip_once(geometry_preview_state)
        status_text = "Geometry overlays hidden. Turn on Show Geometry Overlays to redraw them."
    try:
        progress_label_geometry.config(text=status_text)
    except Exception:
        pass


