def _initialize_runtime_controls_block_11() -> None:
    global \
        _set_geometry_manual_pick_mode, \
        _toggle_geometry_manual_pick_mode, \
        _clear_current_geometry_manual_pairs

    def _set_geometry_manual_pick_mode_with_prewarm(
        enabled: bool,
        message: str | None = None,
    ) -> object:
        result = geometry_tool_action_runtime_callbacks.set_manual_pick_mode(
            enabled,
            message=message,
        )
        if bool(enabled):
            _schedule_geometry_manual_pick_cache_prewarm()
        return result

    def _toggle_geometry_manual_pick_mode_with_prewarm() -> object:
        was_armed = bool(getattr(geometry_runtime_state, "manual_pick_armed", False))
        result = geometry_tool_action_runtime_callbacks.toggle_manual_pick_mode()
        if not was_armed and bool(getattr(geometry_runtime_state, "manual_pick_armed", False)):
            _schedule_geometry_manual_pick_cache_prewarm()
        return result

    _set_geometry_manual_pick_mode = _set_geometry_manual_pick_mode_with_prewarm
    _toggle_geometry_manual_pick_mode = _toggle_geometry_manual_pick_mode_with_prewarm
    _clear_current_geometry_manual_pairs = (
        geometry_tool_action_runtime_callbacks.clear_current_manual_pairs
    )


def _render_current_geometry_manual_pairs(*, update_status: bool = False) -> bool:
    """Render saved manual geometry pairs when overlays are visible."""

    if not _geometry_overlays_enabled():
        del update_status
        _clear_all_geometry_overlay_artists(redraw=True)
        return False
    if bool(getattr(simulation_runtime_state, "gui_state_import_active", False)):
        return bool(
            geometry_manual_runtime_callbacks.render_current_pairs(
                update_status=update_status,
                click_path=True,
            )
        )
    return bool(
        geometry_manual_runtime_callbacks.render_current_pairs(update_status=update_status)
    )


