def _restore_combined_detector_intersection_cache() -> None:
    try:
        primary_weight = float(weight1_var.get())
    except Exception:
        primary_weight = 0.0
    try:
        secondary_weight = float(weight2_var.get())
    except Exception:
        secondary_weight = 0.0
    run_primary = bool(
        simulation_runtime_state.stored_primary_sim_image is not None
        and abs(primary_weight) > 1.0e-12
    )
    run_secondary = bool(
        simulation_runtime_state.stored_secondary_sim_image is not None
        and abs(secondary_weight) > 1.0e-12
    )
    active_sides = _active_peak_row_sides_for_job(
        job_kind="full",
        run_primary=run_primary,
        run_secondary=run_secondary,
        secondary_available=run_secondary,
    )

    current_hit_table_signature = getattr(
        simulation_runtime_state,
        "stored_hit_table_signature",
        None,
    )
    publish_intersection_cache = bool(active_sides) and all(
        _side_detector_cache_is_current(side, current_hit_table_signature) for side in active_sides
    )
    restored_tables: list[object] = []
    if publish_intersection_cache:
        if "primary" in active_sides:
            restored_tables.extend(
                _copy_intersection_cache_tables(
                    simulation_runtime_state.stored_primary_intersection_cache
                )
            )
        if "secondary" in active_sides:
            restored_tables.extend(
                _copy_intersection_cache_tables(
                    simulation_runtime_state.stored_secondary_intersection_cache
                )
            )
    simulation_runtime_state.stored_intersection_cache = restored_tables
    _clear_caked_intersection_cache()


def _apply_main_caked_view_toggle() -> None:
    show_caked_now = bool(
        getattr(
            analysis_view_controls_view_state.show_caked_2d_var,
            "get",
            lambda: False,
        )()
    )
    _clear_pending_main_figure_preview_interaction()
    _clear_geometry_pick_artists(redraw=True)
    if show_caked_now or simulation_runtime_state.unscaled_image is None:
        schedule_update()
        return

    _restore_combined_detector_intersection_cache()
    previous_primary_view_mode = _current_primary_figure_mode()
    preserved_primary_limits = gui_canvas_interactions.capture_axis_limits(ax)
    apply_scale_factor_to_existing_results(
        update_limits=False,
        update_1d=False,
        update_canvas=False,
    )
    gui_canvas_interactions.restore_axis_view(
        ax,
        preserved_limits=preserved_primary_limits,
        default_xlim=(0.0, float(image_size)),
        default_ylim=(float(image_size), 0.0),
        preserve=(previous_primary_view_mode == "detector"),
    )
    ax.set_aspect("auto")
    gui_main_figure_chrome.set_main_figure_axes_axis_visibility(ax, visible=False)
    ax.set_title("")
    _sync_primary_raster_geometry(show_caked_image=False)
    gui_main_figure_chrome.apply_main_figure_axes_chrome(
        ax,
        axes_visible=False,
    )
    _request_main_canvas_redraw(force_matplotlib=False)
    _refresh_settled_overlays()
    _refresh_run_status_bar()


def _normalize_app_shell_view_mode_request(
    requested_mode: object | None,
    *,
    fallback: str,
) -> str:
    normalized = str(requested_mode or fallback).strip().lower()
    if normalized not in {"detector", "caked", "q_space"}:
        normalized = str(fallback or "detector").strip().lower()
    if normalized not in {"detector", "caked", "q_space"}:
        normalized = "detector"
    return normalized


def _toggle_caked_2d_requires_overlay_invalidation(target_view_mode: str) -> bool:
    if str(target_view_mode).strip().lower() not in {"detector", "caked"}:
        return True
    geometry_overlay_view_state = globals().get("geometry_overlay_actions_view_state")
    show_geometry_overlays = bool(
        getattr(
            getattr(geometry_overlay_view_state, "show_geometry_overlays_var", None),
            "get",
            lambda: False,
        )()
    )
    geometry_roi_preview_active = bool(_current_geometry_fit_caked_roi_preview_enabled())
    roi_values = dict(_current_analysis_roi_values() or {})
    selected_qr_rod_active = bool(roi_values.get("integrate_selected_qr_rod", False))
    return bool(show_geometry_overlays or geometry_roi_preview_active or selected_qr_rod_active)


def toggle_caked_2d(requested_mode: str | None = None) -> None:
    show_caked_now = bool(
        getattr(
            analysis_view_controls_view_state.show_caked_2d_var,
            "get",
            lambda: False,
        )()
    )
    target_view_mode = _normalize_app_shell_view_mode_request(
        requested_mode,
        fallback="caked" if show_caked_now else "detector",
    )
    gui_views.set_app_shell_view_mode(
        app_shell_view_state,
        target_view_mode,
    )
    if _toggle_caked_2d_requires_overlay_invalidation(target_view_mode):
        _invalidate_qr_cylinder_overlay_view_state(clear_artists=True)
    _apply_main_caked_view_toggle()
    if target_view_mode == "caked":
        _schedule_geometry_manual_pick_cache_prewarm()
    _sync_selected_qr_rod_controls_state()
    _sync_center_marker(redraw=False)
    reselect_current_peak = getattr(
        globals().get("peak_selection_runtime_callbacks"),
        "reselect_current_peak",
        None,
    )
    if callable(reselect_current_peak):
        reselected_peak = False
        try:
            reselected_peak = bool(reselect_current_peak())
        except Exception:
            reselected_peak = False
        if not reselected_peak:
            selected_peak_artist = globals().get("selected_peak_marker")
            set_visible = getattr(selected_peak_artist, "set_visible", None)
            hidden_stale_peak = False
            if callable(set_visible):
                try:
                    set_visible(False)
                    hidden_stale_peak = True
                except Exception:
                    pass
            if hidden_stale_peak:
                request_main_redraw = globals().get("_request_main_canvas_redraw")
                if callable(request_main_redraw):
                    try:
                        request_main_redraw(force_matplotlib=False)
                    except Exception:
                        pass
    if bool(analysis_peak_selection_state.pick_armed) and not show_caked_now:
        _set_analysis_peak_pick_mode(
            False,
            message="Analysis peak picking requires the caked view.",
        )
        _sync_center_marker(redraw=True)
        return
    _render_analysis_peak_overlays(redraw=True)
    if bool(getattr(geometry_runtime_state, "manual_pick_armed", False)):
        _invalidate_geometry_manual_pick_cache_and_schedule_prewarm_if_armed()


