def _sync_center_marker(*, redraw: bool) -> None:
    marker = globals().get("center_marker")
    if marker is None:
        return
    try:
        center_row = float(center_x_var.get())
        center_col = float(center_y_var.get())
    except Exception:
        return

    marker_x = float(center_col)
    marker_y = float(center_row)
    visible = _beam_center_spot_enabled()
    if visible and _current_geometry_fit_caked_roi_preview_enabled():
        visible = False
    view_mode = _current_app_shell_view_mode()
    if visible and view_mode == "q_space":
        visible = False
    if visible and view_mode == "caked":
        try:
            projected = _native_detector_coords_to_caked_display_coords(
                float(center_col),
                float(center_row),
            )
        except Exception:
            projected = None
        if projected is None:
            visible = False
        else:
            marker_x = float(projected[0])
            marker_y = float(projected[1])
    elif visible:
        coordinate_shape = _current_beam_center_coordinate_shape()
        if coordinate_shape is None:
            visible = False
        else:
            try:
                marker_x, marker_y = gui_geometry_overlay.beam_center_row_col_to_detector_display(
                    float(center_row),
                    float(center_col),
                    coordinate_shape,
                    int(DISPLAY_ROTATE_K),
                )
            except Exception:
                visible = False

    try:
        marker.set_xdata([marker_x])
        marker.set_ydata([marker_y])
        marker.set_visible(bool(visible))
    except Exception:
        return

    if not redraw:
        return
    request_overlay_redraw = globals().get("_request_overlay_canvas_redraw")
    if callable(request_overlay_redraw):
        try:
            request_overlay_redraw(force=True)
            return
        except Exception:
            pass
    request_main_redraw = globals().get("_request_main_canvas_redraw")
    if callable(request_main_redraw):
        try:
            request_main_redraw(force_matplotlib=True)
        except Exception:
            pass


def _minimum_positive_finite_value(image) -> float | None:
    if image is None:
        return None
    try:
        values = np.asarray(image, dtype=float)
    except Exception:
        return None
    if values.size == 0:
        return None
    positive = values[np.isfinite(values) & (values > 0.0)]
    if positive.size == 0:
        return None
    return float(np.min(positive))


def _build_intensity_display_norm(image, min_val, max_val):
    min_val, max_val = gui_controllers.ensure_display_intensity_range(min_val, max_val)
    if not _log_display_enabled():
        return Normalize(vmin=min_val, vmax=max_val)

    positive_floor = _minimum_positive_finite_value(image)
    if positive_floor is None:
        return Normalize(vmin=min_val, vmax=max_val)

    log_min = max(float(min_val), positive_floor)
    if not math.isfinite(log_min) or log_min <= 0.0:
        log_min = positive_floor

    log_max = float(max_val)
    if not math.isfinite(log_max) or log_max <= log_min:
        log_max = log_min + max(abs(log_min) * 1e-6, 1e-12)

    return LogNorm(vmin=log_min, vmax=log_max, clip=True)


def _apply_intensity_display_range(image_artist, image, min_val, max_val) -> None:
    image_artist.set_norm(_build_intensity_display_norm(image, min_val, max_val))


def _refresh_current_intensity_display_scaling(*, redraw: bool = True) -> None:
    (
        image_source,
        _image_extent,
        _image_origin,
        _image_source_signature,
    ) = _primary_raster_source_payload(image_display)
    if image_source is not None:
        image_min, image_max = image_display.get_clim()
        _apply_intensity_display_range(
            image_display,
            image_source,
            image_min,
            image_max,
        )

    (
        background_source,
        _background_extent,
        _background_origin,
        _background_source_signature,
    ) = _primary_raster_source_payload(background_display)
    if background_source is not None:
        background_min, background_max = background_display.get_clim()
        _apply_intensity_display_range(
            background_display,
            background_source,
            background_min,
            background_max,
        )

    colorbar_main.update_normal(image_display)
    caked_colorbar.update_normal(image_display)
    if redraw:
        _request_main_canvas_redraw(force_matplotlib=False)


def _apply_background_limits():
    background_min_var = display_controls_view_state.background_min_var
    background_max_var = display_controls_view_state.background_max_var
    if background_min_var is None or background_max_var is None:
        return False
    min_val = background_min_var.get()
    max_val = background_max_var.get()
    if min_val >= max_val:
        adjustment = max(abs(max_val) * 1.0e-6, 1.0e-6)
        display_controls_state.suppress_background_limit_callback = True
        try:
            background_min_var.set(max_val - adjustment)
        finally:
            display_controls_state.suppress_background_limit_callback = False
        return False
    display_controls_state.background_limits_user_override = True
    background_display.set_clim(min_val, max_val)
    _apply_background_transparency()
    _refresh_current_intensity_display_scaling(redraw=True)
    return True


def _apply_simulation_limits():
    simulation_min_var = display_controls_view_state.simulation_min_var
    simulation_max_var = display_controls_view_state.simulation_max_var
    if simulation_min_var is None or simulation_max_var is None:
        return
    min_val = simulation_min_var.get()
    max_val = simulation_max_var.get()
    if min_val >= max_val:
        adjustment = max(abs(max_val) * 1e-6, 1e-6)
        display_controls_state.suppress_simulation_limit_callback = True
        simulation_min_var.set(max_val - adjustment)
        display_controls_state.suppress_simulation_limit_callback = False
        return
    display_controls_state.simulation_limits_user_override = True
    apply_scale_factor_to_existing_results()


def _initialize_runtime_controls_block_16() -> None:
    global \
        background_display_defaults, \
        background_vmin_default, \
        background_vmax_default, \
        background_slider_min, \
        background_slider_max, \
        background_slider_step, \
        simulation_slider_min, \
        simulation_slider_max
    global \
        simulation_slider_step, \
        scale_factor_slider_min, \
        scale_factor_slider_max, \
        scale_factor_step

    background_display_defaults = gui_background_manager.resolve_background_display_defaults(
        background_runtime_state.current_background_display
    )
    background_vmin_default = background_display_defaults.vmin_default
    background_vmax_default = background_display_defaults.vmax_default
    background_slider_min = background_display_defaults.slider_min
    background_slider_max = background_display_defaults.slider_max
    background_slider_step = background_display_defaults.slider_step

    simulation_slider_min = 0.0
    simulation_slider_max = max(background_slider_max, defaults["vmax"] * 5.0)
    # Ensure fine-grained control so the intensity sliders support at least 1e-4 precision.
    simulation_slider_step = min(
        max((simulation_slider_max - simulation_slider_min) / 500.0, 1e-6),
        1e-4,
    )

    scale_factor_slider_min = 0.0
    scale_factor_slider_max = 2.0
    scale_factor_step = 0.0001

    gui_views.create_display_controls(
        parent=(
            app_shell_view_state.figure_controls_frame
            if app_shell_view_state.figure_controls_frame is not None
            else app_shell_view_state.fig_frame
        ),
        view_state=display_controls_view_state,
        background_range=(background_slider_min, background_slider_max),
        background_defaults=(background_vmin_default, background_vmax_default),
        background_step=background_slider_step,
        background_transparency=0.0,
        simulation_range=(simulation_slider_min, simulation_slider_max),
        simulation_defaults=(0.0, background_vmax_default),
        simulation_step=simulation_slider_step,
        scale_factor_range=(scale_factor_slider_min, scale_factor_slider_max),
        scale_factor_value=1.0,
        scale_factor_step=scale_factor_step,
        on_apply_background_limits=_apply_background_limits,
        on_apply_simulation_limits=_apply_simulation_limits,
    )

    _apply_intensity_display_range(
        background_display,
        background_runtime_state.current_background_display,
        background_vmin_default,
        background_vmax_default,
    )
    _apply_background_transparency()


def _get_scale_factor_value(default=1.0):
    display_controls = globals().get("display_controls_view_state")
    simulation_scale_factor_var = getattr(display_controls, "simulation_scale_factor_var", None)
    if simulation_scale_factor_var is None:
        return default
    try:
        scale = float(simulation_scale_factor_var.get())
    except (tk.TclError, ValueError):
        return default
    if not np.isfinite(scale):
        return default
    return gui_controllers.normalize_display_scale_factor(scale, fallback=1.0)


MAIN_DISPLAY_RASTER_MIN_SIZE = gui_display_projection.MIN_DISPLAY_RASTER_SIZE
MAIN_DISPLAY_RASTER_MAX_SIZE = gui_display_projection.MAX_DISPLAY_RASTER_SIZE
_MAIN_RASTER_SOURCE_ARRAY_ATTR = "_ra_sim_source_image"
_MAIN_RASTER_SOURCE_EXTENT_ATTR = "_ra_sim_source_extent"
_MAIN_RASTER_SOURCE_ORIGIN_ATTR = "_ra_sim_source_origin"
_MAIN_RASTER_SOURCE_SIGNATURE_ATTR = "_ra_sim_source_signature"


def _normalize_main_display_raster_size_limit(value: object | None = None) -> int:
    try:
        fallback = gui_display_projection.default_display_raster_size(image_size)
    except Exception:
        fallback = getattr(
            simulation_runtime_state,
            "main_display_raster_limit",
            MAIN_DISPLAY_RASTER_MAX_SIZE,
        )
    candidate = value
    if candidate is None:
        control_var = globals().get("main_display_raster_size_var")
        getter = getattr(control_var, "get", None)
        if callable(getter):
            try:
                candidate = getter()
            except Exception:
                candidate = None
    normalized = gui_display_projection.normalize_display_raster_size_limit(
        candidate,
        fallback=getattr(
            simulation_runtime_state,
            "main_display_raster_limit",
            fallback,
        ),
        minimum=MAIN_DISPLAY_RASTER_MIN_SIZE,
        maximum=MAIN_DISPLAY_RASTER_MAX_SIZE,
    )
    simulation_runtime_state.main_display_raster_limit = int(normalized)
    control_var = globals().get("main_display_raster_size_var")
    setter = getattr(control_var, "set", None)
    getter = getattr(control_var, "get", None)
    if callable(setter) and callable(getter):
        try:
            current_value = float(getter())
        except Exception:
            current_value = math.nan
        if not math.isfinite(current_value) or abs(current_value - float(normalized)) > 1e-9:
            try:
                setter(float(normalized))
            except Exception:
                pass
    widgets = getattr(app_shell_view_state, "quick_control_widgets", None)
    if isinstance(widgets, dict):
        control = widgets.get("display_raster_size")
        if isinstance(control, dict):
            scale_widget = control.get("scale")
            configure = getattr(scale_widget, "configure", None)
            if callable(configure):
                try:
                    configure(
                        from_=float(MAIN_DISPLAY_RASTER_MIN_SIZE),
                        to=float(MAIN_DISPLAY_RASTER_MAX_SIZE),
                    )
                except Exception:
                    pass
    return int(normalized)


def _current_main_display_raster_size_limit() -> int:
    return int(_normalize_main_display_raster_size_limit())


def _display_scale_signature_value(scale: object | None) -> float:
    try:
        scale_value = round(float(scale), 9)
    except Exception:
        scale_value = 1.0
    if not math.isfinite(scale_value):
        scale_value = 1.0
    return scale_value


def _detector_display_raster_source_signature() -> object | None:
    unscaled_signature = getattr(simulation_runtime_state, "last_unscaled_image_signature", None)
    if unscaled_signature is None:
        return None
    return (
        unscaled_signature,
        _display_scale_signature_value(_get_scale_factor_value(default=1.0)),
    )


def _current_detector_artist_source_signature() -> object | None:
    if not _simulation_overlay_visible():
        return None
    return _primary_raster_source_payload(globals().get("image_display"))[3]


def _resolved_primary_raster_source_signature(
    source: np.ndarray | None,
    *,
    explicit_source_signature: object | None = None,
) -> object | None:
    if explicit_source_signature is not None:
        return explicit_source_signature
    if source is None:
        return None
    detector_buffer = globals().get("global_image_buffer")
    if source is detector_buffer:
        detector_signature = _detector_display_raster_source_signature()
        if detector_signature is not None:
            return detector_signature
    arr = np.asarray(source)
    try:
        data_ptr = int(arr.__array_interface__["data"][0])
    except Exception:
        data_ptr = id(arr)
    return (
        id(source),
        data_ptr,
        tuple(int(value) for value in arr.shape),
        tuple(int(value) for value in arr.strides),
        str(arr.dtype),
    )


def _analysis_view_payload_signature(view_mode: str) -> object | None:
    if str(view_mode) == "q_space":
        return getattr(simulation_runtime_state, "last_q_space_payload_signature", None)
    if str(view_mode) == "caked":
        cache_signature = getattr(simulation_runtime_state, "last_analysis_cache_sig", None)
        if cache_signature is None:
            return None
        return (
            cache_signature,
            _normalize_caked_intensity_mode(
                getattr(simulation_runtime_state, "last_caked_intensity_mode", "density")
            ),
        )
    return None


def _analysis_display_raster_source_signature(
    *,
    view_mode: str,
    role: str,
    scale: object | None,
    display_source: np.ndarray | None,
    raw_source: np.ndarray | None,
) -> object | None:
    if display_source is None:
        return None
    payload_signature = _analysis_view_payload_signature(view_mode)
    display_array = np.asarray(display_source)
    raw_array = None if raw_source is None else np.asarray(raw_source)
    if payload_signature is not None and raw_array is not None and display_array is raw_array:
        return (
            str(view_mode),
            str(role),
            payload_signature,
            _display_scale_signature_value(scale),
        )
    return _resolved_primary_raster_source_signature(display_array)


def _integration_overlay_raster_source_signature(
    *,
    parent_source_signature: object | None,
    overlay_source: np.ndarray | None,
    overlay_source_signature: object | None = None,
) -> object | None:
    return (
        "integration_region_overlay",
        parent_source_signature,
        _resolved_primary_raster_source_signature(
            overlay_source,
            explicit_source_signature=overlay_source_signature,
        ),
    )


def _store_primary_raster_source(
    artist: object | None,
    image: np.ndarray | None,
    *,
    source_signature: object | None = None,
) -> np.ndarray | None:
    if artist is None:
        return None
    source = None if image is None else np.asarray(image)
    setattr(artist, _MAIN_RASTER_SOURCE_ARRAY_ATTR, source)
    setattr(
        artist,
        _MAIN_RASTER_SOURCE_SIGNATURE_ATTR,
        _resolved_primary_raster_source_signature(
            source,
            explicit_source_signature=source_signature,
        ),
    )
    return source


def _store_primary_raster_geometry(
    artist: object | None,
    *,
    origin: str,
    extent: tuple[float, float, float, float] | list[float],
) -> None:
    if artist is None:
        return
    try:
        normalized_extent = tuple(float(value) for value in extent)
    except Exception:
        return
    if len(normalized_extent) != 4:
        return
    setattr(artist, _MAIN_RASTER_SOURCE_EXTENT_ATTR, normalized_extent)
    setattr(artist, _MAIN_RASTER_SOURCE_ORIGIN_ATTR, str(origin))


def _primary_raster_source_payload(
    artist: object | None,
) -> tuple[np.ndarray | None, tuple[float, float, float, float] | None, str, object | None]:
    if artist is None:
        return (None, None, "upper", None)

    source = getattr(artist, _MAIN_RASTER_SOURCE_ARRAY_ATTR, None)
    if source is None:
        getter = getattr(artist, "get_array", None)
        if callable(getter):
            try:
                current = getter()
            except Exception:
                current = None
            if current is not None:
                source = np.asarray(current)
    source_signature = getattr(artist, _MAIN_RASTER_SOURCE_SIGNATURE_ATTR, None)

    extent = getattr(artist, _MAIN_RASTER_SOURCE_EXTENT_ATTR, None)
    if not isinstance(extent, tuple) or len(extent) != 4:
        get_extent = getattr(artist, "get_extent", None)
        if callable(get_extent):
            try:
                live_extent = tuple(float(value) for value in get_extent())
            except Exception:
                live_extent = None
            if isinstance(live_extent, tuple) and len(live_extent) == 4:
                extent = live_extent
    origin = str(getattr(artist, _MAIN_RASTER_SOURCE_ORIGIN_ATTR, "upper") or "upper")
    return (None if source is None else np.asarray(source), extent, origin, source_signature)


def _current_primary_axis_limits() -> tuple[tuple[float, float], tuple[float, float]] | None:
    getter_x = getattr(ax, "get_xlim", None)
    getter_y = getattr(ax, "get_ylim", None)
    if not callable(getter_x) or not callable(getter_y):
        return None
    try:
        xlim = tuple(float(value) for value in getter_x())
        ylim = tuple(float(value) for value in getter_y())
    except Exception:
        return None
    if len(xlim) != 2 or len(ylim) != 2:
        return None
    if not all(np.isfinite(value) for value in (*xlim, *ylim)):
        return None
    return (xlim, ylim)


def _current_primary_axis_bbox_pixels() -> tuple[float | None, float | None]:
    bbox = getattr(ax, "bbox", None)
    width = getattr(bbox, "width", None)
    height = getattr(bbox, "height", None)
    try:
        width_value = float(width)
    except Exception:
        width_value = math.nan
    try:
        height_value = float(height)
    except Exception:
        height_value = math.nan
    return (
        width_value if math.isfinite(width_value) and width_value > 0.0 else None,
        height_value if math.isfinite(height_value) and height_value > 0.0 else None,
    )


def _apply_projected_primary_raster_to_artist(artist: object | None) -> bool:
    source, extent, origin, source_signature = _primary_raster_source_payload(artist)
    if artist is None or source is None or extent is None:
        return False
    try:
        projection_mode = (
            str(_resolved_primary_analysis_display_mode() or "detector").strip().lower()
        )
    except Exception:
        projection_mode = "detector"
    use_live_viewport_projection = projection_mode != "detector"
    if use_live_viewport_projection:
        axis_limits = _current_primary_axis_limits()
        if axis_limits is None:
            axis_xlim = None
            axis_ylim = None
        else:
            axis_xlim, axis_ylim = axis_limits
        bbox_width, bbox_height = _current_primary_axis_bbox_pixels()
    else:
        axis_xlim = None
        axis_ylim = None
        bbox_width = None
        bbox_height = None
    projection = gui_display_projection.project_raster_to_view(
        source,
        source_signature=source_signature,
        extent=extent,
        axis_xlim=axis_xlim,
        axis_ylim=axis_ylim,
        max_size=int(_current_main_display_raster_size_limit()),
        bbox_width_px=bbox_width,
        bbox_height_px=bbox_height,
        preserve_bright_features=bool(
            artist is globals().get("image_display")
            or artist is globals().get("integration_region_overlay")
        ),
    )
    if projection is None:
        return False
    artist.origin = origin
    set_extent = getattr(artist, "set_extent", None)
    if callable(set_extent):
        try:
            set_extent(list(projection.extent))
        except Exception:
            pass
    set_data = getattr(artist, "set_data", None)
    if callable(set_data):
        try:
            set_data(projection.image)
        except Exception:
            return False
    return True


def _apply_current_primary_raster_projection() -> None:
    for artist in (
        globals().get("image_display"),
        globals().get("background_display"),
        globals().get("integration_region_overlay"),
    ):
        _apply_projected_primary_raster_to_artist(artist)


def _set_primary_integration_overlay_image(
    image: object,
    *,
    source_signature: object | None = None,
) -> None:
    overlay_artist = globals().get("integration_region_overlay")
    if overlay_artist is None:
        return
    image_artist = globals().get("image_display")
    _image_source, image_extent, image_origin, image_source_signature = (
        _primary_raster_source_payload(image_artist)
    )
    overlay_source = None if image is None else np.asarray(image, dtype=float)
    overlay_source_signature = _integration_overlay_raster_source_signature(
        parent_source_signature=image_source_signature,
        overlay_source=overlay_source,
        overlay_source_signature=source_signature,
    )
    _store_primary_raster_source(
        overlay_artist,
        overlay_source,
        source_signature=overlay_source_signature,
    )
    if image_extent is not None:
        _store_primary_raster_geometry(
            overlay_artist,
            origin=image_origin,
            extent=image_extent,
        )
    _apply_projected_primary_raster_to_artist(overlay_artist)


def _refresh_main_display_raster_projection() -> None:
    _normalize_main_display_raster_size_limit()
    _clear_pending_main_figure_preview_interaction()
    _apply_current_primary_raster_projection()
    _request_main_canvas_redraw(force_matplotlib=False)


def _initialize_runtime_controls_block_18() -> None:
    _store_primary_raster_source(image_display, global_image_buffer)
    _store_primary_raster_source(
        background_display,
        background_runtime_state.current_background_display,
    )
    _store_primary_raster_source(
        integration_region_overlay,
        np.zeros_like(global_image_buffer),
    )
    _sync_primary_raster_geometry(show_caked_image=False)


def _on_scale_factor_change(
    _variable_name: object | None = None,
    _index: object | None = None,
    _operation: object | None = None,
) -> None:
    if display_controls_state.suppress_scale_factor_callback:
        return
    if _get_scale_factor_value(default=None) is None:
        return
    display_controls_state.scale_factor_user_override = True
    apply_scale_factor_to_existing_results()


def _initialize_runtime_controls_block_19() -> None:
    if display_controls_view_state.simulation_scale_factor_var is not None:
        display_controls_view_state.simulation_scale_factor_var.trace_add(
            "write", _on_scale_factor_change
        )


def _update_background_slider_defaults(image, reset_override=False):
    return gui_background_manager.update_background_slider_defaults(
        display_controls_state,
        display_controls_view_state,
        background_display=background_display,
        image=image,
        reset_override=reset_override,
    )


def _update_simulation_sliders_from_image(image, reset_override=False):
    simulation_min_var = display_controls_view_state.simulation_min_var
    simulation_max_var = display_controls_view_state.simulation_max_var
    simulation_min_slider = display_controls_view_state.simulation_min_slider
    simulation_max_slider = display_controls_view_state.simulation_max_slider
    if image is None or image.size == 0:
        return
    finite_pixels = np.asarray(image, dtype=float)
    finite_pixels = finite_pixels[np.isfinite(finite_pixels)]
    if finite_pixels.size == 0:
        return
    lower_bound = 0.0
    display_upper_bound, slider_upper_bound = gui_controllers.resolve_simulation_display_bounds(
        finite_pixels,
        percentile=99.0,
    )
    slider_to = slider_upper_bound
    simulation_min_slider.configure(from_=lower_bound, to=slider_to)
    simulation_max_slider.configure(from_=lower_bound, to=slider_to)
    slider_from = lower_bound
    display_controls_state.suppress_simulation_limit_callback = True
    if reset_override or not display_controls_state.simulation_limits_user_override:
        min_value = 0.0
        max_value = display_upper_bound
    else:
        min_value = float(simulation_min_var.get())
        max_value = float(simulation_max_var.get())
        min_value = min(max(min_value, slider_from), slider_to)
        max_value = min(max(max_value, slider_from), slider_to)
    min_value, max_value = gui_controllers.ensure_display_intensity_range(min_value, max_value)
    simulation_min_var.set(min_value)
    simulation_max_var.set(max_value)
    display_controls_state.suppress_simulation_limit_callback = False
    if reset_override:
        display_controls_state.simulation_limits_user_override = False


def _set_scale_factor_value(value, adjust_range=True, reset_override=False):
    simulation_scale_factor_var = display_controls_view_state.simulation_scale_factor_var
    scale_factor_slider = display_controls_view_state.scale_factor_slider
    if simulation_scale_factor_var is None or scale_factor_slider is None:
        return
    value = gui_controllers.normalize_display_scale_factor(value, fallback=1.0)

    slider_min = float(scale_factor_slider.cget("from"))
    slider_max = float(scale_factor_slider.cget("to"))
    if adjust_range:
        new_min = slider_min
        new_max = slider_max
        if value < slider_min:
            new_min = value
        if value > slider_max:
            new_max = value
        if new_min != slider_min or new_max != slider_max:
            scale_factor_slider.configure(from_=new_min, to=new_max)
    else:
        value = min(max(value, slider_min), slider_max)

    display_controls_state.suppress_scale_factor_callback = True
    simulation_scale_factor_var.set(value)
    display_controls_state.suppress_scale_factor_callback = False
    if reset_override:
        display_controls_state.scale_factor_user_override = False
    else:
        display_controls_state.scale_factor_user_override = True


def _install_scale_factor_entry_bindings():
    scale_entry = display_controls_view_state.scale_factor_entry
    if scale_entry is None:
        return

    def _apply_scale_entry(_event=None):
        raw = scale_entry.get().strip()
        if not raw:
            current = _get_scale_factor_value(default=1.0)
            scale_entry.delete(0, tk.END)
            scale_entry.insert(0, f"{current:.6g}")
            return
        try:
            value = float(raw)
        except ValueError:
            current = _get_scale_factor_value(default=1.0)
            scale_entry.delete(0, tk.END)
            scale_entry.insert(0, f"{current:.6g}")
            return
        _set_scale_factor_value(value, adjust_range=True, reset_override=False)
        apply_scale_factor_to_existing_results(update_limits=False)

    scale_entry.unbind("<FocusOut>")
    scale_entry.unbind("<Return>")
    scale_entry.bind("<FocusOut>", _apply_scale_entry)
    scale_entry.bind("<Return>", _apply_scale_entry)


def _suggest_scale_factor(sim_image, bg_image):
    sim_pixels = None if sim_image is None else np.asarray(sim_image, dtype=float)
    bg_pixels = None if bg_image is None else np.asarray(bg_image, dtype=float)
    if sim_pixels is None or bg_pixels is None:
        return 1.0

    # Percentiles over every pixel are expensive on full detector images.
    # Subsample finite values to keep this nearly constant-time.
    sim_pixels = sim_pixels[np.isfinite(sim_pixels)]
    bg_pixels = bg_pixels[np.isfinite(bg_pixels)]
    max_samples = 200_000
    if sim_pixels.size > max_samples:
        sim_step = max(1, sim_pixels.size // max_samples)
        sim_pixels = sim_pixels[::sim_step]
    if bg_pixels.size > max_samples:
        bg_step = max(1, bg_pixels.size // max_samples)
        bg_pixels = bg_pixels[::bg_step]

    if sim_pixels.size == 0 or bg_pixels.size == 0:
        return 1.0
    sim_reference_pixels = sim_pixels[sim_pixels > 0]
    if sim_reference_pixels.size == 0:
        sim_reference_pixels = np.abs(sim_pixels)
    bg_reference_pixels = bg_pixels[bg_pixels > 0]
    if bg_reference_pixels.size == 0:
        bg_reference_pixels = np.abs(bg_pixels)
    sim_ref = float(np.nanpercentile(sim_reference_pixels, 99))
    bg_ref = float(np.nanpercentile(bg_reference_pixels, 99))
    if not np.isfinite(sim_ref) or abs(sim_ref) < 1e-12:
        return 1.0
    if not np.isfinite(bg_ref) or abs(bg_ref) < 1e-12:
        return 1.0
    return bg_ref / sim_ref


def _mark_chi_square_dirty():
    simulation_runtime_state.chi_square_update_token = (
        int(simulation_runtime_state.chi_square_update_token) + 1
    )


def _auto_match_scale_factor_to_radial_peak():
    sim_curve = simulation_runtime_state.last_1d_integration_data.get("intensities_2theta_sim")
    bg_curve = simulation_runtime_state.last_1d_integration_data.get("intensities_2theta_bg")

    if sim_curve is None or bg_curve is None:
        sim_img = simulation_runtime_state.last_1d_integration_data.get(
            "simulated_2d_image",
        )
        if sim_img is None:
            sim_img = getattr(simulation_runtime_state, "unscaled_image", None)
        bg_img = _get_current_background_backend()
        if _selected_qr_rod_mode_requested():
            try:
                primary_key = str(
                    simulation_runtime_state.last_1d_integration_data.get(
                        "primary_selected_qr_rod_key",
                        "",
                    )
                    or ""
                )
                profiles = simulation_runtime_state.last_1d_integration_data.get(
                    "selected_qr_rod_profiles",
                )
                if not primary_key or not isinstance(profiles, Mapping):
                    sim_res2 = getattr(simulation_runtime_state, "last_res2_sim", None)
                    bg_res2 = getattr(simulation_runtime_state, "last_res2_background", None)
                    if (
                        (sim_res2 is None or bg_res2 is None)
                        and sim_img is not None
                        and bg_img is not None
                    ):
                        ai_cache = getattr(simulation_runtime_state, "ai_cache", {}) or {}
                        ai = ai_cache.get("ai") if isinstance(ai_cache, Mapping) else None
                        if ai is not None:
                            if sim_res2 is None:
                                sim_res2 = caking(sim_img, ai)
                            if bg_res2 is None:
                                bg_res2 = caking(bg_img, ai)
                    if sim_res2 is not None and bg_res2 is not None:
                        _update_1d_plots_from_caked(sim_res2, bg_res2)
                    primary_key = str(
                        simulation_runtime_state.last_1d_integration_data.get(
                            "primary_selected_qr_rod_key",
                            "",
                        )
                        or ""
                    )
                    profiles = simulation_runtime_state.last_1d_integration_data.get(
                        "selected_qr_rod_profiles",
                    )
                primary_profile = (
                    profiles.get(primary_key)
                    if primary_key and isinstance(profiles, Mapping)
                    else None
                )
                if isinstance(primary_profile, Mapping):
                    sim_curve = _finite_profile_curve(primary_profile.get("sim"))
                    bg_curve = _finite_profile_curve(primary_profile.get("bg"))
                    if sim_curve is not None and bg_curve is not None:
                        simulation_runtime_state.last_1d_integration_data[
                            "intensities_2theta_sim"
                        ] = sim_curve
                        simulation_runtime_state.last_1d_integration_data[
                            "intensities_2theta_bg"
                        ] = bg_curve
                        simulation_runtime_state.last_1d_integration_data[
                            "primary_selected_qr_rod_key"
                        ] = primary_key
                        axis_kind = str(
                            simulation_runtime_state.last_1d_integration_data.get(
                                "x_axis_kind",
                                "",
                            )
                            or ""
                        )
                        axis_label = str(
                            simulation_runtime_state.last_1d_integration_data.get(
                                "x_axis_label",
                                "",
                            )
                            or ""
                        )
                        if axis_kind not in {"l", "qz"}:
                            axis_kind = "l" if primary_profile.get("l") is not None else "qz"
                        if not axis_label:
                            axis_label = "L (r.l.u.)" if axis_kind == "l" else "Qz (A^-1)"
                        simulation_runtime_state.last_1d_integration_data["x_axis_kind"] = axis_kind
                        simulation_runtime_state.last_1d_integration_data["x_axis_label"] = (
                            axis_label
                        )
            except Exception:
                sim_curve = None
                bg_curve = None
        elif sim_img is not None and bg_img is not None:
            try:
                ai_cache = getattr(simulation_runtime_state, "ai_cache", {}) or {}
                ai = ai_cache.get("ai") if isinstance(ai_cache, Mapping) else None
                if ai is None:
                    raise ValueError("Caking integrator unavailable.")
                tth_min, tth_max = sorted((float(tth_min_var.get()), float(tth_max_var.get())))
                phi_min = float(phi_min_var.get())
                phi_max = float(phi_max_var.get())
                sim_res2 = caking(sim_img, ai)
                bg_res2 = caking(bg_img, ai)
                caked_intensity_mode = _current_caked_intensity_mode()
                i2t_sim, _, _, _ = _caked_profiles_from_sum_fields(
                    sim_res2,
                    tth_min=tth_min,
                    tth_max=tth_max,
                    phi_min=phi_min,
                    phi_max=phi_max,
                    intensity_mode=caked_intensity_mode,
                )
                i2t_bg, _, _, _ = _caked_profiles_from_sum_fields(
                    bg_res2,
                    tth_min=tth_min,
                    tth_max=tth_max,
                    phi_min=phi_min,
                    phi_max=phi_max,
                    intensity_mode=caked_intensity_mode,
                )
                sim_curve = i2t_sim
                bg_curve = i2t_bg
                simulation_runtime_state.last_1d_integration_data["intensities_2theta_sim"] = (
                    i2t_sim
                )
                simulation_runtime_state.last_1d_integration_data["intensities_2theta_bg"] = i2t_bg
            except Exception:
                sim_curve = None
                bg_curve = None
        if sim_curve is None or bg_curve is None:
            progress_label_positions.config(
                text=(
                    "Auto-match requires background + simulation radial curves. "
                    "Enable background and run/update simulation once."
                )
            )
            return

    sim_vals = np.asarray(sim_curve, dtype=float)
    bg_vals = np.asarray(bg_curve, dtype=float)
    sim_vals = sim_vals[np.isfinite(sim_vals)]
    bg_vals = bg_vals[np.isfinite(bg_vals)]
    x_axis_kind = simulation_runtime_state.last_1d_integration_data.get("x_axis_kind")
    if x_axis_kind == "qz":
        profile_axis_name = "Qz"
    elif x_axis_kind == "l":
        profile_axis_name = "L"
    else:
        profile_axis_name = "radial"
    if sim_vals.size == 0 or bg_vals.size == 0:
        progress_label_positions.config(
            text=f"Auto-match failed: {profile_axis_name} curves are empty."
        )
        return

    sim_peak = float(np.max(sim_vals))
    bg_peak = float(np.max(bg_vals))
    if not np.isfinite(sim_peak) or sim_peak <= 0.0:
        progress_label_positions.config(
            text=f"Auto-match failed: simulated {profile_axis_name} peak is non-positive."
        )
        return
    if not np.isfinite(bg_peak) or bg_peak < 0.0:
        progress_label_positions.config(
            text=f"Auto-match failed: background {profile_axis_name} peak is invalid."
        )
        return

    target_scale = bg_peak / sim_peak
    _set_scale_factor_value(target_scale, adjust_range=True, reset_override=False)
    apply_scale_factor_to_existing_results(update_limits=False)
    progress_label_positions.config(
        text=(
            f"Auto-matched scale factor to {profile_axis_name} peak: {target_scale:.6g} "
            f"(sim max={sim_peak:.6g}, bg max={bg_peak:.6g})."
        )
    )


def _clear_analysis_integration_region() -> None:
    def _apply_cleared_integration() -> None:
        refresh_cached = globals().get("_refresh_integration_from_cached_results")
        if callable(refresh_cached):
            refresh_cached()
            return
        refresh_visuals = globals().get("refresh_integration_region_visuals")
        if callable(refresh_visuals):
            refresh_visuals()
        request_redraw = globals().get("_request_overlay_canvas_redraw")
        if callable(request_redraw):
            request_redraw()

    for callback in (
        getattr(integration_range_drag_runtime_callbacks, "reset", None),
        lambda: _set_analysis_peak_pick_mode(False),
        _clear_selected_analysis_peaks,
        _apply_cleared_integration,
    ):
        if callable(callback):
            try:
                callback()
            except Exception:
                pass
    setter = getattr(analysis_view_controls_view_state.show_1d_var, "set", None)
    if callable(setter):
        try:
            setter(False)
        except Exception:
            pass
    try:
        progress_label_positions.config(
            text="Integration region cleared. Draw a new box to integrate again."
        )
    except Exception:
        pass


def _update_chi_square_display(force=False):
    state = simulation_runtime_state.chi_square_state
    now = perf_counter()
    # Throttle to avoid repeatedly scanning full detector arrays during slider
    # drags; keep the last displayed value between refreshes.
    if (not force) and ((now - float(state.get("last_ts", 0.0))) < CHI_SQUARE_UPDATE_INTERVAL_S):
        last_text = str(state.get("last_text", "Chi-Squared: N/A"))
        chi_square_label.config(text=last_text)
        return

    token = int(simulation_runtime_state.chi_square_update_token)
    if (not force) and token == int(state.get("last_token", -1)):
        last_text = str(state.get("last_text", "Chi-Squared: N/A"))
        chi_square_label.config(text=last_text)
        state["last_ts"] = now
        return

    try:
        native_background = _get_current_background_backend()
        text = "Chi-Squared: N/A"
        if (
            background_runtime_state.visible
            and native_background is not None
            and global_image_buffer.size
        ):
            sim_vals = np.asarray(global_image_buffer, dtype=float)
            bg_vals = np.asarray(native_background, dtype=float)
            if (
                sim_vals.size
                and bg_vals.size
                and np.max(sim_vals) > 0
                and np.max(bg_vals) > 0
                and sim_vals.shape == bg_vals.shape
            ):
                # Subsample large arrays for responsive UI updates.
                max_points = 250_000
                if sim_vals.ndim == 2 and sim_vals.size > max_points:
                    stride = int(max(1, np.sqrt(sim_vals.size / float(max_points))))
                    sim_vals = sim_vals[::stride, ::stride]
                    bg_vals = bg_vals[::stride, ::stride]
                norm_sim = sim_vals / np.max(sim_vals)
                norm_bg = bg_vals / np.max(bg_vals)
                chi_sq_val = float(np.mean(np.square(norm_bg - norm_sim)) * norm_sim.size)
                text = f"Chi-Squared: {chi_sq_val:.2e}"
    except Exception as exc:
        text = f"Chi-Squared Error: {exc}"

    state["last_ts"] = now
    state["last_token"] = token
    state["last_text"] = text
    chi_square_label.config(text=text)


def _geometry_fit_holistic_image_snapshot(value: object) -> np.ndarray | None:
    try:
        arr = np.array(value, dtype=np.float64, copy=True)
    except Exception:
        return None
    if arr.ndim != 2 or arr.size <= 0:
        return None
    return arr


def _geometry_fit_holistic_snapshot_entry(
    background: object,
    simulation: object,
) -> dict[str, object] | None:
    background_arr = _geometry_fit_holistic_image_snapshot(background)
    if background_arr is None:
        return None
    try:
        simulation_arr = np.asarray(simulation, dtype=np.float64)
    except Exception:
        return None
    if (
        simulation_arr.ndim != 2
        or simulation_arr.size <= 0
        or background_arr.shape != simulation_arr.shape
    ):
        return None
    try:
        initial_metrics = compute_holistic_sim_residual(background_arr, simulation_arr)
    except Exception:
        return None
    return {
        "background": background_arr,
        "initial_metrics": initial_metrics,
    }


def _queue_geometry_fit_holistic_residual_check() -> None:
    """Capture current GUI images before the fitted simulation redraw runs."""

    snapshot: dict[str, object] = {}
    detector_entry = _geometry_fit_holistic_snapshot_entry(
        _get_current_background_backend(),
        getattr(simulation_runtime_state, "unscaled_image", None),
    )
    if detector_entry is not None:
        snapshot["detector"] = detector_entry

    caked_entry = _geometry_fit_holistic_snapshot_entry(
        getattr(simulation_runtime_state, "last_caked_background_image_unscaled", None),
        getattr(simulation_runtime_state, "last_caked_image_unscaled", None),
    )
    if caked_entry is not None:
        snapshot["caked"] = caked_entry

    if not snapshot:
        return
    snapshot["initial_unscaled_signature"] = getattr(
        simulation_runtime_state,
        "last_unscaled_image_signature",
        None,
    )
    snapshot["initial_simulation_signature"] = getattr(
        simulation_runtime_state,
        "last_simulation_signature",
        None,
    )
    simulation_runtime_state.geometry_fit_pending_holistic_residual = snapshot


def _format_geometry_fit_holistic_line(
    space: str,
    comparison: Mapping[str, object],
    *,
    stale_final_simulation: bool,
) -> str:
    initial_rmse = float(comparison.get("holistic_residual_initial_rmse", np.nan))
    final_rmse = float(comparison.get("holistic_residual_final_rmse", np.nan))
    delta_rmse = float(comparison.get("holistic_residual_delta_rmse", np.nan))
    suspicious = bool(comparison.get("holistic_fit_suspicious", False))
    return (
        f"holistic {space}: initial_rmse={initial_rmse:.6g}, "
        f"final_rmse={final_rmse:.6g}, delta={delta_rmse:.6g}, "
        f"suspicious={suspicious}, stale_final_sim={bool(stale_final_simulation)}"
    )


def _flush_pending_geometry_fit_holistic_residual() -> None:
    pending = getattr(simulation_runtime_state, "geometry_fit_pending_holistic_residual", None)
    if not isinstance(pending, dict):
        return

    lines: list[str] = []
    for space in ("detector", "caked"):
        entry = pending.get(space)
        if not isinstance(entry, Mapping):
            continue
        background = entry.get("background")
        initial_metrics = entry.get("initial_metrics")
        if not isinstance(initial_metrics, Mapping):
            lines.append(f"holistic {space}: skipped initial_metrics_unavailable")
            continue
        if space == "detector":
            final_sim_source = getattr(simulation_runtime_state, "unscaled_image", None)
            initial_signature = pending.get("initial_unscaled_signature")
            final_signature = getattr(
                simulation_runtime_state,
                "last_unscaled_image_signature",
                None,
            )
        else:
            final_sim_source = getattr(simulation_runtime_state, "last_caked_image_unscaled", None)
            initial_signature = pending.get("initial_simulation_signature")
            final_signature = getattr(
                simulation_runtime_state,
                "last_simulation_signature",
                None,
            )
        final_sim = _geometry_fit_holistic_image_snapshot(final_sim_source)
        if final_sim is None:
            lines.append(f"holistic {space}: skipped final_simulation_unavailable")
            continue
        stale_final_sim = bool(
            initial_signature is not None
            and final_signature is not None
            and initial_signature == final_signature
        )
        try:
            final_metrics = compute_holistic_sim_residual(background, final_sim)
            comparison = compare_holistic_sim_residuals(initial_metrics, final_metrics)
        except Exception as exc:
            lines.append(f"holistic {space}: error={type(exc).__name__}:{exc}")
            continue
        lines.append(
            _format_geometry_fit_holistic_line(
                space,
                comparison,
                stale_final_simulation=stale_final_sim,
            )
        )

    simulation_runtime_state.geometry_fit_pending_holistic_residual = None
    if not lines:
        return
    for line in lines:
        _geometry_fit_cmd_line(line)


def _schedule_geometry_fit_update_with_holistic_residual() -> None:
    _queue_geometry_fit_holistic_residual_check()
    schedule_update()


def _ensure_global_image_buffer_shape(source_image: object) -> np.ndarray:
    global global_image_buffer

    source = np.asarray(source_image)
    if (
        getattr(global_image_buffer, "shape", None) != source.shape
        or getattr(global_image_buffer, "dtype", None) != np.float64
    ):
        global_image_buffer = np.empty(source.shape, dtype=np.float64)
    return global_image_buffer


def _refresh_global_detector_buffer_from_unscaled(
    *,
    scale: object | None = None,
) -> np.ndarray | None:
    global global_image_buffer
    unscaled_image = getattr(simulation_runtime_state, "unscaled_image", None)
    if unscaled_image is None:
        return None
    try:
        unscaled_array = np.asarray(unscaled_image)
    except Exception:
        return None

    scaled_buffer = _ensure_global_image_buffer_shape(simulation_runtime_state.unscaled_image)
    if (
        not isinstance(scaled_buffer, np.ndarray)
        or scaled_buffer.shape != unscaled_array.shape
        or scaled_buffer.dtype != np.float64
    ):
        if (
            isinstance(global_image_buffer, np.ndarray)
            and global_image_buffer.shape == unscaled_array.shape
            and global_image_buffer.dtype == np.float64
        ):
            scaled_buffer = global_image_buffer
        else:
            global_image_buffer = np.empty(unscaled_array.shape, dtype=np.float64)
            scaled_buffer = global_image_buffer
    try:
        scale_value = float(_get_scale_factor_value(default=1.0) if scale is None else scale)
    except Exception:
        scale_value = 1.0
    if not math.isfinite(scale_value):
        scale_value = 1.0

    if abs(scale_value - 1.0) <= 1e-12:
        np.copyto(scaled_buffer, unscaled_array, casting="unsafe")
    else:
        np.multiply(unscaled_array, scale_value, out=scaled_buffer)
    return scaled_buffer


def apply_scale_factor_to_existing_results(
    update_limits=False,
    *,
    update_1d=True,
    update_canvas=True,
    force_canvas_redraw=False,
    update_chi_square=True,
):
    chi_state = simulation_runtime_state.chi_square_state
    _clear_pending_main_figure_preview_interaction()
    active_view_mode = _resolved_primary_analysis_display_mode()
    show_caked_image = active_view_mode == "caked"
    show_q_space_image = active_view_mode == "q_space"
    show_analysis_image = show_caked_image or show_q_space_image
    if simulation_runtime_state.unscaled_image is None:
        background_min_var = display_controls_view_state.background_min_var
        background_max_var = display_controls_view_state.background_max_var
        chi_square_sig = (
            None,
            bool(background_runtime_state.visible),
            int(background_runtime_state.current_background_index),
        )
        if chi_state.get("buffer_sig") != chi_square_sig:
            chi_state["buffer_sig"] = chi_square_sig
            _mark_chi_square_dirty()
        if not show_analysis_image:
            _sync_primary_raster_geometry(view_mode="detector")
            detector_background_source = _current_background_display_for_mode()
            if background_runtime_state.visible and detector_background_source is not None:
                _preview_sim_unused, preview_background_display = (
                    _geometry_fit_caked_roi_preview_images(
                        show_caked_image=False,
                        simulation_image=None,
                        background_image=detector_background_source,
                    )
                )
                background_preview_source = (
                    preview_background_display
                    if isinstance(preview_background_display, np.ndarray)
                    else detector_background_source
                )
                _store_primary_raster_source(
                    background_display,
                    background_preview_source,
                )
                _apply_intensity_display_range(
                    background_display,
                    background_preview_source,
                    background_min_var.get(),
                    background_max_var.get(),
                )
                background_display.set_visible(True)
            else:
                background_display.set_visible(False)
        _sync_simulation_overlay_artist_visibility()
        if update_canvas:
            _request_main_canvas_redraw(force_matplotlib=False)
        if update_chi_square:
            _update_chi_square_display()
        return

    scale = _get_scale_factor_value(default=1.0)
    scaled_image = _refresh_global_detector_buffer_from_unscaled(scale=scale)
    if scaled_image is None:
        return
    base_unscaled_sig = simulation_runtime_state.last_unscaled_image_signature
    chi_square_sig = (
        base_unscaled_sig,
        round(float(scale), 9),
        bool(background_runtime_state.visible),
        int(background_runtime_state.current_background_index),
    )
    if chi_state.get("buffer_sig") != chi_square_sig:
        chi_state["buffer_sig"] = chi_square_sig
        _mark_chi_square_dirty()

    scaled_caked = None
    scaled_q_space = None
    display_image_for_limits = scaled_image
    if show_q_space_image:
        scaled_q_space = simulation_runtime_state.last_q_space_image_unscaled * scale
        display_image_for_limits = scaled_q_space
    elif show_caked_image:
        scaled_caked = simulation_runtime_state.last_caked_image_unscaled * scale
        display_image_for_limits = scaled_caked
    _update_simulation_sliders_from_image(
        display_image_for_limits,
        reset_override=update_limits,
    )

    preview_background_source = None
    if show_q_space_image:
        if (
            background_runtime_state.visible
            and simulation_runtime_state.last_q_space_background_image_unscaled is not None
        ):
            preview_background_source = (
                simulation_runtime_state.last_q_space_background_image_unscaled * scale
            )
    elif show_caked_image:
        if (
            background_runtime_state.visible
            and simulation_runtime_state.last_caked_background_image_unscaled is not None
        ):
            preview_background_source = (
                simulation_runtime_state.last_caked_background_image_unscaled * scale
            )
    elif background_runtime_state.visible:
        preview_background_source = _current_background_display_for_mode()

    simulation_source = (
        scaled_q_space
        if show_q_space_image
        else (scaled_caked if show_caked_image else global_image_buffer)
    )
    if show_q_space_image:
        simulation_preview_source = simulation_source
        background_preview_source = preview_background_source
    else:
        simulation_preview_source, background_preview_source = (
            _geometry_fit_caked_roi_preview_display_sources(
                show_caked_image=bool(show_caked_image),
                simulation_image=simulation_source,
                background_image=preview_background_source,
            )
        )
        if not isinstance(simulation_preview_source, np.ndarray):
            simulation_preview_source = simulation_source

    analysis_primary_source_signature = None
    analysis_background_source_signature = None
    if show_q_space_image:
        analysis_primary_source_signature = _analysis_display_raster_source_signature(
            view_mode="q_space",
            role="primary",
            scale=scale,
            display_source=simulation_preview_source,
            raw_source=simulation_source,
        )
        analysis_background_source_signature = _analysis_display_raster_source_signature(
            view_mode="q_space",
            role="background",
            scale=scale,
            display_source=background_preview_source,
            raw_source=preview_background_source,
        )
    elif show_caked_image:
        analysis_primary_source_signature = _analysis_display_raster_source_signature(
            view_mode="caked",
            role="primary",
            scale=scale,
            display_source=simulation_preview_source,
            raw_source=simulation_source,
        )
        analysis_background_source_signature = _analysis_display_raster_source_signature(
            view_mode="caked",
            role="background",
            scale=scale,
            display_source=background_preview_source,
            raw_source=preview_background_source,
        )

    if not show_analysis_image:
        _store_primary_raster_source(image_display, simulation_preview_source)
        _apply_intensity_display_range(
            image_display,
            simulation_preview_source,
            display_controls_view_state.simulation_min_var.get(),
            display_controls_view_state.simulation_max_var.get(),
        )
    else:
        _store_primary_raster_source(
            image_display,
            simulation_preview_source,
            source_signature=analysis_primary_source_signature,
        )
    _sync_primary_raster_geometry(view_mode=active_view_mode)

    if show_analysis_image:
        caked_min = float(display_controls_view_state.simulation_min_var.get())
        caked_max = float(display_controls_view_state.simulation_max_var.get())
        caked_min, caked_max = gui_controllers.ensure_display_intensity_range(caked_min, caked_max)
        _apply_intensity_display_range(
            image_display,
            simulation_preview_source,
            caked_min,
            caked_max,
        )
        if not simulation_runtime_state.caked_limits_user_override:
            vmin_caked_var.set(caked_min)
            vmax_caked_var.set(caked_max)

    if not show_analysis_image:
        if isinstance(background_preview_source, np.ndarray):
            _store_primary_raster_source(
                background_display,
                background_preview_source,
            )
            _apply_intensity_display_range(
                background_display,
                background_preview_source,
                display_controls_view_state.background_min_var.get(),
                display_controls_view_state.background_max_var.get(),
            )
            background_display.set_visible(True)
        else:
            background_display.set_visible(False)
    elif isinstance(background_preview_source, np.ndarray):
        _store_primary_raster_source(
            background_display,
            background_preview_source,
            source_signature=analysis_background_source_signature,
        )
        background_display.set_visible(True)
        _apply_intensity_display_range(
            background_display,
            background_preview_source,
            display_controls_view_state.background_min_var.get(),
            display_controls_view_state.background_max_var.get(),
        )
    else:
        background_display.set_visible(False)

    _sync_simulation_overlay_artist_visibility()
    colorbar_main.update_normal(image_display)
    caked_colorbar.update_normal(image_display)

    if update_1d and (
        analysis_view_controls_view_state.show_1d_var.get()
        and _analysis_integration_outputs_visible()
        and line_1d_rad is not None
        and line_1d_az is not None
    ):
        if (
            simulation_runtime_state.last_1d_integration_data["radials_sim"] is not None
            and simulation_runtime_state.last_1d_integration_data["intensities_2theta_sim"]
            is not None
        ):
            line_1d_rad.set_data(
                simulation_runtime_state.last_1d_integration_data["radials_sim"],
                simulation_runtime_state.last_1d_integration_data["intensities_2theta_sim"] * scale,
            )
        if (
            simulation_runtime_state.last_1d_integration_data["azimuths_sim"] is not None
            and simulation_runtime_state.last_1d_integration_data["intensities_azimuth_sim"]
            is not None
        ):
            line_1d_az.set_data(
                simulation_runtime_state.last_1d_integration_data["azimuths_sim"],
                simulation_runtime_state.last_1d_integration_data["intensities_azimuth_sim"]
                * scale,
            )
        if ax_1d_radial is not None:
            ax_1d_radial.relim()
            ax_1d_radial.autoscale_view(scalex=False, scaley=True)
        if ax_1d_azim is not None:
            ax_1d_azim.relim()
            ax_1d_azim.autoscale_view(scalex=False, scaley=True)
        _clear_analysis_peak_fit_results(redraw=False, update_text=True)
        _render_analysis_peak_overlays(redraw=False)
        if canvas_1d is not None:
            canvas_1d.draw_idle()

    if update_canvas:
        _request_main_canvas_redraw(force_matplotlib=bool(force_canvas_redraw))
    if update_chi_square:
        _update_chi_square_display()


def _initialize_runtime_controls_block_21() -> None:
    global \
        vmin_caked_var, \
        vmax_caked_var, \
        analysis_1d_interaction_bindings, \
        analysis_surfaces_initialized

    _update_background_slider_defaults(
        background_runtime_state.current_background_display, reset_override=True
    )

    # Track caked intensity limits without exposing separate sliders in the UI.
    simulation_runtime_state.caked_limits_user_override = False

    vmin_caked_var = tk.DoubleVar(value=0.0)
    vmax_caked_var = tk.DoubleVar(value=2000.0)

    analysis_1d_interaction_bindings = None
    analysis_surfaces_initialized = False


def _reset_analysis_figure_view() -> None:
    if ax_1d_radial is None or ax_1d_azim is None:
        return
    if _selected_qr_rod_mode_requested():
        _set_1d_layout_for_selected_qr_rod()
    else:
        _set_1d_layout_for_standard_profiles()
    if not gui_analysis_figure_controls.reset_analysis_axes_view(
        ax_1d_radial,
        ax_1d_azim,
    ):
        return
    _render_analysis_peak_overlays(redraw=False)
    try:
        canvas_1d.draw_idle()
    except Exception:
        pass


def _mount_analysis_figure(parent) -> None:
    global fig_1d
    global ax_1d_radial, ax_1d_azim
    global line_1d_rad, line_1d_rad_bg, line_1d_az, line_1d_az_bg
    global canvas_1d
    global analysis_1d_interaction_bindings

    _ensure_analysis_figure()

    if canvas_1d is not None:
        try:
            canvas_1d.get_tk_widget().destroy()
        except Exception:
            pass
        canvas_1d = None

    figure_canvas_cls = _get_tk_figure_canvas_cls()
    canvas_1d = figure_canvas_cls(
        fig_1d,
        master=parent,
    )
    canvas_1d.get_tk_widget().pack(side=tk.TOP, fill=tk.BOTH, expand=True)
    analysis_1d_interaction_bindings = (
        gui_analysis_figure_controls.create_analysis_figure_interactions(
            canvas=canvas_1d,
            axes=(ax_1d_radial, ax_1d_azim),
            on_reset_view=_reset_analysis_figure_view,
        )
    )


def _initialize_runtime_controls_block_22() -> None:
    global \
        fig_1d, \
        ax_1d_radial, \
        ax_1d_azim, \
        canvas_1d, \
        line_1d_rad, \
        line_1d_rad_bg, \
        line_1d_az, \
        line_1d_az_bg

    fig_1d = None
    ax_1d_radial = None
    ax_1d_azim = None
    canvas_1d = None
    line_1d_rad = None
    line_1d_rad_bg = None
    line_1d_az = None
    line_1d_az_bg = None


def _ensure_analysis_figure() -> None:
    global fig_1d
    global ax_1d_radial, ax_1d_azim
    global line_1d_rad, line_1d_rad_bg, line_1d_az, line_1d_az_bg

    if fig_1d is not None and ax_1d_radial is not None and ax_1d_azim is not None:
        return

    fig_1d = Figure(figsize=(5, 8))
    _rebuild_standard_1d_axes()


def _refresh_analysis_figure_interactions_for_axes(axes: Sequence[object]) -> None:
    global analysis_1d_interaction_bindings
    if canvas_1d is None:
        return
    try:
        analysis_1d_interaction_bindings = (
            gui_analysis_figure_controls.create_analysis_figure_interactions(
                canvas=canvas_1d,
                axes=tuple(axes),
                on_reset_view=_reset_analysis_figure_view,
            )
        )
    except Exception:
        pass


def _rebuild_standard_1d_axes() -> None:
    global ax_1d_radial, ax_1d_azim
    global line_1d_rad, line_1d_rad_bg, line_1d_az, line_1d_az_bg

    if fig_1d is None:
        return
    try:
        fig_1d.clear()
    except Exception:
        pass
    ax_1d_radial = fig_1d.add_subplot(211)
    ax_1d_azim = fig_1d.add_subplot(212)

    (line_1d_rad,) = ax_1d_radial.plot([], [], "b-", label="Simulated (2θ)")
    (line_1d_rad_bg,) = ax_1d_radial.plot([], [], "r--", label="Background (2θ)")
    ax_1d_radial.legend()
    ax_1d_radial.set_xlabel("2θ (degrees)")
    ax_1d_radial.set_ylabel("Intensity")
    ax_1d_radial.set_title("Radial Integration (2θ)")

    (line_1d_az,) = ax_1d_azim.plot([], [], "b-", label="Simulated (φ)")
    (line_1d_az_bg,) = ax_1d_azim.plot([], [], "r--", label="Background (φ)")
    ax_1d_azim.legend()
    ax_1d_azim.set_xlabel("Azimuth (degrees)")
    ax_1d_azim.set_ylabel("Intensity")
    ax_1d_azim.set_title("Azimuthal Integration (φ)")
    setattr(simulation_runtime_state, "analysis_1d_layout_mode", "standard")
    setattr(simulation_runtime_state, "analysis_1d_plot_mode", "standard")
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_axes", [])
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_lines_by_key", {})
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_line_slots", [])
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_layout_count", 0)
    cache = getattr(simulation_runtime_state, "analysis_1d_layout_cache", None)
    if isinstance(cache, dict):
        cache.clear()
    _refresh_analysis_figure_interactions_for_axes((ax_1d_radial, ax_1d_azim))


def _analysis_1d_layout_cache() -> dict[str, object]:
    cache = getattr(simulation_runtime_state, "analysis_1d_layout_cache", None)
    if not isinstance(cache, dict):
        cache = {}
        setattr(simulation_runtime_state, "analysis_1d_layout_cache", cache)
    return cache


def _axis_position(axis: object) -> object | None:
    get_position = getattr(axis, "get_position", None)
    if not callable(get_position):
        return None
    try:
        position = get_position()
    except Exception:
        return None
    frozen = getattr(position, "frozen", None)
    if callable(frozen):
        try:
            return frozen()
        except Exception:
            return position
    return position


def _set_axis_position(axis: object, position: object | None) -> None:
    if position is None:
        return
    set_position = getattr(axis, "set_position", None)
    if not callable(set_position):
        return
    try:
        set_position(position)
    except Exception:
        pass


def _set_axis_visible(axis: object, visible: bool) -> None:
    set_visible = getattr(axis, "set_visible", None)
    if not callable(set_visible):
        return
    try:
        set_visible(bool(visible))
    except Exception:
        pass


def _remember_standard_1d_layout() -> dict[str, object]:
    cache = _analysis_1d_layout_cache()
    if ax_1d_radial is None or ax_1d_azim is None:
        return cache
    radial_axis_id = id(ax_1d_radial)
    azimuth_axis_id = id(ax_1d_azim)
    if (
        cache.get("radial_axis_id") == radial_axis_id
        and cache.get("azimuth_axis_id") == azimuth_axis_id
    ):
        return cache

    radial_position = _axis_position(ax_1d_radial)
    azimuth_position = _axis_position(ax_1d_azim)
    selected_position = None
    if radial_position is not None and azimuth_position is not None:
        try:
            selected_position = Bbox.from_extents(
                min(float(radial_position.x0), float(azimuth_position.x0)),
                min(float(radial_position.y0), float(azimuth_position.y0)),
                max(float(radial_position.x1), float(azimuth_position.x1)),
                max(float(radial_position.y1), float(azimuth_position.y1)),
            )
        except Exception:
            selected_position = None
    cache.clear()
    cache.update(
        {
            "radial_axis_id": radial_axis_id,
            "azimuth_axis_id": azimuth_axis_id,
            "radial_position": radial_position,
            "azimuth_position": azimuth_position,
            "selected_radial_position": selected_position,
        }
    )
    return cache


def _set_1d_layout_for_selected_qr_rod() -> None:
    if (
        getattr(simulation_runtime_state, "analysis_1d_layout_mode", "standard")
        == "selected_qr_rods"
        and fig_1d is not None
        and len(getattr(fig_1d, "axes", ()) or ()) > 2
    ):
        _rebuild_standard_1d_axes()
    if ax_1d_radial is None or ax_1d_azim is None:
        return
    cache = _remember_standard_1d_layout()
    _set_axis_visible(ax_1d_radial, True)
    _set_axis_visible(ax_1d_azim, False)
    _set_axis_position(ax_1d_radial, cache.get("selected_radial_position"))
    if line_1d_az is not None:
        line_1d_az.set_data([], [])
    if line_1d_az_bg is not None:
        line_1d_az_bg.set_data([], [])
    setattr(simulation_runtime_state, "analysis_1d_layout_mode", "selected_qr_rods")
    setattr(simulation_runtime_state, "analysis_1d_plot_mode", "selected_qr_rods")
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_axes", [ax_1d_radial])
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_layout_count", 1)


def _set_1d_layout_for_selected_qr_rods(count: int) -> list[object]:
    global ax_1d_radial, ax_1d_azim
    global line_1d_rad, line_1d_rad_bg, line_1d_az, line_1d_az_bg

    count = int(max(1, count))
    if fig_1d is None:
        _set_1d_layout_for_selected_qr_rod()
        return [ax_1d_radial] if ax_1d_radial is not None else []
    current_mode = getattr(
        simulation_runtime_state,
        "analysis_1d_plot_mode",
        getattr(simulation_runtime_state, "analysis_1d_layout_mode", "standard"),
    )
    existing_axes = list(
        getattr(simulation_runtime_state, "analysis_selected_qr_rod_axes", []) or []
    )
    existing_count = int(
        getattr(simulation_runtime_state, "analysis_selected_qr_rod_layout_count", 0) or 0
    )
    if (
        current_mode == "selected_qr_rods"
        and existing_count == count
        and len(existing_axes) == count
    ):
        return existing_axes
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_lines_by_key", {})
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_line_slots", [])
    if count <= 1:
        _set_1d_layout_for_selected_qr_rod()
        return [ax_1d_radial] if ax_1d_radial is not None else []
    try:
        fig_1d.clear()
        axes_array = fig_1d.subplots(count, 1, sharex=True, squeeze=False)
        axes = list(axes_array.ravel())
    except Exception:
        _set_1d_layout_for_selected_qr_rod()
        return [ax_1d_radial] if ax_1d_radial is not None else []
    ax_1d_radial = axes[0]
    ax_1d_azim = axes[-1]
    line_1d_rad = None
    line_1d_rad_bg = None
    line_1d_az = None
    line_1d_az_bg = None
    setattr(simulation_runtime_state, "analysis_1d_layout_mode", "selected_qr_rods")
    setattr(simulation_runtime_state, "analysis_1d_plot_mode", "selected_qr_rods")
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_axes", list(axes))
    setattr(simulation_runtime_state, "analysis_selected_qr_rod_layout_count", count)
    _refresh_analysis_figure_interactions_for_axes(axes)
    return axes


