def _selected_qr_rod_profile_component_source(shared: Mapping[str, object]) -> str:
    signal_sum = shared.get("signal_sum")
    normalization_sum = shared.get("normalization_sum")
    if signal_sum is not None and normalization_sum is not None:
        return "sum_normalization"
    if shared.get("acceptance") is not None:
        return "acceptance"
    return "pixel_count"


def _selected_qr_rod_profile_components_for_mask(
    shared: Mapping[str, object],
    mask: np.ndarray,
) -> dict[str, object] | None:
    try:
        image = np.asarray(shared.get("caked_image"), dtype=np.float64)
        qz_map = np.asarray(shared.get("qz_map"), dtype=np.float64)
        qz_edges = np.asarray(shared.get("qz_edges"), dtype=np.float64).reshape(-1)
        mask_array = np.asarray(mask, dtype=bool)
    except Exception:
        return None
    if (
        image.ndim != 2
        or qz_map.shape != image.shape
        or mask_array.shape != image.shape
        or qz_edges.ndim != 1
        or qz_edges.size < 2
    ):
        return None

    bin_count = int(qz_edges.size - 1)
    source = _selected_qr_rod_profile_component_source(shared)
    qz_flat = qz_map.reshape(-1)
    mask_flat = mask_array.reshape(-1)
    bin_index = np.searchsorted(qz_edges, qz_flat, side="right") - 1
    finite_qz = np.isfinite(qz_flat)
    last_edge = finite_qz & (qz_flat == qz_edges[-1])
    if np.any(last_edge):
        bin_index[last_edge] = bin_count - 1
    support = mask_flat & finite_qz & (bin_index >= 0) & (bin_index < bin_count)
    support_bins = bin_index[support].astype(np.intp, copy=False)
    if support_bins.size > 0:
        pixel_count = np.bincount(support_bins, minlength=bin_count)[:bin_count].astype(
            np.int64,
            copy=False,
        )
    else:
        pixel_count = np.zeros(bin_count, dtype=np.int64)

    image_flat = image.reshape(-1)
    acceptance_sum = np.zeros(bin_count, dtype=np.float64)
    weighted_sum = np.zeros(bin_count, dtype=np.float64)

    if source == "sum_normalization":
        try:
            signal_sum = np.asarray(shared.get("signal_sum"), dtype=np.float64)
            normalization_sum = np.asarray(shared.get("normalization_sum"), dtype=np.float64)
        except Exception:
            return None
        if signal_sum.shape != image.shape or normalization_sum.shape != image.shape:
            return None
        signal_flat = signal_sum.reshape(-1)
        normalization_flat = normalization_sum.reshape(-1)
        weighted = (
            support
            & np.isfinite(signal_flat)
            & np.isfinite(normalization_flat)
            & (normalization_flat > 0.0)
        )
        weighted_bins = bin_index[weighted].astype(np.intp, copy=False)
        weighted_sum = _selected_qr_rod_profile_component_bincount(
            weighted_bins,
            signal_flat[weighted],
            bin_count,
        )
        acceptance_sum = _selected_qr_rod_profile_component_bincount(
            weighted_bins,
            normalization_flat[weighted],
            bin_count,
        )
    elif source == "acceptance":
        try:
            acceptance = np.asarray(shared.get("acceptance"), dtype=np.float64)
        except Exception:
            return None
        if acceptance.shape != image.shape:
            return None
        acceptance_flat = acceptance.reshape(-1)
        weighted = support & np.isfinite(acceptance_flat) & (acceptance_flat > 0.0)
        weighted_bins = bin_index[weighted].astype(np.intp, copy=False)
        acceptance_sum = _selected_qr_rod_profile_component_bincount(
            weighted_bins,
            acceptance_flat[weighted],
            bin_count,
        )
        weighted_sum = _selected_qr_rod_profile_component_bincount(
            weighted_bins,
            _selected_qr_rod_profile_nan_to_zero(image_flat[weighted] * acceptance_flat[weighted]),
            bin_count,
        )
    else:
        weighted_sum = _selected_qr_rod_profile_component_bincount(
            support_bins,
            _selected_qr_rod_profile_nan_to_zero(image_flat[support]),
            bin_count,
        )
        acceptance_sum = pixel_count.astype(np.float64)

    return {
        "source": source,
        "qz_center": 0.5 * (qz_edges[:-1] + qz_edges[1:]),
        "pixel_count": pixel_count,
        "weighted_sum": weighted_sum,
        "acceptance_sum": acceptance_sum,
    }


def _selected_qr_rod_profile_component_entry(
    mask: np.ndarray,
    components: Mapping[str, object],
) -> dict[str, object]:
    return {
        "mask": np.asarray(mask, dtype=bool).copy(),
        "source": str(components.get("source", "pixel_count")),
        "qz_center": np.asarray(components["qz_center"], dtype=np.float64).copy(),
        "pixel_count": np.asarray(components["pixel_count"], dtype=np.int64).copy(),
        "weighted_sum": np.asarray(components["weighted_sum"], dtype=np.float64).copy(),
        "acceptance_sum": np.asarray(components["acceptance_sum"], dtype=np.float64).copy(),
    }


def _selected_qr_rod_profile_result_from_components(
    components: Mapping[str, object],
) -> dict[str, np.ndarray] | None:
    try:
        source = str(components.get("source", "pixel_count"))
        qz_center = np.asarray(components["qz_center"], dtype=np.float64)
        pixel_count = np.asarray(components["pixel_count"], dtype=np.int64)
        weighted_sum = np.asarray(components["weighted_sum"], dtype=np.float64)
        acceptance_components = np.asarray(components["acceptance_sum"], dtype=np.float64)
    except Exception:
        return None
    if (
        qz_center.ndim != 1
        or pixel_count.shape != qz_center.shape
        or weighted_sum.shape != qz_center.shape
        or acceptance_components.shape != qz_center.shape
    ):
        return None

    pixel_count = np.maximum(pixel_count, 0)
    empty = pixel_count <= 0
    intensity_sum = weighted_sum.copy()
    intensity_sum[empty] = np.nan
    acceptance_sum = acceptance_components.copy()
    if source == "pixel_count":
        acceptance_sum[empty] = 0.0
    else:
        acceptance_sum[empty] = np.nan
    intensity_mean = np.full(qz_center.shape, np.nan, dtype=np.float64)
    valid = (~empty) & np.isfinite(acceptance_components) & (acceptance_components > 0.0)
    intensity_mean[valid] = weighted_sum[valid] / acceptance_components[valid]
    return {
        "qz_center": qz_center.copy(),
        "pixel_count": pixel_count.copy(),
        "intensity_sum": intensity_sum,
        "intensity_mean": intensity_mean,
        "acceptance_sum": acceptance_sum,
    }


def _selected_qr_rod_profile_from_component_cache(
    shared: Mapping[str, object],
    mask: np.ndarray,
    component_signature: tuple[object, ...],
) -> dict[str, np.ndarray] | None:
    cache = _selected_qr_rod_bounded_cache("selected_qr_rod_profile_component_cache")
    entry = _selected_qr_rod_bounded_cache_get(cache, component_signature)
    if not isinstance(entry, Mapping):
        return None
    try:
        old_mask = np.asarray(entry["mask"], dtype=bool)
        if old_mask.shape != mask.shape:
            return None
        source = str(entry.get("source", "pixel_count"))
        components = {
            "source": source,
            "qz_center": np.asarray(entry["qz_center"], dtype=np.float64).copy(),
            "pixel_count": np.asarray(entry["pixel_count"], dtype=np.int64).copy(),
            "weighted_sum": np.asarray(entry["weighted_sum"], dtype=np.float64).copy(),
            "acceptance_sum": np.asarray(entry["acceptance_sum"], dtype=np.float64).copy(),
        }
    except Exception:
        return None

    current_source = _selected_qr_rod_profile_component_source(shared)
    if current_source != source:
        return None
    added_mask = mask & ~old_mask
    removed_mask = old_mask & ~mask
    if np.any(added_mask):
        added = _selected_qr_rod_profile_components_for_mask(shared, added_mask)
        if not isinstance(added, Mapping) or added.get("source") != source:
            return None
        components["pixel_count"] += np.asarray(added["pixel_count"], dtype=np.int64)
        components["weighted_sum"] += np.asarray(added["weighted_sum"], dtype=np.float64)
        components["acceptance_sum"] += np.asarray(added["acceptance_sum"], dtype=np.float64)
    if np.any(removed_mask):
        removed = _selected_qr_rod_profile_components_for_mask(shared, removed_mask)
        if not isinstance(removed, Mapping) or removed.get("source") != source:
            return None
        components["pixel_count"] -= np.asarray(removed["pixel_count"], dtype=np.int64)
        components["weighted_sum"] -= np.asarray(removed["weighted_sum"], dtype=np.float64)
        components["acceptance_sum"] -= np.asarray(removed["acceptance_sum"], dtype=np.float64)

    components["pixel_count"] = np.maximum(
        np.asarray(components["pixel_count"], dtype=np.int64),
        0,
    )
    acceptance_sum = np.asarray(components["acceptance_sum"], dtype=np.float64)
    near_zero = np.isfinite(acceptance_sum) & (np.abs(acceptance_sum) < 1.0e-12)
    acceptance_sum[near_zero] = 0.0
    components["acceptance_sum"] = np.maximum(acceptance_sum, 0.0)

    result = _selected_qr_rod_profile_result_from_components(components)
    if result is None:
        return None
    _selected_qr_rod_bounded_cache_put(
        cache,
        component_signature,
        _selected_qr_rod_profile_component_entry(mask, components),
        cap=SELECTED_QR_ROD_PROFILE_CACHE_CAP,
    )
    return result


def _selected_qr_rod_seed_profile_component_cache(
    shared: Mapping[str, object],
    mask: np.ndarray,
    component_signature: tuple[object, ...],
) -> None:
    components = _selected_qr_rod_profile_components_for_mask(shared, mask)
    if not isinstance(components, Mapping):
        return
    cache = _selected_qr_rod_bounded_cache("selected_qr_rod_profile_component_cache")
    _selected_qr_rod_bounded_cache_put(
        cache,
        component_signature,
        _selected_qr_rod_profile_component_entry(mask, components),
        cap=SELECTED_QR_ROD_PROFILE_CACHE_CAP,
    )


def _selected_qr_rod_caked_shared_profile_inputs(res2) -> dict[str, object] | None:
    payload = _caked_profile_payload_for_result(res2)
    if payload is None:
        return None
    try:
        image = np.asarray(payload.get("image"), dtype=np.float64)
        radial_axis = np.asarray(payload.get("radial"), dtype=np.float64).reshape(-1)
        azimuth_axis = np.asarray(payload.get("azimuth"), dtype=np.float64).reshape(-1)
    except Exception:
        return None
    if (
        image.ndim != 2
        or image.shape != (int(azimuth_axis.size), int(radial_axis.size))
        or image.size <= 0
    ):
        return None

    roi_values = _current_analysis_roi_values()
    try:
        delta_qr = _selected_qr_rod_delta_qr_half_width_from_roi(roi_values)
        qz_min = float(roi_values.get("qz_min", 0.0))
        qz_max = float(roi_values.get("qz_max", 0.0))
    except Exception:
        return None
    qz_lo, qz_hi = sorted((qz_min, qz_max))
    if not (np.isfinite(qz_lo) and np.isfinite(qz_hi)) or qz_hi <= qz_lo:
        return None
    phi_windows = _selected_qr_rod_phi_windows_from_roi(roi_values)
    if phi_windows is None:
        return None

    qz_map = _caked_qz_map_for_profile_payload(payload)
    if qz_map is None or qz_map.shape != image.shape:
        return None
    qz_edges = np.linspace(qz_lo, qz_hi, int(image.shape[1]) + 1, dtype=np.float64)

    signal_sum = payload.get("sum_signal")
    normalization_sum = payload.get("sum_normalization")
    if (signal_sum is None) != (normalization_sum is None):
        signal_sum = None
        normalization_sum = None
    if signal_sum is not None and normalization_sum is not None:
        try:
            signal_sum = np.asarray(signal_sum, dtype=np.float64)
            normalization_sum = np.asarray(normalization_sum, dtype=np.float64)
        except Exception:
            signal_sum = None
            normalization_sum = None
        if (
            signal_sum is not None
            and normalization_sum is not None
            and (signal_sum.shape != image.shape or normalization_sum.shape != image.shape)
        ):
            signal_sum = None
            normalization_sum = None

    acceptance = payload.get("count")
    if acceptance is not None:
        try:
            acceptance = np.asarray(acceptance, dtype=np.float64)
        except Exception:
            acceptance = None
        if acceptance is not None and acceptance.shape != image.shape:
            acceptance = None

    try:
        projection_context = _selected_qr_rod_caked_projection_context_for_payload(payload)
    except Exception:
        projection_context = None
    resolved_projection = None
    detector_shape = None
    if projection_context is not None:
        try:
            resolved_projection = gui_qr_cylinder_overlay._resolve_caked_projection_context(
                projection_context
            )
        except Exception:
            resolved_projection = None
    if isinstance(resolved_projection, Mapping):
        try:
            detector_shape = tuple(int(v) for v in resolved_projection["detector_shape"][:2])
        except Exception:
            detector_shape = None
    if detector_shape is None:
        try:
            detector_shape = tuple(int(v) for v in payload.get("detector_shape")[:2])
        except Exception:
            detector_shape = None

    include_shape = bool(roi_values.get("include_selected_qr_rod_shape", False))
    shape_mask_index = None
    if include_shape and detector_shape is not None:
        try:
            shape_mask_index = _current_selected_qr_rod_shape_mask_index(detector_shape)
        except Exception:
            shape_mask_index = None

    try:
        selected_entries = _current_selected_qr_rod_entries(_analysis_selected_qr_rod_entries())
    except Exception:
        selected_entries = []
    try:
        selected_keys = _current_selected_qr_rod_keys_from_roi(roi_values)
    except Exception:
        selected_keys = []
    if not selected_keys:
        selected_keys = [
            gui_controllers.encode_bragg_qr_group_key(entry.get("key"))
            for entry in selected_entries
        ]
    caked_projection_signature = _selected_qr_rod_caked_projection_signature(
        payload,
        radial_axis=radial_axis,
        azimuth_axis=azimuth_axis,
        qz_map=qz_map,
        detector_shape=detector_shape,
    )

    return {
        "payload": payload,
        "result_identity": ("res2", id(res2)),
        "caked_image": image,
        "radial_axis": radial_axis,
        "azimuth_axis": azimuth_axis,
        "qz_map": np.asarray(qz_map, dtype=np.float64),
        "qz_edges": qz_edges,
        "phi_windows": phi_windows,
        "delta_qr": delta_qr,
        "qz_min": qz_lo,
        "qz_max": qz_hi,
        "selected_qr_rod_lattice_c": _current_selected_qr_rod_lattice_c(),
        "rod_profile_intensity_mode": _current_rod_profile_intensity_mode(),
        "caked_intensity_mode": _current_caked_intensity_mode(),
        "signal_sum": signal_sum,
        "normalization_sum": normalization_sum,
        "acceptance": acceptance,
        "projection_context": projection_context,
        "resolved_projection_context": resolved_projection,
        "caked_projection_signature": caked_projection_signature,
        "detector_shape": detector_shape,
        "selected_qr_rod_keys": list(selected_keys),
        "selected_entries": [dict(entry) for entry in selected_entries],
        "stored_hit_table_signature": _selected_qr_rod_shape_source_signature(),
        "include_selected_qr_rod_shape": bool(include_shape),
        "shape_mask_index": shape_mask_index,
        "mask_payloads_by_key": {},
    }


def _selected_qr_rod_caked_profile_from_shared_inputs(
    shared: Mapping[str, object] | None,
    selected_entry: Mapping[str, object],
    selected_key: object,
) -> dict[str, np.ndarray] | None:
    if not isinstance(shared, Mapping):
        return None
    encoded_key = str(selected_key or "")
    if not encoded_key and isinstance(selected_entry, Mapping):
        encoded_key = gui_controllers.encode_bragg_qr_group_key(selected_entry.get("key"))
    mask_payload = None
    mask_payloads_by_key = shared.get("mask_payloads_by_key")
    if isinstance(mask_payloads_by_key, Mapping):
        mask_payload = mask_payloads_by_key.get(encoded_key)
    if mask_payload is None and isinstance(selected_entry, Mapping) and "mask" in selected_entry:
        mask_payload = selected_entry
    if not isinstance(mask_payload, Mapping):
        return None
    mask_signature = mask_payload.get("signature")
    if isinstance(mask_signature, tuple) and mask_signature and "union" in str(mask_signature[0]):
        return None
    try:
        image = np.asarray(shared.get("caked_image"), dtype=np.float64)
        qz_map = np.asarray(shared.get("qz_map"), dtype=np.float64)
        qz_edges = np.asarray(shared.get("qz_edges"), dtype=np.float64)
        mask = np.asarray(mask_payload.get("mask"), dtype=bool)
    except Exception:
        return None
    if image.ndim != 2 or qz_map.shape != image.shape or mask.shape != image.shape:
        return None
    cache_signature = _selected_qr_rod_profile_cache_signature(
        shared,
        mask_payload,
        encoded_key,
    )
    cache = _selected_qr_rod_bounded_cache("selected_qr_rod_profile_cache")
    if cache_signature is not None:
        cached_profile = _selected_qr_rod_bounded_cache_get(cache, cache_signature)
        if isinstance(cached_profile, Mapping):
            return _selected_qr_rod_profile_cache_copy(cached_profile)
    component_signature = _selected_qr_rod_profile_component_cache_signature(
        shared,
        encoded_key,
        tuple(int(v) for v in mask.shape),
    )
    component_profile = _selected_qr_rod_profile_from_component_cache(
        shared,
        mask,
        component_signature,
    )
    if component_profile is not None:
        component_profile = _selected_qr_rod_profile_with_l_center(
            component_profile,
            shared.get("selected_qr_rod_lattice_c"),
        )
        if cache_signature is not None:
            _selected_qr_rod_bounded_cache_put(
                cache,
                cache_signature,
                _selected_qr_rod_profile_cache_copy(component_profile),
                cap=SELECTED_QR_ROD_PROFILE_CACHE_CAP,
            )
        return _selected_qr_rod_profile_cache_copy(component_profile)
    try:
        profile = binned_caked_mask_profile(
            image=image,
            coord_map=qz_map,
            coord_edges=qz_edges,
            mask=mask,
            signal_sum=shared.get("signal_sum"),
            normalization_sum=shared.get("normalization_sum"),
            acceptance=shared.get("acceptance"),
            coord_name="qz",
        )
    except Exception:
        return None
    curve_key = (
        "background_weighted_sum"
        if _normalize_rod_profile_intensity_mode(shared.get("rod_profile_intensity_mode"))
        == "raw_sum"
        else "background_density"
    )
    curve = _finite_profile_curve(profile.get(curve_key))
    if curve is None and curve_key == "background_weighted_sum":
        curve = _finite_profile_curve(profile.get("background_sum"))
    if curve is None:
        return None
    result = {
        "qz_center": np.asarray(profile["qz_center"], dtype=np.float64),
        "pixel_count": np.asarray(profile["pixel_count"], dtype=np.int64),
        "intensity_sum": np.asarray(profile["background_weighted_sum"], dtype=np.float64),
        "intensity_mean": np.asarray(profile["background_density"], dtype=np.float64),
        "acceptance_sum": np.asarray(profile["acceptance_sum"], dtype=np.float64),
    }
    result = _selected_qr_rod_profile_with_l_center(
        result,
        shared.get("selected_qr_rod_lattice_c"),
    )
    if cache_signature is not None:
        _selected_qr_rod_bounded_cache_put(
            cache,
            cache_signature,
            _selected_qr_rod_profile_cache_copy(result),
            cap=SELECTED_QR_ROD_PROFILE_CACHE_CAP,
        )
    _selected_qr_rod_seed_profile_component_cache(
        shared,
        mask,
        component_signature,
    )
    return _selected_qr_rod_profile_cache_copy(result)


def _detector_angular_maps_for_shape(ai, detector_shape):
    if ai is None:
        return None, None

    if detector_shape is None or len(detector_shape) < 2:
        return None, None
    if detector_shape[0] <= 0 or detector_shape[1] <= 0:
        return None, None

    detector_shape = tuple(int(v) for v in detector_shape[:2])
    use_cache = getattr(global_image_buffer, "shape", None) == detector_shape

    if use_cache and simulation_runtime_state.ai_cache.get("detector_shape") == detector_shape:
        two_theta = simulation_runtime_state.ai_cache.get("detector_two_theta")
        phi_vals = simulation_runtime_state.ai_cache.get("detector_phi")
    else:
        two_theta, phi_vals = ai.detector_angular_maps_deg(detector_shape)

        if use_cache:
            simulation_runtime_state.ai_cache["detector_shape"] = detector_shape
            simulation_runtime_state.ai_cache["detector_two_theta"] = two_theta
            simulation_runtime_state.ai_cache["detector_phi"] = phi_vals

    if two_theta is None or phi_vals is None:
        return None, None

    return np.asarray(two_theta, dtype=float), np.asarray(phi_vals, dtype=float)


def _get_detector_angular_maps(ai):
    return _detector_angular_maps_for_shape(
        ai,
        getattr(global_image_buffer, "shape", None),
    )


def _prepare_caked_intersection_cache(
    intersection_cache,
    *,
    transform_bundle: CakeTransformBundle | None,
    native_detector_coords_to_bundle_detector_coords: Callable[
        [float, float], tuple[float | None, float | None]
    ]
    | None = None,
):
    source_tables = _copy_intersection_cache_tables(intersection_cache)
    if not source_tables:
        return source_tables

    transformed = []
    for arr in source_tables:
        if arr.shape[1] == CURRENT_CAKED_CACHE_WIDTH:
            out = np.array(arr, dtype=float, copy=True)
        else:
            out = np.full((arr.shape[0], CURRENT_CAKED_CACHE_WIDTH), np.nan, dtype=float)
            if arr.shape[0] > 0 and arr.shape[1] > 0:
                out[:, : arr.shape[1]] = arr

        if out.shape[0] > 0:
            out[:, CURRENT_CAKED_COL_TWO_THETA] = np.nan
            out[:, CURRENT_CAKED_COL_PHI] = np.nan

        if (
            arr.shape[0] == 0
            or arr.shape[1] < (CACHE_COL_DETECTOR_ROW + 1)
            or not isinstance(transform_bundle, CakeTransformBundle)
        ):
            transformed.append(out)
            continue

        cols = np.asarray(arr[:, CACHE_COL_DETECTOR_COL], dtype=float)
        rows = np.asarray(arr[:, CACHE_COL_DETECTOR_ROW], dtype=float)
        valid = np.isfinite(cols) & np.isfinite(rows)
        valid_indices = np.flatnonzero(valid)
        if valid_indices.size == 0:
            transformed.append(out)
            continue

        for row_index in valid_indices:
            bundle_col = float(cols[int(row_index)])
            bundle_row = float(rows[int(row_index)])
            if callable(native_detector_coords_to_bundle_detector_coords):
                try:
                    bundle_point = native_detector_coords_to_bundle_detector_coords(
                        bundle_col,
                        bundle_row,
                    )
                except Exception:
                    continue
                if not isinstance(bundle_point, tuple) or len(bundle_point) < 2:
                    continue
                try:
                    bundle_col = float(bundle_point[0])
                    bundle_row = float(bundle_point[1])
                except Exception:
                    continue
                if not (np.isfinite(bundle_col) and np.isfinite(bundle_row)):
                    continue

            try:
                two_theta_value, phi_value = detector_pixel_to_caked_bin(
                    transform_bundle,
                    bundle_col,
                    bundle_row,
                )
            except Exception:
                continue
            try:
                two_theta_float = float(two_theta_value)
                phi_float = float(phi_value)
            except Exception:
                continue
            if not (np.isfinite(two_theta_float) and np.isfinite(phi_float)):
                continue
            out[int(row_index), CURRENT_CAKED_COL_TWO_THETA] = two_theta_float
            out[int(row_index), CURRENT_CAKED_COL_PHI] = phi_float
        transformed.append(out)

    return transformed


