def _apply_primary_figure_display_from_cached_results(
    previous_primary_view_mode: str | None,
    preserved_primary_limits: object,
) -> str:
    analysis_space_display_mode = _resolved_primary_analysis_display_mode()
    analysis_space_display_available = analysis_space_display_mode in {"caked", "q_space"}
    target_primary_view_mode = (
        analysis_space_display_mode if analysis_space_display_available else "detector"
    )

    if analysis_space_display_available:
        current_scale = _get_scale_factor_value(default=1.0)
        primary_source_signature = None
        secondary_source_signature = None
        if analysis_space_display_mode == "q_space":
            analysis_image = np.asarray(
                simulation_runtime_state.last_q_space_image_unscaled,
                dtype=float,
            )
            analysis_background_source = None
            if (
                background_runtime_state.visible
                and simulation_runtime_state.last_q_space_background_image_unscaled is not None
            ):
                analysis_background_source = (
                    np.asarray(
                        simulation_runtime_state.last_q_space_background_image_unscaled,
                        dtype=float,
                    )
                    * current_scale
                )
            display_primary_source = analysis_image * current_scale
            display_secondary_source = analysis_background_source
            primary_source_signature = _analysis_display_raster_source_signature(
                view_mode="q_space",
                role="primary",
                scale=current_scale,
                display_source=display_primary_source,
                raw_source=display_primary_source,
            )
            secondary_source_signature = _analysis_display_raster_source_signature(
                view_mode="q_space",
                role="background",
                scale=current_scale,
                display_source=display_secondary_source,
                raw_source=analysis_background_source,
            )
            axis_extent = (
                list(simulation_runtime_state.last_q_space_extent)
                if simulation_runtime_state.last_q_space_extent is not None
                else [0.0, 1.0, -1.0, 1.0]
            )
            x_label = "Qr (A^-1)"
            y_label = "Qz (A^-1)"
        else:
            analysis_image = np.asarray(
                simulation_runtime_state.last_caked_image_unscaled,
                dtype=float,
            )
            analysis_background_source = None
            if (
                background_runtime_state.visible
                and simulation_runtime_state.last_caked_background_image_unscaled is not None
            ):
                analysis_background_source = (
                    np.asarray(
                        simulation_runtime_state.last_caked_background_image_unscaled,
                        dtype=float,
                    )
                    * current_scale
                )
            scaled_analysis_for_limits = analysis_image * current_scale
            display_primary_source, display_secondary_source = (
                _geometry_fit_caked_roi_preview_display_sources(
                    show_caked_image=True,
                    simulation_image=scaled_analysis_for_limits,
                    background_image=analysis_background_source,
                )
            )
            if not isinstance(display_primary_source, np.ndarray):
                display_primary_source = scaled_analysis_for_limits
            primary_source_signature = _analysis_display_raster_source_signature(
                view_mode="caked",
                role="primary",
                scale=current_scale,
                display_source=display_primary_source,
                raw_source=scaled_analysis_for_limits,
            )
            secondary_source_signature = _analysis_display_raster_source_signature(
                view_mode="caked",
                role="background",
                scale=current_scale,
                display_source=display_secondary_source,
                raw_source=analysis_background_source,
            )
            axis_extent = (
                list(simulation_runtime_state.last_caked_extent)
                if simulation_runtime_state.last_caked_extent is not None
                else [0.0, 90.0, -180.0, 180.0]
            )
            x_label = "2θ (degrees)"
            y_label = "φ (degrees)"

        _store_primary_raster_source(
            image_display,
            display_primary_source,
            source_signature=primary_source_signature,
        )
        auto_vmin, auto_vmax = _auto_caked_limits(display_primary_source)

        if not display_controls_state.simulation_limits_user_override:
            _update_simulation_sliders_from_image(display_primary_source, reset_override=True)

        if not simulation_runtime_state.caked_limits_user_override:
            vmin_caked_var.set(auto_vmin)
            vmax_caked_var.set(auto_vmax)

        vmin_val = float(display_controls_view_state.simulation_min_var.get())
        vmax_val = float(display_controls_view_state.simulation_max_var.get())
        global_sim_max = vmax_val

        if not math.isfinite(vmin_val):
            vmin_val = auto_vmin
        if not math.isfinite(vmax_val):
            vmax_val = auto_vmax
        vmin_val, vmax_val = gui_controllers.ensure_display_intensity_range(vmin_val, vmax_val)
        if not math.isfinite(global_sim_max) or global_sim_max <= vmin_val:
            global_sim_max = auto_vmax

        display_vmax = min(vmax_val, global_sim_max)
        if not math.isfinite(display_vmax):
            display_vmax = auto_vmax
        if display_vmax <= vmin_val:
            fallback_vmax = max(global_sim_max, auto_vmax, vmax_val)
            if math.isfinite(fallback_vmax) and fallback_vmax > vmin_val:
                display_vmax = fallback_vmax
            else:
                display_vmax = vmin_val + max(abs(vmin_val) * 1e-3, 1e-3)
        _apply_intensity_display_range(
            image_display,
            display_primary_source,
            vmin_val,
            display_vmax,
        )

        background_analysis_available = False
        if isinstance(display_secondary_source, np.ndarray):
            _store_primary_raster_source(
                background_display,
                display_secondary_source,
                source_signature=secondary_source_signature,
            )
            bg_display_vmax = vmax_val
            if not math.isfinite(bg_display_vmax):
                bg_display_vmax = auto_vmax
            if not math.isfinite(bg_display_vmax):
                bg_display_vmax = display_vmax
            if bg_display_vmax <= vmin_val:
                fallback_vmax = None
                for candidate in (auto_vmax, display_vmax, vmax_val):
                    if math.isfinite(candidate) and candidate > vmin_val:
                        fallback_vmax = candidate
                        break
                if fallback_vmax is None:
                    fallback_vmax = vmin_val + max(abs(vmin_val) * 1e-3, 1e-3)
                bg_display_vmax = fallback_vmax
            background_display.set_clim(vmin_val, bg_display_vmax)
            background_display.set_visible(True)
            background_analysis_available = True
        else:
            background_display.set_visible(False)

        axis_min_x, axis_max_x, axis_min_y, axis_max_y = axis_extent
        if not background_analysis_available:
            background_display.set_visible(False)
        if not (
            math.isfinite(axis_min_x) and math.isfinite(axis_max_x) and axis_max_x > axis_min_x
        ):
            axis_min_x, axis_max_x = (
                (0.0, 1.0) if analysis_space_display_mode == "q_space" else (0.0, 90.0)
            )
        if not (
            math.isfinite(axis_min_y) and math.isfinite(axis_max_y) and axis_max_y > axis_min_y
        ):
            axis_min_y, axis_max_y = (
                (-1.0, 1.0) if analysis_space_display_mode == "q_space" else (-180.0, 180.0)
            )

        gui_canvas_interactions.restore_axis_view(
            ax,
            preserved_limits=preserved_primary_limits,
            default_xlim=(axis_min_x, axis_max_x),
            default_ylim=(axis_min_y, axis_max_y),
            preserve=(previous_primary_view_mode == analysis_space_display_mode),
        )
        ax.set_aspect("auto")
        gui_main_figure_chrome.set_main_figure_axes_axis_visibility(ax, visible=True)
        ax.set_xlabel(x_label)
        ax.set_ylabel(y_label)
        ax.set_title("")
        _sync_primary_raster_geometry(view_mode=analysis_space_display_mode)
    else:
        detector_background_source = (
            _current_background_display_for_mode() if background_runtime_state.visible else None
        )
        detector_simulation_source = _refresh_global_detector_buffer_from_unscaled()
        if not isinstance(detector_simulation_source, np.ndarray):
            detector_simulation_source = global_image_buffer
        display_primary_source, display_secondary_source = (
            _geometry_fit_caked_roi_preview_display_sources(
                show_caked_image=False,
                simulation_image=global_image_buffer,
                background_image=detector_background_source,
            )
        )
        if not isinstance(display_primary_source, np.ndarray):
            display_primary_source = detector_simulation_source
        _store_primary_raster_source(image_display, display_primary_source)
        gui_canvas_interactions.restore_axis_view(
            ax,
            preserved_limits=preserved_primary_limits,
            default_xlim=(0.0, float(image_size)),
            default_ylim=(float(image_size), 0.0),
            preserve=(previous_primary_view_mode == "detector"),
        )
        ax.set_aspect("auto")
        gui_main_figure_chrome.set_main_figure_axes_axis_visibility(ax, visible=False)
        ax.set_title("")
        if isinstance(display_secondary_source, np.ndarray):
            _store_primary_raster_source(
                background_display,
                display_secondary_source,
            )
            background_display.set_clim(
                display_controls_view_state.background_min_var.get(),
                display_controls_view_state.background_max_var.get(),
            )
            background_display.set_visible(True)
        else:
            background_display.set_visible(False)
        _sync_primary_raster_geometry(view_mode="detector")

    _sync_simulation_overlay_artist_visibility()
    gui_main_figure_chrome.apply_main_figure_axes_chrome(
        ax,
        axes_visible=bool(analysis_space_display_available),
    )
    return target_primary_view_mode


def do_update():
    if simulation_runtime_state.update_running:
        # another update is in progress; try again shortly
        simulation_runtime_state.update_pending = root.after(
            _current_update_debounce_ms(),
            do_update,
        )
        return

    simulation_runtime_state.update_pending = None
    simulation_runtime_state.update_running = True
    detector_artist_signature_before = _current_detector_artist_source_signature()
    if simulation_runtime_state.worker_active_job is None:
        simulation_runtime_state.update_phase = "applying"
    _refresh_run_status_bar()
    _clear_initial_simulation_loading_overlay(redraw=False)
    update_start_time = perf_counter()
    image_generation_elapsed_ms = 0.0
    image_generation_cached = True

    gamma_updated = float(gamma_var.get())
    Gamma_updated = float(Gamma_var.get())
    chi_updated = float(chi_var.get())
    psi_z_updated = float(psi_z_var.get())
    zs_updated = float(zs_var.get())
    zb_updated = float(zb_var.get())
    sample_width_updated = float(sample_width_var.get())
    sample_length_updated = float(sample_length_var.get())
    sample_depth_updated = float(sample_depth_var.get())
    cor_angle_updated = float(cor_angle_var.get())
    a_updated = float(a_var.get())
    c_updated = float(c_var.get())
    theta_init_up = float(_current_effective_theta_initial(strict_count=False))
    debye_x_updated = float(debye_x_var.get())
    debye_y_updated = float(debye_y_var.get())
    ordered_structure_scale = float(_current_ordered_structure_scale())
    corto_det_up = float(corto_detector_var.get())
    center_x_up = float(center_x_var.get())
    center_y_up = float(center_y_var.get())

    new_two_theta_max = detector_two_theta_max(
        image_size,
        [center_x_up, center_y_up],
        corto_det_up,
        pixel_size=pixel_size_m,
    )

    global two_theta_range
    phase_delta_expression_current = _current_phase_delta_expression()
    phi_l_divisor_current = _current_phi_l_divisor()
    iodine_z_current = _current_iodine_z()
    atom_site_signature = _atom_site_fractional_signature(_current_atom_site_fractional_values())
    parratt_curve_source = _current_parratt_low_q_stitch_curve_source()
    parratt_optics_signature = _current_parratt_optics_signature()
    need_rebuild = False
    if not math.isclose(new_two_theta_max, two_theta_range[1], rel_tol=1e-6, abs_tol=1e-6):
        two_theta_range = (0.0, new_two_theta_max)
        need_rebuild = True
    if not math.isclose(
        c_updated, structure_model_state.last_c_for_ht, rel_tol=1e-9, abs_tol=1e-9
    ):
        need_rebuild = True
    if not math.isclose(
        a_updated, structure_model_state.last_a_for_ht, rel_tol=1e-9, abs_tol=1e-9
    ):
        need_rebuild = True
    if not math.isclose(
        iodine_z_current,
        structure_model_state.last_iodine_z_for_ht,
        rel_tol=1e-9,
        abs_tol=1e-9,
    ):
        need_rebuild = True
    if not math.isclose(
        float(phi_l_divisor_current),
        float(structure_model_state.last_phi_l_divisor),
        rel_tol=1e-9,
        abs_tol=1e-9,
    ):
        need_rebuild = True
    if phase_delta_expression_current != structure_model_state.last_phase_delta_expression:
        need_rebuild = True
    if atom_site_signature != structure_model_state.last_atom_site_fractional_signature:
        need_rebuild = True
    if bool(_current_parratt_low_q_stitch_enabled()) != bool(
        structure_model_state.last_parratt_low_q_stitch
    ):
        need_rebuild = True
    if (
        bool(_current_parratt_low_q_stitch_enabled())
        and str(parratt_curve_source)
        != str(structure_model_state.last_parratt_low_q_stitch_curve_source)
    ):
        need_rebuild = True
    if tuple(parratt_optics_signature) != tuple(
        structure_model_state.last_parratt_optics_signature
    ):
        need_rebuild = True

    if need_rebuild:
        current_occ = [occ_var.get() for occ_var in _occupancy_control_vars()]
        current_p = [p0_var.get(), p1_var.get(), p2_var.get()]
        weight_values = [w0_var.get(), w1_var.get(), w2_var.get()]
        normalized_weights = gui_controllers.normalize_stacking_weight_values(weight_values)
        _rebuild_diffraction_inputs(
            current_occ,
            current_p,
            normalized_weights,
            a_updated,
            c_updated,
            force=True,
            trigger_update=False,
        )

    _sync_center_marker(redraw=False)

    mosaic_params = build_mosaic_params()
    accumulate_image_requested = True
    qr_cylinder_replace_requested = _qr_cylinder_replace_simulation_enabled()
    collect_hit_tables_requested = bool(_should_collect_hit_tables_for_update())
    primary_source_signature = (
        (
            "qr",
            id(simulation_runtime_state.sim_primary_qr),
            len(simulation_runtime_state.sim_primary_qr),
        )
        if isinstance(simulation_runtime_state.sim_primary_qr, dict)
        and len(simulation_runtime_state.sim_primary_qr) > 0
        else (
            "miller",
            id(simulation_runtime_state.sim_miller1),
            tuple(np.asarray(simulation_runtime_state.sim_miller1).shape),
        )
    )
    secondary_source_signature = (
        "miller",
        id(simulation_runtime_state.sim_miller2),
        tuple(np.asarray(simulation_runtime_state.sim_miller2).shape),
    )
    secondary_a = (
        float(structure_model_state.av2)
        if structure_model_state.av2 is not None
        else float(a_updated)
    )
    secondary_c = (
        float(structure_model_state.cv2)
        if structure_model_state.cv2 is not None
        else float(c_updated)
    )

    primary_data = (
        gui_controllers.copy_bragg_qr_dict(simulation_runtime_state.sim_primary_qr)
        if isinstance(simulation_runtime_state.sim_primary_qr, dict)
        and len(simulation_runtime_state.sim_primary_qr) > 0
        else np.asarray(simulation_runtime_state.sim_miller1, dtype=np.float64).copy()
    )
    primary_intensities = np.asarray(
        simulation_runtime_state.sim_intens1,
        dtype=np.float64,
    ).copy()
    if isinstance(primary_data, dict):
        primary_data = _scaled_bragg_qr_dict(primary_data, ordered_structure_scale)
    else:
        primary_intensities *= float(ordered_structure_scale)
    secondary_data = np.asarray(
        simulation_runtime_state.sim_miller2,
        dtype=np.float64,
    ).copy()
    secondary_intensities = np.asarray(
        simulation_runtime_state.sim_intens2,
        dtype=np.float64,
    ).copy()
    primary_available = (
        len(primary_data) > 0
        if isinstance(primary_data, dict)
        else (
            np.asarray(primary_data).ndim == 2
            and np.asarray(primary_data).shape[0] > 0
            and primary_intensities.size > 0
        )
    )
    secondary_available = (
        secondary_data.ndim == 2 and secondary_data.shape[0] > 0 and secondary_intensities.size > 0
    )
    try:
        primary_weight_value = float(weight1_var.get())
    except Exception:
        primary_weight_value = 1.0
    try:
        secondary_weight_value = float(weight2_var.get())
    except Exception:
        secondary_weight_value = 0.0
    primary_weight_active = abs(float(primary_weight_value)) > 1.0e-12
    secondary_weight_active = abs(float(secondary_weight_value)) > 1.0e-12
    primary_run_available = bool(primary_available and primary_weight_active)
    secondary_run_available = bool(secondary_available and secondary_weight_active)
    primary_requested_source_mode = str(
        getattr(
            simulation_runtime_state,
            "primary_requested_source_mode",
            "",
        )
        or ("qr" if isinstance(primary_data, dict) and len(primary_data) > 0 else "miller")
    )
    primary_requested_contribution_keys = tuple(
        getattr(
            simulation_runtime_state,
            "primary_requested_contribution_keys",
            (),
        )
        or ()
    )
    primary_requested_filter_signature = getattr(
        simulation_runtime_state,
        "primary_requested_filter_signature",
        None,
    )
    if primary_requested_filter_signature is None:
        primary_requested_filter_signature = (
            primary_requested_source_mode,
            primary_source_signature,
        )
    disordered_phase_qr_reference_signature = _geometry_disordered_phase_source_signature()
    disordered_phase_hit_tables_required = bool(
        len(disordered_phase_qr_reference_signature) >= 2
        and bool(disordered_phase_qr_reference_signature[1])
    )
    current_primary_source_mode = _current_primary_source_mode()
    if current_primary_source_mode == "rich_phase":
        rich_phase_component_signature = _rich_phase_components_signature(
            _current_rich_phase_components()
        )
    elif current_primary_source_mode == "polytype_2x2":
        rich_phase_component_signature = _polytype_components_signature()
    else:
        rich_phase_component_signature = ()

    def _simulation_signature_base(*, include_mosaic_shape: bool = True):
        return _geometry_source_rows_signature_from_params(
            {
                "gamma": gamma_updated,
                "Gamma": Gamma_updated,
                "chi": chi_updated,
                "psi_z": psi_z_updated,
                "zs": zs_updated,
                "zb": zb_updated,
                "sample_width": sample_width_updated,
                "sample_length": sample_length_updated,
                "sample_depth": sample_depth_updated,
                "debye_x": debye_x_updated,
                "debye_y": debye_y_updated,
                "a": a_updated,
                "c": c_updated,
                "theta_initial": theta_init_up,
                "cor": cor_angle_updated,
                "center_x": center_x_up,
                "center_y": center_y_up,
                "distance_m": corto_det_up,
                "sigma_mosaic_deg": mosaic_params.get("sigma_mosaic_deg", 0.0),
                "gamma_mosaic_deg": mosaic_params.get("gamma_mosaic_deg", 0.0),
                "eta": mosaic_params.get("eta", 0.0),
            },
            mosaic_params=mosaic_params,
            include_mosaic_shape=bool(include_mosaic_shape),
            sf_prune_bias=current_sf_prune_bias(),
            sf_prune_stats=simulation_runtime_state.sf_prune_stats,
            ordered_structure_scale=ordered_structure_scale,
            qr_cylinder_replace_requested=qr_cylinder_replace_requested,
            primary_source_signature=primary_source_signature,
            secondary_source_signature=secondary_source_signature,
            disordered_phase_qr_reference_signature=disordered_phase_qr_reference_signature,
            rich_phase_component_signature=rich_phase_component_signature,
            secondary_a=secondary_a,
            secondary_c=secondary_c,
        )

    def _primary_contribution_cache_signature_base():
        return _geometry_source_rows_signature_from_params(
            {
                "gamma": gamma_updated,
                "Gamma": Gamma_updated,
                "chi": chi_updated,
                "psi_z": psi_z_updated,
                "zs": zs_updated,
                "zb": zb_updated,
                "sample_width": sample_width_updated,
                "sample_length": sample_length_updated,
                "sample_depth": sample_depth_updated,
                "debye_x": debye_x_updated,
                "debye_y": debye_y_updated,
                "a": a_updated,
                "c": c_updated,
                "theta_initial": theta_init_up,
                "cor": cor_angle_updated,
                "center_x": center_x_up,
                "center_y": center_y_up,
                "sigma_mosaic_deg": mosaic_params.get("sigma_mosaic_deg", 0.0),
                "gamma_mosaic_deg": mosaic_params.get("gamma_mosaic_deg", 0.0),
                "eta": mosaic_params.get("eta", 0.0),
                "distance_m": corto_det_up,
            },
            mosaic_params=mosaic_params,
            include_mosaic_shape=True,
            sf_prune_bias=0.0,
            sf_prune_stats={},
            ordered_structure_scale=ordered_structure_scale,
            qr_cylinder_replace_requested=qr_cylinder_replace_requested,
            primary_source_signature=(
                primary_requested_source_mode,
                primary_requested_filter_signature,
            ),
            secondary_source_signature=secondary_source_signature,
            disordered_phase_qr_reference_signature=(
                "disordered_phase_qr_reference",
                False,
            ),
            rich_phase_component_signature=rich_phase_component_signature,
            secondary_a=secondary_a,
            secondary_c=secondary_c,
        ) + (round(float(corto_det_up), 9),)

    # Mosaic-shape changes rescale intensities but do not move detector hits.
    requested_hit_table_sig = _simulation_signature_base(
        include_mosaic_shape=False,
    )
    primary_contribution_cache_signature = _primary_contribution_cache_signature_base()
    hit_tables_reusable = bool(
        _cached_hit_tables_reusable(
            requested_hit_table_sig,
            run_primary=primary_run_available,
            run_secondary=secondary_run_available,
            run_disordered_phase=disordered_phase_hit_tables_required,
        )
    )
    new_sim_image_sig = _simulation_signature_base()
    initial_image_signature_changed = bool(
        new_sim_image_sig != simulation_runtime_state.last_sim_signature
    )
    try:
        manual_pick_session_active = bool(_geometry_manual_pick_session_active())
    except Exception:
        manual_pick_session_active = False
    active_selection_sides = _active_peak_row_sides_for_job(
        job_kind="full",
        run_primary=primary_run_available,
        run_secondary=secondary_run_available,
        secondary_available=secondary_run_available,
    )
    current_hit_table_signature = getattr(
        simulation_runtime_state,
        "stored_hit_table_signature",
        None,
    )
    pre_update_row_content_signature = getattr(
        simulation_runtime_state,
        "stored_q_group_content_signature",
        None,
    )
    pre_update_hit_table_signature = current_hit_table_signature
    refresh_q_group_listing_requested_for_job = bool(
        getattr(geometry_q_group_state, "refresh_requested", False)
    )
    picker_peak_cache_refresh_required = bool(
        getattr(geometry_runtime_state, "manual_pick_armed", False)
        or getattr(peak_selection_state, "hkl_pick_armed", False)
        or getattr(peak_selection_state, "selected_hkl_target", None) is not None
        or manual_pick_session_active
    )
    q_group_refresh_decision = classify_q_group_refresh(
        explicit_refresh_requested=refresh_q_group_listing_requested_for_job,
        picker_refresh_required=picker_peak_cache_refresh_required,
        active_selection_sides=bool(active_selection_sides),
        previous_hit_table_signature=current_hit_table_signature,
        current_hit_table_signature=requested_hit_table_sig,
        previous_q_group_content_signature=pre_update_row_content_signature,
        current_q_group_content_signature=pre_update_row_content_signature,
        image_signature_changed=initial_image_signature_changed,
    )
    selection_peak_cache_needed = bool(q_group_refresh_decision.refresh_selection_cache)
    disordered_phase_status_for_job = _geometry_disordered_phase_qr_enable_status()
    disordered_phase_payload_for_job: Mapping[str, object] | None = None
    if disordered_phase_status_for_job.enabled:
        try:
            disordered_phase_payload_for_job = _geometry_disordered_phase_inventory_payload(
                log_status=False
            )
        except Exception:
            disordered_phase_payload_for_job = None
    disordered_phase_available_for_job = bool(
        disordered_phase_status_for_job.enabled
        and _disordered_phase_inventory_payload_available(disordered_phase_payload_for_job)
    )
    disordered_phase_signature_is_stale = bool(
        disordered_phase_status_for_job.enabled
        and requested_hit_table_sig != current_hit_table_signature
    )
    disordered_collection_requested = bool(
        getattr(
            simulation_runtime_state,
            "disordered_phase_hit_table_collection_requested",
            False,
        )
    )
    needs_disordered_tables = bool(
        disordered_phase_status_for_job.enabled
        and disordered_phase_available_for_job
        and (
            disordered_collection_requested
            or _disordered_phase_stored_hit_table_row_count() <= 0
            or disordered_phase_signature_is_stale
        )
    )
    selection_cache_current = bool(
        active_selection_sides
        and _table_row_count(getattr(simulation_runtime_state, "stored_intersection_cache", None))
        > 0
        and all(
            _side_detector_cache_is_current(side, current_hit_table_signature)
            for side in active_selection_sides
        )
    )
    selection_cache_refresh_needed = bool(
        selection_peak_cache_needed and active_selection_sides and not selection_cache_current
    )
    collect_hit_tables_for_job = bool(
        (collect_hit_tables_requested and not hit_tables_reusable)
        or selection_cache_refresh_needed
        or needs_disordered_tables
    )
    build_intersection_cache_for_job = bool(selection_cache_refresh_needed)
    new_sim_sig = new_sim_image_sig + (
        int(collect_hit_tables_for_job),
        int(build_intersection_cache_for_job),
    )
    classifier_prune_action = gui_runtime_primary_cache.resolve_incremental_sf_prune_action(
        cache_signature=primary_contribution_cache_signature,
        cached_signature=getattr(
            simulation_runtime_state,
            "primary_contribution_cache_signature",
            None,
        ),
        source_mode=primary_requested_source_mode,
        cached_source_mode=str(getattr(simulation_runtime_state, "primary_source_mode", "")),
        active_keys=primary_requested_contribution_keys,
        previous_active_keys=getattr(
            simulation_runtime_state,
            "primary_active_contribution_keys",
            (),
        ),
        primary_hit_table_cache=getattr(
            simulation_runtime_state,
            "primary_hit_table_cache",
            None,
        ),
        active_job=simulation_runtime_state.worker_active_job,
        queued_job=simulation_runtime_state.worker_queued_job,
    )

    def _runtime_var_value(value: object, default: object = None) -> object:
        get_value = getattr(value, "get", None)
        if callable(get_value):
            try:
                return get_value()
            except Exception:
                return default
        return default

    def _runtime_array_signature(value: object) -> tuple[object, ...]:
        try:
            array = np.asarray(value)
        except Exception:
            return ("unavailable",)
        return (
            tuple(int(dim) for dim in array.shape),
            str(array.dtype),
            int(array.size),
        )

    def _runtime_array_has_rows(value: object) -> bool:
        try:
            array = np.asarray(value)
        except Exception:
            return False
        return bool(array.ndim >= 1 and int(array.shape[0]) > 0)

    def _runtime_tuple_signature(value: object) -> tuple[object, ...]:
        if value is None:
            return tuple()
        if isinstance(value, tuple):
            return value
        if isinstance(value, Sequence) and not isinstance(value, (str, bytes)):
            try:
                return tuple(value)
            except Exception:
                return (str(value),)
        return (value,)

    def _safe_frozenset(values: object) -> frozenset[object]:
        try:
            return frozenset(values or ())
        except TypeError:
            try:
                return frozenset(str(value) for value in values or ())
            except Exception:
                return frozenset()

    classifier_missing_keys = _safe_frozenset(getattr(classifier_prune_action, "missing_keys", ()))
    all_primary_source_signature = (
        (
            "qr",
            id(getattr(simulation_runtime_state, "sim_primary_qr_all", {})),
            len(getattr(simulation_runtime_state, "sim_primary_qr_all", {}) or {}),
        )
        if str(primary_requested_source_mode) == "qr"
        else (
            "miller",
            id(getattr(simulation_runtime_state, "sim_miller1_all", None)),
            tuple(np.asarray(getattr(simulation_runtime_state, "sim_miller1_all", ())).shape),
        )
    )
    all_secondary_source_signature = (
        "miller",
        id(getattr(simulation_runtime_state, "sim_miller2_all", None)),
        tuple(np.asarray(getattr(simulation_runtime_state, "sim_miller2_all", ())).shape),
    )
    current_dependency_signatures = SimulationDependencySignatures(
        source_sig=(
            primary_requested_source_mode,
            all_primary_source_signature,
            all_secondary_source_signature,
            _runtime_array_signature(getattr(simulation_runtime_state, "sim_intens1_all", ())),
            _runtime_array_signature(getattr(simulation_runtime_state, "sim_intens2_all", ())),
            bool(
                len(getattr(simulation_runtime_state, "sim_primary_qr_all", {}) or {}) > 0
                or _runtime_array_has_rows(getattr(simulation_runtime_state, "sim_miller1_all", ()))
            ),
            bool(_runtime_array_has_rows(getattr(simulation_runtime_state, "sim_miller2_all", ()))),
            disordered_phase_qr_reference_signature,
        ),
        physics_sig=(
            round(float(gamma_updated), 9),
            round(float(Gamma_updated), 9),
            round(float(chi_updated), 9),
            round(float(psi), 9),
            round(float(psi_z_updated), 9),
            round(float(zs_updated), 9),
            round(float(zb_updated), 9),
            round(float(sample_width_updated), 12),
            round(float(sample_length_updated), 12),
            round(float(sample_depth_updated), 12),
            round(float(cor_angle_updated), 9),
            round(float(a_updated), 9),
            round(float(c_updated), 9),
            round(float(secondary_a), 9),
            round(float(secondary_c), 9),
            round(float(theta_init_up), 9),
            round(float(debye_x_updated), 9),
            round(float(debye_y_updated), 9),
            round(float(mosaic_params.get("sigma_mosaic_deg", 0.0)), 9),
            round(float(mosaic_params.get("gamma_mosaic_deg", 0.0)), 9),
            round(float(mosaic_params.get("eta", 0.0)), 9),
            int(mosaic_params.get("events_per_beam_phase", DEFAULT_EVENTS_PER_BEAM_PHASE)),
            int(mosaic_params.get("solve_q_steps", 0) or 0),
            round(float(mosaic_params.get("solve_q_rel_tol", 0.0) or 0.0), 12),
            int(mosaic_params.get("solve_q_mode", 0) or 0),
            tuple(mosaic_params.get("_sampling_signature", ()) or ()),
            _runtime_array_signature(mosaic_params.get("beam_x_array", ())),
            _runtime_array_signature(mosaic_params.get("beam_y_array", ())),
            _runtime_array_signature(mosaic_params.get("theta_array", ())),
            _runtime_array_signature(mosaic_params.get("phi_array", ())),
            _runtime_array_signature(mosaic_params.get("wavelength_array", ())),
            bool(qr_cylinder_replace_requested),
            round(float(ordered_structure_scale), 9),
        ),
        detector_projection_sig=(
            int(image_size),
            round(float(corto_det_up), 12),
            round(float(pixel_size_m), 15),
            round(float(wave_m), 15),
            round(float(globals().get("lambda_", wave_m)), 9),
        ),
        detector_center_sig=(
            round(float(center_x_up), 9),
            round(float(center_y_up), 9),
        ),
        primary_filter_sig=(
            primary_requested_source_mode,
            primary_requested_filter_signature,
            tuple(primary_requested_contribution_keys),
            round(float(current_sf_prune_bias()), 6),
            tuple(sorted((simulation_runtime_state.sf_prune_stats or {}).items())),
        ),
        combine_sig=(
            round(float(primary_weight_value), 12),
            round(float(secondary_weight_value), 12),
        ),
        analysis_geometry_sig=(
            bool(analysis_view_controls_view_state.show_caked_2d_var.get()),
            bool(_runtime_var_value(analysis_view_controls_view_state.show_1d_var, False)),
            str(_current_app_shell_view_mode()),
            int(background_runtime_state.current_background_index),
            bool(background_runtime_state.visible),
            int(DEFAULT_ANALYSIS_RADIAL_BINS),
            int(DEFAULT_ANALYSIS_AZIMUTH_BINS),
        ),
        display_sig=(
            _runtime_var_value(display_controls_view_state.background_min_var),
            _runtime_var_value(display_controls_view_state.background_max_var),
            _runtime_var_value(display_controls_view_state.simulation_min_var),
            _runtime_var_value(display_controls_view_state.simulation_max_var),
            _runtime_var_value(display_controls_view_state.simulation_scale_factor_var),
            bool(getattr(display_controls_state, "scale_factor_user_override", False)),
        ),
        hit_table_sig=(
            bool(collect_hit_tables_requested),
            bool(refresh_q_group_listing_requested_for_job or picker_peak_cache_refresh_required),
        ),
        full_image_sig=_runtime_tuple_signature(new_sim_image_sig),
    )
    previous_dependency_signatures = getattr(
        simulation_runtime_state,
        "last_dependency_signatures",
        None,
    )
    if not isinstance(previous_dependency_signatures, SimulationDependencySignatures):
        previous_dependency_signatures = None

    primary_detector_remap_cache_signature = (
        "primary_detector_center_remap",
        current_dependency_signatures.source_sig,
        current_dependency_signatures.physics_sig,
        current_dependency_signatures.detector_projection_sig,
        current_dependency_signatures.primary_filter_sig,
    )
    secondary_detector_remap_cache_signature = (
        "secondary_detector_center_remap",
        current_dependency_signatures.source_sig,
        current_dependency_signatures.physics_sig,
        current_dependency_signatures.detector_projection_sig,
    )

    def _dependency_center_pair(
        signatures: SimulationDependencySignatures | None,
    ) -> tuple[float, float] | None:
        if signatures is None:
            return None
        try:
            center_sig = tuple(signatures.detector_center_sig)
            return (float(center_sig[0]), float(center_sig[1]))
        except Exception:
            return None

    def _detector_relative_cache_payload_present(payload: object) -> bool:
        if payload is None:
            return False
        if isinstance(payload, Mapping):
            return bool(payload)
        if isinstance(payload, (str, bytes)):
            return False
        try:
            return bool(len(payload))
        except Exception:
            return True

    def _primary_detector_remap_cache_ready() -> bool:
        if not bool(primary_available):
            return True
        relative_cache = getattr(
            simulation_runtime_state,
            "primary_relative_hit_table_cache",
            None,
        )
        if not isinstance(relative_cache, Mapping):
            return False
        if (
            getattr(
                simulation_runtime_state,
                "primary_relative_hit_table_cache_signature",
                None,
            )
            != primary_detector_remap_cache_signature
        ):
            return False
        required_keys = tuple(primary_requested_contribution_keys)
        if not required_keys:
            return _detector_relative_cache_payload_present(relative_cache)
        return all(key in relative_cache for key in required_keys)

    def _secondary_detector_remap_cache_ready() -> bool:
        if not bool(secondary_available):
            return True
        relative_cache = getattr(
            simulation_runtime_state,
            "secondary_relative_hit_table_cache",
            None,
        )
        if (
            getattr(
                simulation_runtime_state,
                "secondary_relative_hit_table_cache_signature",
                None,
            )
            != secondary_detector_remap_cache_signature
        ):
            return False
        return _detector_relative_cache_payload_present(relative_cache)

    previous_center_pair = _dependency_center_pair(previous_dependency_signatures)
    current_center_pair = (float(center_x_up), float(center_y_up))

    def _refresh_primary_relative_remap_cache_signature(
        detector_remap_cache_signature: object,
    ) -> None:
        primary_relative_cache = getattr(
            simulation_runtime_state,
            "primary_relative_hit_table_cache",
            None,
        )
        primary_relative_center = getattr(
            simulation_runtime_state,
            "primary_relative_hit_table_cache_center",
            None,
        )
        try:
            primary_relative_center_pair = tuple(
                float(value) for value in tuple(primary_relative_center)[:2]
            )
        except Exception:
            primary_relative_center_pair = None
        required_relative_keys = tuple(primary_requested_contribution_keys)
        if (
            isinstance(primary_relative_cache, Mapping)
            and primary_relative_cache
            and required_relative_keys
            and all(key in primary_relative_cache for key in required_relative_keys)
            and primary_relative_center_pair == current_center_pair
        ):
            simulation_runtime_state.primary_relative_hit_table_cache_signature = (
                detector_remap_cache_signature
            )

    exact_detector_center_remap_available = bool(
        previous_center_pair is not None
        and gui_runtime_detector_remap_cache.can_remap_detector_center_exactly(
            gui_runtime_detector_remap_cache.DetectorCenterRemapCacheState(
                detector_relative_hit_tables=(
                    getattr(
                        simulation_runtime_state,
                        "primary_relative_hit_table_cache",
                        None,
                    )
                    if bool(primary_available)
                    else getattr(
                        simulation_runtime_state,
                        "secondary_relative_hit_table_cache",
                        None,
                    )
                ),
            ),
            old_center=previous_center_pair,
            new_center=current_center_pair,
            image_size=int(image_size),
        )
        and _primary_detector_remap_cache_ready()
        and _secondary_detector_remap_cache_ready()
    )
    classifier_cache_state = RuntimeCacheState(
        can_remap_detector_center=bool(exact_detector_center_remap_available),
        prune_cache_mode=getattr(classifier_prune_action, "mode", None),
        missing_contribution_keys=classifier_missing_keys,
    )
    try:
        classifier_decision = classify_update(
            previous_dependency_signatures,
            current_dependency_signatures,
            classifier_cache_state,
        )
    except Exception as exc:
        classifier_decision = UpdateDecision(
            action=UpdateAction.FULL_SIMULATION,
            reason=f"classifier_error:{type(exc).__name__}",
            requires_worker=True,
        )
    classifier_full_simulation_required = bool(
        classifier_decision.action is UpdateAction.FULL_SIMULATION
        and classifier_decision.requires_worker
        and previous_dependency_signatures is not None
        and current_dependency_signatures != previous_dependency_signatures
    )
    non_simulation_update_action = classifier_decision.action in {
        UpdateAction.DISPLAY_ONLY,
        UpdateAction.COMBINE_ONLY,
        UpdateAction.DETECTOR_CENTER_REMAP,
        UpdateAction.PRIMARY_PRUNE_REUSE,
        UpdateAction.PRIMARY_PRUNE_FILL,
        UpdateAction.ANALYSIS_ONLY,
    }
    requires_current_image_signature = classifier_decision.action in {
        UpdateAction.DISPLAY_ONLY,
        UpdateAction.COMBINE_ONLY,
        UpdateAction.ANALYSIS_ONLY,
    }
    effective_update_action = (
        classifier_decision.action
        if non_simulation_update_action
        and (not requires_current_image_signature or not initial_image_signature_changed)
        else UpdateAction.FULL_SIMULATION
    )
    applied_peak_row_refresh_payload: dict[str, object] | None = None
    display_only_fast_path = bool(
        effective_update_action is UpdateAction.DISPLAY_ONLY
        and not initial_image_signature_changed
        and getattr(simulation_runtime_state, "stored_sim_image", None) is not None
    )
    combine_only_fast_path = bool(
        effective_update_action is UpdateAction.COMBINE_ONLY
        and not initial_image_signature_changed
        and (
            getattr(simulation_runtime_state, "stored_primary_sim_image", None) is not None
            or getattr(simulation_runtime_state, "stored_secondary_sim_image", None) is not None
        )
    )
    prune_reuse_fast_path = bool(effective_update_action is UpdateAction.PRIMARY_PRUNE_REUSE)
    center_remap_fast_path = bool(
        effective_update_action is UpdateAction.DETECTOR_CENTER_REMAP
        and exact_detector_center_remap_available
    )
    fast_path_will_use_cache = bool(
        display_only_fast_path
        or combine_only_fast_path
        or prune_reuse_fast_path
        or center_remap_fast_path
    )
    ready_candidate = getattr(simulation_runtime_state, "worker_ready_result", None)
    if fast_path_will_use_cache and isinstance(ready_candidate, dict):
        simulation_runtime_state.worker_ready_result = None
        ready_simulation_result = None
    else:
        ready_simulation_result = _consume_ready_simulation_result(new_sim_sig)
    if ready_simulation_result is not None:
        ready_job_kind = str(ready_simulation_result.get("job_kind", "full"))
        if ready_job_kind == "primary_fill":
            _store_primary_cache_payload(
                cache_signature=ready_simulation_result.get("primary_contribution_cache_signature"),
                source_mode=str(
                    ready_simulation_result.get(
                        "primary_source_mode",
                        primary_requested_source_mode,
                    )
                ),
                active_keys=ready_simulation_result.get(
                    "active_primary_contribution_keys",
                    primary_requested_contribution_keys,
                ),
                contribution_keys=ready_simulation_result.get(
                    "primary_contribution_keys",
                    [],
                ),
                raw_hit_tables=ready_simulation_result.get(
                    "primary_hit_tables_raw",
                    [],
                ),
                best_sample_indices=ready_simulation_result.get(
                    "primary_best_sample_indices",
                    [],
                ),
                representative_intersection_cache=(
                    ready_simulation_result.get("primary_intersection_cache", [])
                    if bool(ready_simulation_result.get("primary_intersection_cache_built", False))
                    else None
                ),
                detector_center=ready_simulation_result.get("center"),
                detector_remap_cache_signature=ready_simulation_result.get(
                    "primary_detector_remap_cache_signature"
                ),
                store_detector_relative_hit_tables=True,
            )
            rematerialized_primary = _rematerialize_primary_cache_artifacts(
                image_size=int(image_size),
                mosaic_params=mosaic_params,
                a_primary=float(a_updated),
                c_primary=float(c_updated),
            )
            _apply_primary_cache_artifacts(rematerialized_primary)
            simulation_runtime_state.stored_simulation_q_space_geometry = _copy_q_space_geometry(
                ready_simulation_result.get("q_space_geometry")
            )
            _refresh_primary_relative_remap_cache_signature(primary_detector_remap_cache_signature)
            if _hit_table_state_present_for_run_sides(
                run_primary=primary_run_available,
                run_secondary=secondary_run_available,
                run_disordered_phase=disordered_phase_hit_tables_required,
            ):
                simulation_runtime_state.stored_hit_table_signature = requested_hit_table_sig
            simulation_runtime_state.primary_filter_signature = primary_requested_filter_signature
        else:
            _apply_ready_simulation_result(ready_simulation_result)
            simulation_runtime_state.primary_filter_signature = primary_requested_filter_signature
        simulation_runtime_state.last_sim_signature = new_sim_image_sig
        simulation_runtime_state.last_simulation_signature = new_sim_sig
        applied_peak_row_refresh_payload = dict(ready_simulation_result)
        image_generation_cached = False
        image_generation_elapsed_ms = float(
            ready_simulation_result.get("image_generation_elapsed_ms", 0.0)
        )
        simulation_runtime_state.update_phase = "applying"
        _refresh_run_status_bar()

    display_only_fast_path = bool(display_only_fast_path and ready_simulation_result is None)
    combine_only_fast_path = bool(combine_only_fast_path and ready_simulation_result is None)
    center_remap_fast_path = bool(center_remap_fast_path and ready_simulation_result is None)
    if display_only_fast_path:
        _invalidate_for_update_action(UpdateAction.DISPLAY_ONLY)
    elif combine_only_fast_path:
        _invalidate_for_update_action(UpdateAction.COMBINE_ONLY)

    image_signature_changed = bool(new_sim_image_sig != simulation_runtime_state.last_sim_signature)
    if classifier_full_simulation_required:
        image_signature_changed = True
    need_hit_table_refresh = bool(
        collect_hit_tables_for_job
        and new_sim_sig != simulation_runtime_state.last_simulation_signature
    )

    def _build_simulation_job(
        *,
        collect_hit_tables_enabled: bool,
        job_kind: str = "full",
        primary_job_data: object | None = None,
        primary_job_intensities: np.ndarray | None = None,
        primary_job_keys: Sequence[int] | None = None,
        run_secondary_job: bool | None = None,
    ) -> dict[str, object]:
        selected_primary_data = primary_data if primary_job_data is None else primary_job_data
        if isinstance(selected_primary_data, dict):
            selected_primary_data = gui_controllers.copy_bragg_qr_dict(selected_primary_data)

        selected_primary_intensities = (
            np.asarray(primary_intensities, dtype=np.float64).copy()
            if primary_job_intensities is None
            else np.asarray(primary_job_intensities, dtype=np.float64).reshape(-1).copy()
        )
        selected_primary_keys = list(
            primary_requested_contribution_keys if primary_job_keys is None else primary_job_keys
        )
        disordered_phase_payload = (
            dict(disordered_phase_payload_for_job)
            if isinstance(disordered_phase_payload_for_job, Mapping)
            else _geometry_disordered_phase_inventory_payload()
        )
        disordered_phase_miller = np.asarray(
            disordered_phase_payload.get("miller", ()),
            dtype=np.float64,
        )
        disordered_phase_intensities = np.asarray(
            disordered_phase_payload.get("intensities", ()),
            dtype=np.float64,
        ).reshape(-1)
        disordered_phase_available = bool(
            disordered_phase_status_for_job.enabled
            and disordered_phase_miller.ndim == 2
            and disordered_phase_miller.shape[0] > 0
            and disordered_phase_intensities.size > 0
        )
        run_primary_job = (
            len(selected_primary_data) > 0
            if isinstance(selected_primary_data, dict)
            else (
                np.asarray(selected_primary_data).ndim == 2
                and np.asarray(selected_primary_data).shape[0] > 0
                and selected_primary_intensities.size > 0
            )
        )
        run_primary_job = bool(run_primary_job and primary_weight_active)
        if not run_primary_job:
            selected_primary_keys = []
        secondary_available_job = bool(secondary_available and secondary_weight_active)
        requested_secondary = (
            bool(secondary_available_job) if run_secondary_job is None else bool(run_secondary_job)
        )
        run_secondary_enabled = bool(requested_secondary and secondary_available_job)
        job_kind_value = str(job_kind)
        active_peak_row_sides = _active_peak_row_sides_for_job(
            job_kind=job_kind_value,
            run_primary=run_primary_job,
            run_secondary=run_secondary_enabled,
            secondary_available=secondary_available_job,
        )
        capture_primary_raw = bool(run_primary_job and job_kind_value in {"full", "primary_fill"})
        capture_secondary_raw = bool(run_secondary_enabled and job_kind_value == "full")
        build_intersection_cache_enabled = bool(
            build_intersection_cache_for_job and job_kind_value in {"full", "primary_fill"}
        )
        collect_primary_hit_tables = bool(
            (collect_hit_tables_enabled or build_intersection_cache_enabled) and run_primary_job
        )
        collect_secondary_hit_tables = bool(
            (collect_hit_tables_enabled or build_intersection_cache_enabled)
            and run_secondary_enabled
        )
        existing_disordered_collection_reason = bool(collect_hit_tables_enabled)
        collect_disordered_phase_hit_tables = bool(
            collect_hit_tables_enabled
            and disordered_phase_available
            and (needs_disordered_tables or existing_disordered_collection_reason)
        )
        build_primary_intersection_cache = bool(
            build_intersection_cache_enabled and collect_primary_hit_tables
        )
        build_secondary_intersection_cache = bool(
            build_intersection_cache_enabled and collect_secondary_hit_tables
        )
        return {
            "job_kind": job_kind_value,
            "signature": new_sim_sig,
            "epoch": int(simulation_runtime_state.simulation_epoch),
            "image_size": int(image_size),
            "pixel_size_m": float(pixel_size_m),
            "center": np.asarray([center_x_up, center_y_up], dtype=np.float64).copy(),
            "mosaic_params": {
                "beam_x_array": np.asarray(mosaic_params["beam_x_array"], dtype=np.float64).copy(),
                "beam_y_array": np.asarray(mosaic_params["beam_y_array"], dtype=np.float64).copy(),
                "theta_array": np.asarray(mosaic_params["theta_array"], dtype=np.float64).copy(),
                "phi_array": np.asarray(mosaic_params["phi_array"], dtype=np.float64).copy(),
                "wavelength_array": np.asarray(
                    mosaic_params["wavelength_array"],
                    dtype=np.float64,
                ).copy(),
                "sample_weights": (
                    None
                    if mosaic_params.get("sample_weights") is None
                    else np.asarray(
                        mosaic_params["sample_weights"],
                        dtype=np.float64,
                    ).copy()
                ),
                "n2_sample_array": (
                    None
                    if mosaic_params.get("n2_sample_array") is None
                    else np.asarray(
                        mosaic_params["n2_sample_array"],
                        dtype=np.complex128,
                    ).copy()
                ),
                "_n2_sample_array_source": mosaic_params.get("_n2_sample_array_source"),
                "_n2_sample_array_wavelength_snapshot": (
                    None
                    if mosaic_params.get("_n2_sample_array_wavelength_snapshot") is None
                    else np.asarray(
                        mosaic_params["_n2_sample_array_wavelength_snapshot"],
                        dtype=np.float64,
                    ).copy()
                ),
                "sigma_mosaic_deg": float(mosaic_params["sigma_mosaic_deg"]),
                "gamma_mosaic_deg": float(mosaic_params["gamma_mosaic_deg"]),
                "eta": float(mosaic_params["eta"]),
                "events_per_beam_phase": int(
                    mosaic_params.get("events_per_beam_phase", DEFAULT_EVENTS_PER_BEAM_PHASE)
                ),
                "solve_q_steps": int(mosaic_params["solve_q_steps"]),
                "solve_q_rel_tol": float(mosaic_params["solve_q_rel_tol"]),
                "solve_q_mode": int(mosaic_params["solve_q_mode"]),
                "_sampling_signature": tuple(mosaic_params.get("_sampling_signature", ())),
            },
            "lambda_value": float(lambda_),
            "distance_m": float(corto_det_up),
            "gamma_deg": float(gamma_updated),
            "Gamma_deg": float(Gamma_updated),
            "chi_deg": float(chi_updated),
            "psi_deg": float(psi),
            "psi_z_deg": float(psi_z_updated),
            "zs": float(zs_updated),
            "zb": float(zb_updated),
            "theta_initial_deg": float(theta_init_up),
            "cor_angle_deg": float(cor_angle_updated),
            "sample_width_m": float(sample_width_updated),
            "sample_length_m": float(sample_length_updated),
            "sample_depth_m": float(sample_depth_updated),
            "debye_x": float(debye_x_updated),
            "debye_y": float(debye_y_updated),
            "collect_hit_tables": bool(collect_hit_tables_enabled),
            "collect_primary_hit_tables": collect_primary_hit_tables,
            "collect_secondary_hit_tables": collect_secondary_hit_tables,
            "collect_disordered_phase_hit_tables": collect_disordered_phase_hit_tables,
            "build_primary_intersection_cache": build_primary_intersection_cache,
            "build_secondary_intersection_cache": build_secondary_intersection_cache,
            "capture_primary_hit_tables_raw": capture_primary_raw,
            "capture_secondary_hit_tables_raw": capture_secondary_raw,
            "secondary_available": bool(secondary_available_job),
            "active_peak_row_sides": tuple(active_peak_row_sides),
            "hit_table_signature": requested_hit_table_sig,
            "primary_contribution_cache_signature": primary_contribution_cache_signature,
            "primary_detector_remap_cache_signature": primary_detector_remap_cache_signature,
            "secondary_detector_remap_cache_signature": (secondary_detector_remap_cache_signature),
            "primary_source_mode": primary_requested_source_mode,
            "primary_contribution_keys": list(selected_primary_keys),
            "active_primary_contribution_keys": list(primary_requested_contribution_keys),
            "accumulate_image": bool(accumulate_image_requested),
            "qr_cylinder_replace_simulation": bool(qr_cylinder_replace_requested),
            "n2_value": _current_effective_n2(),
            "primary_data": selected_primary_data,
            "primary_intensities": selected_primary_intensities,
            "secondary_data": secondary_data,
            "secondary_intensities": secondary_intensities,
            "disordered_phase_data": disordered_phase_miller.copy(),
            "disordered_phase_intensities": disordered_phase_intensities.copy(),
            "disordered_phase_a": float(disordered_phase_payload.get("a", float("nan"))),
            "disordered_phase_c": float(disordered_phase_payload.get("c", float("nan"))),
            "run_primary": bool(run_primary_job),
            "run_secondary": bool(run_secondary_enabled),
            "a_primary": float(a_updated),
            "c_primary": float(c_updated),
            "a_secondary": float(secondary_a),
            "c_secondary": float(secondary_c),
        }

    def _build_scaled_primary_subset_payload(
        requested_keys: Sequence[int],
    ) -> dict[str, object]:
        subset_payload = gui_runtime_primary_cache.build_primary_subset_payload(
            source_mode=primary_requested_source_mode,
            all_primary_qr=simulation_runtime_state.sim_primary_qr_all,
            all_miller=simulation_runtime_state.sim_miller1_all,
            all_intensities=simulation_runtime_state.sim_intens1_all,
            requested_keys=requested_keys,
        )
        subset_primary_data = subset_payload.get("primary_data")
        subset_primary_intensities = np.asarray(
            subset_payload.get("primary_intensities", np.empty((0,), dtype=np.float64)),
            dtype=np.float64,
        ).reshape(-1)
        if isinstance(subset_primary_data, dict):
            subset_primary_data = _scaled_bragg_qr_dict(
                subset_primary_data,
                ordered_structure_scale,
            )
        else:
            subset_primary_intensities = subset_primary_intensities.copy() * float(
                ordered_structure_scale
            )
        return {
            "primary_data": subset_primary_data,
            "primary_intensities": subset_primary_intensities,
            "primary_contribution_keys": list(subset_payload.get("primary_contribution_keys", [])),
        }

    if ready_simulation_result is None and center_remap_fast_path:
        remap_start_time = perf_counter()
        _invalidate_picker_handoff_caches_for_update_action(
            UpdateAction.DETECTOR_CENTER_REMAP,
            detector_geometry_changed=True,
        )
        simulation_runtime_state.peak_positions.clear()
        simulation_runtime_state.peak_millers.clear()
        simulation_runtime_state.peak_intensities.clear()
        simulation_runtime_state.peak_records.clear()
        simulation_runtime_state.selected_peak_record = None
        if bool(primary_available):
            primary_relative_cache = getattr(
                simulation_runtime_state,
                "primary_relative_hit_table_cache",
                {},
            )
            primary_keys = tuple(primary_requested_contribution_keys) or tuple(
                primary_relative_cache.keys() if isinstance(primary_relative_cache, Mapping) else ()
            )
            primary_relative_tables = [
                np.asarray(primary_relative_cache[key], dtype=np.float64).copy()
                for key in primary_keys
            ]
            primary_absolute_tables = (
                gui_runtime_detector_remap_cache.materialize_absolute_hit_tables_from_relative(
                    primary_relative_tables,
                    current_center_pair,
                )
            )
            previous_primary_center = getattr(
                simulation_runtime_state,
                "primary_relative_hit_table_cache_center",
                None,
            )
            primary_representative_cache = getattr(
                simulation_runtime_state,
                "primary_intersection_cache_entry_cache",
                {},
            )
            remapped_primary_representative_cache = {}
            try:
                delta_row = float(current_center_pair[0]) - float(previous_primary_center[0])
                delta_col = float(current_center_pair[1]) - float(previous_primary_center[1])
                remapped_primary_representative_cache = gui_runtime_primary_cache.translate_intersection_cache_entry_cache_for_center_delta(
                    primary_representative_cache,
                    delta_row=delta_row,
                    delta_col=delta_col,
                )
            except Exception:
                remapped_primary_representative_cache = {}
            simulation_runtime_state.primary_hit_table_cache = {
                key: np.asarray(table, dtype=np.float64).copy()
                for key, table in zip(primary_keys, primary_absolute_tables)
            }
            simulation_runtime_state.primary_intersection_cache_entry_cache = (
                remapped_primary_representative_cache
            )
            simulation_runtime_state.primary_contribution_cache_signature = (
                primary_contribution_cache_signature
            )
            simulation_runtime_state.primary_source_mode = primary_requested_source_mode
            simulation_runtime_state.primary_filter_signature = primary_requested_filter_signature
            simulation_runtime_state.primary_active_contribution_keys = list(primary_keys)
            simulation_runtime_state.primary_relative_hit_table_cache_center = current_center_pair
            remapped_primary = gui_runtime_primary_cache.rematerialize_primary_artifacts(
                primary_hit_table_cache=simulation_runtime_state.primary_hit_table_cache,
                primary_best_sample_index_cache=getattr(
                    simulation_runtime_state,
                    "primary_best_sample_index_cache",
                    {},
                ),
                active_keys=list(primary_keys),
                primary_intersection_cache_cache=remapped_primary_representative_cache,
                image_size=int(image_size),
                a_primary=float(a_updated),
                c_primary=float(c_updated),
                beam_x_array=np.asarray(mosaic_params["beam_x_array"], dtype=np.float64),
                beam_y_array=np.asarray(mosaic_params["beam_y_array"], dtype=np.float64),
                theta_array=np.asarray(mosaic_params["theta_array"], dtype=np.float64),
                phi_array=np.asarray(mosaic_params["phi_array"], dtype=np.float64),
                wavelength_array=np.asarray(
                    mosaic_params["wavelength_array"],
                    dtype=np.float64,
                ),
                lattice_label="primary",
            )
            _apply_primary_cache_artifacts(remapped_primary)
            simulation_runtime_state.stored_primary_intersection_cache_signature = (
                requested_hit_table_sig
            )
        if bool(secondary_available):
            secondary_relative_tables = getattr(
                simulation_runtime_state,
                "secondary_relative_hit_table_cache",
                [],
            )
            secondary_absolute_tables = (
                gui_runtime_detector_remap_cache.materialize_absolute_hit_tables_from_relative(
                    secondary_relative_tables,
                    current_center_pair,
                )
            )
            secondary_cache = {
                int(idx): np.asarray(table, dtype=np.float64).copy()
                for idx, table in enumerate(secondary_absolute_tables)
            }
            remapped_secondary = gui_runtime_primary_cache.rematerialize_primary_artifacts(
                primary_hit_table_cache=secondary_cache,
                primary_best_sample_index_cache=getattr(
                    simulation_runtime_state,
                    "secondary_relative_best_sample_index_cache",
                    {},
                ),
                active_keys=list(secondary_cache.keys()),
                image_size=int(image_size),
                a_primary=float(secondary_a),
                c_primary=float(secondary_c),
                beam_x_array=np.asarray(mosaic_params["beam_x_array"], dtype=np.float64),
                beam_y_array=np.asarray(mosaic_params["beam_y_array"], dtype=np.float64),
                theta_array=np.asarray(mosaic_params["theta_array"], dtype=np.float64),
                phi_array=np.asarray(mosaic_params["phi_array"], dtype=np.float64),
                wavelength_array=np.asarray(
                    mosaic_params["wavelength_array"],
                    dtype=np.float64,
                ),
                lattice_label="secondary",
            )
            _apply_secondary_detector_remap_artifacts(
                remapped_secondary,
                hit_table_signature=requested_hit_table_sig,
            )
            simulation_runtime_state.secondary_relative_hit_table_cache_center = current_center_pair
        elif getattr(simulation_runtime_state, "stored_secondary_sim_image", None) is not None:
            _clear_secondary_simulation_artifacts()
        if _hit_table_state_present_for_run_sides(
            run_primary=primary_run_available,
            run_secondary=secondary_run_available,
            run_disordered_phase=disordered_phase_hit_tables_required,
        ):
            simulation_runtime_state.stored_hit_table_signature = requested_hit_table_sig
        else:
            simulation_runtime_state.stored_hit_table_signature = None
        simulation_runtime_state.last_sim_signature = new_sim_image_sig
        simulation_runtime_state.last_simulation_signature = new_sim_sig
        simulation_runtime_state.stored_simulation_q_space_geometry = (
            _current_q_space_geometry_from_live_controls(
                distance_m=corto_det_up,
                center=np.asarray([center_x_up, center_y_up], dtype=np.float64),
                pixel_size_m_value=pixel_size_m,
                wavelength_m_value=wave_m,
                gamma_deg=gamma_updated,
                Gamma_deg=Gamma_updated,
                chi_deg=chi_updated,
                psi_deg=psi,
                psi_z_deg=psi_z_updated,
                theta_initial_deg=theta_init_up,
                cor_angle_deg=cor_angle_updated,
                zs=zs_updated,
                zb=zb_updated,
            )
        )
        applied_peak_row_refresh_payload = {
            "job_kind": "detector_center_remap",
            "run_primary": bool(primary_run_available),
            "run_secondary": bool(secondary_run_available),
            "secondary_available": bool(secondary_run_available),
            "active_peak_row_sides": tuple(active_selection_sides),
            "primary_raw_rows_fresh": bool(primary_run_available),
            "secondary_raw_rows_fresh": bool(secondary_run_available),
        }
        image_generation_cached = False
        image_generation_elapsed_ms = (perf_counter() - remap_start_time) * 1e3
        simulation_runtime_state.last_image_generation_ms = float(image_generation_elapsed_ms)
        simulation_runtime_state.preview_active = False
        simulation_runtime_state.preview_sample_count = None
        _invalidate_analysis_cache(clear_visuals=True)
        _clear_detector_center_projection_caches()
        _invalidate_for_update_action(
            UpdateAction.DETECTOR_CENTER_REMAP,
            physics_signature_changed=False,
            hit_table_signature_changed=False,
            q_group_content_signature_changed=False,
            detector_geometry_changed=False,
        )
        simulation_runtime_state.update_phase = "applying"
        _refresh_run_status_bar()
        image_signature_changed = False
        need_hit_table_refresh = False

    if ready_simulation_result is None and image_signature_changed:
        pre_picker_action = (
            classifier_decision.action
            if classifier_decision.action
            in {UpdateAction.PRIMARY_PRUNE_REUSE, UpdateAction.PRIMARY_PRUNE_FILL}
            else UpdateAction.FULL_SIMULATION
        )
        prune_hit_table_identity_changed = bool(
            pre_picker_action in {UpdateAction.PRIMARY_PRUNE_REUSE, UpdateAction.PRIMARY_PRUNE_FILL}
            and requested_hit_table_sig != pre_update_hit_table_signature
        )
        _invalidate_picker_handoff_caches_for_update_action(
            pre_picker_action,
            physics_signature_changed=pre_picker_action is UpdateAction.FULL_SIMULATION,
            hit_table_signature_changed=(
                pre_picker_action is UpdateAction.FULL_SIMULATION
                or prune_hit_table_identity_changed
            ),
            q_group_content_signature_changed=(
                pre_picker_action is UpdateAction.FULL_SIMULATION
                or pre_picker_action is UpdateAction.PRIMARY_PRUNE_FILL
            ),
            detector_geometry_changed=(
                pre_picker_action is UpdateAction.FULL_SIMULATION
                and previous_center_pair != current_center_pair
            ),
        )
        simulation_runtime_state.peak_positions.clear()
        simulation_runtime_state.peak_millers.clear()
        simulation_runtime_state.peak_intensities.clear()
        simulation_runtime_state.peak_records.clear()
        simulation_runtime_state.selected_peak_record = None
        if classifier_decision.action in {
            UpdateAction.PRIMARY_PRUNE_REUSE,
            UpdateAction.PRIMARY_PRUNE_FILL,
        }:
            incremental_sf_prune_action = classifier_prune_action
        else:
            incremental_sf_prune_action = gui_runtime_primary_cache.IncrementalSfPruneAction(
                mode="full",
                added_keys=tuple(),
                removed_keys=tuple(),
                missing_keys=tuple(),
                reason=f"classifier_{classifier_decision.action.value}",
            )
        if incremental_sf_prune_action.mode == "reuse":
            _invalidate_for_update_action(
                UpdateAction.PRIMARY_PRUNE_REUSE,
                physics_signature_changed=False,
                hit_table_signature_changed=prune_hit_table_identity_changed,
                q_group_content_signature_changed=False,
                detector_geometry_changed=False,
            )
            rematerialize_start_time = perf_counter()
            simulation_runtime_state.primary_contribution_cache_signature = (
                primary_contribution_cache_signature
            )
            simulation_runtime_state.primary_source_mode = primary_requested_source_mode
            simulation_runtime_state.primary_filter_signature = primary_requested_filter_signature
            simulation_runtime_state.primary_active_contribution_keys = list(
                primary_requested_contribution_keys
            )
            rematerialized_primary = _rematerialize_primary_cache_artifacts(
                image_size=int(image_size),
                mosaic_params=mosaic_params,
                a_primary=float(a_updated),
                c_primary=float(c_updated),
            )
            _apply_primary_cache_artifacts(rematerialized_primary)
            _refresh_primary_relative_remap_cache_signature(primary_detector_remap_cache_signature)
            if _hit_table_state_present_for_run_sides(
                run_primary=primary_run_available,
                run_secondary=secondary_run_available,
                run_disordered_phase=disordered_phase_hit_tables_required,
            ):
                simulation_runtime_state.stored_hit_table_signature = requested_hit_table_sig
            simulation_runtime_state.last_sim_signature = new_sim_image_sig
            simulation_runtime_state.last_simulation_signature = new_sim_sig
            image_generation_cached = False
            image_generation_elapsed_ms = (perf_counter() - rematerialize_start_time) * 1e3
            simulation_runtime_state.last_image_generation_ms = float(image_generation_elapsed_ms)
            simulation_runtime_state.update_phase = "applying"
            _refresh_run_status_bar()
        elif incremental_sf_prune_action.mode == "fill":
            _invalidate_for_update_action(
                UpdateAction.PRIMARY_PRUNE_FILL,
                physics_signature_changed=False,
                hit_table_signature_changed=prune_hit_table_identity_changed,
                q_group_content_signature_changed=True,
                detector_geometry_changed=False,
            )
            subset_payload = _build_scaled_primary_subset_payload(
                incremental_sf_prune_action.missing_keys
            )
            simulation_job = _build_simulation_job(
                collect_hit_tables_enabled=False,
                job_kind="primary_fill",
                primary_job_data=subset_payload["primary_data"],
                primary_job_intensities=subset_payload["primary_intensities"],
                primary_job_keys=subset_payload["primary_contribution_keys"],
                run_secondary_job=False,
            )
            if not bool(simulation_job.get("run_primary", False)):
                incremental_sf_prune_action = gui_runtime_primary_cache.IncrementalSfPruneAction(
                    mode="full",
                    added_keys=incremental_sf_prune_action.added_keys,
                    removed_keys=incremental_sf_prune_action.removed_keys,
                    missing_keys=incremental_sf_prune_action.missing_keys,
                    reason="invalid_fill_subset",
                )
            else:
                request_status = _request_async_simulation_job(simulation_job)
                if (
                    request_status in {"submitted", "queued", "running"}
                    and "progress_label" in globals()
                    and progress_label is not None
                ):
                    progress_label.config(text="Extending primary cache in background...")
                simulation_runtime_state.update_running = False
                return
        if incremental_sf_prune_action.mode == "full":
            simulation_job = _build_simulation_job(
                collect_hit_tables_enabled=collect_hit_tables_for_job
            )
            has_cached_simulation = (
                simulation_runtime_state.stored_primary_sim_image is not None
                or simulation_runtime_state.stored_secondary_sim_image is not None
            )
            if (
                not has_cached_simulation
                and simulation_runtime_state.worker_active_job is None
                and simulation_runtime_state.worker_queued_job is None
            ):
                if "progress_label" in globals() and progress_label is not None:
                    progress_label.config(text="Computing initial simulation...")
                    try:
                        root.update_idletasks()
                    except Exception:
                        pass
                sync_result = _run_simulation_generation_job(
                    {
                        **simulation_job,
                        "job_id": 0,
                    }
                )
                _apply_ready_simulation_result(sync_result)
                simulation_runtime_state.last_sim_signature = new_sim_image_sig
                simulation_runtime_state.last_simulation_signature = new_sim_sig
                simulation_runtime_state.primary_filter_signature = (
                    primary_requested_filter_signature
                )
                applied_peak_row_refresh_payload = dict(sync_result)
                image_generation_cached = False
                image_generation_elapsed_ms = float(
                    sync_result.get("image_generation_elapsed_ms", 0.0)
                )
                simulation_runtime_state.update_phase = "applying"
                _refresh_run_status_bar()
            else:
                request_status = _request_async_simulation_job(simulation_job)
                if (
                    request_status in {"submitted", "queued", "running"}
                    and "progress_label" in globals()
                    and progress_label is not None
                ):
                    progress_label.config(text="Computing simulation in background...")
                if request_status != "ready":
                    simulation_runtime_state.update_running = False
                    return
    elif (
        ready_simulation_result is None
        and need_hit_table_refresh
        and not display_only_fast_path
        and not combine_only_fast_path
    ):
        request_status = _request_async_simulation_job(
            _build_simulation_job(collect_hit_tables_enabled=True)
        )
        if (
            request_status in {"submitted", "queued", "running"}
            and "progress_label" in globals()
            and progress_label is not None
        ):
            progress_label.config(text="Refreshing peak tables in background...")

    if (
        simulation_runtime_state.stored_primary_sim_image is None
        and simulation_runtime_state.stored_secondary_sim_image is None
    ):
        simulation_runtime_state.update_phase = "queued"
        _refresh_run_status_bar()
        simulation_runtime_state.update_running = False
        return

    previous_row_content_signature = pre_update_row_content_signature
    applied_active_peak_row_sides: tuple[str, ...] = ()
    applied_primary_raw_rows_fresh = False
    applied_secondary_raw_rows_fresh = False
    all_active_raw_rows_fresh = False
    if applied_peak_row_refresh_payload is not None:
        applied_active_peak_row_sides = _normalized_active_peak_row_sides(
            applied_peak_row_refresh_payload.get("active_peak_row_sides", ())
        )
        if "active_peak_row_sides" not in applied_peak_row_refresh_payload:
            applied_active_peak_row_sides = _active_peak_row_sides_for_job(
                job_kind=str(applied_peak_row_refresh_payload.get("job_kind", "full")),
                run_primary=bool(applied_peak_row_refresh_payload.get("run_primary", False)),
                run_secondary=bool(applied_peak_row_refresh_payload.get("run_secondary", False)),
                secondary_available=bool(
                    applied_peak_row_refresh_payload.get(
                        "secondary_available",
                        applied_peak_row_refresh_payload.get("run_secondary", False),
                    )
                ),
            )
        applied_primary_raw_rows_fresh = bool(
            applied_peak_row_refresh_payload.get(
                "primary_raw_rows_fresh",
                applied_peak_row_refresh_payload.get(
                    "primary_hit_table_state_refreshed",
                    False,
                ),
            )
        )
        applied_secondary_raw_rows_fresh = bool(
            applied_peak_row_refresh_payload.get(
                "secondary_raw_rows_fresh",
                applied_peak_row_refresh_payload.get(
                    "secondary_hit_table_state_refreshed",
                    False,
                ),
            )
        )
        all_active_raw_rows_fresh = _active_peak_row_sides_have_fresh_raw_rows(
            applied_active_peak_row_sides,
            primary_raw_rows_fresh=applied_primary_raw_rows_fresh,
            secondary_raw_rows_fresh=applied_secondary_raw_rows_fresh,
        )
    publish_active_peak_row_sides = None
    if applied_peak_row_refresh_payload is not None:
        publish_active_peak_row_sides = (
            applied_active_peak_row_sides if all_active_raw_rows_fresh else ()
        )
    if display_only_fast_path:
        run_primary = bool(
            simulation_runtime_state.stored_primary_sim_image is not None
            and abs(float(primary_weight_value)) > 1e-12
        )
        run_secondary = bool(
            simulation_runtime_state.stored_secondary_sim_image is not None
            and abs(float(secondary_weight_value)) > 1e-12
        )
        updated_image = simulation_runtime_state.stored_sim_image
        max_positions_local = list(simulation_runtime_state.stored_max_positions_local or [])
        combined_state_diagnostics = {
            "run_primary": bool(run_primary),
            "run_secondary": bool(run_secondary),
            "combined_row_count": int(_table_row_count(max_positions_local)),
        }
    else:
        combined_state_diagnostics = _publish_combined_simulation_state(
            image_size_value=int(image_size),
            primary_a_value=float(a_updated),
            primary_c_value=float(c_updated),
            secondary_a_value=float(secondary_a),
            secondary_c_value=float(secondary_c),
            active_peak_row_sides=publish_active_peak_row_sides,
            theta_initial_value=float(theta_init_up),
        )
        run_primary = bool(combined_state_diagnostics.get("run_primary", False))
        run_secondary = bool(combined_state_diagnostics.get("run_secondary", False))
        updated_image = simulation_runtime_state.stored_sim_image
        max_positions_local = list(simulation_runtime_state.stored_max_positions_local or [])
    if applied_peak_row_refresh_payload is not None:
        if all_active_raw_rows_fresh:
            applied_job_kind = str(
                applied_peak_row_refresh_payload.get("job_kind", "full") or "full"
            )
            if applied_job_kind == "detector_center_remap":
                applied_policy_action = UpdateAction.DETECTOR_CENTER_REMAP
            elif applied_job_kind == "primary_fill":
                applied_policy_action = UpdateAction.PRIMARY_PRUNE_FILL
            else:
                applied_policy_action = UpdateAction.FULL_SIMULATION
            pending_row_content_signature = getattr(
                simulation_runtime_state,
                "stored_q_group_content_signature",
                None,
            )
            _invalidate_picker_handoff_caches_for_update_action(
                applied_policy_action,
                physics_signature_changed=applied_policy_action is UpdateAction.FULL_SIMULATION,
                hit_table_signature_changed=applied_policy_action
                in {UpdateAction.FULL_SIMULATION, UpdateAction.PRIMARY_PRUNE_FILL},
                q_group_content_signature_changed=(
                    applied_policy_action is not UpdateAction.DETECTOR_CENTER_REMAP
                    and pending_row_content_signature != previous_row_content_signature
                ),
                detector_geometry_changed=False,
            )
        _restore_live_peak_rows_from_combined_hit_tables(
            active_peak_row_sides=applied_active_peak_row_sides,
            primary_raw_rows_fresh=applied_primary_raw_rows_fresh,
            secondary_raw_rows_fresh=applied_secondary_raw_rows_fresh,
            previous_row_content_signature=previous_row_content_signature,
        )

    refresh_q_group_listing_requested = bool(
        getattr(geometry_q_group_state, "refresh_requested", False)
    )
    current_row_content_signature = getattr(
        simulation_runtime_state,
        "stored_q_group_content_signature",
        None,
    )
    current_hit_table_signature_after_apply = getattr(
        simulation_runtime_state,
        "stored_hit_table_signature",
        None,
    )
    q_group_listing_decision = classify_q_group_refresh(
        explicit_refresh_requested=refresh_q_group_listing_requested,
        picker_refresh_required=False,
        active_selection_sides=bool(active_selection_sides),
        previous_hit_table_signature=pre_update_hit_table_signature,
        current_hit_table_signature=current_hit_table_signature_after_apply,
        previous_q_group_content_signature=previous_row_content_signature,
        current_q_group_content_signature=current_row_content_signature,
        image_signature_changed=initial_image_signature_changed,
    )
    if not need_hit_table_refresh and q_group_listing_decision.refresh_listing:
        if refresh_q_group_listing_requested:
            # fmt: off
            gui_controllers.consume_geometry_q_group_refresh_request(
                geometry_q_group_state
            )
            # fmt: on
        q_group_bindings_factory = globals().get("geometry_q_group_runtime_bindings_factory")
        if callable(q_group_bindings_factory):
            disordered_qr_status = _geometry_disordered_phase_qr_enable_status()
            disordered_refresh = _ensure_generated_disordered_qr_rows_for_live_refresh(
                disordered_qr_status,
                primary_a=float(a_updated),
                primary_c=float(c_updated),
            )
            if not disordered_refresh.can_refresh_selector:
                if disordered_refresh.scheduled_collection:
                    gui_controllers.request_geometry_q_group_refresh(geometry_q_group_state)
                    schedule_update_fn = globals().get("schedule_update")
                    if callable(schedule_update_fn):
                        schedule_update_fn()
                    simulation_runtime_state.update_phase = "queued"
                else:
                    simulation_runtime_state.update_phase = "ready"
                try:
                    progress_label_geometry.config(text=disordered_refresh.visible_message)
                except Exception:
                    pass
                simulation_runtime_state.update_running = False
                _refresh_run_status_bar()
                return
            listed_entries = (
                gui_geometry_q_group_manager.capture_runtime_geometry_q_group_entries_snapshot(
                    q_group_bindings_factory()
                )
            )
            q_group_update_message = _format_qr_qz_group_update_log_message(listed_entries)
            progress_label_geometry.config(text=q_group_update_message)

    redraw_update_start_time = perf_counter()
    display_image = np.rot90(updated_image, SIM_DISPLAY_ROTATE_K)
    refresh_peak_selection = getattr(
        peak_selection_runtime_maintenance,
        "refresh_after_simulation_update",
        None,
    )
    if callable(refresh_peak_selection):
        refresh_peak_selection(bool(_live_geometry_preview_enabled()))
    normalization_scale = 1.0
    normalization_sig = None
    native_background = _get_current_background_backend()
    if native_background is not None and display_image is not None:
        normalization_sig = (
            new_sim_image_sig,
            int(background_runtime_state.current_background_index),
            id(background_runtime_state.current_background_image),
            tuple(display_image.shape),
            tuple(np.asarray(native_background).shape),
        )
        if simulation_runtime_state.normalization_scale_cache.get("sig") == normalization_sig:
            normalization_scale = float(
                simulation_runtime_state.normalization_scale_cache.get("value", 1.0)
            )
        else:
            normalization_scale = _suggest_scale_factor(display_image, native_background)
            simulation_runtime_state.normalization_scale_cache["sig"] = normalization_sig
            simulation_runtime_state.normalization_scale_cache["value"] = float(normalization_scale)
        if not np.isfinite(normalization_scale) or normalization_scale <= 0.0:
            normalization_scale = 1.0

    simulation_runtime_state.unscaled_image = None
    simulation_runtime_state.last_unscaled_image_signature = None
    if display_image is not None:
        if abs(float(normalization_scale) - 1.0) <= 1e-12:
            simulation_runtime_state.unscaled_image = display_image
        else:
            simulation_runtime_state.unscaled_image = display_image * normalization_scale
        simulation_runtime_state.last_unscaled_image_signature = (
            new_sim_image_sig,
            round(float(normalization_scale), 9),
            tuple(display_image.shape),
            int(background_runtime_state.current_background_index),
            id(background_runtime_state.current_background_image),
        )
        if simulation_runtime_state.peak_intensities and normalization_scale != 1.0:
            simulation_runtime_state.peak_intensities[:] = [
                intensity * normalization_scale
                for intensity in simulation_runtime_state.peak_intensities
            ]
            for rec in simulation_runtime_state.peak_records:
                rec["intensity"] = float(rec.get("intensity", 0.0)) * normalization_scale
    else:
        simulation_runtime_state.stored_simulation_q_space_geometry = None

    simulation_runtime_state.last_1d_integration_data["simulated_2d_image"] = (
        simulation_runtime_state.unscaled_image
    )

    if simulation_runtime_state.unscaled_image is not None:
        if display_controls_state.scale_factor_user_override:
            _set_scale_factor_value(
                _get_scale_factor_value(default=1.0),
                adjust_range=False,
                reset_override=False,
            )
        else:
            _set_scale_factor_value(
                1.0,
                adjust_range=False,
                reset_override=True,
            )
    # ---------------------------------------------------------------
    # The exact-cake analysis integrator setup is relatively expensive. Cache
    # the runtime integrator instance and only recreate it when the detector
    # distance, detector center, or pixel size changes. Tilt updates intentionally
    # do not flush the detector-map or LUT
    # caches so the live detector<->angle transform stays stable during geometry
    # work.
    # ---------------------------------------------------------------
    sig = _caked_geometry_cache_signature(
        corto_det_up,
        center_x_up,
        center_y_up,
        pixel_size_m,
    )
    if simulation_runtime_state.ai_cache.get("sig") != sig:
        simulation_runtime_state.ai_cache = {
            "sig": sig,
            "ai": ExactCakeIntegrator(
                PortableGeometry(
                    pixel_size_m=pixel_size_m,
                    distance_m=corto_det_up,
                    center_row_px=center_x_up,
                    center_col_px=center_y_up,
                )
            ),
        }
    caked_correct_solid_angle = False
    sim_caking_sig = (
        new_sim_image_sig,
        sig,
        round(float(normalization_scale), 9),
        caked_correct_solid_angle,
    )
    bg_caking_sig = None
    if native_background is not None:
        bg_caking_sig = (
            sig,
            int(background_runtime_state.current_background_index),
            id(background_runtime_state.current_background_image),
            tuple(np.asarray(native_background).shape),
            caked_correct_solid_angle,
        )

    show_caked_2d = bool(analysis_view_controls_view_state.show_caked_2d_var.get())
    requested_view_mode = _current_app_shell_view_mode()
    q_space_requested = bool(
        simulation_runtime_state.unscaled_image is not None and requested_view_mode == "q_space"
    )
    show_1d_requested = bool(analysis_view_controls_view_state.show_1d_var.get())
    one_d_analysis_requested = bool(
        (not qr_cylinder_replace_requested)
        and show_1d_requested
        and _analysis_integration_outputs_visible()
    )
    caked_analysis_requested = bool(
        show_caked_2d and simulation_runtime_state.unscaled_image is not None
    )
    caked_outputs_requested = bool(caked_analysis_requested or one_d_analysis_requested)
    q_space_geometry = _current_q_space_geometry_for_stored_simulation()
    if q_space_geometry is None:
        q_space_geometry = _current_q_space_geometry_from_live_controls(
            distance_m=corto_det_up,
            center=np.asarray([center_x_up, center_y_up], dtype=np.float64),
            pixel_size_m_value=pixel_size_m,
            wavelength_m_value=wave_m,
            gamma_deg=gamma_updated,
            Gamma_deg=Gamma_updated,
            chi_deg=chi_updated,
            psi_deg=psi,
            psi_z_deg=psi_z_updated,
            theta_initial_deg=theta_init_up,
            cor_angle_deg=cor_angle_updated,
            zs=zs_updated,
            zb=zb_updated,
        )
    q_space_payload_geometry_sig = _q_space_geometry_cache_signature_from_geometry(q_space_geometry)
    q_space_geometry_sig = q_space_payload_geometry_sig if q_space_requested else None
    caked_intensity_mode = _current_caked_intensity_mode()
    analysis_requested = bool(
        simulation_runtime_state.unscaled_image is not None
        and (caked_outputs_requested or q_space_requested)
    )
    analysis_sig = (
        (
            sim_caking_sig,
            bg_caking_sig,
            q_space_geometry_sig,
            bool(caked_outputs_requested),
            bool(q_space_requested),
            caked_intensity_mode,
        )
        if analysis_requested
        else None
    )
    if q_space_requested and not caked_outputs_requested:
        analysis_bins = (
            DEFAULT_Q_SPACE_DISPLAY_QR_BINS,
            DEFAULT_Q_SPACE_DISPLAY_QZ_BINS,
        )
    else:
        analysis_bins = (DEFAULT_ANALYSIS_RADIAL_BINS, DEFAULT_ANALYSIS_AZIMUTH_BINS)
    sim_cache_sig = (sim_caking_sig, int(analysis_bins[0]), int(analysis_bins[1]))
    bg_cache_sig = (
        (bg_caking_sig, int(analysis_bins[0]), int(analysis_bins[1]))
        if bg_caking_sig is not None
        else None
    )
    current_analysis_cache_sig = (sim_cache_sig, bg_cache_sig)
    _invalidate_hidden_analysis_space_payloads_if_stale(
        caked_analysis_requested=caked_analysis_requested,
        q_space_requested=q_space_requested,
        current_analysis_cache_sig=current_analysis_cache_sig,
        q_space_payload_geometry_sig=q_space_payload_geometry_sig,
    )
    ready_analysis_result = None
    if analysis_sig is not None:
        ready_analysis_result = _consume_ready_analysis_result(
            analysis_sig,
            is_preview=False,
            sim_cache_sig=sim_cache_sig,
            bg_cache_sig=bg_cache_sig,
        )
        if ready_analysis_result is not None:
            _apply_ready_analysis_result(ready_analysis_result)
            if one_d_analysis_requested and not bool(
                ready_analysis_result.get("is_preview", False)
            ):
                _refresh_integration_from_cached_results()
            simulation_runtime_state.update_phase = "applying"
            _refresh_run_status_bar()

    has_current_caked_product = bool(
        (not caked_outputs_requested) or simulation_runtime_state.last_res2_sim is not None
    )
    has_current_q_space_product = bool(
        (not q_space_requested)
        or (
            simulation_runtime_state.last_q_space_image_unscaled is not None
            and simulation_runtime_state.last_q_space_extent is not None
            and getattr(simulation_runtime_state, "last_q_space_payload_signature", None)
            == (current_analysis_cache_sig, q_space_geometry_sig)
        )
    )
    analysis_result_current = bool(
        analysis_sig is not None
        and simulation_runtime_state.last_analysis_signature == analysis_sig
        and getattr(simulation_runtime_state, "last_analysis_cache_sig", None)
        == current_analysis_cache_sig
        and has_current_caked_product
        and has_current_q_space_product
    )
    analysis_payload_ready = _analysis_display_payload_ready(
        show_caked_2d=show_caked_2d,
        q_space_requested=q_space_requested,
        background_visible=bool(background_runtime_state.visible),
        caked_image=simulation_runtime_state.last_caked_image_unscaled,
        caked_extent=simulation_runtime_state.last_caked_extent,
        caked_background_image=simulation_runtime_state.last_caked_background_image_unscaled,
        q_space_image=simulation_runtime_state.last_q_space_image_unscaled,
        q_space_extent=simulation_runtime_state.last_q_space_extent,
        q_space_background_image=(simulation_runtime_state.last_q_space_background_image_unscaled),
    )
    missing_analysis_payload = bool(analysis_result_current and not analysis_payload_ready)
    if missing_analysis_payload:
        analysis_payload_ready = _analysis_payload_ready_after_restore_attempt(
            analysis_result_current=analysis_result_current,
            show_caked_2d=show_caked_2d,
            q_space_requested=q_space_requested,
            background_visible=bool(background_runtime_state.visible),
            restore_payload=lambda: _restore_caked_display_payload_from_cached_results(
                background_visible=bool(background_runtime_state.visible),
            ),
        )
    analysis_result_matches_target = bool(
        analysis_result_current
        and not bool(simulation_runtime_state.analysis_preview_active)
        and analysis_payload_ready
    )
    analysis_request_in_flight = bool(
        analysis_sig is not None
        and any(
            _analysis_job_key(payload)
            == (
                analysis_sig,
                int(simulation_runtime_state.analysis_epoch),
                False,
                sim_cache_sig,
                bg_cache_sig,
            )
            for payload in (
                simulation_runtime_state.analysis_ready_result,
                simulation_runtime_state.analysis_active_job,
                simulation_runtime_state.analysis_queued_job,
            )
        )
    )
    if (
        analysis_sig is not None
        and (not analysis_result_matches_target)
        and not analysis_request_in_flight
    ):
        cached_bg_entry = _get_cached_caking_entry("bg", bg_cache_sig)
        preserve_caked_visuals = bool(
            show_caked_2d
            and simulation_runtime_state.last_caked_image_unscaled is not None
            and simulation_runtime_state.last_caked_extent is not None
        )
        _invalidate_analysis_cache(clear_visuals=not preserve_caked_visuals)
        _request_async_analysis_job(
            {
                "signature": analysis_sig,
                "epoch": int(simulation_runtime_state.analysis_epoch),
                "is_preview": False,
                "npt_rad": int(analysis_bins[0]),
                "npt_azim": int(analysis_bins[1]),
                "sim_cache_sig": sim_cache_sig,
                "bg_cache_sig": bg_cache_sig,
                "image": np.asarray(
                    simulation_runtime_state.unscaled_image,
                    dtype=np.float64,
                ).copy(),
                "background_image": (
                    None
                    if not (background_runtime_state.visible and native_background is not None)
                    else np.asarray(native_background, dtype=np.float64).copy()
                ),
                "cached_bg_res2": (
                    None if not isinstance(cached_bg_entry, dict) else cached_bg_entry.get("res2")
                ),
                "cached_bg_caked": (
                    None
                    if not isinstance(cached_bg_entry, dict)
                    else cached_bg_entry.get("payload")
                ),
                "intersection_cache": _copy_intersection_cache_tables(
                    simulation_runtime_state.stored_intersection_cache
                ),
                "intersection_cache_source_signature": (
                    _current_combined_detector_intersection_cache_signature()
                ),
                "distance_m": float(q_space_geometry["distance_m"]),
                "center": np.asarray(q_space_geometry["center"], dtype=np.float64).copy(),
                "pixel_size_m": float(q_space_geometry["pixel_size_m"]),
                "wavelength_m": float(q_space_geometry["wavelength_m"]),
                "gamma_deg": float(q_space_geometry["gamma_deg"]),
                "Gamma_deg": float(q_space_geometry["Gamma_deg"]),
                "chi_deg": float(q_space_geometry["chi_deg"]),
                "psi_deg": float(q_space_geometry["psi_deg"]),
                "psi_z_deg": float(q_space_geometry["psi_z_deg"]),
                "theta_initial_deg": float(q_space_geometry["theta_initial_deg"]),
                "cor_angle_deg": float(q_space_geometry["cor_angle_deg"]),
                "zs": float(q_space_geometry["zs"]),
                "zb": float(q_space_geometry["zb"]),
                "q_space_geometry": _copy_q_space_geometry(q_space_geometry),
                "q_space_requested": q_space_requested,
                "caked_outputs_requested": caked_outputs_requested,
                "caked_correct_solid_angle": caked_correct_solid_angle,
                "caked_intensity_mode": caked_intensity_mode,
                "requested_view_mode": requested_view_mode,
                "sim_caking_sig": sim_caking_sig,
                "bg_caking_sig": bg_caking_sig,
            }
        )
        if "progress_label" in globals() and progress_label is not None:
            progress_label.config(text=_analysis_progress_text())

    sim_res2 = simulation_runtime_state.last_res2_sim if analysis_result_current else None
    bg_res2 = simulation_runtime_state.last_res2_background if analysis_result_current else None
    _clear_pending_main_figure_preview_interaction()
    previous_primary_view_mode = _current_primary_figure_mode()
    preserved_primary_limits = gui_canvas_interactions.capture_axis_limits(ax)
    defer_overlay_refresh = _defer_nonessential_redraw()
    target_primary_view_mode = _apply_primary_figure_display_from_cached_results(
        previous_primary_view_mode,
        preserved_primary_limits,
    )

    if not defer_overlay_refresh:
        _sync_selected_qr_rod_controls_state()

    # 1D integration
    if one_d_analysis_requested and sim_res2 is not None and not defer_overlay_refresh:
        _update_1d_plots_from_caked(sim_res2, bg_res2)
    elif not defer_overlay_refresh:
        _clear_1d_plot_cache_and_lines()

    if analysis_result_current:
        simulation_runtime_state.last_res2_sim = sim_res2
        simulation_runtime_state.last_res2_background = bg_res2

    # Recompute the slider bounds from the current simulation on every refresh.
    # Manual overrides are preserved unless they exceed the refreshed bounds.
    current_unscaled_image_signature = getattr(
        simulation_runtime_state,
        "last_unscaled_image_signature",
        None,
    )
    apply_scale_factor_to_existing_results(
        update_limits=False,
        update_1d=False,
        force_canvas_redraw=(previous_primary_view_mode != target_primary_view_mode),
        update_chi_square=not defer_overlay_refresh,
    )
    _capture_geometry_fit_review_new_image_after_update()

    if defer_overlay_refresh:
        if _live_interaction_active():
            _clear_deferred_overlays(clear_qr_overlay=True)
        else:
            qr_cylinder_overlay_runtime_refresh(redraw=True, update_status=False)
            _clear_deferred_overlays(clear_qr_overlay=False)
    else:
        _refresh_settled_overlays()

    desired_detector_signature = _detector_display_raster_source_signature()
    detector_artist_signature_after = _current_detector_artist_source_signature()
    first_visible_detector_simulation_after_update = bool(
        target_primary_view_mode == "detector"
        and desired_detector_signature is not None
        and detector_artist_signature_after == desired_detector_signature
        and detector_artist_signature_before != desired_detector_signature
    )
    if first_visible_detector_simulation_after_update:
        _schedule_post_idle_main_canvas_redraw()
    if current_unscaled_image_signature is None:
        gui_controllers.clear_tk_after_token(
            root,
            getattr(simulation_runtime_state, "first_visible_simulation_settle_token", None),
        )
        simulation_runtime_state.first_visible_simulation_settle_token = None
        simulation_runtime_state.first_visible_simulation_settled_signature = None
    elif (
        target_primary_view_mode == "detector"
        and not bool(simulation_runtime_state.preview_active)
        and simulation_runtime_state.worker_active_job is None
        and simulation_runtime_state.worker_queued_job is None
        and not _live_interaction_active()
        and current_unscaled_image_signature
        != getattr(
            simulation_runtime_state,
            "first_visible_simulation_settled_signature",
            None,
        )
    ):
        _schedule_first_visible_simulation_settle_pass()

    redraw_update_elapsed_ms = (perf_counter() - redraw_update_start_time) * 1e3
    total_update_elapsed_ms = (perf_counter() - update_start_time) * 1e3
    image_generation_text = (
        "cached" if image_generation_cached else f"{image_generation_elapsed_ms:.1f} ms"
    )
    if "update_timing_label" in globals():
        update_timing_label.config(
            text=(
                "Timing | image generation: "
                f"{image_generation_text} | redraw/update: "
                f"{redraw_update_elapsed_ms:.1f} ms | total: "
                f"{total_update_elapsed_ms:.1f} ms"
            )
        )

    # mark update completion so future updates can run
    simulation_runtime_state.last_total_update_ms = float(total_update_elapsed_ms)
    if simulation_runtime_state.worker_active_job is not None:
        simulation_runtime_state.update_phase = "computing"
    elif simulation_runtime_state.worker_queued_job is not None:
        simulation_runtime_state.update_phase = "queued"
    elif simulation_runtime_state.analysis_active_job is not None:
        simulation_runtime_state.update_phase = "analyzing"
    elif simulation_runtime_state.analysis_queued_job is not None:
        simulation_runtime_state.update_phase = "queued"
    else:
        simulation_runtime_state.update_phase = "ready"
    dependency_image_signature_applied = bool(
        getattr(simulation_runtime_state, "last_sim_signature", None) == new_sim_image_sig
    )
    dependency_full_signature_applied = bool(
        getattr(simulation_runtime_state, "last_simulation_signature", None) == new_sim_sig
        or (
            effective_update_action in {UpdateAction.DISPLAY_ONLY, UpdateAction.COMBINE_ONLY}
            and dependency_image_signature_applied
        )
    )
    dependency_signatures_applied = bool(
        dependency_image_signature_applied
        and dependency_full_signature_applied
        and getattr(simulation_runtime_state, "worker_active_job", None) is None
        and getattr(simulation_runtime_state, "worker_queued_job", None) is None
        and getattr(simulation_runtime_state, "worker_future", None) is None
        and getattr(simulation_runtime_state, "worker_poll_token", None) is None
        and getattr(simulation_runtime_state, "worker_ready_result", None) is None
        and getattr(simulation_runtime_state, "analysis_active_job", None) is None
        and getattr(simulation_runtime_state, "analysis_queued_job", None) is None
        and getattr(simulation_runtime_state, "analysis_future", None) is None
        and getattr(simulation_runtime_state, "analysis_poll_token", None) is None
        and getattr(simulation_runtime_state, "analysis_ready_result", None) is None
    )
    if dependency_signatures_applied:
        simulation_runtime_state.last_dependency_signatures = current_dependency_signatures
    _complete_simulation_update_and_schedule_geometry_manual_prewarm()
    if "progress_label" in globals() and progress_label is not None:
        try:
            current_progress_text = str(progress_label.cget("text"))
        except Exception:
            current_progress_text = ""
        if (
            simulation_runtime_state.preview_active
            and simulation_runtime_state.worker_active_job is not None
        ):
            progress_label.config(text="Preview ready, refining full simulation...")
        elif simulation_runtime_state.analysis_active_job is not None:
            progress_label.config(text=_analysis_progress_text())
        elif current_progress_text in {
            "Computing initial simulation...",
            "Computing preview simulation...",
            "Computing simulation in background...",
            "Simulation loading in background...",
            "Preview ready, refining full simulation...",
            "Updating low-res caked preview...",
            "Updating caked integration in background...",
        }:
            progress_label.config(text="Simulation ready.")
    _refresh_run_status_bar()


