def _apply_full_gui_state_snapshot(snapshot: dict[str, object]) -> str:

    if not isinstance(snapshot, dict):
        raise ValueError("GUI state v1 state must be an object.")
    required_sections = {
        "variables",
        "dynamic_lists",
        "files",
        "geometry",
        "analysis_range",
    }
    missing_sections = sorted(required_sections - set(snapshot))
    unexpected_sections = sorted(set(snapshot) - required_sections)
    if missing_sections or unexpected_sections:
        raise ValueError(
            "GUI state v1 requires exactly variables, dynamic_lists, files, geometry, "
            f"and analysis_range; missing={missing_sections}, unexpected={unexpected_sections}"
        )
    for section_name in required_sections:
        if not isinstance(snapshot[section_name], Mapping):
            raise ValueError(f"GUI state v1 {section_name} must be an object.")

    warnings: list[str] = []

    warnings.extend(
        gui_state_io.apply_gui_state_files(
            snapshot.get("files", {}),
            apply_primary_cif_path=_apply_primary_cif_path,
            apply_secondary_cif_path=_apply_secondary_cif_path,
            load_background_files=_load_background_files_for_import_state,
        )
    )

    variables = snapshot.get("variables", {})
    warnings.extend(
        gui_state_io.apply_gui_state_variables(
            variables,
            global_items=_gui_state_variable_items(),
            tk_variable_type=tk.Variable,
        )
    )
    defaults["parratt_low_q_stitch"] = bool(_current_parratt_low_q_stitch_enabled())
    restored_parratt_settings = _current_parratt_optics_settings()
    defaults["parratt_use_cif_optics"] = bool(restored_parratt_settings["parratt_use_cif_optics"])
    defaults["parratt_n_real"] = float(restored_parratt_settings["parratt_n_real"])
    defaults["parratt_n_imag"] = float(restored_parratt_settings["parratt_n_imag"])
    if bool(structure_model_state.has_second_cif):
        try:
            update_weights()
        except Exception as exc:
            warnings.append(f"secondary CIF weights: {exc}")
    _apply_analysis_range_snapshot(snapshot.get("analysis_range", {}))

    gui_state_io.apply_dynamic_gui_state_lists(
        snapshot.get("dynamic_lists", {}),
        occ_vars=_occupancy_control_vars(),
        atom_site_fract_vars=_atom_site_fractional_control_vars(),
    )

    geometry_snapshot = (
        snapshot.get("geometry", {}) if isinstance(snapshot.get("geometry"), Mapping) else {}
    )
    geometry_state = gui_state_io.apply_gui_state_geometry(
        geometry_snapshot,
        apply_geometry_manual_pairs_snapshot=_apply_geometry_manual_pairs_snapshot,
        current_background_index=background_runtime_state.current_background_index,
        selected_hkl_target=peak_selection_state.selected_hkl_target,
    )
    apply_selected_hkl_target = getattr(
        peak_selection_runtime_maintenance,
        "apply_restored_selected_hkl_target",
        None,
    )
    if callable(apply_selected_hkl_target):
        apply_selected_hkl_target(geometry_state["selected_hkl_target"])
    warnings.extend(list(geometry_state["warnings"]))
    if finite_stack_controls_view_state.phase_delta_entry_var is not None:
        gui_views.set_finite_stack_phase_delta_entry_text(
            finite_stack_controls_view_state,
            _current_phase_delta_expression(),
        )
    if finite_stack_controls_view_state.phi_l_divisor_entry_var is not None:
        gui_views.set_finite_stack_phi_l_divisor_entry_text(
            finite_stack_controls_view_state,
            gui_controllers.format_finite_stack_phi_l_divisor(_current_phi_l_divisor()),
        )
    _sync_finite_controls()
    _apply_rod_points_per_gz(trigger_update=False)
    _apply_geometry_fit_background_selection(trigger_update=False)
    _refresh_background_status()
    _update_geometry_preview_exclude_button_label()
    if bool(getattr(simulation_runtime_state, "gui_state_import_active", False)):
        _request_geometry_q_group_refresh_if_available()
    else:
        geometry_q_group_runtime_callbacks.refresh_window()
    peak_selection_runtime_callbacks.reselect_current_peak()
    _normalize_random_sample_count_control()
    toggle_1d_plots()
    toggle_caked_2d()
    toggle_log_display()
    _sync_primary_raster_geometry()
    _sync_selected_qr_rod_controls_state()
    if bool(analysis_peak_selection_state.pick_armed) and bool(
        _current_analysis_roi_values().get("integrate_selected_qr_rod", False)
    ):
        _set_analysis_peak_pick_mode(
            False,
            message="Analysis peak picking is disabled while selected Qr rod ROI mode is active.",
        )
    _mark_chi_square_dirty()
    _update_chi_square_display(force=True)
    qr_cylinder_overlay_runtime_refresh(redraw=True, update_status=False)
    _refresh_live_geometry_preview(update_status=False)
    schedule_update()

    return gui_state_io.build_gui_state_import_summary(warnings)


def _apply_gui_state_snapshot_for_manual_import(snapshot: dict[str, object]) -> str:
    previous_startup_updates_suspended = bool(
        getattr(simulation_runtime_state, "startup_updates_suspended", False)
    )
    previous_gui_state_import_active = bool(
        getattr(simulation_runtime_state, "gui_state_import_active", False)
    )
    previous_pending_startup_refresh = bool(
        getattr(simulation_runtime_state, "pending_startup_refresh", False)
    )
    pending_startup_refresh = False

    simulation_runtime_state.startup_updates_suspended = True
    simulation_runtime_state.gui_state_import_active = True
    simulation_runtime_state.pending_startup_refresh = False
    try:
        message = _apply_full_gui_state_snapshot(snapshot)
        pending_startup_refresh = bool(
            getattr(simulation_runtime_state, "pending_startup_refresh", False)
        )
    finally:
        simulation_runtime_state.startup_updates_suspended = previous_startup_updates_suspended
        simulation_runtime_state.gui_state_import_active = previous_gui_state_import_active
        simulation_runtime_state.pending_startup_refresh = previous_pending_startup_refresh

    if pending_startup_refresh and not previous_startup_updates_suspended:
        schedule_update()
    elif pending_startup_refresh:
        simulation_runtime_state.pending_startup_refresh = True
    return message


def _export_full_gui_state() -> None:
    try:
        initial_dir = str(get_dir("file_dialog_dir"))
    except Exception:
        initial_dir = str(Path.cwd())
    file_path = filedialog.asksaveasfilename(
        title="Export Full GUI State",
        initialdir=initial_dir,
        defaultextension=".json",
        filetypes=[("JSON files", "*.json"), ("All files", "*.*")],
        initialfile=f"ra_sim_gui_state_{datetime.now().strftime('%Y%m%d_%H%M%S')}.json",
    )
    if not file_path:
        progress_label.config(text="GUI state export canceled.")
        return
    try:
        save_gui_state_file(
            file_path,
            _collect_full_gui_state_snapshot(),
            metadata={"entrypoint": gui_manual_geometry.DEFAULT_GUI_ENTRYPOINT},
        )
    except Exception as exc:
        progress_label.config(text=f"Failed to export GUI state: {exc}")
        return
    progress_label.config(text=f"Saved GUI state to {file_path}")


def _import_full_gui_state() -> None:
    try:
        initial_dir = str(get_dir("file_dialog_dir"))
    except Exception:
        initial_dir = str(Path.cwd())
    file_path = filedialog.askopenfilename(
        title="Import Full GUI State",
        initialdir=initial_dir,
        filetypes=[
            ("SLATE-rMC GUI state", "*.json"),
            ("All files", "*.*"),
        ],
    )
    if not file_path:
        progress_label.config(text="GUI state import canceled.")
        return

    try:
        payload = load_gui_state_file(file_path)
        message = _apply_gui_state_snapshot_for_manual_import(payload.get("state", {}))
    except Exception as exc:
        progress_label.config(text=f"Failed to import GUI state: {exc}")
        return
    progress_label.config(text=message)


