def _geometry_source_signature_numeric(
    value: object,
    *,
    default: float = 0.0,
) -> float:
    try:
        numeric = float(value)
    except Exception:
        numeric = float(default)
    if not np.isfinite(numeric):
        numeric = float(default)
    return float(numeric)


def _geometry_source_rows_signature_from_params(
    param_set,
    *,
    mosaic_params,
    include_mosaic_shape: bool = True,
    sf_prune_bias: float,
    sf_prune_stats,
    ordered_structure_scale: float,
    qr_cylinder_replace_requested: bool,
    primary_source_signature,
    secondary_source_signature,
    secondary_a: float,
    secondary_c: float,
    disordered_phase_qr_reference_signature=None,
    rich_phase_component_signature=(),
):
    params = dict(param_set or {})

    def _param_value(*keys: str, default: object = 0.0) -> object:
        for key in keys:
            if key in params:
                return params.get(key)
        return default

    signature = (
        round(_geometry_source_signature_numeric(_param_value("gamma")), 6),
        round(_geometry_source_signature_numeric(_param_value("Gamma")), 6),
        round(_geometry_source_signature_numeric(_param_value("chi")), 6),
        round(_geometry_source_signature_numeric(_param_value("psi_z", "psi")), 6),
        round(_geometry_source_signature_numeric(_param_value("zs")), 9),
        round(_geometry_source_signature_numeric(_param_value("zb")), 9),
        round(_geometry_source_signature_numeric(_param_value("sample_width")), 9),
        round(_geometry_source_signature_numeric(_param_value("sample_length")), 9),
        round(_geometry_source_signature_numeric(_param_value("sample_depth")), 12),
        round(_geometry_source_signature_numeric(_param_value("debye_x")), 6),
        round(_geometry_source_signature_numeric(_param_value("debye_y")), 6),
        round(_geometry_source_signature_numeric(_param_value("a")), 6),
        round(_geometry_source_signature_numeric(_param_value("c")), 6),
        round(
            _geometry_source_signature_numeric(_param_value("theta_initial", "theta_init")),
            6,
        ),
        round(_geometry_source_signature_numeric(_param_value("cor", "cor_angle")), 6),
        round(_geometry_source_signature_numeric(_param_value("center_x")), 3),
        round(_geometry_source_signature_numeric(_param_value("center_y")), 3),
        round(
            _geometry_source_signature_numeric(_param_value("distance_m", "d", "corto_detector")),
            9,
        ),
        int(mosaic_params["solve_q_steps"]),
        round(float(mosaic_params["solve_q_rel_tol"]), 8),
        int(mosaic_params["solve_q_mode"]),
        int(mosaic_params.get("events_per_beam_phase", DEFAULT_EVENTS_PER_BEAM_PHASE)),
        tuple(mosaic_params.get("_sampling_signature", ())),
        round(_geometry_source_signature_numeric(sf_prune_bias), 3),
        int((sf_prune_stats or {}).get("qr_kept", 0)),
        int((sf_prune_stats or {}).get("hkl_primary_kept", 0)),
        round(_geometry_source_signature_numeric(ordered_structure_scale), 6),
        int(bool(qr_cylinder_replace_requested)),
        int(np.size(mosaic_params["beam_x_array"])),
        int(np.size(mosaic_params["theta_array"])),
        primary_source_signature,
        secondary_source_signature,
        disordered_phase_qr_reference_signature,
        rich_phase_component_signature,
        round(_geometry_source_signature_numeric(secondary_a), 6),
        round(_geometry_source_signature_numeric(secondary_c), 6),
    )
    if include_mosaic_shape:
        signature += (
            round(
                _geometry_source_signature_numeric(
                    _param_value(
                        "sigma_mosaic_deg",
                        default=mosaic_params.get("sigma_mosaic_deg", 0.0),
                    )
                ),
                6,
            ),
            round(
                _geometry_source_signature_numeric(
                    _param_value(
                        "gamma_mosaic_deg",
                        default=mosaic_params.get("gamma_mosaic_deg", 0.0),
                    )
                ),
                6,
            ),
            round(
                _geometry_source_signature_numeric(
                    _param_value("eta", default=mosaic_params.get("eta", 0.0))
                ),
                6,
            ),
        )
    return signature


def _geometry_source_rows_signature_for_background(
    param_set: dict[str, object] | None = None,
):
    params = dict(_current_geometry_fit_params())
    if isinstance(param_set, dict):
        params.update(dict(param_set))
    mosaic_params = build_mosaic_params()
    primary_source_signature = (
        (
            "qr",
            id(simulation_runtime_state.sim_primary_qr),
            len(simulation_runtime_state.sim_primary_qr),
        )
        if isinstance(simulation_runtime_state.sim_primary_qr, dict)
        and len(simulation_runtime_state.sim_primary_qr) > 0
        else (
            "miller",
            id(simulation_runtime_state.sim_miller1),
            tuple(np.asarray(simulation_runtime_state.sim_miller1).shape),
        )
    )
    secondary_source_signature = (
        "miller",
        id(simulation_runtime_state.sim_miller2),
        tuple(np.asarray(simulation_runtime_state.sim_miller2).shape),
    )
    primary_source_mode = _current_primary_source_mode()
    if primary_source_mode == "rich_phase":
        rich_phase_component_signature = _rich_phase_components_signature(
            _current_rich_phase_components()
        )
        stacking_p_signature = ()
        stacking_weight_signature = rich_phase_component_signature
    elif primary_source_mode == "polytype_2x2":
        rich_phase_component_signature = _polytype_components_signature()
        stacking_p_signature = ()
        stacking_weight_signature = rich_phase_component_signature
    else:
        rich_phase_component_signature = ()
        stacking_p_signature: tuple[object, ...] = ()
        try:
            stacking_p_signature = tuple(
                _geometry_source_signature_numeric(var.get()) for var in (p0_var, p1_var, p2_var)
            )
        except Exception:
            stacking_p_signature = ()
        stacking_weight_signature: tuple[object, ...] = ()
        try:
            stacking_weight_signature = tuple(
                _geometry_source_signature_numeric(value)
                for value in gui_controllers.normalize_stacking_weight_values(
                    [w0_var.get(), w1_var.get(), w2_var.get()]
                )
            )
        except Exception:
            stacking_weight_signature = ()
    primary_a = _geometry_source_signature_numeric(params.get("a"))
    primary_c = _geometry_source_signature_numeric(params.get("c"))
    secondary_a = (
        float(structure_model_state.av2)
        if structure_model_state.av2 is not None
        else primary_a
    )
    secondary_c = (
        float(structure_model_state.cv2)
        if structure_model_state.cv2 is not None
        else primary_c
    )
    image_signature = _geometry_source_rows_signature_from_params(
        params,
        mosaic_params=mosaic_params,
        include_mosaic_shape=True,
        sf_prune_bias=current_sf_prune_bias(),
        sf_prune_stats=simulation_runtime_state.sf_prune_stats,
        ordered_structure_scale=float(_current_ordered_structure_scale()),
        qr_cylinder_replace_requested=_qr_cylinder_replace_simulation_enabled(),
        primary_source_signature=primary_source_signature,
        secondary_source_signature=secondary_source_signature,
        disordered_phase_qr_reference_signature=_geometry_disordered_phase_source_signature(),
        rich_phase_component_signature=rich_phase_component_signature,
        secondary_a=secondary_a,
        secondary_c=secondary_c,
    )
    row_content_signature = gui_geometry_q_group_manager._geometry_q_group_signature_value(
        getattr(simulation_runtime_state, "stored_q_group_content_signature", None)
    )
    sf_picker_inventory_signature = (
        "sf_picker_inventory",
        str(getattr(simulation_runtime_state, "primary_source_mode", "")),
        str(getattr(simulation_runtime_state, "primary_requested_source_mode", "")),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_active_contribution_keys", ())
        ),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_requested_contribution_keys", ())
        ),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_filter_signature", None)
        ),
        gui_geometry_q_group_manager._geometry_q_group_signature_value(
            getattr(simulation_runtime_state, "primary_requested_filter_signature", None)
        ),
        tuple(sorted((simulation_runtime_state.sf_prune_stats or {}).items())),
        stacking_p_signature,
        stacking_weight_signature,
    )
    return image_signature + (row_content_signature, sf_picker_inventory_signature)


def _geometry_manual_set_runtime_peak_cache_from_projected_rows(
    projected_rows: Sequence[object] | None,
) -> None:
    normalized_projected_rows = [
        dict(entry) for entry in (projected_rows or ()) if isinstance(entry, Mapping)
    ]
    try:
        normalized_projected_rows = gui_controllers.filter_enabled_q_group_rows(
            normalized_projected_rows,
            geometry_q_group_state,
        )
    except Exception:
        normalized_projected_rows = [
            dict(entry) for entry in normalized_projected_rows or () if isinstance(entry, Mapping)
        ]

    restored_records: list[dict[str, object]] = []
    restored_positions: list[tuple[float, float]] = []
    restored_millers: list[tuple[int, int, int]] = []
    restored_intensities: list[float] = []
    use_caked_display = bool(_active_caked_primary_view())

    def _detector_mode_projected_point(
        entry: Mapping[str, object] | None,
    ) -> tuple[float, float] | None:
        if not isinstance(entry, Mapping):
            return None
        for key_x, key_y in (
            ("sim_col_raw", "sim_row_raw"),
            ("sim_col", "sim_row"),
            ("display_col", "display_row"),
        ):
            try:
                col = float(entry.get(key_x, np.nan))
                row = float(entry.get(key_y, np.nan))
            except Exception:
                continue
            if np.isfinite(col) and np.isfinite(row):
                return float(col), float(row)
        return None

    for raw_entry in normalized_projected_rows:
        peak_record = gui_manual_geometry.geometry_manual_canonicalize_live_source_entry(
            raw_entry,
            normalize_hkl_key=_normalize_hkl_key,
        )
        if peak_record is None:
            continue
        try:
            active_point = gui_manual_geometry._geometry_manual_entry_active_view_point(
                peak_record,
                use_caked_display=use_caked_display,
            )
        except Exception:
            active_point = None
        if active_point is None and not use_caked_display:
            active_point = _detector_mode_projected_point(peak_record)
        if active_point is None:
            continue
        try:
            active_col = float(active_point[0])
            active_row = float(active_point[1])
        except Exception:
            continue
        if not (np.isfinite(active_col) and np.isfinite(active_row)):
            continue

        hkl_value = peak_record.get("hkl")
        if not isinstance(hkl_value, tuple) or len(hkl_value) < 3:
            continue
        try:
            hkl_triplet = (
                int(hkl_value[0]),
                int(hkl_value[1]),
                int(hkl_value[2]),
            )
        except Exception:
            continue

        try:
            intensity = float(peak_record.get("weight", peak_record.get("intensity", 0.0)))
        except Exception:
            intensity = 0.0
        if not np.isfinite(intensity):
            intensity = 0.0

        peak_record["intensity"] = float(intensity)
        peak_record["weight"] = float(intensity)

        restored_records.append(peak_record)
        restored_positions.append((float(active_col), float(active_row)))
        restored_millers.append(hkl_triplet)
        restored_intensities.append(float(intensity))

    simulation_runtime_state.peak_records = restored_records
    simulation_runtime_state.peak_positions = restored_positions
    simulation_runtime_state.peak_positions_filtered = True
    simulation_runtime_state.peak_millers = restored_millers
    simulation_runtime_state.peak_intensities = restored_intensities
    simulation_runtime_state.selected_peak_record = None
    if restored_records:
        simulation_runtime_state.peak_overlay_cache = {
            "sig": None,
            "positions": list(restored_positions),
            "millers": list(restored_millers),
            "intensities": list(restored_intensities),
            "records": [dict(record) for record in restored_records],
            "peak_positions_filtered": True,
        }
    else:
        simulation_runtime_state.peak_overlay_cache = _empty_peak_overlay_cache()
    _invalidate_geometry_manual_pick_cache()


def _geometry_manual_set_runtime_peak_cache_from_source_rows(
    source_rows: Sequence[object] | None,
) -> None:
    projected_rows = [dict(entry) for entry in (source_rows or ()) if isinstance(entry, Mapping)]
    if callable(_project_geometry_manual_peaks_to_current_view):
        try:
            projected_rows = [
                dict(entry)
                for entry in (_project_geometry_manual_peaks_to_current_view(projected_rows) or ())
                if isinstance(entry, Mapping)
            ]
        except Exception:
            projected_rows = [
                dict(entry) for entry in (source_rows or ()) if isinstance(entry, Mapping)
            ]
    _geometry_manual_set_runtime_peak_cache_from_projected_rows(projected_rows)


_GEOMETRY_FIT_FROZEN_CENTROID_PROJECTION_BINDING_SCHEMA = (
    "geometry_fit_frozen_centroid_projection_binding_v1"
)
_GEOMETRY_FIT_FROZEN_CENTROID_PROJECTION_BINDING_FIELD = "frozen_centroid_projection_binding"


_geometry_fit_frozen_centroid_shape = gui_geometry_q_group_manager._positive_shape


def _geometry_fit_frozen_centroid_geometry(
    params: Mapping[str, object],
) -> PortableGeometry | None:
    center = gui_geometry_fit._geometry_fit_center_from_params(params)
    pixel_size = geometry_fit_pixel_size_m(params)
    try:
        distance = float(params.get("corto_detector", np.nan))
        pixel_size_value = float(pixel_size)
    except (TypeError, ValueError):
        return None
    if (
        center is None
        or not np.isfinite(distance)
        or distance <= 0.0
        or not np.isfinite(pixel_size_value)
        or pixel_size_value <= 0.0
    ):
        return None
    return PortableGeometry(
        pixel_size_m=float(pixel_size_value),
        distance_m=float(distance),
        center_row_px=float(center[0]),
        center_col_px=float(center[1]),
    )


def _geometry_fit_frozen_centroid_payload_bundle(
    projection_payload: Mapping[str, object],
) -> tuple[CakeTransformBundle, tuple[int, int], str] | None:
    """Validate one projection payload against its exact frozen bundle."""

    transform_bundle = projection_payload.get("transform_bundle")
    if not isinstance(transform_bundle, CakeTransformBundle):
        return None
    payload_shape = _geometry_fit_frozen_centroid_shape(projection_payload.get("detector_shape"))
    bundle_shape = _geometry_fit_frozen_centroid_shape(transform_bundle.detector_shape)
    if payload_shape is None or bundle_shape is None or payload_shape != bundle_shape:
        return None

    try:
        radial_axis = np.asarray(projection_payload.get("radial_axis"), dtype=np.float64).reshape(
            -1
        )
        azimuth_axis = np.asarray(projection_payload.get("azimuth_axis"), dtype=np.float64).reshape(
            -1
        )
        raw_azimuth_axis = np.asarray(
            projection_payload.get("raw_azimuth_axis"), dtype=np.float64
        ).reshape(-1)
        bundle_radial_axis = np.asarray(transform_bundle.radial_deg, dtype=np.float64).reshape(-1)
        bundle_gui_axis = np.asarray(transform_bundle.gui_azimuth_deg, dtype=np.float64).reshape(-1)
        bundle_raw_axis = np.asarray(transform_bundle.raw_azimuth_deg, dtype=np.float64).reshape(-1)
    except Exception:
        return None
    if (
        radial_axis.size < 2
        or azimuth_axis.size < 2
        or raw_azimuth_axis.size < 2
        or radial_axis.shape != bundle_radial_axis.shape
        or raw_azimuth_axis.shape != bundle_raw_axis.shape
        or azimuth_axis.shape != bundle_gui_axis.shape
        or not all(
            np.all(np.isfinite(axis))
            for axis in (
                radial_axis,
                azimuth_axis,
                raw_azimuth_axis,
                bundle_radial_axis,
                bundle_gui_axis,
                bundle_raw_axis,
            )
        )
        or not np.allclose(radial_axis, bundle_radial_axis, rtol=0.0, atol=1.0e-9)
        or not np.allclose(raw_azimuth_axis, bundle_raw_axis, rtol=0.0, atol=1.0e-9)
    ):
        return None

    try:
        permutation = np.asarray(
            projection_payload.get("raw_to_gui_row_permutation"),
            dtype=np.int64,
        ).reshape(-1)
    except Exception:
        return None
    if (
        permutation.shape != azimuth_axis.shape
        or not np.array_equal(
            np.sort(permutation),
            np.arange(int(azimuth_axis.size), dtype=np.int64),
        )
        or not np.allclose(
            azimuth_axis,
            bundle_gui_axis[permutation],
            rtol=0.0,
            atol=1.0e-9,
        )
    ):
        return None

    lut = getattr(transform_bundle, "lut", None)
    lut_shape = _geometry_fit_frozen_centroid_shape(getattr(lut, "image_shape", None))
    try:
        lut_n_rad = int(getattr(lut, "n_rad"))
        lut_n_az = int(getattr(lut, "n_az"))
        matrix_shape = tuple(int(value) for value in tuple(lut.matrix.shape)[:2])
        count_size = int(np.asarray(lut.count_flat).size)
    except Exception:
        return None
    expected_bin_count = int(radial_axis.size * raw_azimuth_axis.size)
    expected_pixel_count = int(bundle_shape[0] * bundle_shape[1])
    if (
        lut_shape != bundle_shape
        or lut_n_rad != int(radial_axis.size)
        or lut_n_az != int(raw_azimuth_axis.size)
        or matrix_shape != (expected_bin_count, expected_pixel_count)
        or count_size != expected_bin_count
    ):
        return None

    projection_digest = _geometry_fit_projection_payload_digest(
        projection_payload,
        trust_stored_token=False,
    )
    if not isinstance(projection_digest, str) or not projection_digest:
        return None
    token_schema = str(projection_payload.get("projection_token_schema") or "").strip()
    token_source = str(projection_payload.get("projection_content_token_source") or "").strip()
    stored_token = projection_payload.get("projection_content_token_v3")
    if any((token_schema, token_source, stored_token)) and (
        token_schema != _GEOMETRY_FIT_PROJECTION_TOKEN_SCHEMA
        or token_source != _GEOMETRY_FIT_PROJECTION_TOKEN_SOURCE
        or stored_token != projection_digest
    ):
        return None
    return transform_bundle, bundle_shape, projection_digest


def _geometry_fit_build_frozen_centroid_projection_binding(
    *,
    params: Mapping[str, object],
    native_detector_shape: object,
    bundle_detector_shape: object,
    projection_payload: Mapping[str, object],
) -> dict[str, object] | None:
    """Bind canonical frozen projection content to its fit-start geometry."""

    geometry = _geometry_fit_frozen_centroid_geometry(params)
    native_shape = _geometry_fit_frozen_centroid_shape(native_detector_shape)
    expected_bundle_shape = _geometry_fit_frozen_centroid_shape(bundle_detector_shape)
    validated = _geometry_fit_frozen_centroid_payload_bundle(projection_payload)
    if (
        geometry is None
        or native_shape is None
        or expected_bundle_shape is None
        or validated is None
    ):
        return None
    _bundle, actual_bundle_shape, projection_digest = validated
    if actual_bundle_shape != expected_bundle_shape:
        return None

    canonical_native_shape = _geometry_fit_frozen_centroid_shape(
        projection_payload.get("native_detector_shape")
    )
    canonical_bundle_shape = _geometry_fit_frozen_centroid_shape(
        projection_payload.get("bundle_detector_shape")
    )
    try:
        canonical_center = np.asarray(
            projection_payload.get("bundle_center_row_col"),
            dtype=np.float64,
        ).reshape(-1)
    except Exception:
        return None
    if (
        canonical_native_shape != native_shape
        or canonical_bundle_shape != expected_bundle_shape
        or canonical_center.size != 2
        or not np.all(np.isfinite(canonical_center))
        or not np.allclose(
            canonical_center,
            np.asarray(
                [geometry.center_row_px, geometry.center_col_px],
                dtype=np.float64,
            ),
            rtol=0.0,
            atol=1.0e-9,
        )
        or str(projection_payload.get("center_input_frame") or "") != "simulation_cake_raster"
    ):
        return None
    return {
        "schema": _GEOMETRY_FIT_FROZEN_CENTROID_PROJECTION_BINDING_SCHEMA,
        "projection_payload_digest": str(projection_digest),
        "native_detector_shape": [int(value) for value in native_shape],
        "bundle_detector_shape": [int(value) for value in expected_bundle_shape],
        "center_row_col": [
            float(geometry.center_row_px),
            float(geometry.center_col_px),
        ],
        "distance_m": float(geometry.distance_m),
        "pixel_size_m": float(geometry.pixel_size_m),
        "center_input_frame": "simulation_cake_raster",
        "hit_table_point_frame": "simulation_detector_native",
        "projector_point_frame": "frozen_exact_cake_bundle_detector",
    }








def _geometry_fit_stamp_frozen_centroid_roi_centers(
    source_rows: Sequence[Mapping[str, object]] | None,
    *,
    required_manual_fit_targets: Sequence[Mapping[str, object]] | None,
    centroid_frozen_roi_native_detector_coords_to_caked_display_coords: (
        Callable[[float, float], object] | None
    ),
) -> list[dict[str, object]]:
    return gui_geometry_q_group_manager.stamp_selected_branch_frozen_caked_centroid_roi_centers(
        source_rows,
        required_manual_fit_targets=required_manual_fit_targets,
        frozen_roi_native_detector_coords_to_caked_display_coords=(
            centroid_frozen_roi_native_detector_coords_to_caked_display_coords
        ),
    )


def _geometry_manual_build_source_rows_from_hit_tables(
    hit_tables: Sequence[object] | None,
    *,
    image_size_value: int,
    params_local: Mapping[str, object],
    allow_nominal_hkl_indices: bool,
    required_manual_fit_targets: Sequence[Mapping[str, object]] | None = None,
    attach_caked_centroids: bool = True,
    centroid_hit_table_coords_to_caked_display_coords: (
        Callable[[float, float], object] | None
    ) = None,
    centroid_projection_provenance: Mapping[str, object] | None = None,
    centroid_hit_table_coords_to_native_detector_coords: (
        Callable[[float, float], object] | None
    ) = None,
    centroid_frozen_roi_native_detector_coords_to_caked_display_coords: (
        Callable[[float, float], object] | None
    ) = None,
    project_source_rows_to_current_view: (
        Callable[[Sequence[Mapping[str, object]]], object] | None
    ) = None,
) -> tuple[
    list[dict[str, object]],
    list[tuple[float, float, str]],
    list[object],
]:
    copied_hit_tables = gui_geometry_q_group_manager.copy_geometry_fit_hit_tables(hit_tables)
    centroid_hit_tables = getattr(copied_hit_tables, "centroid_hit_tables", None)
    if not copied_hit_tables:
        return [], [], []
    copied_centroid_hit_tables = (
        list(centroid_hit_tables) if centroid_hit_tables is not None else []
    )

    try:
        primary_a = float(params_local.get("a", np.nan))
    except Exception:
        primary_a = float("nan")
    try:
        primary_c = float(params_local.get("c", np.nan))
    except Exception:
        primary_c = float("nan")
    try:
        theta_initial_value = float(params_local.get("theta_initial", np.nan))
    except Exception:
        theta_initial_value = float("nan")

    raw_rows, peak_table_lattice = (
        gui_geometry_q_group_manager.build_geometry_fit_full_order_source_rows(
            copied_hit_tables,
            image_shape=(int(image_size_value), int(image_size_value)),
            native_sim_to_display_coords=_native_sim_to_display_coords,
            primary_a=primary_a,
            primary_c=primary_c,
            default_source_label="primary",
            round_pixel_centers=False,
            allow_nominal_hkl_indices=bool(allow_nominal_hkl_indices),
        )
    )
    raw_rows = [dict(entry) for entry in (raw_rows or ()) if isinstance(entry, Mapping)]
    if np.isfinite(theta_initial_value):
        for entry in raw_rows:
            entry["theta_initial"] = float(theta_initial_value)
            entry["theta_initial_deg"] = float(theta_initial_value)
    if bool(attach_caked_centroids) and copied_centroid_hit_tables:
        try:
            row_projector = (
                project_source_rows_to_current_view
                if callable(project_source_rows_to_current_view)
                else _project_geometry_manual_peaks_to_current_view
            )
            projected_target_rows = [
                dict(entry)
                for entry in (row_projector(raw_rows) or ())
                if isinstance(entry, Mapping)
            ]
            projected_target_rows = _geometry_fit_stamp_frozen_centroid_roi_centers(
                projected_target_rows,
                required_manual_fit_targets=required_manual_fit_targets,
                centroid_frozen_roi_native_detector_coords_to_caked_display_coords=(
                    centroid_frozen_roi_native_detector_coords_to_caked_display_coords
                ),
            )
            projected_target_rows = (
                gui_geometry_q_group_manager.attach_selected_branch_caked_centroids_from_hit_tables(
                    projected_target_rows,
                    copied_centroid_hit_tables,
                    native_detector_coords_to_caked_display_coords=(
                        centroid_hit_table_coords_to_caked_display_coords
                        if callable(centroid_hit_table_coords_to_caked_display_coords)
                        else _native_detector_coords_to_caked_display_coords
                    ),
                    hit_table_detector_coords_to_native_detector_coords=(
                        centroid_hit_table_coords_to_native_detector_coords
                    ),
                )
            )
            projected_target_rows = gui_geometry_q_group_manager.stamp_selected_branch_caked_centroid_projector_provenance(
                projected_target_rows,
                centroid_projection_provenance,
            )
        except Exception:
            projected_target_rows = []
        if projected_target_rows:
            try:
                centroid_fields_by_key: dict[tuple[object, ...], dict[str, object]] = {}
                for projected_entry in projected_target_rows:
                    key = gui_geometry_q_group_manager._centroid_source_row_group_key(
                        projected_entry
                    )
                    if key is None or "selected_branch_caked_centroid_deg" not in projected_entry:
                        continue
                    centroid_fields = {
                        field: value
                        for field, value in projected_entry.items()
                        if str(field).startswith("selected_branch_caked_centroid")
                        or str(field).startswith("process_peaks_centroid")
                        or str(field).startswith("predicted_centroid_")
                    }
                    if centroid_fields:
                        centroid_fields_by_key[key] = centroid_fields
                attached_rows: list[dict[str, object]] = []
                for raw_entry in raw_rows:
                    copied = dict(raw_entry)
                    key = gui_geometry_q_group_manager._centroid_source_row_group_key(copied)
                    if key in centroid_fields_by_key:
                        copied.update(centroid_fields_by_key[key])
                    attached_rows.append(copied)
                raw_rows = attached_rows
            except Exception:
                pass
    return raw_rows, peak_table_lattice, copied_hit_tables


def _geometry_fit_targeted_projected_cache_store() -> dict[int, dict[str, dict[str, object]]]:
    cache_store = getattr(
        simulation_runtime_state,
        "geometry_fit_targeted_projected_cache_by_background",
        None,
    )
    if isinstance(cache_store, dict):
        return cache_store
    cache_store = {}
    setattr(
        simulation_runtime_state,
        "geometry_fit_targeted_projected_cache_by_background",
        cache_store,
    )
    return cache_store


def _geometry_fit_store_targeted_projected_cache_entry(
    *,
    background_index: int,
    key_digest: str,
    payload: Mapping[str, object] | None,
) -> None:
    if not str(key_digest).strip() or not isinstance(payload, Mapping):
        return
    if not gui_geometry_fit._geometry_fit_projected_rows_cacheable(
        background_index=int(background_index),
        projected_rows=payload.get("projected_rows"),
        projection_view_signature=payload.get("projection_view_signature"),
        requested_projection_view_signature=payload.get("projection_view_signature"),
        consumer=str(payload.get("consumer") or ""),
    ):
        return
    cache_store = _geometry_fit_targeted_projected_cache_store()
    background_store = cache_store.setdefault(int(background_index), {})
    background_store[str(key_digest)] = copy.deepcopy(dict(payload))


def _geometry_fit_projection_content_hash(*parts: bytes | str) -> str:
    hasher = hashlib.blake2b(digest_size=16)
    for part in parts:
        raw = part.encode("utf-8", "backslashreplace") if isinstance(part, str) else bytes(part)
        hasher.update(len(raw).to_bytes(8, "little", signed=False))
        hasher.update(raw)
    return hasher.hexdigest()


def _geometry_fit_projection_dense_content_token(
    value: object,
    *,
    kind: str,
    allow_empty: bool = True,
) -> dict[str, object] | None:
    try:
        raw = np.asarray(value)
    except Exception:
        return None
    if raw.dtype.kind == "O":
        return None
    if raw.dtype.kind in {"f", "c"}:
        try:
            arr = np.asarray(value, dtype=np.dtype("<f8"))
        except Exception:
            return None
        if not np.all(np.isfinite(arr)):
            return None
    elif raw.dtype.kind in {"i", "u"}:
        try:
            arr = np.asarray(value, dtype=np.dtype("<i8"))
        except Exception:
            return None
    elif raw.dtype.kind == "b":
        arr = np.asarray(value, dtype=np.dtype("u1"))
    else:
        return None
    if arr.size <= 0 and not bool(allow_empty):
        return None
    arr = np.ascontiguousarray(arr)
    shape = [int(v) for v in arr.shape]
    dtype_text = str(arr.dtype)
    return {
        "kind": "dense_content_v3",
        "content_kind": str(kind),
        "shape": shape,
        "dtype": dtype_text,
        "digest": _geometry_fit_projection_content_hash(
            "dense_content_v3",
            str(kind),
            repr(shape),
            dtype_text,
            arr.tobytes(order="C"),
        ),
    }


def _geometry_fit_projection_sparse_content_token(
    value: object,
    *,
    kind: str,
) -> dict[str, object] | None:
    if not hasattr(value, "tocsr"):
        return None
    try:
        csr = value.tocsr(copy=True)  # type: ignore[attr-defined]
    except Exception:
        return None
    try:
        csr.sort_indices()
    except Exception:
        pass
    try:
        shape = [int(v) for v in tuple(csr.shape)[:2]]
        indptr = np.ascontiguousarray(np.asarray(csr.indptr, dtype=np.dtype("<i8")).reshape(-1))
        indices = np.ascontiguousarray(np.asarray(csr.indices, dtype=np.dtype("<i8")).reshape(-1))
        raw_data = np.asarray(csr.data)
    except Exception:
        return None
    if len(shape) < 2 or shape[0] < 0 or shape[1] < 0 or raw_data.dtype.kind == "O":
        return None
    if raw_data.dtype.kind in {"f", "c"}:
        data = np.asarray(csr.data, dtype=np.dtype("<f8")).reshape(-1)
        if not np.all(np.isfinite(data)):
            return None
    elif raw_data.dtype.kind in {"i", "u", "b"}:
        data = np.asarray(csr.data, dtype=np.dtype("<i8")).reshape(-1)
    else:
        return None
    data = np.ascontiguousarray(data)
    dtype_text = str(data.dtype)
    return {
        "kind": "sparse_csr_content_v3",
        "content_kind": str(kind),
        "shape": shape,
        "indptr_length": int(indptr.size),
        "indices_length": int(indices.size),
        "data_length": int(data.size),
        "data_dtype": dtype_text,
        "digest": _geometry_fit_projection_content_hash(
            "sparse_csr_content_v3",
            str(kind),
            repr(shape),
            indptr.tobytes(order="C"),
            indices.tobytes(order="C"),
            dtype_text,
            data.tobytes(order="C"),
        ),
    }


def _geometry_fit_projection_freeze_array(array: np.ndarray) -> np.ndarray:
    array.setflags(write=False)
    return array


def _geometry_fit_projection_dense_storage_copy(
    value: object,
    *,
    allow_empty: bool = True,
) -> np.ndarray | None:
    try:
        raw = np.asarray(value)
    except Exception:
        return None
    if raw.dtype.kind == "O":
        return None
    if raw.dtype.kind in {"f", "c"}:
        try:
            copied = np.asarray(value, dtype=np.dtype("<f8"))
        except Exception:
            return None
        if not np.all(np.isfinite(copied)):
            return None
    elif raw.dtype.kind in {"i", "u"}:
        try:
            copied = np.asarray(value, dtype=np.dtype("<i8"))
        except Exception:
            return None
    elif raw.dtype.kind == "b":
        copied = np.asarray(value, dtype=np.dtype("u1"))
    else:
        return None
    if copied.size <= 0 and not bool(allow_empty):
        return None
    return _geometry_fit_projection_freeze_array(np.ascontiguousarray(copied).copy())


def _geometry_fit_projection_sparse_storage_copy(value: object) -> object | None:
    if not hasattr(value, "tocsr"):
        return None
    try:
        csr = value.tocsr(copy=True)  # type: ignore[attr-defined]
    except Exception:
        return None
    try:
        csr.sort_indices()
    except Exception:
        pass
    try:
        shape = tuple(int(v) for v in tuple(csr.shape)[:2])
        indptr = np.ascontiguousarray(np.asarray(csr.indptr, dtype=np.dtype("<i8")).reshape(-1))
        indices = np.ascontiguousarray(np.asarray(csr.indices, dtype=np.dtype("<i8")).reshape(-1))
        raw_data = np.asarray(csr.data)
    except Exception:
        return None
    if len(shape) < 2 or shape[0] < 0 or shape[1] < 0 or raw_data.dtype.kind == "O":
        return None
    if raw_data.dtype.kind in {"f", "c"}:
        data = np.asarray(csr.data, dtype=np.dtype("<f8")).reshape(-1)
        if not np.all(np.isfinite(data)):
            return None
    elif raw_data.dtype.kind in {"i", "u", "b"}:
        data = np.asarray(csr.data, dtype=np.dtype("<i8")).reshape(-1)
    else:
        return None
    data = np.ascontiguousarray(data)
    try:
        csr.indptr = indptr.copy()
        csr.indices = indices.copy()
        csr.data = data.copy()
        csr.sort_indices()
        csr.indptr.setflags(write=False)
        csr.indices.setflags(write=False)
        csr.data.setflags(write=False)
    except Exception:
        return None
    return csr


def _geometry_fit_projection_transform_storage_copy(value: object) -> object | None:
    if value is None:
        return None
    if all(
        hasattr(value, attr) for attr in ("image_shape", "n_rad", "n_az", "matrix", "count_flat")
    ):
        try:
            image_shape = tuple(int(v) for v in tuple(value.image_shape)[:2])
            n_rad = int(value.n_rad)
            n_az = int(value.n_az)
        except Exception:
            return None
        matrix = _geometry_fit_projection_transform_storage_copy(value.matrix)
        count_flat = _geometry_fit_projection_dense_storage_copy(
            value.count_flat,
            allow_empty=True,
        )
        if matrix is None or count_flat is None:
            return None
        try:
            return type(value)(
                image_shape=image_shape,
                n_rad=n_rad,
                n_az=n_az,
                matrix=matrix,
                count_flat=count_flat,
            )
        except Exception:
            return SimpleNamespace(
                image_shape=image_shape,
                n_rad=n_rad,
                n_az=n_az,
                matrix=matrix,
                count_flat=count_flat,
            )
    sparse = _geometry_fit_projection_sparse_storage_copy(value)
    if sparse is not None:
        return sparse
    return _geometry_fit_projection_dense_storage_copy(value, allow_empty=True)


def _geometry_fit_projection_bundle_storage_copy(
    bundle: object,
) -> CakeTransformBundle | None:
    if not isinstance(bundle, CakeTransformBundle):
        return None
    detector_shape = _geometry_fit_projection_shape_token(getattr(bundle, "detector_shape", None))
    radial = _geometry_fit_projection_dense_storage_copy(
        getattr(bundle, "radial_deg", None),
        allow_empty=False,
    )
    raw_azimuth = _geometry_fit_projection_dense_storage_copy(
        getattr(bundle, "raw_azimuth_deg", None),
        allow_empty=False,
    )
    gui_azimuth = _geometry_fit_projection_dense_storage_copy(
        getattr(bundle, "gui_azimuth_deg", None),
        allow_empty=False,
    )
    lut = _geometry_fit_projection_transform_storage_copy(getattr(bundle, "lut", None))
    if (
        detector_shape is None
        or radial is None
        or raw_azimuth is None
        or gui_azimuth is None
        or lut is None
    ):
        return None
    return CakeTransformBundle(
        detector_shape=tuple(int(v) for v in detector_shape[:2]),
        radial_deg=radial,
        raw_azimuth_deg=raw_azimuth,
        gui_azimuth_deg=gui_azimuth,
        lut=lut,
    )


def _geometry_fit_projection_transform_content_token(
    value: object,
    *,
    kind: str,
) -> dict[str, object] | None:
    if value is None:
        return {"kind": "transform_none_v3", "content_kind": str(kind)}
    if all(
        hasattr(value, attr) for attr in ("image_shape", "n_rad", "n_az", "matrix", "count_flat")
    ):
        try:
            image_shape = [int(v) for v in tuple(value.image_shape)[:2]]
            n_rad = int(value.n_rad)
            n_az = int(value.n_az)
        except Exception:
            return None
        matrix_token = _geometry_fit_projection_transform_content_token(
            value.matrix,
            kind=f"{kind}.matrix",
        )
        count_token = _geometry_fit_projection_dense_content_token(
            value.count_flat,
            kind=f"{kind}.count_flat",
            allow_empty=True,
        )
        if matrix_token is None or count_token is None:
            return None
        return {
            "kind": "detector_cake_lut_content_v3",
            "content_kind": str(kind),
            "image_shape": image_shape,
            "n_rad": int(n_rad),
            "n_az": int(n_az),
            "matrix": matrix_token,
            "count_flat": count_token,
        }
    sparse_token = _geometry_fit_projection_sparse_content_token(value, kind=kind)
    if sparse_token is not None:
        return sparse_token
    return _geometry_fit_projection_dense_content_token(value, kind=kind, allow_empty=True)


def _geometry_fit_projection_bundle_content_token(
    bundle: object,
) -> dict[str, object] | None:
    if not isinstance(bundle, CakeTransformBundle):
        return None
    detector_shape = _geometry_fit_projection_shape_token(getattr(bundle, "detector_shape", None))
    radial_axis = _geometry_fit_projection_axis_token(getattr(bundle, "radial_deg", None))
    azimuth_axis = _geometry_fit_projection_axis_token(getattr(bundle, "gui_azimuth_deg", None))
    raw_azimuth_axis = _geometry_fit_projection_axis_token(getattr(bundle, "raw_azimuth_deg", None))
    lut = _geometry_fit_projection_transform_content_token(getattr(bundle, "lut", None), kind="lut")
    if (
        detector_shape is None
        or radial_axis is None
        or azimuth_axis is None
        or raw_azimuth_axis is None
        or lut is None
    ):
        return None
    return {
        "kind": "cake_transform_bundle_content_v3",
        "detector_shape": detector_shape,
        "radial_axis": radial_axis,
        "azimuth_axis": azimuth_axis,
        "raw_azimuth_axis": raw_azimuth_axis,
        "lut": lut,
    }


def _geometry_fit_projection_payload_digest(
    payload: Mapping[str, object] | None,
    *,
    trust_stored_token: bool = True,
) -> str | None:
    if not isinstance(payload, Mapping):
        return None
    existing_schema = str(payload.get("projection_token_schema") or "").strip()
    existing_token = payload.get("projection_content_token_v3")
    existing_source = str(payload.get("projection_content_token_source") or "").strip()
    if (
        bool(trust_stored_token)
        and existing_schema == _GEOMETRY_FIT_PROJECTION_TOKEN_SCHEMA
        and existing_source == _GEOMETRY_FIT_PROJECTION_TOKEN_SOURCE
        and isinstance(existing_token, str)
        and existing_token
    ):
        return str(existing_token)
    transform_bundle_token = _geometry_fit_projection_bundle_content_token(
        payload.get("transform_bundle")
    )
    if transform_bundle_token is None:
        return None
    token_payload = {
        "kind": "geometry_fit_projection_payload_content_v3",
        "detector_shape": _geometry_fit_projection_shape_token(payload.get("detector_shape")),
        "radial_axis": _geometry_fit_projection_axis_token(payload.get("radial_axis")),
        "azimuth_axis": _geometry_fit_projection_axis_token(payload.get("azimuth_axis")),
        "raw_azimuth_axis": _geometry_fit_projection_axis_token(payload.get("raw_azimuth_axis")),
        "raw_to_gui_row_permutation": gui_manual_geometry.geometry_manual_stable_permutation_value_token(
            payload.get("raw_to_gui_row_permutation")
        ),
        "transform_bundle": transform_bundle_token,
    }
    if any(
        token_payload.get(key) is None
        for key in ("detector_shape", "radial_axis", "azimuth_axis", "raw_azimuth_axis")
    ):
        return None
    return gui_geometry_fit._geometry_fit_digest_payload(token_payload)


def _geometry_fit_projection_shape_token(value: object) -> list[int] | None:
    try:
        shape = [int(item) for item in tuple(value)[:2]]  # type: ignore[arg-type]
    except Exception:
        return None
    if len(shape) < 2 or shape[0] <= 0 or shape[1] <= 0:
        return None
    return shape[:2]


def _geometry_fit_projection_axis_token(value: object) -> tuple[object, ...] | None:
    token = gui_manual_geometry.geometry_manual_stable_axis_value_token(value)
    return tuple(token) if token is not None else None


def _geometry_fit_frozen_centroid_binding_storage_copy(
    value: object,
    *,
    projection_payload_digest: str,
) -> dict[str, object] | None:
    if not isinstance(value, Mapping):
        return None
    if (
        str(value.get("schema") or "") != _GEOMETRY_FIT_FROZEN_CENTROID_PROJECTION_BINDING_SCHEMA
        or value.get("projection_payload_digest") != projection_payload_digest
    ):
        return None
    native_shape = _geometry_fit_frozen_centroid_shape(value.get("native_detector_shape"))
    bundle_shape = _geometry_fit_frozen_centroid_shape(value.get("bundle_detector_shape"))
    try:
        center = np.asarray(value.get("center_row_col"), dtype=np.float64).reshape(-1)
        distance = float(value.get("distance_m", np.nan))
        pixel_size = float(value.get("pixel_size_m", np.nan))
    except Exception:
        return None
    if (
        native_shape is None
        or bundle_shape is None
        or center.size != 2
        or not np.all(np.isfinite(center))
        or not np.isfinite(distance)
        or distance <= 0.0
        or not np.isfinite(pixel_size)
        or pixel_size <= 0.0
        or str(value.get("center_input_frame") or "") != "simulation_cake_raster"
        or str(value.get("hit_table_point_frame") or "") != "simulation_detector_native"
        or str(value.get("projector_point_frame") or "") != "frozen_exact_cake_bundle_detector"
    ):
        return None
    return {
        "schema": _GEOMETRY_FIT_FROZEN_CENTROID_PROJECTION_BINDING_SCHEMA,
        "projection_payload_digest": str(projection_payload_digest),
        "native_detector_shape": [int(item) for item in native_shape],
        "bundle_detector_shape": [int(item) for item in bundle_shape],
        "center_row_col": [float(center[0]), float(center[1])],
        "distance_m": float(distance),
        "pixel_size_m": float(pixel_size),
        "center_input_frame": "simulation_cake_raster",
        "hit_table_point_frame": "simulation_detector_native",
        "projector_point_frame": "frozen_exact_cake_bundle_detector",
    }


def _geometry_fit_projection_payload_storage_copy(
    payload: Mapping[str, object] | None,
) -> dict[str, object] | None:
    projection = gui_geometry_fit.geometry_fit_caked_projection_payload(payload)
    if not isinstance(projection, Mapping):
        return None
    stored: dict[str, object] = {"payload_kind": "projection"}
    detector_shape = _geometry_fit_projection_shape_token(projection.get("detector_shape"))
    if detector_shape is not None:
        stored["detector_shape"] = tuple(int(v) for v in detector_shape[:2])
    for key in ("radial_axis", "azimuth_axis", "raw_azimuth_axis"):
        value = projection.get(key)
        if value is None:
            continue
        axis_copy = _geometry_fit_projection_dense_storage_copy(value, allow_empty=False)
        if axis_copy is None:
            return None
        stored[key] = axis_copy
    permutation = projection.get("raw_to_gui_row_permutation")
    if permutation is not None:
        try:
            permutation_copy = np.asarray(permutation, dtype=np.dtype("<i8")).reshape(-1)
        except Exception:
            return None
        if permutation_copy.size <= 0:
            return None
        stored["raw_to_gui_row_permutation"] = _geometry_fit_projection_freeze_array(
            np.ascontiguousarray(permutation_copy).copy()
        )
    transform_bundle = projection.get("transform_bundle")
    if transform_bundle is not None:
        copied_bundle = _geometry_fit_projection_bundle_storage_copy(transform_bundle)
        if copied_bundle is None:
            return None
        stored["transform_bundle"] = copied_bundle
        if "detector_shape" not in stored:
            stored["detector_shape"] = tuple(int(v) for v in copied_bundle.detector_shape[:2])
    projection_token = _geometry_fit_projection_payload_digest(stored, trust_stored_token=False)
    if projection_token is not None:
        stored["projection_token_schema"] = _GEOMETRY_FIT_PROJECTION_TOKEN_SCHEMA
        stored["projection_content_token_v3"] = str(projection_token)
        stored["projection_content_token_source"] = _GEOMETRY_FIT_PROJECTION_TOKEN_SOURCE
        binding = _geometry_fit_frozen_centroid_binding_storage_copy(
            payload.get(_GEOMETRY_FIT_FROZEN_CENTROID_PROJECTION_BINDING_FIELD),
            projection_payload_digest=str(projection_token),
        )
        if binding is not None:
            stored[_GEOMETRY_FIT_FROZEN_CENTROID_PROJECTION_BINDING_FIELD] = binding
    return stored


def _geometry_fit_targeted_projection_view_mode() -> str:
    try:
        view_mode = _current_app_shell_view_mode()
    except Exception:
        view_mode = None
    try:
        figure_mode = _current_primary_figure_mode()
    except Exception:
        figure_mode = None
    normalized_figure_mode = str(figure_mode or "").strip().lower()
    if normalized_figure_mode in {"caked", "q_space"}:
        return normalized_figure_mode
    normalized_mode = str(view_mode or "").strip().lower()
    if normalized_mode not in {"detector", "caked", "q_space"}:
        return "detector"
    return normalized_mode


def _geometry_manual_consumer_is_manual_pick_cache(lookup_context: object) -> bool:
    return str(lookup_context or "").strip() in {
        "manual_pick_cache",
        "manual_pick_cache_coverage",
    }


def _geometry_manual_projection_mode_override_for_consumer(
    lookup_context: str | None,
    *,
    background_index: int | None = None,
) -> str | None:
    if not _geometry_manual_consumer_is_manual_pick_cache(lookup_context):
        return None
    pick_uses_caked = False
    pick_uses_caked_factory = globals().get("_geometry_manual_pick_uses_caked_space")
    if callable(pick_uses_caked_factory):
        try:
            pick_uses_caked = bool(pick_uses_caked_factory())
        except Exception:
            pick_uses_caked = False
    if not pick_uses_caked:
        return "detector"
    if background_index is None:
        return "detector"
    try:
        caked_payload = _geometry_fit_caked_view_for_index(int(background_index))
    except Exception:
        caked_payload = None
    if not isinstance(caked_payload, Mapping):
        return "detector"
    try:
        hydrated_payload = gui_geometry_fit._geometry_fit_hydrate_exact_caked_payload(
            caked_payload,
            detector_shape=caked_payload.get("detector_shape"),
            require_background=False,
        )
    except Exception:
        hydrated_payload = None
    if not isinstance(hydrated_payload, Mapping) or not isinstance(
        hydrated_payload.get("transform_bundle"),
        CakeTransformBundle,
    ):
        return "detector"
    return None


def _geometry_fit_projection_signature_public(
    signature: Mapping[str, object],
) -> dict[str, object]:
    return {
        str(key): gui_geometry_fit._geometry_fit_cache_jsonable(value)
        for key, value in signature.items()
    }


def _geometry_fit_targeted_projection_view_signature(
    background_index: int | None = None,
    *,
    mode_override: str | None = None,
    caked_payload: Mapping[str, object] | None = None,
    detector_shape: Sequence[object] | None = None,
    ai: ExactCakeIntegrator | None = None,
    q_space_image: object = None,
    analysis_preview_bins: Sequence[object] | None = None,
) -> dict[str, object]:
    normalized_mode = (
        str(
            mode_override
            if mode_override is not None
            else _geometry_fit_targeted_projection_view_mode()
        )
        .strip()
        .lower()
    )
    if normalized_mode not in {"detector", "caked", "q_space"}:
        normalized_mode = "detector"
    try:
        current_background_idx = int(background_runtime_state.current_background_index)
    except Exception:
        current_background_idx = int(background_index or 0)
    try:
        background_idx = int(
            current_background_idx if background_index is None else background_index
        )
    except Exception:
        background_idx = int(background_index or 0)
    signature: dict[str, object] = {
        "mode": str(normalized_mode),
        "background_index": int(background_idx),
        "current_background_index": int(current_background_idx),
    }
    ai_value = ai
    if ai_value is None:
        ai_cache = getattr(simulation_runtime_state, "ai_cache", None)
        ai_value = ai_cache.get("ai") if isinstance(ai_cache, Mapping) else None
    normalized_shape = _geometry_fit_detector_shape_2d(detector_shape)
    if normalized_shape is None:
        try:
            if int(background_idx) == int(current_background_idx):
                native_background = _get_current_background_native()
            else:
                native_background, _display_background = _load_background_image_by_index(
                    int(background_idx)
                )
            normalized_shape = _geometry_fit_detector_shape_2d(
                np.asarray(native_background, dtype=np.float64).shape[:2]
            )
        except Exception:
            normalized_shape = None
    if normalized_shape is not None:
        signature["detector_shape"] = [int(v) for v in normalized_shape[:2]]
    if normalized_mode == "detector":
        signature["available"] = True
        return _geometry_fit_projection_signature_public(signature)
    preview_bins = analysis_preview_bins
    if preview_bins is None:
        preview_bins = getattr(simulation_runtime_state, "analysis_preview_bins", None)
    if isinstance(preview_bins, (tuple, list)) and len(preview_bins) >= 2:
        normalized_bins = [int(preview_bins[0]), int(preview_bins[1])]
        signature["analysis_bins"] = list(normalized_bins)
    if normalized_mode == "q_space":
        if int(background_idx) != int(current_background_idx):
            signature["available"] = False
            signature["reason"] = "missing_background_projection_payload"
            signature["projection_payload_digest"] = None
            return _geometry_fit_projection_signature_public(signature)
        signature["available"] = True
        signature["extent"] = _resolve_primary_extent(
            getattr(simulation_runtime_state, "last_q_space_extent", None),
            (0.0, 1.0, -1.0, 1.0),
        )
        resolved_q_space_image = q_space_image
        if resolved_q_space_image is None:
            try:
                resolved_q_space_image = np.asarray(
                    getattr(simulation_runtime_state, "last_q_space_image", None)
                )
            except Exception:
                resolved_q_space_image = None
        if isinstance(resolved_q_space_image, np.ndarray) and resolved_q_space_image.ndim >= 2:
            signature["image_shape"] = [int(v) for v in resolved_q_space_image.shape[:2]]
        signature["projection_payload_digest"] = gui_geometry_fit._geometry_fit_digest_payload(
            {
                "extent": signature.get("extent"),
                "image_shape": signature.get("image_shape"),
                "analysis_bins": signature.get("analysis_bins"),
            }
        )
        return _geometry_fit_projection_signature_public(signature)
    if normalized_mode == "caked":
        normalized_payload = _geometry_fit_resolve_targeted_caked_projection_payload(
            background_idx,
            caked_payload=caked_payload,
            detector_shape=detector_shape,
            ai=ai_value,
            analysis_preview_bins=analysis_preview_bins,
            allow_generated_payload=True,
        )
        if isinstance(normalized_payload, Mapping):
            projection_payload_digest = _geometry_fit_projection_payload_digest(normalized_payload)
            if projection_payload_digest is None:
                signature["available"] = False
                signature["reason"] = "invalid_background_caked_payload"
                signature["projection_payload_digest"] = None
                return _geometry_fit_projection_signature_public(signature)
            signature.update(
                {
                    "available": True,
                    "detector_shape": list(tuple(normalized_payload.get("detector_shape", ()))[:2]),
                    "radial_axis": _geometry_fit_projection_axis_token(
                        normalized_payload.get("radial_axis")
                    ),
                    "azimuth_axis": _geometry_fit_projection_axis_token(
                        normalized_payload.get("azimuth_axis")
                    ),
                    "raw_azimuth_axis": _geometry_fit_projection_axis_token(
                        normalized_payload.get("raw_azimuth_axis")
                    ),
                    "raw_to_gui_row_permutation": gui_manual_geometry.geometry_manual_stable_permutation_value_token(
                        normalized_payload.get("raw_to_gui_row_permutation")
                    ),
                    "projection_payload_digest": projection_payload_digest,
                }
            )
        else:
            signature["available"] = False
            signature["reason"] = "missing_background_caked_payload"
            signature["projection_payload_digest"] = None
        return _geometry_fit_projection_signature_public(signature)
    return _geometry_fit_projection_signature_public(signature)




def _geometry_fit_background_label(background_index: int) -> str:
    """Return a short human-readable label for one background index."""

    try:
        osc_path = background_runtime_state.osc_files[int(background_index)]
    except Exception:
        osc_path = None
    if osc_path is not None:
        try:
            name = Path(str(osc_path)).name
        except Exception:
            name = ""
        if str(name).strip():
            return str(name)
    return f"background {int(background_index) + 1}"


def _normalize_geometry_fit_projection_view_signature(
    raw: object,
    background_index: int,
) -> dict[str, object]:
    """Validate the current mapping-based projection signature."""

    if not isinstance(raw, Mapping):
        raise ValueError(
            "projection_view_signature must be a mapping; "
            f"got {type(raw).__name__} for background {int(background_index)}"
        )
    return dict(raw)


def _commit_geometry_manual_source_row_rebuild_result(
    rebuild_result: gui_geometry_fit.GeometryFitSourceRowRebuildResult,
    *,
    consumer: str | None = None,
) -> list[dict[str, object]]:
    """Commit one pure source-row rebuild payload onto the live runtime state."""

    if not isinstance(rebuild_result, gui_geometry_fit.GeometryFitSourceRowRebuildResult):
        return []

    background_idx = int(rebuild_result.background_index)
    try:
        current_background_index = int(background_runtime_state.current_background_index)
    except Exception:
        current_background_index = int(background_idx)
    is_current_background = int(background_idx) == int(current_background_index)
    stored_rows = [
        dict(entry) for entry in (rebuild_result.stored_rows or ()) if isinstance(entry, Mapping)
    ]
    projected_rows = [
        dict(entry) for entry in (rebuild_result.projected_rows or ()) if isinstance(entry, Mapping)
    ]
    diagnostics = (
        dict(rebuild_result.diagnostics) if isinstance(rebuild_result.diagnostics, Mapping) else {}
    )
    lookup_context = str(diagnostics.get("consumer") or consumer or "unspecified")
    targeted_preflight_enabled = bool(diagnostics.get("targeted_preflight_enabled", False))
    targeted_cache_key_digest = str(
        diagnostics.get("required_hkl_branch_keys_digest") or ""
    ).strip()
    rebuild_succeeded = bool(stored_rows or projected_rows) and bool(
        str(rebuild_result.rebuild_source or "").strip()
    )

    if not rebuild_succeeded:
        return []

    if stored_rows:
        if targeted_preflight_enabled and targeted_cache_key_digest:
            targeted_projection_mode = str(
                diagnostics.get("projection_view_mode")
                or _geometry_fit_targeted_projection_view_mode()
            )
            targeted_projection_signature = _normalize_geometry_fit_projection_view_signature(
                diagnostics.get("projection_view_signature")
                or _geometry_fit_targeted_projection_view_signature(
                    background_idx,
                    mode_override=targeted_projection_mode,
                ),
                background_idx,
            )
            _geometry_fit_store_targeted_projected_cache_entry(
                background_index=int(background_idx),
                key_digest=str(targeted_cache_key_digest),
                payload={
                    "requested_signature": (
                        gui_geometry_fit._geometry_fit_cache_jsonable(
                            rebuild_result.requested_signature
                        )
                    ),
                    "requested_signature_summary": (
                        gui_geometry_fit._geometry_fit_cache_jsonable(
                            rebuild_result.requested_signature_summary
                        )
                    ),
                    "stored_rows": [dict(entry) for entry in stored_rows],
                    "projected_rows": [dict(entry) for entry in projected_rows],
                    "diagnostics": copy.deepcopy(diagnostics),
                    "cache_source": str(rebuild_result.rebuild_source or "unknown"),
                    "consumer": str(lookup_context),
                    "projection_view_mode": str(targeted_projection_mode),
                    "projection_view_signature": targeted_projection_signature,
                },
            )
    hit_tables_local = rebuild_result.hit_tables
    q_group_content_signature = None
    source_rows_carry_theta = any(
        isinstance(entry, Mapping)
        and ("theta_initial" in entry or "theta_initial_deg" in entry or "theta_i" in entry)
        for entry in stored_rows
    )
    if stored_rows and (source_rows_carry_theta or hit_tables_local is None):
        q_group_content_signature = (
            gui_geometry_q_group_manager._geometry_q_group_content_signature_from_source_rows(
                stored_rows
            )
        )
    if q_group_content_signature is None and hit_tables_local is not None:
        q_group_content_signature = (
            gui_geometry_q_group_manager._geometry_q_group_content_signature_from_hit_tables(
                hit_tables_local
            )
        )
    if hit_tables_local is not None:
        try:
            max_positions_local = hit_tables_to_max_positions(hit_tables_local)
        except Exception:
            max_positions_local = np.empty((0, 6), dtype=np.float64)
        simulation_runtime_state.stored_max_positions_local = list(max_positions_local)
    else:
        simulation_runtime_state.stored_max_positions_local = None
    simulation_runtime_state.stored_q_group_content_signature = q_group_content_signature
    if rebuild_result.peak_table_lattice is not None:
        simulation_runtime_state.stored_peak_table_lattice = list(rebuild_result.peak_table_lattice)
    simulation_runtime_state.stored_sim_image = np.zeros(
        (int(image_size), int(image_size)),
        dtype=np.float64,
    )
    if rebuild_result.intersection_cache is not None:
        simulation_runtime_state.stored_intersection_cache = _copy_intersection_cache_tables(
            rebuild_result.intersection_cache
        )
        _clear_caked_intersection_cache()
    simulation_runtime_state.last_simulation_signature = rebuild_result.requested_signature
    if is_current_background:
        if projected_rows:
            _geometry_manual_set_runtime_peak_cache_from_projected_rows(projected_rows)
        else:
            _geometry_manual_set_runtime_peak_cache_from_source_rows(stored_rows)

    strict_projection_return = not is_current_background and str(
        diagnostics.get("projection_view_mode") or _geometry_fit_targeted_projection_view_mode()
    ).strip().lower() in {"caked", "q_space"}
    if lookup_context == "geometry_fit_trial_source_rows":
        if projected_rows:
            return projected_rows
        if strict_projection_return:
            return []
        return stored_rows
    if projected_rows:
        return projected_rows
    if not is_current_background and str(
        diagnostics.get("projection_view_mode") or _geometry_fit_targeted_projection_view_mode()
    ).strip().lower() in {"caked", "q_space"}:
        return []
    return stored_rows


def _geometry_manual_rebuild_source_rows_for_background(
    background_index: int,
    param_set: dict[str, object] | None = None,
    *,
    consumer: str | None = None,
    required_pairs: Sequence[Mapping[str, object]] | None = None,
) -> tuple[list[dict[str, object]], dict[str, object]]:
    background_idx = int(background_index)
    lookup_context = str(consumer or "unspecified")
    params_local = dict(_current_geometry_fit_params())
    if isinstance(param_set, Mapping):
        params_local.update(dict(param_set))

    requested_signature = _geometry_source_rows_signature_for_background(
        params_local,
    )
    requested_signature_summary = _live_cache_signature_summary(requested_signature)
    background_label = _geometry_fit_background_label(background_idx)
    projection_mode_override = _geometry_manual_projection_mode_override_for_consumer(
        lookup_context,
        background_index=background_idx,
    )
    projection_view_signature = _normalize_geometry_fit_projection_view_signature(
        _geometry_fit_targeted_projection_view_signature(
            background_idx,
            mode_override=projection_mode_override,
        ),
        background_idx,
    )
    projection_view_mode = str(projection_view_signature.get("mode") or "detector")
    projection_payload = (
        _geometry_fit_resolve_targeted_caked_projection_payload(
            int(background_idx),
            analysis_preview_bins=getattr(
                simulation_runtime_state,
                "analysis_preview_bins",
                None,
            ),
            allow_generated_payload=True,
        )
        if projection_view_mode == "caked"
        else None
    )
    required_manual_fit_targets = (
        gui_geometry_fit.collect_geometry_fit_required_manual_fit_targets(
            required_pairs,
            background_index=int(background_idx),
        )
        if required_pairs
        else []
    )
    required_branch_group_keys = gui_geometry_fit._geometry_fit_required_branch_group_keys(
        required_manual_fit_targets
    )

    def _build_source_rows_for_rebuild(
        source_tables: Sequence[object] | None,
        *,
        required_branch_group_keys: Sequence[tuple[tuple[int, int, int], int | None, object | None]]
        | None = None,
        required_manual_fit_targets: Sequence[Mapping[str, object]] | None = None,
        preflight_mode: str = "full",
        consumer: str | None = None,
    ) -> tuple[
        list[dict[str, object]],
        list[tuple[float, float, str]],
        list[object],
    ]:
        del required_branch_group_keys, preflight_mode, consumer
        if not source_tables:
            raise RuntimeError("fresh geometry simulation returned no hit tables")
        return _geometry_manual_build_source_rows_from_hit_tables(
            source_tables,
            image_size_value=int(image_size),
            params_local=params_local,
            allow_nominal_hkl_indices=True,
            required_manual_fit_targets=required_manual_fit_targets,
        )

    rebuild_result = gui_geometry_fit.rebuild_geometry_fit_source_rows(
        background_index=int(background_idx),
        background_label=background_label,
        params_local=params_local,
        consumer=lookup_context,
        requested_signature=requested_signature,
        requested_signature_summary=requested_signature_summary,
        build_source_rows_from_hit_tables=_build_source_rows_for_rebuild,
        simulate_hit_tables=(
            lambda normalized_params, **kwargs: _simulate_hit_tables_for_fit(
                structure_model_state.miller,
                structure_model_state.intensities,
                int(image_size),
                normalized_params,
                **kwargs,
            )
        ),
        project_rows_for_background_view=(
            lambda rows: _geometry_manual_project_peaks_for_background(
                int(background_idx),
                rows,
                mode_override=projection_view_mode,
                caked_payload=projection_payload,
                strict_caked_projection=True,
            )
        ),
        required_pairs=required_pairs,
        required_branch_group_keys=required_branch_group_keys,
        required_manual_fit_targets=required_manual_fit_targets,
    )
    strict_fresh_rows = gui_geometry_fit.strict_caked_geometry_fresh_native_rows(rebuild_result)
    if strict_fresh_rows:
        rows = strict_fresh_rows
    else:
        rows = _commit_geometry_manual_source_row_rebuild_result(
            rebuild_result,
            consumer=lookup_context,
        )
    return rows, dict(rebuild_result.diagnostics)


def _geometry_manual_source_rows_for_background(
    background_index: int,
    param_set: dict[str, object] | None = None,
    *,
    consumer: str | None = None,
    required_pairs: Sequence[Mapping[str, object]] | None = None,
) -> list[dict[str, object]]:
    rows, _diagnostics = _geometry_manual_rebuild_source_rows_for_background(
        int(background_index),
        param_set,
        consumer=str(consumer or "unspecified"),
        required_pairs=required_pairs,
    )
    return rows


