def _geometry_fit_row_status_rows_from_action_result(action_result) -> list[dict[str, object]]:
    execution_result = getattr(action_result, "execution_result", None)
    apply_result = getattr(execution_result, "apply_result", None)
    postprocess = getattr(apply_result, "postprocess", None)
    rows = getattr(postprocess, "row_status_rows", None)
    if not isinstance(rows, Sequence) or isinstance(rows, (str, bytes)):
        return []
    return [dict(row) for row in rows if isinstance(row, Mapping)]


def _update_geometry_fit_audit_report(action_result) -> None:
    if not isinstance(action_result, gui_geometry_fit.GeometryFitRuntimeActionResult):
        return
    try:
        report = gui_geometry_fit.build_geometry_fit_audit_report(
            action_result,
            metadata={"source": "ra_sim_gui"},
        )
    except Exception:
        report = None
    setattr(simulation_runtime_state, "last_geometry_fit_audit_report", report)
    overlay_rows = []
    if isinstance(report, Mapping):
        raw_overlay_rows = report.get("overlay_marker_rows")
        if isinstance(raw_overlay_rows, Sequence) and not isinstance(
            raw_overlay_rows,
            (str, bytes),
        ):
            overlay_rows = [dict(row) for row in raw_overlay_rows if isinstance(row, Mapping)]
    setattr(simulation_runtime_state, "last_geometry_fit_overlay_marker_rows", overlay_rows)


def _update_geometry_fit_row_status_table(rows: Sequence[Mapping[str, object]] | None) -> None:
    resolved_rows = [dict(row) for row in (rows or ()) if isinstance(row, Mapping)]
    setattr(simulation_runtime_state, "last_geometry_fit_row_status_rows", resolved_rows)
    try:
        gui_views.update_geometry_fit_row_status_table(
            geometry_tool_actions_view_state,
            resolved_rows,
        )
    except Exception:
        pass


