def _current_analysis_roi_values() -> dict[str, object]:
    range_values = dict(_current_analysis_range_values())
    range_values.update(
        {
            "integrate_selected_qr_rod": _read_analysis_control(
                "integrate_selected_qr_rod_var",
                "integrate_selected_qr_rod_value",
                False,
                bool,
            ),
            "mirror_selected_qr_phi": _read_analysis_control(
                "mirror_selected_qr_phi_var",
                "mirror_selected_qr_phi_value",
                False,
                bool,
            ),
            "include_selected_qr_rod_shape": _read_analysis_control(
                "include_selected_qr_rod_shape_var",
                "include_selected_qr_rod_shape_value",
                False,
                bool,
            ),
            "caked_intensity_mode": _normalize_caked_intensity_mode(
                _read_analysis_control(
                    "caked_intensity_mode_var",
                    "caked_intensity_mode_value",
                    "density",
                    str,
                )
            ),
            "rod_profile_intensity_mode": _normalize_rod_profile_intensity_mode(
                _read_analysis_control(
                    "rod_profile_intensity_mode_var",
                    "rod_profile_intensity_mode_value",
                    "density",
                    str,
                )
            ),
            "selected_qr_rod_key": str(
                gui_integration_range_drag._safe_var_get(globals().get("selected_qr_rod_key_var"))
                or getattr(
                    globals().get("integration_range_controls_view_state"),
                    "selected_qr_rod_key_value",
                    "",
                )
            ),
            "selected_qr_rod_keys": _current_selected_qr_rod_keys_from_view_state(),
            "qz_min": _read_analysis_control("qz_min_var", "qz_min_value", 0.0, float),
            "qz_max": _read_analysis_control("qz_max_var", "qz_max_value", 5.0, float),
            "delta_qr": _read_analysis_control("delta_qr_var", "delta_qr_value", 0.1, float),
            "delta_qr_width_mode": "full_width",
        }
    )
    range_view_state = globals().get("integration_range_controls_view_state")
    range_values["qz_min"] = _selected_qr_rod_display_to_qz_value(
        range_values.get("qz_min", 0.0),
        range_view_state,
    )
    range_values["qz_max"] = _selected_qr_rod_display_to_qz_value(
        range_values.get("qz_max", 5.0),
        range_view_state,
    )
    lo, hi = _SELECTED_QR_ROD_DELTA_QR_WIDTH_BOUNDS
    try:
        delta_qr_width = float(range_values.get("delta_qr", 0.1))
    except Exception:
        delta_qr_width = 0.1
    if not np.isfinite(delta_qr_width):
        delta_qr_width = 0.1
    range_values["delta_qr"] = min(max(delta_qr_width, min(lo, hi)), max(lo, hi))
    return range_values


