def _analysis_peak_fit_results_text() -> str:
    empty_text = str(
        globals().get("_ANALYSIS_PEAK_EMPTY_RESULTS_TEXT", "Fit results will appear here.")
    )
    if not getattr(analysis_peak_selection_state, "radial_fit_results", None) and not getattr(
        analysis_peak_selection_state, "azimuth_fit_results", None
    ):
        return empty_text

    analysis_peak_tools = _get_analysis_peak_tools_module()
    lines = [
        line
        for line in (
            analysis_peak_tools.format_peak_fit_axis_table(
                "Radial",
                getattr(analysis_peak_selection_state, "radial_fit_results", ()),
            ),
            analysis_peak_tools.format_peak_fit_axis_table(
                "Azimuth",
                getattr(analysis_peak_selection_state, "azimuth_fit_results", ()),
            ),
        )
        if line
    ]
    if not lines:
        return empty_text
    return "\n\n".join(lines)


def _analysis_peak_state_list(field_name: str) -> list[object]:
    values = getattr(analysis_peak_selection_state, field_name, None)
    if isinstance(values, list):
        return values
    if values is None or isinstance(values, (str, bytes)):
        values = []
    else:
        try:
            values = list(values)
        except Exception:
            values = []
    setattr(analysis_peak_selection_state, field_name, values)
    return values


def _remove_artist_refs(artists: list[object]) -> None:
    while artists:
        artist = artists.pop()
        remover = getattr(artist, "remove", None)
        if callable(remover):
            try:
                remover()
            except Exception:
                pass


def _clear_analysis_peak_overlay_artists(*, redraw: bool) -> None:
    _remove_artist_refs(_analysis_peak_state_list("caked_peak_artists"))
    _remove_artist_refs(_analysis_peak_state_list("radial_peak_artists"))
    _remove_artist_refs(_analysis_peak_state_list("azimuth_peak_artists"))
    _remove_artist_refs(_analysis_peak_state_list("radial_fit_artists"))
    _remove_artist_refs(_analysis_peak_state_list("azimuth_fit_artists"))
    if redraw:
        try:
            canvas_1d.draw_idle()
        except Exception:
            pass
        if callable(globals().get("_request_overlay_canvas_redraw")):
            _request_overlay_canvas_redraw(force=True)


def _clear_analysis_peak_fit_results(*, redraw: bool, update_text: bool) -> None:
    _analysis_peak_state_list("radial_fit_results").clear()
    _analysis_peak_state_list("azimuth_fit_results").clear()
    _remove_artist_refs(_analysis_peak_state_list("radial_fit_artists"))
    _remove_artist_refs(_analysis_peak_state_list("azimuth_fit_artists"))
    _restore_analysis_1d_base_lines_visible()
    if update_text:
        _set_analysis_peak_fit_results_text(
            str(
                globals().get(
                    "_ANALYSIS_PEAK_EMPTY_RESULTS_TEXT",
                    "Fit results will appear here.",
                )
            )
        )
    if redraw:
        try:
            canvas_1d.draw_idle()
        except Exception:
            pass


def _set_analysis_1d_base_lines_visible(axis_kind: str, visible: bool) -> None:
    lines = (
        (globals().get("line_1d_rad"), globals().get("line_1d_rad_bg"))
        if str(axis_kind) == "radial"
        else (globals().get("line_1d_az"), globals().get("line_1d_az_bg"))
    )
    for line in lines:
        if line is None:
            continue
        set_visible = getattr(line, "set_visible", None)
        if callable(set_visible):
            try:
                set_visible(bool(visible))
            except Exception:
                pass
        get_label = getattr(line, "get_label", None)
        set_label = getattr(line, "set_label", None)
        if not callable(get_label) or not callable(set_label):
            continue
        try:
            saved_label = getattr(line, "_ra_sim_analysis_base_label")
            if visible:
                set_label(str(saved_label))
            else:
                set_label("_nolegend_")
            continue
        except Exception:
            pass
        if visible:
            continue
        try:
            setattr(line, "_ra_sim_analysis_base_label", str(get_label()))
            set_label("_nolegend_")
        except Exception:
            pass


def _restore_analysis_1d_base_lines_visible() -> None:
    _set_analysis_1d_base_lines_visible("radial", True)
    _set_analysis_1d_base_lines_visible("azimuth", True)


def _normalize_analysis_peak_source(
    value: object,
    *,
    default: str | None = None,
) -> str:
    text = str(value or "").strip().lower()
    if text in {"background", "simulated", "unknown"}:
        return text
    if default is None:
        return "unknown"
    default_text = str(default or "").strip().lower()
    return default_text if default_text in {"background", "simulated", "unknown"} else "unknown"


def _analysis_peak_match_config(*, max_peaks: int | None = None) -> dict[str, object]:
    return {
        "search_radius_px": 18.0,
        "local_max_size_px": 5,
        "smooth_sigma_px": 1.4,
        "climb_sigma_px": 0.8,
        "min_prominence_sigma": 1.5,
        "min_match_prominence_sigma": 1.5,
        "max_candidate_peaks": max(1, int(10 if max_peaks is None else max_peaks)),
    }


def _analysis_peak_overlay_style(source_name: object) -> dict[str, object]:
    normalized_source = _normalize_analysis_peak_source(source_name)
    if normalized_source == "background":
        return {
            "label_prefix": "B",
            "color": "#00c2ff",
            "marker": "o",
            "line_style": ":",
        }
    if normalized_source == "simulated":
        return {
            "label_prefix": "S",
            "color": "#ff9f1c",
            "marker": "s",
            "line_style": "--",
        }
    return {
        "label_prefix": "U",
        "color": "#9aa0a6",
        "marker": "x",
        "line_style": "-.",
    }


def _analysis_selected_peak_display_entries(
    selected_peaks: Sequence[object] | None,
) -> list[dict[str, object]]:
    source_counts: dict[str, int] = defaultdict(int)
    entries: list[dict[str, object]] = []
    for peak_entry in selected_peaks or ():
        source_name = _normalize_analysis_peak_source(
            peak_entry.get("source") if isinstance(peak_entry, Mapping) else None
        )
        source_counts[source_name] += 1
        source_display_index = int(source_counts[source_name])
        style = _analysis_peak_overlay_style(source_name)
        entries.append(
            {
                "source": source_name,
                "source_display_index": source_display_index,
                "label": f"{style['label_prefix']}{source_display_index}",
                "style": style,
            }
        )
    return entries


def _analysis_resolve_caked_coordinate_pair(
    x_value: float,
    y_value: float,
    *,
    radial_axis: Sequence[float] | None,
    azimuth_axis: Sequence[float] | None,
    convert_indices_if_needed: bool,
) -> tuple[float, float] | None:
    if not (np.isfinite(x_value) and np.isfinite(y_value)):
        return None
    radial_arr = np.asarray(radial_axis, dtype=float).reshape(-1)
    azimuth_arr = np.asarray(azimuth_axis, dtype=float).reshape(-1)
    if radial_arr.size <= 0 or azimuth_arr.size <= 0:
        return float(x_value), float(y_value)

    finite_radial = radial_arr[np.isfinite(radial_arr)]
    finite_azimuth = azimuth_arr[np.isfinite(azimuth_arr)]
    radial_min = float(np.min(finite_radial)) if finite_radial.size else float("nan")
    radial_max = float(np.max(finite_radial)) if finite_radial.size else float("nan")
    azimuth_min = float(np.min(finite_azimuth)) if finite_azimuth.size else float("nan")
    azimuth_max = float(np.max(finite_azimuth)) if finite_azimuth.size else float("nan")
    looks_like_axis = bool(
        np.isfinite(radial_min)
        and np.isfinite(radial_max)
        and np.isfinite(azimuth_min)
        and np.isfinite(azimuth_max)
        and radial_min - 1.0e-9 <= float(x_value) <= radial_max + 1.0e-9
        and azimuth_min - 1.0e-9 <= float(y_value) <= azimuth_max + 1.0e-9
    )
    looks_like_index = bool(
        0.0 <= float(x_value) <= float(radial_arr.size - 1)
        and 0.0 <= float(y_value) <= float(azimuth_arr.size - 1)
    )
    if convert_indices_if_needed and looks_like_index and not looks_like_axis:
        return (
            float(gui_manual_geometry.caked_image_index_to_axis(float(x_value), radial_arr)),
            float(gui_manual_geometry.caked_image_index_to_axis(float(y_value), azimuth_arr)),
        )
    return float(x_value), float(y_value)


def _analysis_simulated_peak_entry_from_record(
    raw_record: Mapping[str, object] | None,
    *,
    radial_axis: Sequence[float] | None,
    azimuth_axis: Sequence[float] | None,
) -> dict[str, object] | None:
    if not isinstance(raw_record, Mapping):
        return None

    resolved_pair = None
    for x_key, y_key, convert_indices_if_needed in (
        ("refined_sim_caked_x", "refined_sim_caked_y", False),
        ("caked_two_theta_deg", "caked_phi_deg", False),
        ("caked_x", "caked_y", False),
        ("two_theta_deg", "phi_deg", False),
        ("tth_deg", "phi_deg", False),
        ("raw_caked_x", "raw_caked_y", True),
    ):
        try:
            x_value = float(raw_record.get(x_key, np.nan))
            y_value = float(raw_record.get(y_key, np.nan))
        except Exception:
            continue
        resolved_pair = _analysis_resolve_caked_coordinate_pair(
            x_value,
            y_value,
            radial_axis=radial_axis,
            azimuth_axis=azimuth_axis,
            convert_indices_if_needed=bool(convert_indices_if_needed),
        )
        if resolved_pair is not None:
            break
    if resolved_pair is None:
        return None

    resolved_two_theta, resolved_phi = resolved_pair
    if not (np.isfinite(resolved_two_theta) and np.isfinite(resolved_phi)):
        return None

    wrapped_phi = float(_get_analysis_peak_tools_module().wrap_angle_degrees(resolved_phi))
    entry: dict[str, object] = {
        "two_theta_deg": float(resolved_two_theta),
        "phi_deg": float(wrapped_phi),
        "source": "simulated",
        "raw_two_theta_deg": float(resolved_two_theta),
        "raw_phi_deg": float(wrapped_phi),
        "discovery_method": "simulation_peak_record",
    }
    for key in ("hkl", "hkl_raw", "q_group_key", "source_label"):
        if key in raw_record:
            entry[key] = raw_record.get(key)
    try:
        intensity_value = float(raw_record.get("intensity", raw_record.get("weight", np.nan)))
    except Exception:
        intensity_value = float("nan")
    if np.isfinite(intensity_value):
        entry["intensity"] = float(intensity_value)
    return entry


def _analysis_caked_peak_sources() -> list[dict[str, object]]:
    sources: list[dict[str, object]] = []

    def _coerce_axis(axis_values: object) -> np.ndarray:
        try:
            return np.asarray(axis_values, dtype=float).reshape(-1)
        except Exception:
            return np.empty((0,), dtype=float)

    radial_axis = _coerce_axis(simulation_runtime_state.last_caked_radial_values)
    azimuth_axis = _coerce_axis(simulation_runtime_state.last_caked_azimuth_values)

    def _image_payload(source_name: str, image: object) -> dict[str, object] | None:
        try:
            image_arr = np.asarray(image, dtype=float)
        except Exception:
            return None
        if image_arr.ndim != 2 or image_arr.size <= 0:
            return None
        if (
            radial_axis.size != int(image_arr.shape[1])
            or azimuth_axis.size != int(image_arr.shape[0])
            or radial_axis.size <= 0
            or azimuth_axis.size <= 0
        ):
            return None
        return {
            "source": str(source_name),
            "image": image_arr,
            "radial_axis": np.asarray(radial_axis, dtype=float),
            "azimuth_axis": np.asarray(azimuth_axis, dtype=float),
        }

    background_payload = _image_payload(
        "background",
        simulation_runtime_state.last_caked_background_image_unscaled,
    )
    if isinstance(background_payload, dict):
        sources.append(background_payload)

    simulated_payload = _image_payload(
        "simulated",
        simulation_runtime_state.last_caked_image_unscaled,
    )
    usable_peak_records = [
        dict(entry)
        for entry in (simulation_runtime_state.peak_records or ())
        if _analysis_simulated_peak_entry_from_record(
            entry if isinstance(entry, Mapping) else None,
            radial_axis=radial_axis,
            azimuth_axis=azimuth_axis,
        )
        is not None
    ]
    if usable_peak_records:
        if simulated_payload is None:
            simulated_payload = {
                "source": "simulated",
                "radial_axis": np.asarray(radial_axis, dtype=float),
                "azimuth_axis": np.asarray(azimuth_axis, dtype=float),
            }
        simulated_payload["peak_records"] = usable_peak_records
    if isinstance(simulated_payload, dict):
        simulated_payload["source"] = "simulated"
        sources.append(simulated_payload)
    return sources


def _current_analysis_caked_peak_source() -> dict[str, object] | None:
    source_payloads = [
        payload
        for payload in _analysis_caked_peak_sources()
        if isinstance(payload, dict) and payload.get("image") is not None
    ]
    if not source_payloads:
        return None
    if bool(background_runtime_state.visible):
        for payload in source_payloads:
            if _normalize_analysis_peak_source(payload.get("source")) == "background":
                return payload
    for payload in source_payloads:
        if _normalize_analysis_peak_source(payload.get("source")) == "simulated":
            return payload
    return source_payloads[0]


def _analysis_selected_box_index_windows(
    radial_axis: Sequence[float] | None,
    azimuth_axis: Sequence[float] | None,
    image_shape: Sequence[int] | None,
) -> list[dict[str, int | float]]:
    radial_arr = np.asarray(radial_axis, dtype=float).reshape(-1)
    azimuth_arr = np.asarray(azimuth_axis, dtype=float).reshape(-1)
    if image_shape is None or len(tuple(image_shape)) < 2:
        return []
    row_count = int(tuple(image_shape)[0])
    col_count = int(tuple(image_shape)[1])
    if (
        radial_arr.size <= 0
        or azimuth_arr.size <= 0
        or row_count <= 0
        or col_count <= 0
        or radial_arr.size != col_count
        or azimuth_arr.size != row_count
    ):
        return []

    range_values = _current_analysis_range_values()
    tth_lo, tth_hi = sorted(
        (
            float(range_values.get("tth_min", np.nan)),
            float(range_values.get("tth_max", np.nan)),
        )
    )
    if not (np.isfinite(tth_lo) and np.isfinite(tth_hi)):
        return []
    col_lo = float(gui_manual_geometry.caked_axis_to_image_index(tth_lo, radial_arr))
    col_hi = float(gui_manual_geometry.caked_axis_to_image_index(tth_hi, radial_arr))
    if not (np.isfinite(col_lo) and np.isfinite(col_hi)):
        return []
    col_start = max(0, min(col_count, int(np.floor(min(col_lo, col_hi)))))
    col_stop = max(0, min(col_count, int(np.ceil(max(col_lo, col_hi))) + 1))
    if col_stop <= col_start:
        return []

    analysis_peak_tools = _get_analysis_peak_tools_module()
    phi_min = analysis_peak_tools.align_angle_to_axis(
        float(range_values.get("phi_min", np.nan)),
        azimuth_arr,
    )
    phi_max = analysis_peak_tools.align_angle_to_axis(
        float(range_values.get("phi_max", np.nan)),
        azimuth_arr,
    )
    if not (np.isfinite(phi_min) and np.isfinite(phi_max)):
        return []

    finite_row_mask = np.isfinite(azimuth_arr)
    if phi_max >= phi_min:
        row_mask = finite_row_mask & (azimuth_arr >= phi_min) & (azimuth_arr <= phi_max)
    else:
        row_mask = finite_row_mask & ((azimuth_arr >= phi_min) | (azimuth_arr <= phi_max))
    row_indices = np.flatnonzero(row_mask)
    if row_indices.size <= 0:
        return []

    windows: list[dict[str, int | float]] = []
    split_points = np.flatnonzero(np.diff(row_indices) > 1)
    segment_start = 0
    for split_point in np.append(split_points, row_indices.size - 1):
        segment = row_indices[segment_start : int(split_point) + 1]
        segment_start = int(split_point) + 1
        if segment.size <= 0:
            continue
        row_start = max(0, min(row_count, int(segment[0])))
        row_stop = max(0, min(row_count, int(segment[-1]) + 1))
        if row_stop <= row_start:
            continue
        segment_phi = np.asarray(azimuth_arr[row_start:row_stop], dtype=float)
        finite_phi = segment_phi[np.isfinite(segment_phi)]
        windows.append(
            {
                "row_start": int(row_start),
                "row_stop": int(row_stop),
                "col_start": int(col_start),
                "col_stop": int(col_stop),
                "phi_min": float(np.min(finite_phi)) if finite_phi.size > 0 else float("nan"),
                "phi_max": float(np.max(finite_phi)) if finite_phi.size > 0 else float("nan"),
                "two_theta_min": float(tth_lo),
                "two_theta_max": float(tth_hi),
            }
        )
    return windows


def _discover_caked_image_peaks_in_selected_box(
    source_payload: Mapping[str, object],
    *,
    max_peaks: int,
    source_name: str,
) -> list[dict[str, object]]:
    try:
        source_image = np.asarray(source_payload.get("image"), dtype=float)
        radial_axis = np.asarray(source_payload.get("radial_axis"), dtype=float).reshape(-1)
        azimuth_axis = np.asarray(source_payload.get("azimuth_axis"), dtype=float).reshape(-1)
    except Exception:
        return []
    if (
        source_image.ndim != 2
        or source_image.size <= 0
        or radial_axis.size != int(source_image.shape[1])
        or azimuth_axis.size != int(source_image.shape[0])
    ):
        return []

    analysis_peak_tools = _get_analysis_peak_tools_module()
    range_values = _current_analysis_range_values()
    windows = _analysis_selected_box_index_windows(
        radial_axis,
        azimuth_axis,
        source_image.shape,
    )
    if not windows:
        return []

    cfg = _analysis_peak_match_config(max_peaks=max_peaks)
    discovered: list[dict[str, object]] = []
    normalized_source = _normalize_analysis_peak_source(source_name)
    for window in windows:
        row_start = int(window["row_start"])
        row_stop = int(window["row_stop"])
        col_start = int(window["col_start"])
        col_stop = int(window["col_stop"])
        crop = np.asarray(source_image[row_start:row_stop, col_start:col_stop], dtype=float)
        if crop.ndim != 2 or crop.size <= 0:
            continue
        try:
            background_context = build_background_peak_context(crop, cfg)
        except Exception:
            continue
        for summit_record in background_context.get("summit_records", ()):
            if not isinstance(summit_record, Mapping):
                continue
            try:
                local_col = float(summit_record.get("center_col", summit_record.get("col", np.nan)))
                local_row = float(summit_record.get("center_row", summit_record.get("row", np.nan)))
            except Exception:
                continue
            if not (np.isfinite(local_col) and np.isfinite(local_row)):
                continue
            full_col = float(local_col + col_start)
            full_row = float(local_row + row_start)
            raw_two_theta = float(
                gui_manual_geometry.caked_image_index_to_axis(full_col, radial_axis)
            )
            raw_phi = float(gui_manual_geometry.caked_image_index_to_axis(full_row, azimuth_axis))
            if not (np.isfinite(raw_two_theta) and np.isfinite(raw_phi)):
                continue
            refined_two_theta, refined_phi = _refine_caked_peak_center(
                source_image,
                radial_axis,
                azimuth_axis,
                raw_two_theta,
                raw_phi,
            )
            if not (np.isfinite(refined_two_theta) and np.isfinite(refined_phi)):
                refined_two_theta = float(raw_two_theta)
                refined_phi = float(raw_phi)
            wrapped_phi = float(analysis_peak_tools.wrap_angle_degrees(refined_phi))
            if not analysis_peak_tools.integration_region_contains(
                refined_two_theta,
                wrapped_phi,
                tth_min=float(range_values.get("tth_min", np.nan)),
                tth_max=float(range_values.get("tth_max", np.nan)),
                phi_min=float(range_values.get("phi_min", np.nan)),
                phi_max=float(range_values.get("phi_max", np.nan)),
            ):
                continue
            peak_entry = {
                "two_theta_deg": float(refined_two_theta),
                "phi_deg": float(wrapped_phi),
                "source": normalized_source,
                "raw_two_theta_deg": float(raw_two_theta),
                "raw_phi_deg": float(analysis_peak_tools.wrap_angle_degrees(raw_phi)),
            }
            if normalized_source == "background":
                peak_entry["discovery_method"] = "background_local_max"
                peak_entry["prominence_sigma"] = float(
                    summit_record.get("prominence_sigma", np.nan)
                )
                peak_entry["background_intensity"] = float(
                    summit_record.get("background_intensity", np.nan)
                )
            else:
                peak_entry["discovery_method"] = "simulated_image_local_max"
                peak_entry["simulated_intensity"] = float(
                    summit_record.get("background_intensity", np.nan)
                )
            discovered.append(peak_entry)
    return discovered


def _discover_background_peaks_in_selected_box(
    source_payload: Mapping[str, object],
    *,
    max_peaks: int,
) -> list[dict[str, object]]:
    discovered = _discover_caked_image_peaks_in_selected_box(
        source_payload,
        max_peaks=max_peaks,
        source_name="background",
    )
    discovered.sort(
        key=lambda entry: (
            -float(entry.get("prominence_sigma", -np.inf)),
            -float(entry.get("background_intensity", -np.inf)),
            float(entry.get("two_theta_deg", np.inf)),
            float(entry.get("phi_deg", np.inf)),
        )
    )
    return discovered[: max(1, int(max_peaks))]


def _discover_simulated_peaks_in_selected_box(
    source_payload: Mapping[str, object],
    *,
    max_peaks: int,
) -> list[dict[str, object]]:
    radial_axis = np.asarray(source_payload.get("radial_axis"), dtype=float).reshape(-1)
    azimuth_axis = np.asarray(source_payload.get("azimuth_axis"), dtype=float).reshape(-1)
    analysis_peak_tools = _get_analysis_peak_tools_module()
    range_values = _current_analysis_range_values()

    record_entries: list[dict[str, object]] = []
    for raw_record in source_payload.get("peak_records", ()):
        peak_entry = _analysis_simulated_peak_entry_from_record(
            raw_record if isinstance(raw_record, Mapping) else None,
            radial_axis=radial_axis,
            azimuth_axis=azimuth_axis,
        )
        if peak_entry is None:
            continue
        if not analysis_peak_tools.integration_region_contains(
            float(peak_entry.get("two_theta_deg", np.nan)),
            float(peak_entry.get("phi_deg", np.nan)),
            tth_min=float(range_values.get("tth_min", np.nan)),
            tth_max=float(range_values.get("tth_max", np.nan)),
            phi_min=float(range_values.get("phi_min", np.nan)),
            phi_max=float(range_values.get("phi_max", np.nan)),
        ):
            continue
        record_entries.append(peak_entry)
    if record_entries:
        record_entries.sort(
            key=lambda entry: (
                -float(entry.get("intensity", -np.inf)),
                float(entry.get("two_theta_deg", np.inf)),
                float(entry.get("phi_deg", np.inf)),
            )
        )
        return record_entries[: max(1, int(max_peaks))]

    discovered = _discover_caked_image_peaks_in_selected_box(
        source_payload,
        max_peaks=max_peaks,
        source_name="simulated",
    )
    discovered.sort(
        key=lambda entry: (
            -float(entry.get("simulated_intensity", -np.inf)),
            float(entry.get("two_theta_deg", np.inf)),
            float(entry.get("phi_deg", np.inf)),
        )
    )
    return discovered[: max(1, int(max_peaks))]


def _analysis_peak_match_index_by_source(
    peaks: Sequence[object] | None,
    *,
    source: object,
    two_theta_deg: float,
    phi_deg: float,
    radial_tolerance_deg: float,
    azimuth_tolerance_deg: float,
) -> int | None:
    target_source = _normalize_analysis_peak_source(source)
    analysis_peak_tools = _get_analysis_peak_tools_module()
    target_tth = float(two_theta_deg)
    target_phi = float(analysis_peak_tools.wrap_angle_degrees(phi_deg))
    radial_tol = max(float(radial_tolerance_deg), 1.0e-6)
    azimuth_tol = max(float(azimuth_tolerance_deg), 1.0e-6)
    for idx, entry in enumerate(peaks or ()):
        if not isinstance(entry, Mapping):
            continue
        if _normalize_analysis_peak_source(entry.get("source")) != target_source:
            continue
        try:
            peak_tth = float(entry.get("two_theta_deg", np.nan))
            peak_phi = float(analysis_peak_tools.wrap_angle_degrees(entry.get("phi_deg", np.nan)))
        except Exception:
            continue
        phi_delta = abs(float(analysis_peak_tools.wrap_angle_degrees(peak_phi - target_phi)))
        if abs(float(peak_tth) - target_tth) <= radial_tol and phi_delta <= azimuth_tol:
            return int(idx)
    return None


def _find_analysis_peaks_in_selected_box(
    *,
    replace_existing: bool = True,
) -> int:
    source_payloads = {
        _normalize_analysis_peak_source(payload.get("source")): payload
        for payload in _analysis_caked_peak_sources()
        if isinstance(payload, Mapping)
    }
    max_peaks = int(_analysis_peak_match_config().get("max_candidate_peaks", 10))
    background_peaks = []
    simulated_peaks = []
    if isinstance(source_payloads.get("background"), Mapping):
        background_peaks = _discover_background_peaks_in_selected_box(
            source_payloads["background"],
            max_peaks=max_peaks,
        )
    if isinstance(source_payloads.get("simulated"), Mapping):
        simulated_peaks = _discover_simulated_peaks_in_selected_box(
            source_payloads["simulated"],
            max_peaks=max_peaks,
        )

    selected_peaks = (
        []
        if bool(replace_existing)
        else [dict(entry) for entry in analysis_peak_selection_state.selected_peaks]
    )
    radial_tol, azimuth_tol = _analysis_peak_duplicate_tolerances()
    for peak_entry in [*background_peaks, *simulated_peaks]:
        match_index = _analysis_peak_match_index_by_source(
            selected_peaks,
            source=peak_entry.get("source"),
            two_theta_deg=float(peak_entry.get("two_theta_deg", np.nan)),
            phi_deg=float(peak_entry.get("phi_deg", np.nan)),
            radial_tolerance_deg=float(radial_tol),
            azimuth_tolerance_deg=float(azimuth_tol),
        )
        if match_index is None:
            selected_peaks.append(dict(peak_entry))
        else:
            selected_peaks[int(match_index)] = dict(peak_entry)

    analysis_peak_selection_state.selected_peaks = selected_peaks
    _clear_analysis_peak_fit_results(redraw=False, update_text=True)
    _set_analysis_peak_selection_status_text(_analysis_peak_selection_status_text())
    if background_peaks or simulated_peaks:
        status_text = (
            f"Found {len(background_peaks)} background and "
            f"{len(simulated_peaks)} simulated peaks in selected box."
        )
    elif not source_payloads:
        status_text = "No background or simulated sources were available in Analyze mode."
    else:
        status_text = "No background or simulated peaks were found in selected box."
    try:
        progress_label_positions.config(text=status_text)
    except Exception:
        pass
    _render_analysis_peak_overlays(redraw=True)
    return int(len(selected_peaks))


def _analysis_curve_data(
    axis_kind: str,
    source_preference: str,
) -> tuple[np.ndarray, np.ndarray, str]:
    data = simulation_runtime_state.last_1d_integration_data
    scale = _get_scale_factor_value(default=1.0)

    def _extract(source_name: str) -> tuple[np.ndarray, np.ndarray]:
        if source_name not in {"background", "simulated"}:
            return np.empty((0,), dtype=float), np.empty((0,), dtype=float)
        if not isinstance(data, Mapping):
            return np.empty((0,), dtype=float), np.empty((0,), dtype=float)
        source_key = "bg" if str(source_name) == "background" else "sim"
        if str(axis_kind) == "radial":
            x_values = data.get(f"radials_{source_key}")
            y_values = data.get(f"intensities_2theta_{source_key}")
        else:
            x_values = data.get(f"azimuths_{source_key}")
            y_values = data.get(f"intensities_azimuth_{source_key}")
        if x_values is None or y_values is None:
            return np.empty((0,), dtype=float), np.empty((0,), dtype=float)
        x_arr = np.asarray(x_values, dtype=float)
        y_arr = np.asarray(y_values, dtype=float)
        if str(source_name) != "background":
            y_arr = y_arr * float(scale)
        return x_arr, y_arr

    resolved = _normalize_analysis_peak_source(source_preference)
    if resolved not in {"background", "simulated"}:
        return np.empty((0,), dtype=float), np.empty((0,), dtype=float), resolved
    x_arr, y_arr = _extract(resolved)
    if x_arr.size > 0 and y_arr.size > 0:
        return x_arr, y_arr, resolved
    return np.empty((0,), dtype=float), np.empty((0,), dtype=float), resolved


def _analysis_linear_background_enabled() -> bool:
    var = getattr(
        analysis_peak_tools_view_state,
        "subtract_linear_background_var",
        None,
    )
    return bool(
        getattr(
            var,
            "get",
            lambda: True,
        )()
    )


def _analysis_linear_background_corrected_curves(
    source_payload: Mapping[str, object] | None,
    selected_items: Sequence[Mapping[str, object]],
) -> dict[str, object] | None:
    """Return selected-box 1D curves after local 2D plane subtraction."""

    if not isinstance(source_payload, Mapping):
        return None
    try:
        source_image = np.asarray(source_payload.get("image"), dtype=float)
        radial_axis = np.asarray(source_payload.get("radial_axis"), dtype=float).reshape(-1)
        azimuth_axis = np.asarray(source_payload.get("azimuth_axis"), dtype=float).reshape(-1)
    except Exception:
        return None
    if (
        source_image.ndim != 2
        or source_image.size <= 0
        or radial_axis.size != int(source_image.shape[1])
        or azimuth_axis.size != int(source_image.shape[0])
    ):
        return None

    windows = _analysis_selected_box_index_windows(
        radial_axis,
        azimuth_axis,
        source_image.shape,
    )
    if not windows:
        return None

    analysis_peak_tools = _get_analysis_peak_tools_module()
    fit_metadata: list[dict[str, object]] = []
    fit_failures: list[dict[str, object]] = []
    selected_peaks: list[dict[str, object]] = []
    for item in selected_items or ():
        if not isinstance(item, Mapping):
            continue
        peak_entry = item.get("peak_entry")
        if isinstance(peak_entry, Mapping):
            selected_peaks.append(dict(peak_entry))
        else:
            selected_peaks.append(dict(item))
    radial_parts: list[tuple[np.ndarray, np.ndarray]] = []
    azimuth_parts: list[tuple[np.ndarray, np.ndarray]] = []

    def _combine_local_profile_parts(
        parts: Sequence[tuple[np.ndarray, np.ndarray]],
    ) -> tuple[np.ndarray, np.ndarray]:
        x_arrays: list[np.ndarray] = []
        y_arrays: list[np.ndarray] = []
        for x_values, y_values in parts:
            x_arr = np.asarray(x_values, dtype=float).reshape(-1)
            y_arr = np.asarray(y_values, dtype=float).reshape(-1)
            if x_arr.size <= 0 or x_arr.size != y_arr.size:
                continue
            finite_mask = np.isfinite(x_arr) & np.isfinite(y_arr)
            if not np.any(finite_mask):
                continue
            x_arrays.append(np.asarray(x_arr[finite_mask], dtype=float))
            y_arrays.append(np.asarray(y_arr[finite_mask], dtype=float))
        if not x_arrays:
            return np.empty((0,), dtype=float), np.empty((0,), dtype=float)

        x_all = np.concatenate(x_arrays).astype(float, copy=False)
        y_all = np.concatenate(y_arrays).astype(float, copy=False)
        order = np.argsort(x_all)
        x_sorted = np.asarray(x_all[order], dtype=float)
        y_sorted = np.asarray(y_all[order], dtype=float)
        unique_x, inverse = np.unique(x_sorted, return_inverse=True)
        y_combined = np.empty(unique_x.shape, dtype=float)
        for index in range(int(unique_x.size)):
            samples = y_sorted[inverse == index]
            y_combined[index] = float(np.nanmean(samples))
        finite_combined = np.isfinite(unique_x) & np.isfinite(y_combined)
        return (
            np.asarray(unique_x[finite_combined], dtype=float),
            np.asarray(y_combined[finite_combined], dtype=float),
        )

    for window in windows:
        try:
            row_start = int(window["row_start"])
            row_stop = int(window["row_stop"])
            col_start = int(window["col_start"])
            col_stop = int(window["col_stop"])
        except Exception:
            continue
        if row_stop <= row_start or col_stop <= col_start:
            fit_failures.append(
                {
                    "success": False,
                    "error": "Selected-box window has no caked pixels.",
                    "row_start": int(row_start),
                    "row_stop": int(row_stop),
                    "col_start": int(col_start),
                    "col_stop": int(col_stop),
                }
            )
            continue
        roi = np.asarray(source_image[row_start:row_stop, col_start:col_stop], dtype=float)
        theta_values = np.asarray(radial_axis[col_start:col_stop], dtype=float)
        phi_values = np.asarray(azimuth_axis[row_start:row_stop], dtype=float)
        result = analysis_peak_tools.subtract_linear_background_plane(
            theta_values,
            phi_values,
            roi,
            selected_peaks,
        )
        if not bool(result.get("success", False)):
            fit_failures.append(
                {
                    "success": False,
                    "error": str(result.get("error", "linear background fit failed")),
                    "row_start": int(row_start),
                    "row_stop": int(row_stop),
                    "col_start": int(col_start),
                    "col_stop": int(col_stop),
                    "fit_sample_count": int(result.get("fit_sample_count", 0)),
                    "finite_sample_count": int(result.get("finite_sample_count", 0)),
                    "peak_mask_sample_count": int(result.get("peak_mask_sample_count", 0)),
                }
            )
            continue
        corrected_roi = np.asarray(result.get("corrected"), dtype=float)
        if corrected_roi.shape != roi.shape:
            fit_failures.append(
                {
                    "success": False,
                    "error": "Linear background correction returned a mismatched ROI shape.",
                    "row_start": int(row_start),
                    "row_stop": int(row_stop),
                    "col_start": int(col_start),
                    "col_stop": int(col_stop),
                }
            )
            continue

        with np.errstate(invalid="ignore"):
            radial_y = np.nanmean(corrected_roi, axis=0)
            azimuth_y = np.nanmean(corrected_roi, axis=1)
        radial_parts.append((theta_values, np.asarray(radial_y, dtype=float)))
        azimuth_parts.append((phi_values, np.asarray(azimuth_y, dtype=float)))
        fit_metadata.append(
            {
                "success": True,
                "coefficients": list(result.get("coefficients", [])),
                "theta_ref": float(result.get("theta_ref", np.nan)),
                "phi_ref": float(result.get("phi_ref", np.nan)),
                "fit_sample_count": int(result.get("fit_sample_count", 0)),
                "initial_fit_sample_count": int(result.get("initial_fit_sample_count", 0)),
                "finite_sample_count": int(result.get("finite_sample_count", 0)),
                "peak_mask_sample_count": int(result.get("peak_mask_sample_count", 0)),
                "clipped_sample_count": int(result.get("clipped_sample_count", 0)),
                "row_start": int(row_start),
                "row_stop": int(row_stop),
                "col_start": int(col_start),
                "col_stop": int(col_stop),
            }
        )

    metadata: dict[str, object] = {
        "enabled": True,
        "applied": False,
        "method": "local_2d_linear_plane",
        "windows": fit_metadata,
        "failures": fit_failures,
    }
    if fit_failures or not fit_metadata:
        metadata["error"] = "Linear background subtraction failed for the selected box."
        return {"metadata": metadata}

    radial_x, radial_y = _combine_local_profile_parts(radial_parts)
    azimuth_x, azimuth_y = _combine_local_profile_parts(azimuth_parts)
    if radial_x.size <= 0 or azimuth_x.size <= 0:
        metadata["error"] = "Linear background subtraction produced no finite 1D curves."
        return {"metadata": metadata}

    metadata["applied"] = True
    return {
        "radial": (
            np.asarray(radial_x, dtype=float),
            np.asarray(radial_y, dtype=float),
        ),
        "azimuth": (
            np.asarray(azimuth_x, dtype=float),
            np.asarray(azimuth_y, dtype=float),
        ),
        "metadata": metadata,
    }


def _analysis_peak_duplicate_tolerances() -> tuple[float, float]:
    radial_axis = np.asarray(simulation_runtime_state.last_caked_radial_values, dtype=float)
    azimuth_axis = np.asarray(simulation_runtime_state.last_caked_azimuth_values, dtype=float)
    if radial_axis.size >= 2:
        radial_step = float(np.nanmedian(np.abs(np.diff(np.sort(radial_axis)))))
    else:
        radial_step = 0.0
    if azimuth_axis.size >= 2:
        azimuth_step = float(np.nanmedian(np.abs(np.diff(np.sort(azimuth_axis)))))
    else:
        azimuth_step = 0.0
    return max(2.0 * radial_step, 0.05), max(2.0 * azimuth_step, 0.5)


def _analysis_peak_axis_value(
    peak_entry: Mapping[str, object],
    *,
    axis_kind: str,
    axis_values: Sequence[float] | None,
) -> float:
    if str(axis_kind) == "radial":
        return float(peak_entry.get("two_theta_deg", np.nan))
    return _get_analysis_peak_tools_module().align_angle_to_axis(
        float(peak_entry.get("phi_deg", np.nan)),
        axis_values,
    )


def _analysis_curve_selected_window(
    axis_kind: str,
    x_values: Sequence[float] | None,
    y_values: Sequence[float] | None,
) -> tuple[np.ndarray, np.ndarray]:
    """Return the selected-window subset of one cached 1D integration curve."""

    x_arr = np.asarray(x_values, dtype=float)
    y_arr = np.asarray(y_values, dtype=float)
    if x_arr.ndim != 1 or y_arr.ndim != 1 or x_arr.size != y_arr.size:
        return np.empty((0,), dtype=float), np.empty((0,), dtype=float)

    finite_mask = np.isfinite(x_arr) & np.isfinite(y_arr)
    if not np.any(finite_mask):
        return np.empty((0,), dtype=float), np.empty((0,), dtype=float)

    x_arr = np.asarray(x_arr[finite_mask], dtype=float)
    y_arr = np.asarray(y_arr[finite_mask], dtype=float)
    range_values = _current_analysis_range_values()
    if str(axis_kind) == "radial":
        lower_bound, upper_bound = sorted(
            (
                float(range_values.get("tth_min", np.min(x_arr))),
                float(range_values.get("tth_max", np.max(x_arr))),
            )
        )
        window_mask = (x_arr >= lower_bound) & (x_arr <= upper_bound)
    else:
        analysis_peak_tools = _get_analysis_peak_tools_module()
        phi_min = analysis_peak_tools.align_angle_to_axis(
            float(range_values.get("phi_min", np.min(x_arr))),
            x_arr,
        )
        phi_max = analysis_peak_tools.align_angle_to_axis(
            float(range_values.get("phi_max", np.max(x_arr))),
            x_arr,
        )
        if phi_max >= phi_min:
            window_mask = (x_arr >= phi_min) & (x_arr <= phi_max)
        else:
            window_mask = (x_arr >= phi_min) | (x_arr <= phi_max)

    if np.any(window_mask):
        return np.asarray(x_arr[window_mask], dtype=float), np.asarray(
            y_arr[window_mask], dtype=float
        )
    return np.empty((0,), dtype=float), np.empty((0,), dtype=float)


def _analysis_curve_with_gap_breaks(
    x_values: Sequence[float] | None,
    y_values: Sequence[float] | None,
) -> tuple[np.ndarray, np.ndarray]:
    """Insert NaN breaks so wrapped selected windows do not plot through excluded gaps."""

    x_arr = np.asarray(x_values, dtype=float)
    y_arr = np.asarray(y_values, dtype=float)
    if x_arr.ndim != 1 or y_arr.ndim != 1 or x_arr.size != y_arr.size:
        return np.empty((0,), dtype=float), np.empty((0,), dtype=float)

    finite_mask = np.isfinite(x_arr) & np.isfinite(y_arr)
    if not np.any(finite_mask):
        return np.empty((0,), dtype=float), np.empty((0,), dtype=float)

    x_arr = np.asarray(x_arr[finite_mask], dtype=float)
    y_arr = np.asarray(y_arr[finite_mask], dtype=float)
    if x_arr.size < 3:
        return x_arr, y_arr

    unique_x = np.unique(x_arr[np.isfinite(x_arr)])
    if unique_x.size < 2:
        return x_arr, y_arr

    positive_diffs = np.diff(np.sort(unique_x))
    positive_diffs = positive_diffs[np.isfinite(positive_diffs) & (positive_diffs > 0.0)]
    if positive_diffs.size <= 0:
        return x_arr, y_arr

    axis_step = float(np.nanmedian(positive_diffs))
    if not np.isfinite(axis_step) or axis_step <= 0.0:
        return x_arr, y_arr

    gap_threshold = max(180.0, 10.0 * axis_step)
    gap_indices = np.flatnonzero(np.abs(np.diff(x_arr)) > gap_threshold)
    if gap_indices.size <= 0:
        return x_arr, y_arr

    x_segments: list[float] = []
    y_segments: list[float] = []
    for idx, (x_value, y_value) in enumerate(zip(x_arr, y_arr, strict=False)):
        x_segments.append(float(x_value))
        y_segments.append(float(y_value))
        if int(idx) in gap_indices:
            x_segments.append(float("nan"))
            y_segments.append(float("nan"))

    return np.asarray(x_segments, dtype=float), np.asarray(y_segments, dtype=float)


def _analysis_peak_fit_failure_entry(
    *,
    peak_index: int,
    axis_kind: str,
    selected_axis_value: float,
    two_theta_deg: float,
    phi_deg: float,
    source: str,
    source_display_index: int,
    curve_source: str,
    model: str,
    label: str,
    fit_group_id: str,
    error: str,
) -> dict[str, object]:
    """Return one failed Analyze-mode peak-fit entry."""

    return {
        "success": False,
        "peak_index": int(peak_index),
        "axis_kind": str(axis_kind),
        "selected_axis_value": float(selected_axis_value),
        "two_theta_deg": float(two_theta_deg),
        "phi_deg": float(phi_deg),
        "source": str(source),
        "source_display_index": int(source_display_index),
        "curve_source": str(curve_source),
        "model": str(model),
        "label": str(label),
        "fit_group_id": str(fit_group_id),
        "error": " ".join(str(error or "fit failed").split()),
    }


def _analysis_cache_overlay_tables(show_caked: bool) -> list[object]:
    if bool(show_caked):
        cache_tables = []
        if _live_caked_intersection_cache_is_current():
            cache_tables = simulation_runtime_state.last_caked_intersection_cache
        if not cache_tables:
            cache_tables = simulation_runtime_state.stored_intersection_cache
    else:
        cache_tables = simulation_runtime_state.stored_intersection_cache
        if not cache_tables and _live_caked_intersection_cache_is_current():
            cache_tables = simulation_runtime_state.last_caked_intersection_cache
    return list(cache_tables or [])


def _render_analysis_peak_overlays(*, redraw: bool) -> None:
    _clear_analysis_peak_overlay_artists(redraw=False)
    _restore_analysis_1d_base_lines_visible()

    if _resolved_primary_analysis_display_mode() != "caked":
        if redraw:
            try:
                canvas_1d.draw_idle()
            except Exception:
                pass
            if callable(globals().get("_request_overlay_canvas_redraw")):
                _request_overlay_canvas_redraw(force=True)
        else:
            if callable(globals().get("_request_overlay_canvas_redraw")):
                _request_overlay_canvas_redraw()
        return

    selected_peaks = list(_analysis_peak_state_list("selected_peaks"))
    display_entries = _analysis_selected_peak_display_entries(selected_peaks)
    radial_fit_results = list(_analysis_peak_state_list("radial_fit_results"))
    azimuth_fit_results = list(_analysis_peak_state_list("azimuth_fit_results"))
    caked_peak_artists = _analysis_peak_state_list("caked_peak_artists")
    radial_peak_artists = _analysis_peak_state_list("radial_peak_artists")
    azimuth_peak_artists = _analysis_peak_state_list("azimuth_peak_artists")
    radial_fit_artists = _analysis_peak_state_list("radial_fit_artists")
    azimuth_fit_artists = _analysis_peak_state_list("azimuth_fit_artists")
    has_fit_results = bool(radial_fit_results or azimuth_fit_results)
    show_caked = True
    cache_tables = _analysis_cache_overlay_tables(show_caked)
    if not selected_peaks and not cache_tables and not has_fit_results:
        if redraw:
            try:
                canvas_1d.draw_idle()
            except Exception:
                pass
            if callable(globals().get("_request_overlay_canvas_redraw")):
                _request_overlay_canvas_redraw(force=True)
        else:
            if callable(globals().get("_request_overlay_canvas_redraw")):
                _request_overlay_canvas_redraw()
        return

    if show_caked:
        for peak_entry, display_entry in zip(selected_peaks, display_entries, strict=False):
            try:
                peak_tth = float(peak_entry.get("two_theta_deg"))
                peak_phi = float(peak_entry.get("phi_deg"))
            except Exception:
                continue
            style = dict(display_entry.get("style", {}))
            try:
                marker_artist = ax.plot(
                    [peak_tth],
                    [peak_phi],
                    linestyle="none",
                    marker=str(style.get("marker", "o")),
                    markersize=7.0,
                    markerfacecolor="none",
                    markeredgecolor=str(style.get("color", "#00c2ff")),
                    markeredgewidth=1.6,
                    zorder=11,
                )[0]
                label_artist = ax.text(
                    peak_tth,
                    peak_phi,
                    str(display_entry.get("label", "P?")),
                    color=str(style.get("color", "#00c2ff")),
                    fontsize=8,
                    ha="left",
                    va="bottom",
                    zorder=12,
                )
                caked_peak_artists.extend([marker_artist, label_artist])
            except Exception:
                continue

    axis_specs = (
        (
            "radial",
            ax_1d_radial,
            radial_peak_artists,
            radial_fit_artists,
            radial_fit_results,
        ),
        (
            "azimuth",
            ax_1d_azim,
            azimuth_peak_artists,
            azimuth_fit_artists,
            azimuth_fit_results,
        ),
    )
    for axis_kind, axis_obj, marker_store, fit_store, fit_results in axis_specs:
        background_subtracted_fit_entries: list[Mapping[str, object]] = []
        for fit_entry in fit_results:
            if not bool(fit_entry.get("success", False)):
                continue
            if fit_entry.get("plot_fit") is False:
                continue
            if not bool(fit_entry.get("background_subtracted", False)):
                continue
            linear_background = fit_entry.get("linear_background")
            if isinstance(linear_background, Mapping) and not bool(
                linear_background.get("applied", True)
            ):
                continue
            background_subtracted_fit_entries.append(fit_entry)
        if background_subtracted_fit_entries:
            _set_analysis_1d_base_lines_visible(axis_kind, False)

        plotted_background_subtracted_group_ids: set[str] = set()
        background_subtracted_curves_by_source: dict[str, tuple[np.ndarray, np.ndarray]] = {}
        for fit_entry in background_subtracted_fit_entries:
            fit_group_id = str(fit_entry.get("fit_group_id", "") or "").strip()
            if fit_group_id and fit_group_id in plotted_background_subtracted_group_ids:
                continue
            x_data = np.asarray(fit_entry.get("x_window"), dtype=float)
            y_data = np.asarray(fit_entry.get("y_window"), dtype=float)
            if x_data.size <= 0 or y_data.size <= 0 or x_data.size != y_data.size:
                continue
            x_data, y_data = _analysis_curve_with_gap_breaks(x_data, y_data)
            if x_data.size <= 0 or y_data.size <= 0 or x_data.size != y_data.size:
                continue
            try:
                data_artist = axis_obj.plot(
                    x_data,
                    y_data,
                    color="#1f77b4",
                    linewidth=1.2,
                    alpha=0.9,
                    zorder=4,
                    label="Background-subtracted data",
                )[0]
                fit_store.append(data_artist)
                source_name = _normalize_analysis_peak_source(
                    fit_entry.get("source"),
                    default="unknown",
                )
                background_subtracted_curves_by_source.setdefault(
                    source_name,
                    (
                        np.asarray(x_data, dtype=float),
                        np.asarray(y_data, dtype=float),
                    ),
                )
                if fit_group_id:
                    plotted_background_subtracted_group_ids.add(fit_group_id)
            except Exception:
                continue

        plotted_fit_group_ids: set[str] = set()
        for peak_entry, display_entry in zip(selected_peaks, display_entries, strict=False):
            source_name = str(display_entry.get("source", "unknown"))
            normalized_source = _normalize_analysis_peak_source(
                source_name,
                default="unknown",
            )
            corrected_pair = background_subtracted_curves_by_source.get(normalized_source)
            if corrected_pair is not None:
                x_curve, y_curve = corrected_pair
            else:
                x_curve, y_curve, _resolved_source = _analysis_curve_data(
                    axis_kind,
                    source_name,
                )
            if x_curve.size <= 0 or y_curve.size <= 0:
                continue
            axis_value = _analysis_peak_axis_value(
                peak_entry,
                axis_kind=axis_kind,
                axis_values=x_curve,
            )
            if not np.isfinite(axis_value):
                continue
            y_value = _get_analysis_peak_tools_module().sample_curve_value(
                x_curve,
                y_curve,
                axis_value,
            )
            style = dict(display_entry.get("style", {}))
            try:
                vline_artist = axis_obj.axvline(
                    axis_value,
                    color=str(style.get("color", "#7b2cbf")),
                    linestyle=str(style.get("line_style", ":")),
                    linewidth=1.0,
                    alpha=0.65,
                )
                marker_store.append(vline_artist)
                if np.isfinite(y_value):
                    marker_artist = axis_obj.plot(
                        [axis_value],
                        [y_value],
                        linestyle="none",
                        marker=str(style.get("marker", "o")),
                        markersize=5.5,
                        color=str(style.get("color", "#7b2cbf")),
                        zorder=6,
                    )[0]
                    marker_store.append(marker_artist)
                    label_artist = axis_obj.text(
                        axis_value,
                        y_value,
                        str(display_entry.get("label", "P?")),
                        color=str(style.get("color", "#7b2cbf")),
                        fontsize=8,
                        ha="left",
                        va="bottom",
                    )
                    marker_store.append(label_artist)
            except Exception:
                continue

        for fit_entry in fit_results:
            if not bool(fit_entry.get("success", False)):
                continue
            if fit_entry.get("plot_fit") is False:
                continue
            fit_group_id = str(fit_entry.get("fit_group_id", "") or "").strip()
            if fit_group_id and fit_group_id in plotted_fit_group_ids:
                continue
            x_values = fit_entry.get("x_fit")
            if x_values is None:
                x_values = fit_entry.get("x_window")
            x_window = np.asarray(x_values, dtype=float)
            y_fit = np.asarray(fit_entry.get("y_fit"), dtype=float)
            if x_window.size <= 0 or y_fit.size <= 0 or x_window.size != y_fit.size:
                continue
            x_window, y_fit = _analysis_curve_with_gap_breaks(x_window, y_fit)
            if x_window.size <= 0 or y_fit.size <= 0 or x_window.size != y_fit.size:
                continue
            try:
                fit_artist = axis_obj.plot(
                    x_window,
                    y_fit,
                    color=_ANALYSIS_PEAK_MODEL_COLORS.get(
                        str(fit_entry.get("model")),
                        "#6d597a",
                    ),
                    linewidth=1.5,
                    alpha=0.95,
                    zorder=5,
                )[0]
                fit_store.append(fit_artist)
                if fit_group_id:
                    plotted_fit_group_ids.add(fit_group_id)
            except Exception:
                continue

        try:
            axis_obj.legend()
        except Exception:
            pass

    if redraw:
        try:
            canvas_1d.draw_idle()
        except Exception:
            pass
        if callable(globals().get("_request_overlay_canvas_redraw")):
            _request_overlay_canvas_redraw(force=True)
    elif callable(globals().get("_request_overlay_canvas_redraw")):
        _request_overlay_canvas_redraw()


