def _render_analysis_integration_range_controls(
    *,
    parent,
    range_values: Mapping[str, object] | None = None,
) -> None:
    global tth_min_var, tth_max_var, phi_min_var, phi_max_var
    global integrate_selected_qr_rod_var, mirror_selected_qr_phi_var
    global include_selected_qr_rod_shape_var, selected_qr_rod_key_var
    global caked_intensity_mode_var, rod_profile_intensity_mode_var
    global qz_min_var, qz_max_var, delta_qr_var
    global tth_min_slider, tth_max_slider, phi_min_slider, phi_max_slider

    values = dict(range_values or _current_analysis_roi_values())
    _clear_widget_children(parent)
    refresh_region_visuals_callback = globals().get("refresh_integration_region_visuals")
    if not callable(refresh_region_visuals_callback):
        refresh_region_visuals_callback = None

    selected_qr_lattice_c = _current_selected_qr_rod_lattice_c()
    selected_qr_qz_display_scale = (
        float(selected_qr_lattice_c) / (2.0 * np.pi) if selected_qr_lattice_c is not None else 1.0
    )
    selected_qr_axis_label = "L" if selected_qr_lattice_c is not None else "Qz"

    gui_integration_range_drag.create_runtime_integration_range_controls(
        parent=parent,
        views_module=gui_views,
        view_state=integration_range_controls_view_state,
        show_1d_var=analysis_view_controls_view_state.show_1d_var,
        tth_min=float(values.get("tth_min", 0.0)),
        tth_max=float(values.get("tth_max", 80.0)),
        phi_min=float(values.get("phi_min", -15.0)),
        phi_max=float(values.get("phi_max", 15.0)),
        integrate_selected_qr_rod=bool(values.get("integrate_selected_qr_rod", False)),
        mirror_selected_qr_phi=bool(values.get("mirror_selected_qr_phi", False)),
        include_selected_qr_rod_shape=bool(values.get("include_selected_qr_rod_shape", False)),
        caked_intensity_mode=_normalize_caked_intensity_mode(
            values.get("caked_intensity_mode", "density")
        ),
        rod_profile_intensity_mode=_normalize_rod_profile_intensity_mode(
            values.get("rod_profile_intensity_mode", "density")
        ),
        selected_qr_rod_default_intensity_mode=(
            "raw_sum" if _current_app_shell_view_mode() == "detector" else "density"
        ),
        selected_qr_rod_key=str(values.get("selected_qr_rod_key", "")),
        selected_qr_rod_keys=list(values.get("selected_qr_rod_keys", []) or ()),
        selected_qr_rod_options=_selected_qr_rod_option_pairs(_analysis_selected_qr_rod_entries()),
        qz_min=float(values.get("qz_min", 0.0)),
        qz_max=float(values.get("qz_max", 5.0)),
        qz_display_scale=selected_qr_qz_display_scale,
        qz_display_axis_label=selected_qr_axis_label,
        selected_qr_geometry_summary=_selected_qr_rod_geometry_summary_text(),
        delta_qr=float(values.get("delta_qr", 0.1)),
        schedule_range_update=integration_range_update_runtime_callbacks.schedule_range_update,
        disable_peak_pick=lambda: _set_analysis_peak_pick_mode(False),
        refresh_region_visuals=refresh_region_visuals_callback,
    )

    tth_min_var = integration_range_controls_view_state.tth_min_var
    tth_max_var = integration_range_controls_view_state.tth_max_var
    phi_min_var = integration_range_controls_view_state.phi_min_var
    phi_max_var = integration_range_controls_view_state.phi_max_var
    integrate_selected_qr_rod_var = (
        integration_range_controls_view_state.integrate_selected_qr_rod_var
    )
    mirror_selected_qr_phi_var = integration_range_controls_view_state.mirror_selected_qr_phi_var
    include_selected_qr_rod_shape_var = (
        integration_range_controls_view_state.include_selected_qr_rod_shape_var
    )
    caked_intensity_mode_var = integration_range_controls_view_state.caked_intensity_mode_var
    rod_profile_intensity_mode_var = (
        integration_range_controls_view_state.rod_profile_intensity_mode_var
    )
    selected_qr_rod_key_var = integration_range_controls_view_state.selected_qr_rod_key_var
    qz_min_var = integration_range_controls_view_state.qz_min_var
    qz_max_var = integration_range_controls_view_state.qz_max_var
    delta_qr_var = integration_range_controls_view_state.delta_qr_var
    tth_min_slider = integration_range_controls_view_state.tth_min_slider
    tth_max_slider = integration_range_controls_view_state.tth_max_slider
    phi_min_slider = integration_range_controls_view_state.phi_min_slider
    phi_max_slider = integration_range_controls_view_state.phi_max_slider
    _sync_selected_qr_rod_controls_state()
    _sync_selected_qr_rod_geometry_summary_text()

    if any(
        ref is None
        for ref in (
            tth_min_var,
            tth_max_var,
            phi_min_var,
            phi_max_var,
            tth_min_slider,
            tth_max_slider,
            phi_min_slider,
            phi_max_slider,
        )
    ):
        raise RuntimeError("Integration-range controls did not create the expected widgets.")

    _render_analysis_peak_overlays(redraw=False)


