def _parse_sample_count(raw_value, fallback):
    return gui_controllers.normalize_sample_count(
        raw_value,
        fallback,
        minimum=MIN_RANDOM_SAMPLE_COUNT,
        maximum=MAX_RANDOM_SAMPLE_COUNT,
    )


def _parse_events_per_beam_phase(raw_value, fallback):
    return gui_controllers.normalize_events_per_beam_phase(
        raw_value,
        fallback,
        minimum=MIN_EVENTS_PER_BEAM_PHASE,
        maximum=MAX_EVENTS_PER_BEAM_PHASE,
    )


def _default_random_sample_count() -> int:
    return _parse_sample_count(
        defaults.get("sampling_count", DEFAULT_RANDOM_SAMPLE_COUNT),
        DEFAULT_RANDOM_SAMPLE_COUNT,
    )


def _default_events_per_beam_phase() -> int:
    return _parse_events_per_beam_phase(
        defaults.get("events_per_beam_phase", DEFAULT_EVENTS_PER_BEAM_PHASE),
        DEFAULT_EVENTS_PER_BEAM_PHASE,
    )


def _current_rod_points_per_gz(default=None):
    fallback = gui_controllers.default_rod_points_per_gz(
        defaults["c"],
    )
    if default is not None:
        fallback = gui_controllers.normalize_rod_points_per_gz(default, fallback)
    rod_var = sampling_optics_controls_view_state.rod_points_per_gz_var
    raw_value = rod_var.get() if rod_var is not None else fallback
    return gui_controllers.normalize_rod_points_per_gz(raw_value, fallback)


def _current_sampling_optics_bool(var_name: str, default_key: str, fallback_value: bool, default):
    fallback = bool(default if default is not None else defaults.get(default_key, fallback_value))
    view_var = getattr(
        sampling_optics_controls_view_state,
        var_name,
        None,
    )
    global_var = globals().get(var_name)
    value_var = view_var if view_var is not None else global_var
    getter = getattr(value_var, "get", None)
    if not callable(getter):
        return fallback
    try:
        return bool(getter())
    except Exception:
        return fallback


def _current_parratt_low_q_stitch_enabled(default=None) -> bool:
    return _current_sampling_optics_bool(
        "parratt_low_q_stitch_var",
        "parratt_low_q_stitch",
        True,
        default,
    )


def _current_parratt_use_cif_optics(default=None) -> bool:
    return _current_sampling_optics_bool(
        "parratt_use_cif_optics_var",
        "parratt_use_cif_optics",
        False,
        default,
    )


def _current_parratt_float(var_name: str, default_key: str, fallback_value: float) -> float:
    fallback = float(defaults.get(default_key, fallback_value))
    view_var = getattr(sampling_optics_controls_view_state, var_name, None)
    global_var = globals().get(var_name)
    value_var = view_var if view_var is not None else global_var
    getter = getattr(value_var, "get", None)
    if not callable(getter):
        return fallback
    try:
        value = float(getter())
    except Exception:
        return fallback
    if not np.isfinite(value):
        return fallback
    return float(value)


def _current_manual_parratt_refractive_index() -> complex:
    return complex(
        _current_parratt_float(
            "parratt_n_real_var",
            "parratt_n_real",
            gui_film_reflectivity.DEFAULT_BI2SE3_REFLECTIVITY_N_REAL,
        ),
        _current_parratt_float(
            "parratt_n_imag_var",
            "parratt_n_imag",
            gui_film_reflectivity.DEFAULT_BI2SE3_REFLECTIVITY_N_IMAG,
        ),
    )


def _current_parratt_optics_settings() -> dict[str, object]:
    manual_index = _current_manual_parratt_refractive_index()
    return {
        "parratt_use_cif_optics": bool(_current_parratt_use_cif_optics()),
        "parratt_n_real": float(manual_index.real),
        "parratt_n_imag": float(manual_index.imag),
    }


def _current_reflectivity_stack_float(
    var_name: str,
    default_key: str,
    fallback_value: float,
    *,
    positive: bool = False,
) -> float:
    fallback = float(defaults.get(default_key, fallback_value))
    if positive:
        fallback = fallback if fallback > 0.0 else float(fallback_value)
    else:
        fallback = fallback if fallback >= 0.0 else float(fallback_value)
    value = _current_parratt_float(var_name, default_key, fallback)
    if positive and value <= 0.0:
        return float(fallback)
    if not positive and value < 0.0:
        return float(fallback)
    return float(value)


def _current_reflectivity_stack_settings() -> dict[str, float]:
    return {
        "reflectivity_substrate_n_real": _current_reflectivity_stack_float(
            "reflectivity_substrate_n_real_var",
            "reflectivity_substrate_n_real",
            gui_film_reflectivity.DEFAULT_SIO2_REFLECTIVITY_N_REAL,
            positive=True,
        ),
        "reflectivity_substrate_n_imag": _current_reflectivity_stack_float(
            "reflectivity_substrate_n_imag_var",
            "reflectivity_substrate_n_imag",
            gui_film_reflectivity.DEFAULT_SIO2_REFLECTIVITY_N_IMAG,
        ),
        "reflectivity_top_roughness_nm": _current_reflectivity_stack_float(
            "reflectivity_top_roughness_nm_var",
            "reflectivity_top_roughness_nm",
            0.0,
        ),
        "reflectivity_bottom_roughness_nm": _current_reflectivity_stack_float(
            "reflectivity_bottom_roughness_nm_var",
            "reflectivity_bottom_roughness_nm",
            0.0,
        ),
    }


def _current_parratt_optics_signature() -> tuple[object, ...]:
    if not _current_parratt_low_q_stitch_enabled():
        return (False, None, None)
    settings = {
        **_current_parratt_optics_settings(),
        **_current_reflectivity_stack_settings(),
    }
    settings["parratt_cif_path"] = _current_primary_cif_path()
    return gui_structure_model.parratt_optics_signature(**settings)


def _current_film_reflectivity_refractive_index() -> tuple[complex | None, str]:
    if _current_parratt_use_cif_optics():
        try:
            return (
                complex(
                    resolve_index_of_refraction(
                        float(lambda_) * 1.0e-10,
                        cif_path=_current_primary_cif_path(),
                    )
                ),
                "cif",
            )
        except Exception as exc:
            return None, f"index_of_refraction_failed: {exc}"

    return _current_manual_parratt_refractive_index(), "manual"


def _current_reflectivity_optical_stack():
    try:
        finite_stack_enabled = bool(finite_stack_var.get())
    except Exception:
        finite_stack_enabled = bool(defaults.get("finite_stack", True))
    film_refractive_index, optics_source = _current_film_reflectivity_refractive_index()
    if film_refractive_index is None:
        return None, optics_source
    stack_settings = _current_reflectivity_stack_settings()
    try:
        return (
            gui_film_reflectivity.build_reflectivity_optical_stack(
                finite_stack=finite_stack_enabled,
                film_thickness_nm=_current_film_thickness_nm(),
                c_lattice_angstrom=_current_c_axis_angstrom(),
                lambda_angstrom=float(lambda_),
                film_refractive_index=complex(film_refractive_index),
                substrate_refractive_index=complex(
                    stack_settings["reflectivity_substrate_n_real"],
                    stack_settings["reflectivity_substrate_n_imag"],
                ),
                top_roughness_nm=stack_settings["reflectivity_top_roughness_nm"],
                bottom_roughness_nm=stack_settings["reflectivity_bottom_roughness_nm"],
            ),
            None,
        )
    except ValueError as exc:
        return None, str(exc)


def _empty_film_stitched_preview(reason: str):
    return SimpleNamespace(
        valid=False,
        reason=str(reason),
        curve_source="unavailable",
        curve_label="preview unavailable",
        qz_over_qc=np.asarray([], dtype=np.float64),
        qz_angstrom_inv=np.asarray([], dtype=np.float64),
        reflectivity=np.asarray([], dtype=np.float64),
        critical_qz_angstrom_inv=np.nan,
        critical_L=np.nan,
        metadata={},
    )


def _film_stitched_preview_curve_name(curve_source: str) -> str:
    if str(curve_source) == "scaled_ht_over_q2":
        return "scaled HT/Qz^2"
    return "stitched"


def _film_metadata_float_matches(
    metadata: Mapping[str, object],
    key: str,
    current_value: object,
) -> bool:
    try:
        metadata_value = float(metadata[key])
        value = float(current_value)
    except (KeyError, TypeError, ValueError):
        return False
    if not np.isfinite(metadata_value) or not np.isfinite(value):
        return False
    return math.isclose(metadata_value, value, rel_tol=1.0e-9, abs_tol=1.0e-12)


def _film_stitch_metadata_matches_current_stack(
    metadata: Mapping[str, object],
    stack,
) -> bool:
    if stack is None:
        return False
    try:
        stack_layers = int(stack.stack_layers)
        film_n = complex(stack.film.refractive_index)
        substrate_n = complex(stack.substrate.refractive_index)
        top_roughness_nm = float(stack.air.roughness_nm)
        bottom_roughness_nm = float(stack.film.roughness_nm)
    except Exception:
        return False
    try:
        metadata_layers = int(metadata["stack_layers"])
    except (KeyError, TypeError, ValueError):
        return False
    return (
        metadata_layers == stack_layers
        and _film_metadata_float_matches(metadata, "n_real", film_n.real)
        and _film_metadata_float_matches(metadata, "n_imag", film_n.imag)
        and _film_metadata_float_matches(
            metadata,
            "reflectivity_substrate_n_real",
            substrate_n.real,
        )
        and _film_metadata_float_matches(
            metadata,
            "reflectivity_substrate_n_imag",
            substrate_n.imag,
        )
        and _film_metadata_float_matches(
            metadata,
            "reflectivity_top_roughness_nm",
            top_roughness_nm,
        )
        and _film_metadata_float_matches(
            metadata,
            "reflectivity_bottom_roughness_nm",
            bottom_roughness_nm,
        )
    )


def _film_cache_value_matches(
    cache: Mapping[str, object],
    key: str,
    current_value: object,
) -> bool:
    if key not in cache:
        return True
    try:
        cache_value = cache[key]
        if isinstance(current_value, bool):
            return bool(cache_value) == current_value
        if isinstance(current_value, int):
            return int(cache_value) == current_value
        return str(cache_value) == str(current_value)
    except (TypeError, ValueError):
        return False


def _film_stitch_cache_matches_current_inputs(cache: Mapping[str, object]) -> bool:
    if not bool(cache.get("parratt_low_q_stitch", False)):
        return False
    try:
        cached_optics_signature = tuple(cache["parratt_optics_signature"])
        current_optics_signature = tuple(_current_parratt_optics_signature())
    except Exception:
        return False
    if cached_optics_signature != current_optics_signature:
        return False

    try:
        finite_stack_enabled = bool(finite_stack_var.get())
    except Exception:
        finite_stack_enabled = bool(defaults.get("finite_stack", True))
    try:
        stack_layers = int(
            gui_controllers.finite_stack_layers_from_thickness_nm(
                film_thickness_nm=_current_film_thickness_nm(),
                c_axis_angstrom=_current_c_axis_angstrom(),
            )
        )
    except Exception:
        stack_layers = None

    if not _film_cache_value_matches(cache, "finite_stack", finite_stack_enabled):
        return False
    if stack_layers is not None and not _film_cache_value_matches(
        cache,
        "stack_layers",
        stack_layers,
    ):
        return False
    if "primary_source_mode" in cache and not _film_cache_value_matches(
        cache,
        "primary_source_mode",
        _current_primary_source_mode(),
    ):
        return False
    if "parratt_low_q_stitch_curve_source" in cache and not _film_cache_value_matches(
        cache,
        "parratt_low_q_stitch_curve_source",
        _current_parratt_low_q_stitch_curve_source(),
    ):
        return False
    if "phase_delta_expression" in cache:
        try:
            current_phase_delta = _current_phase_delta_expression()
        except Exception:
            return False
        if not _film_cache_value_matches(cache, "phase_delta_expression", current_phase_delta):
            return False
    if "rod_points_per_gz" in cache:
        try:
            current_rod_points = _current_rod_points_per_gz()
        except Exception:
            return False
        if not _film_cache_value_matches(cache, "rod_points_per_gz", current_rod_points):
            return False
    float_checks = (
        ("a", lambda: float(a_var.get())),
        ("c", _current_c_axis_angstrom),
        ("phi_l_divisor", _current_phi_l_divisor),
    )
    for key, current_value_factory in float_checks:
        if key not in cache:
            continue
        try:
            current_value = current_value_factory()
        except Exception:
            return False
        if not _film_metadata_float_matches(cache, key, current_value):
            return False

    cached_iodine_z = getattr(structure_model_state, "last_iodine_z_for_ht", None)
    if cached_iodine_z is not None:
        try:
            current_iodine_z = float(_current_iodine_z())
            cached_iodine_z = float(cached_iodine_z)
        except Exception:
            return False
        if not math.isclose(current_iodine_z, cached_iodine_z, rel_tol=1.0e-9, abs_tol=1.0e-12):
            return False

    cached_atom_site_signature = getattr(
        structure_model_state,
        "last_atom_site_fractional_signature",
        None,
    )
    if cached_atom_site_signature is not None:
        try:
            current_atom_site_signature = _atom_site_fractional_signature(
                _current_atom_site_fractional_values()
            )
        except Exception:
            return False
        if tuple(cached_atom_site_signature) != tuple(current_atom_site_signature):
            return False

    try:
        current_occ, current_p_vals, current_weights = _current_structure_model_rebuild_inputs()
    except Exception:
        return True
    for attr_name, current_values in (
        ("last_occ_for_ht", current_occ),
        ("last_p_triplet", current_p_vals),
        ("last_weights", current_weights),
    ):
        cached_values = getattr(structure_model_state, attr_name, None)
        try:
            if cached_values is None or len(cached_values) == 0:
                continue
            if not np.allclose(
                np.asarray(cached_values, dtype=np.float64),
                np.asarray(current_values, dtype=np.float64),
                rtol=1.0e-9,
                atol=1.0e-12,
            ):
                return False
        except Exception:
            return False
    cached_rich_phase_components = getattr(structure_model_state, "last_rich_phase_components", {})
    if cached_rich_phase_components:
        try:
            current_rich_phase_signature = _rich_phase_components_signature(
                _current_rich_phase_components()
            )
            cached_rich_phase_signature = _rich_phase_components_signature(
                cached_rich_phase_components
            )
        except Exception:
            return False
        if current_rich_phase_signature != cached_rich_phase_signature:
            return False
    return True


def _current_film_stitched_preview():
    stack, stack_status = _current_reflectivity_optical_stack()
    if not _current_parratt_low_q_stitch_enabled():
        return _empty_film_stitched_preview("parratt_stitch_disabled"), stack, stack_status

    cache = getattr(structure_model_state, "ht_curves_cache", {})
    cache = cache if isinstance(cache, Mapping) else {}
    metadata = cache.get("parratt_low_q_stitch_metadata", {})
    metadata = metadata if isinstance(metadata, Mapping) else {}
    if not bool(metadata.get("active", False)):
        reason = str(metadata.get("reason", "stitched_curve_unavailable"))
        return _empty_film_stitched_preview(reason), stack, stack_status
    if not _film_stitch_cache_matches_current_inputs(cache):
        return _empty_film_stitched_preview("stitched_curve_stale"), stack, stack_status
    if not _film_stitch_metadata_matches_current_stack(metadata, stack):
        return _empty_film_stitched_preview("stitched_curve_stale"), stack, stack_status

    curve_source = gui_structure_model.normalize_parratt_low_q_stitch_curve_source(
        metadata.get(
            "selected_curve_source",
            cache.get("parratt_low_q_stitch_curve_source", "stitched"),
        )
    )
    # The simulation-owned 00L curve is now in kinematic Bragg-intensity
    # units. Film/Fig. 2 must continue to display the corresponding
    # dimensionless reflectivity diagnostic stored in the stitch metadata.
    if curve_source == "scaled_ht_over_q2":
        reflectivity_values = metadata.get("scaled_ht_over_q2")
    else:
        reflectivity_values = metadata.get("stitched_curve")
    if reflectivity_values is None:
        reflectivity_values = []
    qz_over_qc = np.asarray(metadata.get("qz_over_qc", []), dtype=np.float64)
    reflectivity = np.asarray(reflectivity_values, dtype=np.float64)
    if qz_over_qc.shape != reflectivity.shape or qz_over_qc.size == 0:
        return _empty_film_stitched_preview("stitched_curve_missing"), stack, stack_status
    valid = np.isfinite(qz_over_qc) & np.isfinite(reflectivity)
    if not np.any(valid):
        return _empty_film_stitched_preview("stitched_curve_invalid"), stack, stack_status

    qz = np.asarray(metadata.get("qz_angstrom_inv", []), dtype=np.float64)
    if qz.shape != qz_over_qc.shape:
        qz = np.full_like(qz_over_qc, np.nan, dtype=np.float64)
    return (
        SimpleNamespace(
            valid=True,
            reason=str(metadata.get("reason", "applied")),
            curve_source=curve_source,
            curve_label=f"{_film_stitched_preview_curve_name(curve_source)} simulation 00L",
            qz_over_qc=qz_over_qc,
            qz_angstrom_inv=qz,
            reflectivity=reflectivity,
            critical_qz_angstrom_inv=float(metadata.get("critical_qz_angstrom_inv", np.nan)),
            critical_L=float(metadata.get("critical_L", np.nan)),
            metadata=dict(metadata),
        ),
        stack,
        stack_status,
    )


def _film_reflectivity_float(value: object, fallback: float | None = None) -> float | None:
    try:
        parsed = float(value)
    except (TypeError, ValueError):
        return fallback
    if not np.isfinite(parsed):
        return fallback
    return parsed


def _film_reflectivity_format(value: object, *, suffix: str = "") -> str:
    parsed = _film_reflectivity_float(value)
    if parsed is None:
        return "n/a"
    return f"{parsed:.6g}{suffix}"


def _set_film_reflectivity_readout(key: str, text: object) -> None:
    if str(key) != "preview_status":
        return
    view_state = film_reflectivity_controls_view_state
    value_var = getattr(view_state, "preview_status_var", None)
    setter = getattr(value_var, "set", None)
    if callable(setter):
        try:
            setter(str(text))
        except Exception:
            pass


def _sync_film_reflectivity_readouts(
    *,
    sync_profile_values: bool = False,
) -> None:
    if sync_profile_values:
        _sync_embedded_film_profile_value_fields()
    _set_film_reflectivity_readout(
        "preview_status",
        "preview source: simulation "
        f"{_film_stitched_preview_curve_name(_current_parratt_low_q_stitch_curve_source())} "
        "00L preview",
    )


def _ensure_film_reflectivity_preview_canvas() -> bool:
    view_state = film_reflectivity_controls_view_state
    if getattr(view_state, "plot_frame", None) is None:
        return False
    if getattr(view_state, "figure", None) is not None:
        return True

    figure = Figure(figsize=(5.2, 4.2), dpi=100)
    reflectivity_ax = figure.add_subplot(211)
    diagram_ax = figure.add_subplot(212)
    figure_canvas_cls = _get_tk_figure_canvas_cls()
    preview_canvas = figure_canvas_cls(figure, master=view_state.plot_frame)
    preview_widget = preview_canvas.get_tk_widget()
    preview_widget.pack(side=tk.TOP, fill=tk.BOTH, expand=True)

    view_state.figure = figure
    view_state.reflectivity_ax = reflectivity_ax
    view_state.diagram_ax = diagram_ax
    view_state.canvas = preview_canvas
    view_state.canvas_widget = preview_widget
    _connect_film_profile_canvas_events(view_state)
    return True


def _film_reflectivity_tab_selected() -> bool:
    tab_var = getattr(app_shell_view_state, "control_tab_var", None)
    return str(_get_var_value(tab_var, "")) == "film"


def _film_reflectivity_preview_should_render() -> bool:
    view_state = film_reflectivity_controls_view_state
    if getattr(view_state, "plot_frame", None) is None:
        return False
    return _film_reflectivity_tab_selected()


def _embedded_film_profile_controls_active() -> bool:
    view_state = film_reflectivity_controls_view_state
    profile_value_vars = getattr(view_state, "profile_value_vars", None)
    qc_readout_vars = getattr(view_state, "qc_readout_vars", None)
    has_profile_targets = (
        isinstance(profile_value_vars, Mapping) and bool(profile_value_vars)
    ) or (isinstance(qc_readout_vars, Mapping) and bool(qc_readout_vars))
    return bool(has_profile_targets and _film_reflectivity_tab_selected())


def _draw_film_reflectivity_curve(reflectivity_ax, preview) -> None:
    if bool(getattr(preview, "valid", False)):
        reflectivity = np.maximum(np.asarray(preview.reflectivity, dtype=np.float64), 1.0e-12)
        reflectivity_ax.semilogy(
            preview.qz_over_qc,
            reflectivity,
            color="#2563eb",
            linewidth=1.4,
            label=str(getattr(preview, "curve_label", "stitched simulation 00L")),
        )
        reflectivity_ax.set_xlim(0.0, float(np.nanmax(preview.qz_over_qc)))
        reflectivity_ax.set_ylim(1.0e-12, max(1.0, float(np.nanmax(reflectivity)) * 1.2))
        reflectivity_ax.legend(loc="best", frameon=False)
    else:
        reflectivity_ax.text(
            0.5,
            0.5,
            str(getattr(preview, "reason", "preview unavailable")),
            ha="center",
            va="center",
            transform=reflectivity_ax.transAxes,
        )
        reflectivity_ax.set_xlim(0.0, 12.0)
        reflectivity_ax.set_ylim(0.0, 1.0)
    reflectivity_ax.set_xlabel("Qz/Qc")
    reflectivity_ax.set_ylabel("Reflectivity")
    reflectivity_ax.grid(True, alpha=0.25)


def _remove_film_reflectivity_profile_mu_axis(view_state) -> None:
    mu_ax = getattr(view_state, "profile_mu_ax", None)
    if mu_ax is None:
        return
    remove = getattr(mu_ax, "remove", None)
    if callable(remove):
        try:
            remove()
        except Exception:
            pass
    try:
        view_state.profile_mu_ax = None
    except Exception:
        pass


_FILM_PROFILE_QCSQ_PER_DENSITY = gui_film_reflectivity.QCSQ_PER_ELECTRON_DENSITY


def _film_profile_visible(visibility_vars: object, key: str, default: bool) -> bool:
    if not isinstance(visibility_vars, Mapping):
        return bool(default)
    value_var = visibility_vars.get(key)
    getter = getattr(value_var, "get", None)
    if not callable(getter):
        return bool(default)
    try:
        return bool(getter())
    except Exception:
        return bool(default)


def _film_profile_density_to_qcsq(value: object):
    return np.asarray(value, dtype=np.float64) * _FILM_PROFILE_QCSQ_PER_DENSITY


def _film_profile_popout_values_from_drag_values(values: Mapping[str, object]) -> dict[str, float]:
    return {
        "thickness": float(values["thickness"]),
        "top_roughness": float(values["top_roughness"]),
        "bottom_roughness": float(values["bottom_roughness"]),
        "film_qcsq": float(_film_profile_density_to_qcsq(values["film_density"])),
        "substrate_qcsq": float(_film_profile_density_to_qcsq(values["substrate_density"])),
        "film_mu": float(values["film_mu"]),
        "substrate_mu": float(values["substrate_mu"]),
    }


def _film_profile_stack_popout_values(stack) -> dict[str, float] | None:
    if stack is None:
        return None
    handle_values = gui_film_reflectivity.build_profile_handle_values(stack)
    return _film_profile_popout_values_from_drag_values(
        {
            "thickness": handle_values.thickness_nm,
            "top_roughness": handle_values.top_roughness_nm,
            "bottom_roughness": handle_values.bottom_roughness_nm,
            "film_density": handle_values.film_density_e_per_angstrom3,
            "substrate_density": handle_values.substrate_density_e_per_angstrom3,
            "film_mu": handle_values.film_absorption_inv_angstrom,
            "substrate_mu": handle_values.substrate_absorption_inv_angstrom,
        }
    )


def _current_film_profile_popout_values() -> dict[str, float]:
    return _film_profile_popout_values_from_drag_values(_current_film_profile_drag_values())


def _set_film_profile_text_var(value_var: object, text: str) -> None:
    setter = getattr(value_var, "set", None)
    if not callable(setter):
        return
    getter = getattr(value_var, "get", None)
    if callable(getter):
        try:
            if str(getter()) == text:
                return
        except Exception:
            pass
    try:
        setter(text)
    except Exception:
        pass


def _sync_film_profile_value_vars(view_state: object, values: Mapping[str, object]) -> None:
    value_vars = getattr(view_state, "profile_value_vars", None)
    if not isinstance(value_vars, Mapping):
        return
    for key, value in values.items():
        _set_film_profile_text_var(
            value_vars.get(key),
            _film_reflectivity_format(value),
        )


def _sync_film_profile_popout_value_fields(values: Mapping[str, object] | None = None) -> None:
    if values is None:
        try:
            values = _current_film_profile_popout_values()
        except Exception:
            return
    _sync_film_profile_value_vars(film_reflectivity_popout_view_state, values)


_FILM_PROFILE_VALUE_UPDATE_KINDS = {
    "thickness": "thickness",
    "top_roughness": "top_roughness",
    "bottom_roughness": "bottom_roughness",
    "film_qcsq": "film_density",
    "substrate_qcsq": "substrate_density",
    "film_mu": "film_mu",
    "substrate_mu": "substrate_mu",
}


def _commit_film_profile_value_from_view(view_state, key: str, sync_callback) -> None:
    value_vars = getattr(view_state, "profile_value_vars", None)
    if not isinstance(value_vars, Mapping):
        sync_callback()
        return
    value_key = str(key)
    update_kind = _FILM_PROFILE_VALUE_UPDATE_KINDS.get(value_key)
    value_var = value_vars.get(value_key)
    getter = getattr(value_var, "get", None)
    if update_kind is None or not callable(getter):
        sync_callback()
        return
    raw_value = getter()
    if value_key.endswith("_qcsq"):
        try:
            raw_value = gui_film_reflectivity.electron_density_from_qcsq(raw_value)
        except (TypeError, ValueError):
            sync_callback()
            return
    _apply_film_profile_parameter_update(update_kind, raw_value)
    sync_callback()


def _commit_film_profile_popout_value(key: str) -> None:
    _commit_film_profile_value_from_view(
        film_reflectivity_popout_view_state,
        key,
        _sync_film_profile_popout_value_fields,
    )


def _commit_embedded_film_profile_value(key: str) -> None:
    _commit_film_profile_value_from_view(
        film_reflectivity_controls_view_state,
        key,
        _sync_embedded_film_profile_value_fields,
    )


def _sync_embedded_film_profile_value_fields(values: Mapping[str, object] | None = None) -> None:
    explicit_values = values is not None
    if not explicit_values and not _embedded_film_profile_controls_active():
        return
    if values is None:
        try:
            values = _current_film_profile_popout_values()
        except Exception:
            values = {}
    values = values if isinstance(values, Mapping) else {}

    _sync_film_profile_value_vars(film_reflectivity_controls_view_state, values)

    qc_readout_vars = getattr(film_reflectivity_controls_view_state, "qc_readout_vars", None)
    if not isinstance(qc_readout_vars, Mapping):
        return
    for readout_key, qcsq_key in (
        ("film_qc", "film_qcsq"),
        ("substrate_qc", "substrate_qcsq"),
    ):
        value_var = qc_readout_vars.get(readout_key)
        setter = getattr(value_var, "set", None)
        if not callable(setter):
            continue
        try:
            qc_value = gui_film_reflectivity.qc_from_qcsq(values[qcsq_key])
            text = _film_reflectivity_format(qc_value)
        except Exception:
            text = "n/a"
        try:
            setter(text)
        except Exception:
            pass


def _draw_film_reflectivity_depth_profile(
    depth_ax,
    stack,
    *,
    handles=None,
    profile_visibility_vars=None,
):
    if handles is not None:
        handles.clear()
    if stack is None:
        depth_ax.text(
            0.5,
            0.5,
            "optical stack unavailable",
            ha="center",
            va="center",
            transform=depth_ax.transAxes,
        )
        depth_ax.set_xlim(0.0, 1.0)
        depth_ax.set_ylim(0.0, 1.0)
        depth_ax.set_xlabel("Depth (nm)")
        if _film_profile_visible(profile_visibility_vars, "qcsq", True):
            depth_ax.set_ylabel("qcsq (1/A^2)")
        return None

    show_qcsq = _film_profile_visible(profile_visibility_vars, "qcsq", True)
    show_mu = _film_profile_visible(profile_visibility_vars, "mu", False)
    profile = gui_film_reflectivity.build_depth_density_profile(stack)
    handle_values = gui_film_reflectivity.build_profile_handle_values(stack)
    depth = np.asarray(profile.depth_nm, dtype=np.float64)
    density = np.asarray(profile.density_e_per_angstrom3, dtype=np.float64)
    qcsq = _film_profile_density_to_qcsq(density)
    absorption = np.asarray(profile.absorption_inv_angstrom, dtype=np.float64)
    film_qcsq = float(_film_profile_density_to_qcsq(handle_values.film_density_e_per_angstrom3))
    substrate_qcsq = float(
        _film_profile_density_to_qcsq(handle_values.substrate_density_e_per_angstrom3)
    )
    mu_ax = depth_ax.twinx() if show_mu else None
    if show_qcsq:
        depth_ax.plot(depth, qcsq, color="#b00020", linewidth=1.4)
    if mu_ax is not None:
        mu_ax.plot(depth, absorption, color="#cc7a00", linewidth=1.2)
    depth_ax.axvline(0.0, color="#64748b", linewidth=0.9, linestyle="--")
    interface_line = depth_ax.axvline(
        profile.film_thickness_nm,
        color="#0f172a",
        linewidth=1.1,
        linestyle="--",
        picker=8,
    )
    if handles is not None:
        handles.append({"kind": "thickness", "artist": interface_line, "axis": depth_ax})

    density_handle_style = dict(
        marker="s",
        s=36,
        color="#b00020",
        edgecolors="black",
        linewidths=0.7,
        zorder=5,
        picker=8,
    )
    if show_qcsq:
        film_density_handle = depth_ax.scatter(
            [handle_values.top_roughness_nm],
            [film_qcsq],
            **density_handle_style,
        )
        substrate_density_handle = depth_ax.scatter(
            [handle_values.thickness_nm + handle_values.bottom_roughness_nm],
            [substrate_qcsq],
            **density_handle_style,
        )
        if handles is not None:
            handles.extend(
                [
                    {
                        "kind": "film_density",
                        "artist": film_density_handle,
                        "axis": depth_ax,
                        "value_scale": _FILM_PROFILE_QCSQ_PER_DENSITY,
                    },
                    {
                        "kind": "substrate_density",
                        "artist": substrate_density_handle,
                        "axis": depth_ax,
                        "value_scale": _FILM_PROFILE_QCSQ_PER_DENSITY,
                    },
                ]
            )
    if mu_ax is not None:
        mu_handle_style = dict(
            marker="s",
            s=32,
            color="#cc7a00",
            edgecolors="black",
            linewidths=0.7,
            zorder=5,
            picker=8,
        )
        film_mu_handle = mu_ax.scatter(
            [handle_values.top_roughness_nm],
            [handle_values.film_absorption_inv_angstrom],
            **mu_handle_style,
        )
        substrate_mu_handle = mu_ax.scatter(
            [handle_values.thickness_nm + handle_values.bottom_roughness_nm],
            [handle_values.substrate_absorption_inv_angstrom],
            **mu_handle_style,
        )
        if handles is not None:
            handles.extend(
                [
                    {"kind": "film_mu", "artist": film_mu_handle, "axis": mu_ax},
                    {"kind": "substrate_mu", "artist": substrate_mu_handle, "axis": mu_ax},
                ]
            )

    y_values = qcsq if show_qcsq else np.array([0.0, 1.0], dtype=np.float64)
    y_min = float(np.nanmin(y_values)) if y_values.size else 0.0
    y_max = float(np.nanmax(y_values)) if y_values.size else 1.0
    y_span = max(y_max - y_min, 1.0e-12)
    label_y = y_min + 0.85 * y_span
    depth_ax.text(depth[0], label_y, "air", ha="left", va="center", color="#334155")
    depth_ax.text(
        0.5 * profile.film_thickness_nm,
        label_y,
        "film",
        ha="center",
        va="center",
        color="#0f172a",
    )
    depth_ax.text(depth[-1], label_y, "substrate", ha="right", va="center", color="#334155")
    annotation = (
        f"d={profile.film_thickness_nm:.3g} nm; "
        f"N={int(stack.stack_layers)}; "
        f"qcsq film={film_qcsq:.3g} 1/A^2; "
        f"qcsq substrate={substrate_qcsq:.3g} 1/A^2; "
        f"roughness top/bottom={profile.top_roughness_nm:.3g}/{profile.bottom_roughness_nm:.3g} nm"
    )
    depth_ax.text(
        0.01,
        0.04,
        annotation,
        ha="left",
        va="bottom",
        transform=depth_ax.transAxes,
        color="#334155",
        fontsize=8,
    )
    depth_ax.set_xlim(float(depth[0]), float(depth[-1]))
    depth_ax.set_ylim(y_min - 0.08 * y_span, y_max + 0.12 * y_span)
    depth_ax.set_xlabel("Depth (nm)")
    if show_qcsq:
        depth_ax.set_ylabel("qcsq (1/A^2)")
        depth_ax.tick_params(axis="y", labelcolor="#b00020")
    if mu_ax is not None:
        mu_min = float(np.nanmin(absorption)) if absorption.size else 0.0
        mu_max = float(np.nanmax(absorption)) if absorption.size else 1.0
        mu_span = max(mu_max - mu_min, 1.0e-12)
        mu_ax.set_ylim(mu_min - 0.08 * mu_span, mu_max + 0.12 * mu_span)
        mu_ax.set_ylabel(f"mu ({profile.absorption_unit})")
        mu_ax.tick_params(axis="y", labelcolor="#cc7a00")
        mu_ax.ticklabel_format(axis="y", style="sci", scilimits=(-2, 2))
    depth_ax.grid(True, alpha=0.2)
    return mu_ax


def _sync_film_reflectivity_preview_status(
    preview,
    stack,
    status_message: str | None,
) -> None:
    if bool(getattr(preview, "valid", False)):
        effective_nm = float(getattr(stack, "effective_thickness_nm", np.nan))
        stack_layers = int(getattr(stack, "stack_layers", 0))
        preview_text = (
            "preview source: simulation stitched 00L preview; "
            "effective {effective:.3f} nm | N={layers:d} | "
            "Qc={qc:.6g} A^-1 | Lc={lc:.6g}".format(
                effective=effective_nm,
                layers=stack_layers,
                qc=float(getattr(preview, "critical_qz_angstrom_inv", np.nan)),
                lc=float(getattr(preview, "critical_L", np.nan)),
            )
        )
    else:
        preview_text = (
            "preview source: simulation stitched 00L preview unavailable; "
            f"reason {getattr(preview, 'reason', 'preview unavailable')}"
        )
    if status_message:
        preview_text = f"{preview_text}; status: {status_message}"
    if _film_profile_main_updates_paused():
        preview_text = f"{preview_text}; main simulation updates paused"
    if film_profile_pending_main_update_kinds:
        preview_text = f"{preview_text}; pending main update"
    _set_film_reflectivity_readout("preview_status", preview_text)


def _draw_film_reflectivity_preview(preview, stack, *, status_message: str | None = None) -> None:
    if not _ensure_film_reflectivity_preview_canvas():
        return

    view_state = film_reflectivity_controls_view_state
    reflectivity_ax = view_state.reflectivity_ax
    diagram_ax = view_state.diagram_ax
    if reflectivity_ax is None or diagram_ax is None:
        return

    _remove_film_reflectivity_profile_mu_axis(view_state)
    reflectivity_ax.clear()
    diagram_ax.clear()
    _draw_film_reflectivity_curve(reflectivity_ax, preview)
    view_state.profile_ax = diagram_ax
    view_state.profile_mu_ax = _draw_film_reflectivity_depth_profile(
        diagram_ax,
        stack,
        handles=view_state.profile_handles,
        profile_visibility_vars=getattr(view_state, "profile_visibility_vars", None),
    )

    try:
        view_state.figure.tight_layout()
    except Exception:
        pass

    _sync_film_reflectivity_preview_status(preview, stack, status_message)

    draw_idle = getattr(view_state.canvas, "draw_idle", None)
    if callable(draw_idle):
        draw_idle()


def _ensure_film_reflectivity_popout_canvas() -> bool:
    view_state = film_reflectivity_popout_view_state
    if getattr(view_state, "plot_frame", None) is None:
        return False
    if getattr(view_state, "figure", None) is not None:
        return True

    figure = Figure(figsize=(8.8, 5.4), dpi=100)
    figure_canvas_cls = _get_tk_figure_canvas_cls()
    preview_canvas = figure_canvas_cls(figure, master=view_state.plot_frame)
    preview_widget = preview_canvas.get_tk_widget()
    preview_widget.pack(side=tk.TOP, fill=tk.BOTH, expand=True)

    view_state.figure = figure
    view_state.canvas = preview_canvas
    view_state.canvas_widget = preview_widget
    _connect_film_profile_canvas_events(view_state)
    return True


def _set_film_reflectivity_popout_status(text: object) -> None:
    status_var = getattr(film_reflectivity_popout_view_state, "status_var", None)
    setter = getattr(status_var, "set", None)
    if callable(setter):
        try:
            setter(str(text))
        except Exception:
            pass


def _film_reflectivity_popout_limit_value(axis_limit_vars: Mapping, key: str) -> float | None:
    raw_value = _get_var_value(axis_limit_vars.get(key), "")
    if str(raw_value).strip() == "":
        return None
    return _film_reflectivity_float(raw_value)


def _film_reflectivity_popout_limit_pair(
    axis_limit_vars: Mapping,
    min_key: str,
    max_key: str,
    *,
    default_min: float,
    default_max: float,
    min_width: float,
) -> tuple[float, float] | None:
    low = _film_reflectivity_popout_limit_value(axis_limit_vars, min_key)
    high = _film_reflectivity_popout_limit_value(axis_limit_vars, max_key)
    if low is None and high is None:
        return None
    left = float(default_min if low is None else low)
    right = float(default_max if high is None else high)
    if not np.isfinite(left):
        left = float(default_min)
    if not np.isfinite(right):
        right = float(default_max)
    if right <= left:
        right = left + float(min_width)
    return left, right


def _film_reflectivity_popout_visible_y_values(ax) -> np.ndarray:
    get_xlim = getattr(ax, "get_xlim", None)
    get_lines = getattr(ax, "get_lines", None)
    if not callable(get_xlim) or not callable(get_lines):
        return np.empty(0, dtype=np.float64)

    try:
        x_left, x_right = get_xlim()
    except Exception:
        return np.empty(0, dtype=np.float64)
    try:
        x_left = float(x_left)
        x_right = float(x_right)
    except (TypeError, ValueError):
        return np.empty(0, dtype=np.float64)
    if not np.isfinite(x_left) or not np.isfinite(x_right):
        return np.empty(0, dtype=np.float64)
    x_low, x_high = sorted((x_left, x_right))

    y_chunks: list[np.ndarray] = []
    try:
        lines = get_lines()
    except Exception:
        return np.empty(0, dtype=np.float64)
    for line in lines:
        visible = getattr(line, "get_visible", None)
        if callable(visible):
            try:
                if not bool(visible()):
                    continue
            except Exception:
                pass
        get_xdata = getattr(line, "get_xdata", None)
        get_ydata = getattr(line, "get_ydata", None)
        if not callable(get_xdata) or not callable(get_ydata):
            continue
        try:
            x_data = np.asarray(get_xdata(), dtype=np.float64)
            y_data = np.asarray(get_ydata(), dtype=np.float64)
        except Exception:
            continue
        if x_data.shape != y_data.shape or x_data.size == 0:
            continue
        mask = (
            np.isfinite(x_data)
            & np.isfinite(y_data)
            & (y_data > 1.0e-299)
            & (x_data >= x_low)
            & (x_data <= x_high)
        )
        if np.any(mask):
            y_chunks.append(y_data[mask])
    if not y_chunks:
        return np.empty(0, dtype=np.float64)
    return np.concatenate(y_chunks)


def _apply_film_reflectivity_popout_visible_y_limits(ax) -> None:
    visible_y = _film_reflectivity_popout_visible_y_values(ax)
    if visible_y.size == 0:
        return
    y_min = float(np.nanmin(visible_y))
    y_max = float(np.nanmax(visible_y))
    if not np.isfinite(y_min) or not np.isfinite(y_max) or y_min <= 0.0 or y_max <= 0.0:
        return
    y_min_log = float(np.log10(y_min))
    y_max_log = float(np.log10(y_max))
    if not np.isfinite(y_min_log) or not np.isfinite(y_max_log):
        return
    y_span_log = y_max_log - y_min_log
    if y_span_log <= 0.0:
        y_span_log = 1.0
    y_pad_log = max(0.05 * y_span_log, 0.05)
    ax.set_ylim(10.0 ** (y_min_log - y_pad_log), 10.0 ** (y_max_log + y_pad_log))


def _apply_film_reflectivity_popout_axis_limits(ax, qz_over_qc) -> None:
    axis_limit_vars = getattr(film_reflectivity_popout_view_state, "axis_limit_vars", {})
    axis_limit_vars = axis_limit_vars if isinstance(axis_limit_vars, Mapping) else {}
    x_min = float(np.nanmin(qz_over_qc))
    x_max = float(np.nanmax(qz_over_qc))
    if np.isfinite(x_min) and np.isfinite(x_max) and x_max > x_min:
        x_limits = _film_reflectivity_popout_limit_pair(
            axis_limit_vars,
            "qz_over_qc_min",
            "qz_over_qc_max",
            default_min=max(0.0, x_min),
            default_max=x_max,
            min_width=1.0e-6,
        )
        ax.set_xlim(*(x_limits or (max(0.0, x_min), x_max)))

    y_limits = _film_reflectivity_popout_limit_pair(
        axis_limit_vars,
        "y_min_log",
        "y_max_log",
        default_min=-12.0,
        default_max=0.0,
        min_width=0.1,
    )
    if y_limits is not None:
        y_min_log, y_max_log = y_limits
        ax.set_ylim(10.0**y_min_log, 10.0**y_max_log)
    else:
        _apply_film_reflectivity_popout_visible_y_limits(ax)


def _draw_film_reflectivity_popout() -> None:
    if not _ensure_film_reflectivity_popout_canvas():
        return

    preview, _stack, stack_status = _current_film_stitched_preview()
    view_state = film_reflectivity_popout_view_state
    figure = view_state.figure
    if figure is None:
        return
    _remove_film_reflectivity_profile_mu_axis(view_state)
    figure.clear()
    ax = figure.add_subplot(211)
    profile_ax = figure.add_subplot(212)
    view_state.reflectivity_ax = ax
    view_state.profile_ax = profile_ax
    profile_handles = getattr(view_state, "profile_handles", None)
    if profile_handles is None:
        profile_handles = []
        try:
            view_state.profile_handles = profile_handles
        except Exception:
            pass

    view_state.last_request_signature = _current_film_fig2_request_signature(
        preview=preview,
        stack=_stack,
    )

    if not bool(getattr(preview, "valid", False)):
        reason = str(getattr(preview, "reason", "preview unavailable"))
        if stack_status:
            reason = f"{reason}; {stack_status}"
        ax.text(0.5, 0.5, reason, ha="center", va="center", transform=ax.transAxes)
        ax.set_axis_off()
        _set_film_reflectivity_popout_status(f"Fig. 2 curves unavailable: {reason}")
    else:
        metadata = getattr(preview, "metadata", {})
        qz_over_qc = np.asarray(metadata.get("qz_over_qc", preview.qz_over_qc), dtype=np.float64)
        visibility_vars = getattr(view_state, "curve_visibility_vars", {})
        visibility_vars = visibility_vars if isinstance(visibility_vars, Mapping) else {}
        curve_specs = (
            ("pure_parratt", "Pure Parratt reflectivity"),
            ("scaled_ht_over_q2", "Scaled HT/Qz^2"),
            ("stitched_curve", "Stitched Parratt + scaled HT/Qz^2"),
        )
        curve_styles = gui_film_reflectivity.FIG2_REFLECTIVITY_CURVE_STYLES
        for curve_key, label in curve_specs:
            visible_var = visibility_vars.get(curve_key)
            getter = getattr(visible_var, "get", None)
            if callable(getter):
                try:
                    if not bool(getter()):
                        continue
                except Exception:
                    pass
            values = metadata.get(curve_key)
            curve = np.asarray(values, dtype=np.float64)
            if curve.shape != qz_over_qc.shape or curve.size == 0:
                continue
            ax.semilogy(
                qz_over_qc,
                np.maximum(curve, 1.0e-300),
                label=label,
                **curve_styles[curve_key],
            )
        ax.set_xlabel("Qz/Qc")
        ax.set_ylabel("Reflectivity")
        ax.grid(True, alpha=0.25)
        ax.legend(loc="best", frameon=False)
        _apply_film_reflectivity_popout_axis_limits(ax, qz_over_qc)
        critical_L = float(getattr(preview, "critical_L", np.nan))
        if np.isfinite(critical_L) and critical_L > 0.0:
            top_ax = ax.twiny()
            top_ax.set_xlim(ax.get_xlim())
            ticks = ax.get_xticks()
            top_ax.set_xticks(ticks)
            top_ax.set_xticklabels([f"{tick * critical_L:.3g}" for tick in ticks])
            top_ax.set_xlabel("L")
        scale = metadata.get(
            "parratt_to_kinematic_scale_factor",
            metadata.get("scale_factor", "n/a"),
        )
        blend_x1 = metadata.get("blend_x1_q_over_qc", "n/a")
        blend_x2 = metadata.get("blend_x2_q_over_qc", "n/a")
        _set_film_reflectivity_popout_status(
            "Fig. 2 curves from active simulation; "
            f"scale={_film_reflectivity_format(scale)}; "
            f"blend={_film_reflectivity_format(blend_x1)}-"
            f"{_film_reflectivity_format(blend_x2)} Qz/Qc"
        )
    view_state.profile_mu_ax = _draw_film_reflectivity_depth_profile(
        profile_ax,
        _stack,
        handles=profile_handles,
        profile_visibility_vars=getattr(view_state, "profile_visibility_vars", None),
    )
    _sync_film_profile_popout_value_fields(_film_profile_stack_popout_values(_stack))
    try:
        figure.tight_layout()
    except Exception:
        pass
    draw_idle = getattr(view_state.canvas, "draw_idle", None)
    if callable(draw_idle):
        draw_idle()


def _film_fig2_array_signature(value: object) -> tuple[object, ...]:
    try:
        array = np.asarray(value, dtype=np.float64)
    except Exception:
        return ("invalid",)
    if array.size == 0:
        return (tuple(array.shape), 0)
    finite = np.isfinite(array)
    if not np.any(finite):
        return (tuple(array.shape), int(array.size), "no_finite")
    finite_values = array[finite]
    return (
        tuple(array.shape),
        int(array.size),
        float(finite_values[0]),
        float(finite_values[-1]),
        float(np.nanmin(finite_values)),
        float(np.nanmax(finite_values)),
    )


def _current_film_fig2_request_signature(*, preview=None, stack=None) -> tuple[object, ...]:
    if preview is None or stack is None:
        preview, stack, _stack_status = _current_film_stitched_preview()
    metadata = getattr(preview, "metadata", {})
    metadata = metadata if isinstance(metadata, Mapping) else {}
    stack_settings = _current_reflectivity_stack_settings()
    stack_layers = getattr(stack, "stack_layers", None)
    effective_nm = getattr(stack, "effective_thickness_nm", None)
    runtime_state = globals().get("simulation_runtime_state")
    return (
        ("valid", bool(getattr(preview, "valid", False))),
        ("reason", str(getattr(preview, "reason", ""))),
        ("L", _film_fig2_array_signature(metadata.get("L_values", []))),
        ("qz_over_qc", _film_fig2_array_signature(metadata.get("qz_over_qc", []))),
        ("stitched", _film_fig2_array_signature(metadata.get("stitched_curve", []))),
        ("pure_parratt", _film_fig2_array_signature(metadata.get("pure_parratt", []))),
        ("scaled_ht_over_q2", _film_fig2_array_signature(metadata.get("scaled_ht_over_q2", []))),
        ("bandwidth_fraction", float(_current_bandwidth_fraction())),
        ("divergence_sigma", float(_current_divergence_sigma())),
        ("sample_count", int(getattr(runtime_state, "num_samples", 0) or 0)),
        ("stack_layers", None if stack_layers is None else int(stack_layers)),
        ("effective_thickness_nm", None if effective_nm is None else float(effective_nm)),
        ("optical_stack", tuple(sorted(stack_settings.items()))),
        ("stitch_enabled", bool(_current_parratt_low_q_stitch_enabled())),
    )


def _refresh_film_reflectivity_popout_if_open() -> None:
    if gui_views.film_reflectivity_popout_window_open(film_reflectivity_popout_view_state):
        signature = _current_film_fig2_request_signature()
        if signature == getattr(
            film_reflectivity_popout_view_state, "last_request_signature", None
        ):
            _sync_film_profile_popout_value_fields()
            return
        _draw_film_reflectivity_popout()


def _film_profile_axis_limit(
    axis,
    getter_name: str,
) -> tuple[float, float] | None:
    getter = getattr(axis, getter_name, None)
    if not callable(getter):
        return None
    try:
        limits = tuple(float(value) for value in getter())
    except Exception:
        return None
    if len(limits) == 2 and all(np.isfinite(value) for value in limits):
        return limits
    return None


def _restore_film_profile_axis_limit(
    axis,
    setter_name: str,
    limits: tuple[float, float] | None,
) -> None:
    if limits is None:
        return
    setter = getattr(axis, setter_name, None)
    if not callable(setter):
        return
    try:
        setter(*limits)
    except Exception:
        pass


def _sync_film_profile_drag_value_fields(view_state) -> None:
    if view_state is globals().get("film_reflectivity_popout_view_state"):
        _sync_film_profile_popout_value_fields()
        return
    if view_state is globals().get("film_reflectivity_controls_view_state"):
        _sync_embedded_film_profile_value_fields()
        return
    try:
        values = _current_film_profile_popout_values()
    except Exception:
        return
    _sync_film_profile_value_vars(view_state, values)


def _refresh_film_profile_drag_preview(view_state) -> None:
    profile_ax = getattr(view_state, "profile_ax", None)
    if profile_ax is None:
        return
    stack, _stack_status = _current_reflectivity_optical_stack()
    x_limits = _film_profile_axis_limit(profile_ax, "get_xlim")
    y_limits = _film_profile_axis_limit(profile_ax, "get_ylim")
    old_mu_ax = getattr(view_state, "profile_mu_ax", None)
    old_mu_ylim = _film_profile_axis_limit(old_mu_ax, "get_ylim")
    _remove_film_reflectivity_profile_mu_axis(view_state)

    clear = getattr(profile_ax, "clear", None)
    if callable(clear):
        try:
            clear()
        except Exception:
            return

    profile_handles = getattr(view_state, "profile_handles", None)
    if not isinstance(profile_handles, list):
        profile_handles = []
        try:
            view_state.profile_handles = profile_handles
        except Exception:
            pass
    else:
        profile_handles.clear()

    view_state.profile_mu_ax = _draw_film_reflectivity_depth_profile(
        profile_ax,
        stack,
        handles=profile_handles,
        profile_visibility_vars=getattr(view_state, "profile_visibility_vars", None),
    )
    _sync_film_profile_drag_value_fields(view_state)
    _restore_film_profile_axis_limit(profile_ax, "set_xlim", x_limits)
    _restore_film_profile_axis_limit(profile_ax, "set_ylim", y_limits)
    if old_mu_ylim is not None and getattr(view_state, "profile_mu_ax", None) is not None:
        _restore_film_profile_axis_limit(view_state.profile_mu_ax, "set_ylim", old_mu_ylim)
    draw_idle = getattr(getattr(view_state, "canvas", None), "draw_idle", None)
    if callable(draw_idle):
        draw_idle()


def _close_film_reflectivity_popout() -> None:
    gui_views.close_film_reflectivity_popout_window(film_reflectivity_popout_view_state)


def _open_film_reflectivity_popout() -> None:
    gui_views.open_film_reflectivity_popout_window(
        root=root,
        view_state=film_reflectivity_popout_view_state,
        on_close=_close_film_reflectivity_popout,
        on_curve_visibility_change=_draw_film_reflectivity_popout,
        profile_visibility_vars=getattr(
            film_reflectivity_controls_view_state,
            "profile_visibility_vars",
            None,
        ),
        on_profile_visibility_change=_on_film_profile_visibility_change,
        on_profile_value_commit=_commit_film_profile_popout_value,
        pause_main_updates_var=getattr(
            film_reflectivity_controls_view_state,
            "pause_main_updates_var",
            None,
        ),
        on_toggle_main_updates=_on_film_profile_main_updates_pause_toggle,
        on_axis_limit_commit=_draw_film_reflectivity_popout,
    )
    _draw_film_reflectivity_popout()


def _on_film_profile_visibility_change() -> None:
    if gui_views.film_reflectivity_popout_window_open(film_reflectivity_popout_view_state):
        _draw_film_reflectivity_popout()
    _refresh_film_reflectivity_preview()


def _refresh_film_reflectivity_preview(
    *,
    sync_profile_values: bool = False,
) -> None:
    _sync_film_reflectivity_readouts(sync_profile_values=sync_profile_values)
    _refresh_film_reflectivity_popout_if_open()
    if not _film_reflectivity_preview_should_render():
        return
    preview, stack, stack_status = _current_film_stitched_preview()
    _draw_film_reflectivity_preview(preview, stack, status_message=stack_status)


def _on_film_reflectivity_tab_selected(
    _variable_name: str | None = None,
    _index: str | None = None,
    _operation: str | None = None,
) -> None:
    if _film_reflectivity_tab_selected():
        _refresh_film_reflectivity_preview(sync_profile_values=True)


def _set_film_profile_float_var(value_var, value: float) -> bool:
    setter = getattr(value_var, "set", None)
    if not callable(setter):
        return False
    clean_value = float(value)
    getter = getattr(value_var, "get", None)
    if callable(getter):
        try:
            current = float(getter())
        except Exception:
            current = None
        if current is not None and math.isclose(
            current,
            clean_value,
            rel_tol=1.0e-12,
            abs_tol=1.0e-12,
        ):
            return False
    try:
        setter(clean_value)
    except Exception:
        return False
    return True


def _film_profile_sampling_var(name: str):
    view_var = getattr(sampling_optics_controls_view_state, name, None)
    return view_var if view_var is not None else globals().get(name)


def _film_profile_wavelength_angstrom() -> float:
    try:
        wavelength = float(lambda_)
    except Exception as exc:
        raise ValueError("invalid_wavelength") from exc
    if not np.isfinite(wavelength) or wavelength <= 0.0:
        raise ValueError("invalid_wavelength")
    return float(wavelength)


def _disable_cif_optics_for_film_profile_edit() -> bool:
    use_cif_var = _film_profile_sampling_var("parratt_use_cif_optics_var")
    setter = getattr(use_cif_var, "set", None)
    changed = False
    if callable(setter):
        getter = getattr(use_cif_var, "get", None)
        if callable(getter):
            try:
                changed = bool(getter()) is not False
            except Exception:
                changed = True
        else:
            changed = True
        try:
            if changed:
                setter(False)
        except Exception:
            changed = False
    if changed:
        try:
            _sync_sampling_parratt_manual_entry_state()
        except Exception:
            pass
    defaults["parratt_use_cif_optics"] = False
    return changed


def _sync_film_profile_owner_defaults() -> None:
    optics = _current_parratt_optics_settings()
    defaults["parratt_use_cif_optics"] = bool(optics["parratt_use_cif_optics"])
    defaults["parratt_n_real"] = float(optics["parratt_n_real"])
    defaults["parratt_n_imag"] = float(optics["parratt_n_imag"])

    stack = _current_reflectivity_stack_settings()
    defaults["reflectivity_substrate_n_real"] = float(stack["reflectivity_substrate_n_real"])
    defaults["reflectivity_substrate_n_imag"] = float(stack["reflectivity_substrate_n_imag"])
    defaults["reflectivity_top_roughness_nm"] = float(stack["reflectivity_top_roughness_nm"])
    defaults["reflectivity_bottom_roughness_nm"] = float(stack["reflectivity_bottom_roughness_nm"])


def _film_profile_main_update_needed(kind: str) -> bool:
    if kind == "thickness":
        finite_var = globals().get("finite_stack_var")
        getter = getattr(finite_var, "get", None)
        if callable(getter):
            try:
                return bool(getter())
            except Exception:
                pass
        return bool(defaults.get("finite_stack", True))
    return bool(_current_parratt_low_q_stitch_enabled())


def _film_profile_main_updates_paused() -> bool:
    for view_state in (
        globals().get("film_reflectivity_controls_view_state"),
        globals().get("film_reflectivity_popout_view_state"),
    ):
        pause_var = getattr(view_state, "pause_main_updates_var", None)
        getter = getattr(pause_var, "get", None)
        if callable(getter):
            try:
                if bool(getter()):
                    return True
            except Exception:
                pass
    return False


def _request_film_profile_main_update(kind: str) -> None:
    if not _film_profile_main_update_needed(kind):
        return
    if _film_profile_main_updates_paused():
        film_profile_pending_main_update_kinds.add(str(kind))
        update_occupancies(trigger_update=False)
        _refresh_film_reflectivity_preview(sync_profile_values=True)
        return
    update_occupancies()


def _on_film_profile_main_updates_pause_toggle() -> None:
    if not _film_profile_main_updates_paused() and film_profile_pending_main_update_kinds:
        film_profile_pending_main_update_kinds.clear()
        update_occupancies()
    _refresh_film_reflectivity_preview()


def _film_profile_handle_at_event(view_state, event):
    if getattr(event, "x", None) is None or getattr(event, "y", None) is None:
        return None
    handles = getattr(view_state, "profile_handles", None)
    if not isinstance(handles, list):
        return None
    for handle_info in reversed(handles):
        artist = handle_info.get("artist") if isinstance(handle_info, Mapping) else None
        contains = getattr(artist, "contains", None)
        if not callable(contains):
            continue
        try:
            hit, _details = contains(event)
        except Exception:
            hit = False
        if hit:
            return handle_info
    return None


def _film_profile_axis_data_delta_per_pixel(axis, event) -> tuple[float, float]:
    transform = getattr(axis, "transData", None)
    inverted = getattr(transform, "inverted", None)
    if not callable(inverted):
        return (0.0, 0.0)
    try:
        inverse = inverted()
        x0_data, y0_data = inverse.transform((float(event.x), float(event.y)))
        x1_data, _ = inverse.transform((float(event.x) + 1.0, float(event.y)))
        _, y1_data = inverse.transform((float(event.x), float(event.y) + 1.0))
    except Exception:
        return (0.0, 0.0)
    return (float(x1_data) - float(x0_data), float(y1_data) - float(y0_data))


def _current_film_profile_drag_values() -> dict[str, float]:
    wavelength = _film_profile_wavelength_angstrom()
    try:
        thickness_nm = _current_film_thickness_nm()
    except Exception:
        thickness_nm = float(
            defaults.get(
                "film_thickness_nm",
                gui_controllers.DEFAULT_FINITE_STACK_FILM_THICKNESS_NM,
            )
        )
    stack_settings = _current_reflectivity_stack_settings()
    film_refractive_index, _source = _current_film_reflectivity_refractive_index()
    if film_refractive_index is None:
        film_refractive_index = _current_manual_parratt_refractive_index()
    substrate_refractive_index = complex(
        stack_settings["reflectivity_substrate_n_real"],
        stack_settings["reflectivity_substrate_n_imag"],
    )
    return {
        "thickness": float(thickness_nm),
        "top_roughness": float(stack_settings["reflectivity_top_roughness_nm"]),
        "bottom_roughness": float(stack_settings["reflectivity_bottom_roughness_nm"]),
        "film_density": gui_film_reflectivity.electron_density_from_refractive_index(
            film_refractive_index,
            wavelength,
        ),
        "substrate_density": gui_film_reflectivity.electron_density_from_refractive_index(
            substrate_refractive_index,
            wavelength,
        ),
        "film_mu": gui_film_reflectivity.absorption_from_refractive_index(
            film_refractive_index,
            wavelength,
        ),
        "substrate_mu": gui_film_reflectivity.absorption_from_refractive_index(
            substrate_refractive_index,
            wavelength,
        ),
    }


def _film_profile_drag_state(view_state) -> dict[str, object]:
    drag_state = getattr(view_state, "profile_drag_state", None)
    if not isinstance(drag_state, dict):
        drag_state = {}
        try:
            view_state.profile_drag_state = drag_state
        except Exception:
            pass
    return drag_state


def _start_film_profile_drag(view_state, event) -> None:
    handle_info = _film_profile_handle_at_event(view_state, event)
    if handle_info is None:
        return
    axis = handle_info.get("axis") or getattr(view_state, "profile_ax", None)
    if axis is None:
        return
    x_data_per_pixel, y_data_per_pixel = _film_profile_axis_data_delta_per_pixel(
        axis,
        event,
    )
    drag_state = _film_profile_drag_state(view_state)
    start_values = _current_film_profile_drag_values()
    drag_state.clear()
    drag_state.update(
        {
            "kind": str(handle_info["kind"]),
            "axis": axis,
            "x0": float(event.x),
            "y0": float(event.y),
            "x_data_per_pixel": float(x_data_per_pixel),
            "y_data_per_pixel": float(y_data_per_pixel),
            "value_scale": float(handle_info.get("value_scale", 1.0) or 1.0),
            "drag_mode": None,
            "shift": bool(getattr(event, "key", None) == "shift"),
            "changed": False,
            "start_thickness": start_values["thickness"],
            "start_top_roughness": start_values["top_roughness"],
            "start_bottom_roughness": start_values["bottom_roughness"],
            "start_film_density": start_values["film_density"],
            "start_substrate_density": start_values["substrate_density"],
            "start_film_mu": start_values["film_mu"],
            "start_substrate_mu": start_values["substrate_mu"],
        }
    )


def _record_film_profile_drag_update(
    view_state,
    drag_state: dict[str, object],
    kind: str,
    value: float,
) -> None:
    changed = _apply_film_profile_parameter_update(
        kind,
        value,
        trigger_main_update=False,
        refresh_preview=False,
    )
    drag_state["changed"] = bool(changed or drag_state.get("changed", False))
    if changed:
        _refresh_film_profile_drag_preview(view_state)


_FILM_PROFILE_HANDLE_ROUGHNESS_STARTS = {
    "film_density": ("top_roughness", "start_top_roughness"),
    "film_mu": ("top_roughness", "start_top_roughness"),
    "substrate_density": ("bottom_roughness", "start_bottom_roughness"),
    "substrate_mu": ("bottom_roughness", "start_bottom_roughness"),
}


def _move_film_profile_drag(view_state, event) -> None:
    drag_state = _film_profile_drag_state(view_state)
    if drag_state.get("kind") is None:
        return
    if getattr(event, "x", None) is None or getattr(event, "y", None) is None:
        return

    kind = str(drag_state["kind"])
    dx_pixels = float(event.x) - float(drag_state.get("x0", event.x))
    dy_pixels = float(event.y) - float(drag_state.get("y0", event.y))
    dx_data = dx_pixels * float(drag_state.get("x_data_per_pixel", 0.0))
    dy_data = dy_pixels * float(drag_state.get("y_data_per_pixel", 0.0))

    update_roughness = True
    update_value = True
    shift_active = bool(drag_state.get("shift", False) or getattr(event, "key", None) == "shift")
    if kind != "thickness" and not shift_active:
        drag_mode = drag_state.get("drag_mode")
        if drag_mode is None:
            if max(abs(dx_pixels), abs(dy_pixels)) < 4.0:
                return
            drag_mode = "roughness" if abs(dx_pixels) >= abs(dy_pixels) else "value"
            drag_state["drag_mode"] = drag_mode
        update_roughness = drag_mode == "roughness"
        update_value = drag_mode == "value"

    if kind == "thickness":
        _record_film_profile_drag_update(
            view_state,
            drag_state,
            "thickness",
            max(1.0e-6, float(drag_state.get("start_thickness", 0.0)) + dx_data),
        )
        return

    roughness_info = _FILM_PROFILE_HANDLE_ROUGHNESS_STARTS.get(kind)
    if roughness_info is None:
        return
    roughness_kind, roughness_start_key = roughness_info
    if update_roughness:
        _record_film_profile_drag_update(
            view_state,
            drag_state,
            roughness_kind,
            max(0.0, float(drag_state.get(roughness_start_key, 0.0)) + dx_data),
        )
    if update_value:
        value_scale = max(1.0e-300, float(drag_state.get("value_scale", 1.0) or 1.0))
        scaled_start_value = float(drag_state.get(f"start_{kind}", 0.0)) * value_scale
        _record_film_profile_drag_update(
            view_state,
            drag_state,
            kind,
            max(0.0, scaled_start_value + dy_data) / value_scale,
        )


def _end_film_profile_drag(view_state, _event) -> None:
    drag_state = _film_profile_drag_state(view_state)
    kind = drag_state.get("kind")
    changed = bool(drag_state.get("changed", False))
    drag_state.clear()
    drag_state["kind"] = None
    if kind is not None and changed:
        _request_film_profile_main_update(str(kind))


def _connect_film_profile_canvas_events(view_state) -> None:
    event_cids = getattr(view_state, "profile_drag_event_cids", None)
    if event_cids:
        return
    canvas = getattr(view_state, "canvas", None)
    connector = getattr(canvas, "mpl_connect", None)
    if not callable(connector):
        return
    if not isinstance(event_cids, list):
        event_cids = []
        try:
            view_state.profile_drag_event_cids = event_cids
        except Exception:
            pass
    event_cids.extend(
        [
            connector(
                "button_press_event",
                lambda event, state=view_state: _start_film_profile_drag(state, event),
            ),
            connector(
                "motion_notify_event",
                lambda event, state=view_state: _move_film_profile_drag(state, event),
            ),
            connector(
                "button_release_event",
                lambda event, state=view_state: _end_film_profile_drag(state, event),
            ),
        ]
    )


_FILM_PROFILE_OPTICAL_OWNER_VARS = {
    "film_density": "parratt_n_real_var",
    "film_mu": "parratt_n_imag_var",
    "substrate_density": "reflectivity_substrate_n_real_var",
    "substrate_mu": "reflectivity_substrate_n_imag_var",
}

_FILM_PROFILE_ROUGHNESS_OWNER_VARS = {
    "top_roughness": "reflectivity_top_roughness_nm_var",
    "bottom_roughness": "reflectivity_bottom_roughness_nm_var",
}


def _film_profile_refractive_index_owner_value(kind: str, value: float) -> float:
    wavelength = _film_profile_wavelength_angstrom()
    if kind.endswith("_density"):
        return gui_film_reflectivity.refractive_index_real_from_electron_density(
            value,
            wavelength,
        )
    return gui_film_reflectivity.refractive_index_imag_from_absorption(
        value,
        wavelength,
    )


def _seed_manual_film_optics_from_current_refractive_index() -> bool:
    try:
        film_refractive_index, _source = _current_film_reflectivity_refractive_index()
    except Exception:
        film_refractive_index = None
    if film_refractive_index is None:
        return False
    n_value = complex(film_refractive_index)
    if not np.isfinite(n_value.real) or not np.isfinite(n_value.imag) or n_value.real <= 0.0:
        return False
    real_changed = _set_film_profile_float_var(
        _film_profile_sampling_var("parratt_n_real_var"),
        float(n_value.real),
    )
    imag_changed = _set_film_profile_float_var(
        _film_profile_sampling_var("parratt_n_imag_var"),
        max(0.0, float(n_value.imag)),
    )
    return bool(real_changed or imag_changed)


def _apply_film_profile_optical_update(kind: str, value: float) -> bool:
    owner_var_name = _FILM_PROFILE_OPTICAL_OWNER_VARS.get(kind)
    if owner_var_name is None:
        return False
    owner_value = _film_profile_refractive_index_owner_value(kind, value)
    changed = False
    if kind.startswith("film_"):
        if _current_parratt_use_cif_optics():
            changed = _seed_manual_film_optics_from_current_refractive_index()
        changed = _disable_cif_optics_for_film_profile_edit() or changed
    changed = (
        _set_film_profile_float_var(
            _film_profile_sampling_var(owner_var_name),
            owner_value,
        )
        or changed
    )
    _sync_film_profile_owner_defaults()
    return changed


def _apply_film_profile_roughness_update(kind: str, value: float) -> bool:
    owner_var_name = _FILM_PROFILE_ROUGHNESS_OWNER_VARS.get(kind)
    if owner_var_name is None:
        return False
    changed = _set_film_profile_float_var(
        _film_profile_sampling_var(owner_var_name),
        max(0.0, value),
    )
    _sync_film_profile_owner_defaults()
    return changed


def _apply_film_profile_parameter_update(
    kind: str,
    raw_value: object,
    *,
    trigger_main_update: bool = True,
    refresh_preview: bool = True,
) -> bool:
    try:
        value = float(raw_value)
    except (TypeError, ValueError):
        return False
    if not np.isfinite(value):
        return False

    normalized_kind = str(kind)
    changed = False
    try:
        if normalized_kind == "thickness":
            value = gui_controllers.normalize_finite_stack_thickness_nm(
                value,
                _current_film_thickness_nm(),
            )
            value_var = getattr(
                finite_stack_controls_view_state,
                "film_thickness_nm_var",
                None,
            )
            if value_var is None:
                value_var = globals().get("film_thickness_nm_var")
            gui_views.ensure_finite_stack_thickness_scale_max(
                finite_stack_controls_view_state,
                value,
            )
            changed = _set_film_profile_float_var(value_var, value)
            defaults["film_thickness_nm"] = float(value)
            _sync_thickness_entry_from_var()
            _current_stack_layers()
        elif normalized_kind in _FILM_PROFILE_OPTICAL_OWNER_VARS:
            changed = _apply_film_profile_optical_update(normalized_kind, value)
        elif normalized_kind in _FILM_PROFILE_ROUGHNESS_OWNER_VARS:
            changed = _apply_film_profile_roughness_update(normalized_kind, value)
        else:
            return False
    except ValueError:
        return False

    if not changed:
        return False
    if normalized_kind != "thickness":
        _refresh_resolution_display()

    if (
        trigger_main_update
        and _film_profile_main_update_needed(normalized_kind)
        and _film_profile_main_updates_paused()
    ):
        _request_film_profile_main_update(normalized_kind)
        return True
    if refresh_preview:
        _refresh_film_reflectivity_preview(sync_profile_values=True)
    if trigger_main_update:
        _request_film_profile_main_update(normalized_kind)
    return True


def _current_random_sample_count(default=None):
    fallback = _parse_sample_count(
        default if default is not None else _default_random_sample_count(),
        DEFAULT_RANDOM_SAMPLE_COUNT,
    )
    sample_count_var = sampling_optics_controls_view_state.sample_count_var
    raw_value = sample_count_var.get() if sample_count_var is not None else fallback
    return _parse_sample_count(raw_value, fallback)


def _events_per_beam_phase_independent() -> bool:
    independent_var = getattr(
        sampling_optics_controls_view_state,
        "events_per_phase_independent_var",
        None,
    )
    getter = getattr(independent_var, "get", None)
    if not callable(getter):
        return True
    try:
        return bool(getter())
    except Exception:
        return True


def _linked_events_per_beam_phase(sample_count=None) -> int:
    if sample_count is None:
        sample_count = _current_random_sample_count()
    normalized_samples = _parse_sample_count(sample_count, DEFAULT_EVENTS_PER_BEAM_PHASE)
    linked_events = int(normalized_samples) * int(DEFAULT_LINKED_EVENTS_PER_SAMPLE)
    return _parse_events_per_beam_phase(linked_events, DEFAULT_EVENTS_PER_BEAM_PHASE)


def _sync_events_per_beam_phase_to_sample_count(sample_count=None) -> int:
    normalized = _linked_events_per_beam_phase(sample_count)
    events_var = getattr(sampling_optics_controls_view_state, "events_per_phase_var", None)
    if events_var is not None:
        try:
            current_value = int(round(float(events_var.get())))
        except Exception:
            current_value = normalized
        if current_value != normalized:
            events_var.set(normalized)
    defaults["events_per_beam_phase"] = int(normalized)
    return int(normalized)


def _current_events_per_beam_phase(default=None):
    if not _events_per_beam_phase_independent():
        return _linked_events_per_beam_phase()

    fallback = _parse_events_per_beam_phase(
        default if default is not None else _default_events_per_beam_phase(),
        DEFAULT_EVENTS_PER_BEAM_PHASE,
    )
    events_var = getattr(sampling_optics_controls_view_state, "events_per_phase_var", None)
    raw_value = events_var.get() if events_var is not None else fallback
    return _parse_events_per_beam_phase(raw_value, fallback)


def _sync_active_sample_count() -> int:
    simulation_runtime_state.num_samples = int(
        max(1, _current_random_sample_count(default=max(1, simulation_runtime_state.num_samples)))
    )
    return int(simulation_runtime_state.num_samples)


