def _apply_random_sample_count(*, trigger_update=True):
    previous_num_samples = int(simulation_runtime_state.num_samples)
    _normalize_random_sample_count_control(default=max(1, simulation_runtime_state.num_samples))
    _sync_active_sample_count()
    _refresh_resolution_display()
    _sync_film_reflectivity_readouts()
    if trigger_update and simulation_runtime_state.num_samples != previous_num_samples:
        update_mosaic_cache()
        schedule_update()


def _apply_events_per_beam_phase(*, trigger_update=True):
    _normalize_events_per_beam_phase_control(default=_default_events_per_beam_phase())
    _refresh_resolution_display()
    _sync_film_reflectivity_readouts()
    if trigger_update:
        _invalidate_picker_handoff_caches_for_update_action(
            UpdateAction.FULL_SIMULATION,
            physics_signature_changed=True,
            hit_table_signature_changed=True,
            q_group_content_signature_changed=True,
            detector_geometry_changed=False,
        )
        simulation_runtime_state.last_sim_signature = None
        simulation_runtime_state.last_simulation_signature = None
        simulation_runtime_state.worker_ready_result = None
        schedule_update()


def _on_events_per_beam_phase_independent_change():
    previous_events = _parse_events_per_beam_phase(
        defaults.get("events_per_beam_phase", _default_events_per_beam_phase()),
        DEFAULT_EVENTS_PER_BEAM_PHASE,
    )
    if _events_per_beam_phase_independent():
        current_events = _normalize_events_per_beam_phase_control(default=previous_events)
    else:
        current_events = _sync_events_per_beam_phase_to_sample_count()
    _set_random_sample_controls_state()
    _refresh_resolution_display()
    if current_events != previous_events:
        _invalidate_geometry_manual_pick_cache()
        simulation_runtime_state.last_sim_signature = None
        simulation_runtime_state.last_simulation_signature = None
        simulation_runtime_state.worker_ready_result = None
        schedule_update()


