def _atom_site_fractional_label_text(site_idx: int) -> str:
    idx = int(site_idx)
    atom_site_rows = _atom_site_fractional_rows()
    if idx < len(atom_site_rows):
        return str(atom_site_rows[idx].get("label", f"site_{idx + 1}"))
    return f"site_{idx + 1}"


